window._rvLoad({"n":3,"s":[{"n":1,"t":"Agni","v":[{"n":1,"d":"सोमस्य मा तवसं वक्ष्यग्ने वह्निं चकर्थ विदथे यजध्यै | देवानछा दीद्यद युञ्जे अद्रिं शमाये अग्ने तन्वंजुषस्व ||","b":"সোমস্য মা তবসং বক্ষ্যগ্নে বহ্নিং চকর্থ বিদথে যজধ্যৈ | দেবানছা দীদ্যদ যুঞ্জে অদ্রিং শমাযে অগ্নে তন্বংজুষস্ব ||","e":"THOU, Agni, who wilt have the strong, hast made me the Soma's priest, to worship in assembly. Thou shinest to the Gods, I set the press-stones. I toil; be joyful in thyself, O Agni.","mb":"হে অগ্নি! তুমি যজ্ঞ করবার নিমিত্ত আমাকে সোমের বাহক করেছ, অতএব আমাকে বলবান কর। হে অগ্নি! আ দীপ্যমান হয়ে দেবতাগণের উদ্দেশে অভিষবণের জন্য প্রস্তর খন্ড গ্রহণ করছি ও স্তব করছি। হে অগ্নি। তুমি আমার শরীর রক্ষা কর।"},{"n":2,"d":"पराञ्चं यज्ञं चक्र्म वर्धतां गीः समिद्भिरग्निं नमसा दुवस्यन | दिवः शशासुर्विदथा कवीनां गर्त्साय चित तवसे गातुमीषुः ||","b":"পরাঞ্চং যজ্ঞং চক্র্ম বর্ধতাং গীঃ সমিদ্ভিরগ্নিং নমসা দুবস্যন | দিবঃ শশাসুর্বিদথা কবীনাং গর্ত্সায চিত তবসে গাতুমীষুঃ ||","e":"East have we turned the rite; may the hymn aid it. With wood and worship shall they honour Agni. From heaven the synods of the wise have learnt it: e’en for the quick and strong they seek advancement.","mb":"হে অগ্নি! আমরা সম্যকরূপে যজ্ঞ করছি, আমাদের স্তুতি বর্ধিত হোক। সমিধ ও হব্যদ্বারা অগ্নিকে লোকে পরিচর্যা করুক। (দেবগণ) দ্যুলোক হতে এসে স্তোতাদের স্তোত্র শিখিয়েছেন। স্তোতাগণ স্তুতিযোগ্য ও প্রবৃদ্ধ অগ্নিকে স্তব করতে অভিলাষ করে।"},{"n":3,"d":"मयो दधे मेधिरः पूतदक्षो दिवः सुबन्धुर्जनुषा पर्थिव्याः | अविन्दन्नु दर्शतमप्स्वन्तर्देवासो अग्निमपसि सवसॄणाम ||","b":"মযো দধে মেধিরঃ পূতদক্ষো দিবঃ সুবন্ধুর্জনুষা পর্থিব্যাঃ | অবিন্দন্নু দর্শতমপ্স্বন্তর্দেবাসো অগ্নিমপসি সবসৄণাম ||","e":"The Prudent, he whose will is pure, brought welfare, allied by birth to Heaven and Earth in kinship. The Gods discovered in the midst of waters beautiful Agni with the Sisters' labour.","mb":"যিনি মেধাবী, বিশুদ্ধ বলশালী জন্মিবামাত্রেই উৎকৃষ্ট বন্ধু, যিনি দ্যুলোক ও পৃথিবীর সুখবিধান করেন, সে দর্শনীয় অগ্নিকে দেবগণ যজ্ঞ কার্যের জন্য ভগিনীরূপ (নদী সকলের) জলের মধ্যে প্রাপ্ত হয়েছেন।"},{"n":4,"d":"अवर्धयन सुभगं सप्त यह्वीः शवेतं जज्ञानमरुषम्महित्वा | शिशुं न जातमभ्यारुरश्वा देवासो अग्निंजनिमन वपुष्यन ||","b":"অবর্ধযন সুভগং সপ্ত যহ্বীঃ শবেতং জজ্ঞানমরুষম্মহিত্বা | শিশুং ন জাতমভ্যারুরশ্বা দেবাসো অগ্নিংজনিমন বপুষ্যন ||","e":"Him, Blessed One, the Seven strong Floods augmented, him white at birth and red when waxen mighty. As mother mares run to their new-born you ling, so at his birth the Gods wondered at Agni.","mb":"শোভনধনযুক্ত, শুভ্র ও নিজ মাহাত্ম্যে দীপ্তিশালী অগ্নি উৎপন্ন হলেই সপ্ত মহতী নদী তাকে বর্ধিত করেছিলেন। অশ্বী যেরূপ নবজাত শিশুর নিকট  যায়, সেরূপ নদীসকল নবজাত অগ্নির নিকট গমন করেছিলেন। অগ্নি উৎপন্ন হলেই তাকে দেবগণ দীপ্তিমান করেছেন।"},{"n":5,"d":"शुक्रेभिरङगै रज आततन्वान करतुं पुनानः कविभिः पवित्रैः | शोचिर्वसानः पर्यायुरपां शरियो मिमीते बर्हतीरनूनाः ||","b":"শুক্রেভিরঙগৈ রজ আততন্বান করতুং পুনানঃ কবিভিঃ পবিত্রৈঃ | শোচির্বসানঃ পর্যাযুরপাং শরিযো মিমীতে বর্হতীরনূনাঃ ||","e":"Spreading with radiant limbs throughout the region, purging his power with wise purifications, Robing himself in light, the life of waters, he spreads abroad his high and perfect glories.","mb":"অগ্নির শুভ্রবর্ণ তেজদ্বারা অন্তরীক্ষ ব্যাপ্ত করে যজমানকে স্তবনীয় ও পবিত্র তেজদ্বারা পরিশোধিত করেন এবং দীপ্তি পরিধান করে যজমানকে অন্ন এবং প্রভূত ও সম্পূর্ণ সম্পত্তি দান করেন।"},{"n":6,"d":"वव्राजा सीमनदतीरदब्धा दिवो यह्वीरवसाना अनग्नाः | सना अत्र युवतयः सयोनीरेकं गर्भं दधिरे सप्त वाणीः ||","b":"বব্রাজা সীমনদতীরদব্ধা দিবো যহ্বীরবসানা অনগ্নাঃ | সনা অত্র যুবতযঃ সযোনীরেকং গর্ভং দধিরে সপ্ত বাণীঃ ||","e":"He sought heaven's Mighty Ones, the unconsuming, the unimpaired, not clothed and yet not naked. Then they, ancient and young, who dwell together, Seven sounding Rivers, as one germ received him.","mb":"অগ্নি জলের চতুর্দিকে গমন করছেন, সে জল অগ্নিকে নির্বাণ করছে না, অথবা অগ্নিদ্বারা শোষিত হচ্ছে না। অন্তরীক্ষের অপত্যভূত অগ্নি বস্ত্রদ্বারা আচ্ছাদিত নন অথচ জলবেষ্টিত হওয়ায় উলঙ্গও নন। সনাতনী নিত্যতরুণা ও এক স্থান হতে উৎপন্না সপ্তনদী এক অগ্নিকে গর্ভে ধারণ করেন।"},{"n":7,"d":"सतीर्णा अस्य संहतो विश्वरूपा घर्तस्य योनौ सरवथे मधूनाम | अस्थुरत्र धेनवः पिन्वमाना मही दस्मस्य मातरा समीची ||","b":"সতীর্ণা অস্য সংহতো বিশ্বরূপা ঘর্তস্য যোনৌ সরবথে মধূনাম | অস্থুরত্র ধেনবঃ পিন্বমানা মহী দস্মস্য মাতরা সমীচী ||","e":"His piles, assuming every form, are scattered where flow sweet waters, at the spring of fatness; There stood the milch-kine with full-laden udders, and both paired Mighty Mothers of the Wondrous.","mb":"জলবর্ষণ হলে উদকের গর্ভস্বরূপ ও অন্তরীক্ষে পুঞ্জীভূত নানাবর্ণ অগ্নির রশ্মি সকল বিদ্যমান থকে। এ অগ্নিতে জলরূপ পীনা ধেনুসকল সকলের প্রীতিদায়িনী হয়। সুন্দর মহৎ দ্যাবাপৃথিবী দর্শনয়ি অগ্নির পিতামাতা।"},{"n":8,"d":"बभ्राणः सूनो सहसो वयद्यौद दाधानः शुक्रा रभसा वपूंषि | शचोतन्ति धारा मधुनो घर्तस्य वर्षा यत्र वाव्र्धे काव्येन ||","b":"বভ্রাণঃ সূনো সহসো বযদ্যৌদ দাধানঃ শুক্রা রভসা বপূংষি | শচোতন্তি ধারা মধুনো ঘর্তস্য বর্ষা যত্র বাব্র্ধে কাব্যেন ||","e":"Carefully cherished, Son of Strength, thou shoncst assuming lasting and refulgent beauties. Full streams of fatness and sweet juice descended, there where the Mighty One grew strong by wisdom.","mb":"হে বলের পুত্র! সকলে তোমাকে ধারণ করলে তুমি উজ্জ্বল ও বেগবান রশ্মি ধারণ করে দ্যোতিত হও। যখন অগ্নি যজমানের স্তোত্রদ্বারা বৃদ্ধিপ্রাপ্ত হয় তখন মধুর জলধারা পতিত হয়।"},{"n":9,"d":"पितुश्चिदूधर्जनुषा विवेद वयस्य धारा अस्र्जद वि धेनाः | गुहा चरन्तं सखिभिः शिवेभिर्दिवो यह्वीभिर्नगुहा बभूव ||","b":"পিতুশ্চিদূধর্জনুষা বিবেদ বযস্য ধারা অস্র্জদ বি ধেনাঃ | গুহা চরন্তং সখিভিঃ শিবেভির্দিবো যহ্বীভির্নগুহা বভূব ||","e":"From birth he knew even his Father's bosom, he set his voices and his streams in motion; Knew him who moved with blessed Friends in secret, with the young Dames of heaven. He stayed not hidden.","mb":"অগ্নি জন্মিবামাত্রেই পিতা অন্তরীক্ষের উধ, উধ:স্বরূপ জল প্রদেশ জেনেছেন এবং ঐ উধ: সম্বন্ধিনী ধারা বৃষ্টি ও অন্তরীক্ষচারী শব্দ বজ্র পাতিত করেছিলেন। অগ্নি শুভকারী বন্ধু (বায়ু প্রভৃতির) সাথে অবস্থান করেন ও অন্তরীক্ষের অপত্যভূত জলের সাথে গুহাতে বর্তমান থাকেন, এ অগ্নিকে কেউই প্রাপ্ত হয় না।"},{"n":10,"d":"पितुश्च गर्भं जनितुश्च बभ्रे पूर्वीरेको अधयत पीप्यानाः | वर्ष्णे सपत्नी शुचये सबन्धू उभे अस्मै मनुष्येनि पाहि ||","b":"পিতুশ্চ গর্ভং জনিতুশ্চ বভ্রে পূর্বীরেকো অধযত পীপ্যানাঃ | বর্ষ্ণে সপত্নী শুচযে সবন্ধূ উভে অস্মৈ মনুষ্যেনি পাহি ||","e":"He nursed the Infant of the Sire and Maker: alone the Babe sucked many a teeming bosom. Guard, for the Bright and Strong, the fellow-spouses friendly to men and bound to him in kinship.","mb":"অগ্নি পিতার অন্তরীক্ষের ও জনয়িতা রগর্ভধারধ করেন, এক অগ্নি বহুতর বৃদ্ধি প্রাপ্ত ওষধি ভক্ষণ করেন। সপত্নী (২) ও মনুষ্যদের হিতকারণিী দ্যাবাপৃথিবী উভয়েই অভীষ্টবর্ষী অগ্নির বন্ধু। হে অগ্নি! তুমি দ্যাবাপৃথিবীকে বিশেষরূপে রক্ষা কর।"},{"n":11,"d":"उरौ महाननिबाधे ववर्धापो अग्निं यशसः सं हि पूर्वीः | रतस्य योनावशयद दमूना जामीनामग्निरपसिस्वसॄणाम ||","b":"উরৌ মহাননিবাধে ববর্ধাপো অগ্নিং যশসঃ সং হি পূর্বীঃ | রতস্য যোনাবশযদ দমূনা জামীনামগ্নিরপসিস্বসৄণাম ||","e":"The Mighty One increased in space unbounded; full many a glorious flood gave strength to Agni. Friend of the house, within the lap of Order lay Agni, in the Sister Rivers' service.","mb":"মহান অগ্নি অসম্বাধ ও বিস্তীর্ণ অন্তীরক্ষে বর্ধিত হন, কারণ বহু অন্নবান জল তাকে সম্যকরূপে বর্ধিত করে। জলের জন্মস্থানে অন্তরীক্ষে, স্থির অগ্নি ভগিনী স্থানীয়া স্রোতদ্বিনীগণের জলে প্রশান্ত মনে শয়ন করেন।"},{"n":12,"d":"अक्रो न बभ्रिः समिथे महीनां दिद्र्क्षेयः सूनवे भार्जीकः | उदुस्रिया जनिता यो जजानापां गर्भो नर्तमो यह्वो अग्निः ||","b":"অক্রো ন বভ্রিঃ সমিথে মহীনাং দিদ্র্ক্ষেযঃ সূনবে ভার্জীকঃ | উদুস্রিযা জনিতা যো জজানাপাং গর্ভো নর্তমো যহ্বো অগ্নিঃ ||","e":"As keen supporter where great waters gather, light-shedder whom the brood rejoice to look on; He who begat, and will beget, the dawnlights, most manly, Child of Floods, is youthful Agni.","mb":"যে অগ্নি সমস্ত লোকের জনক, উদকের গর্ভভূত, মনুষ্যদের বিশেষরূপে রক্ষক, মহৎশত্রুর আক্রমণকারী, সংগ্রামে মহৎ স্বীয় সেনাগণের রক্ষক সকলের দর্শনীয় এবং স্বীয় দীপ্তিদ্বারা প্রকাশমান, তিনি যজমানের জন্য জল উৎপন্ন করেছেন।"},{"n":13,"d":"अपां गर्भं दर्शतमोषधीनां वना जजान सुभगा विरूपम | देवासश्चिन मनसा सं हि जग्मुः पनिष्ठं जातं तवसं दुवस्यन ||","b":"অপাং গর্ভং দর্শতমোষধীনাং বনা জজান সুভগা বিরূপম | দেবাসশ্চিন মনসা সং হি জগ্মুঃ পনিষ্ঠং জাতং তবসং দুবস্যন ||","e":"Him, varied in his form, the lovely Infant of floods and plants the blessed wood hath gendered. Gods even, moved in spirit, came around him, and served him at his birth, the Strong, the Wondrous.","mb":"সৌভাগ্যযুক্ত অরণি, দর্শনীয়, নানারূপবিশিষ্ট এবং জল ও ওষধি সকলের গর্ভভূত অগ্নিকে উৎপাদন করেছেন। সমুদয় দেবগণও স্তবনীয়, প্রবৃদ্ধ, সদ্যজাত অগ্নির নিকট স্তুতিযুক্ত হয়ে গমন করেছিলেন ও তার স্তবনীয়, প্রবৃদ্ধ, সদ্যজাত অগ্নির নিকট স্তুতিযুক্ত হয়ে গমন করেছিলেন ও তার পরিচর্যা করেছিলেন।"},{"n":14,"d":"बर्हन्त इद भानवो भार्जीकमग्निं सचन्त विद्युतो न शुक्राः | गुहेव वर्द्धं सदसि सवे अन्तरपार ऊर्वे अम्र्तन्दुहानाः ||","b":"বর্হন্ত ইদ ভানবো ভার্জীকমগ্নিং সচন্ত বিদ্যুতো ন শুক্রাঃ | গুহেব বর্দ্ধং সদসি সবে অন্তরপার ঊর্বে অম্র্তন্দুহানাঃ ||","e":"Like brilliant lightnings, mighty luminaries accompany the light-diffusing Agni, Waxen, as ’twere in secret, in his dwelling, while in the boundless stall they milk out Amṛta.","mb":"দীপ্তিমান বিদ্যুৎ সদৃশ মহৎ সূর্যগণ অগাধ সমুদ্র মধ্যে অমৃত দোহন করে গুহার ন্যায় স্বকীয় সদনে অন্তরীক্ষে প্রবৃদ্ধ এবং প্রভাদ্বারা দীপ্তিমান অগ্নিকে আশ্রয় করেন।"},{"n":15,"d":"ईळे च तवा यजमानो हविर्भिरीळे सखित्वं सुमतिं निकामः | देवैरवो मिमीहि सं जरित्रे रक्षा च नो दम्येभिरनीकैः ||","b":"ঈলে চ তবা যজমানো হবির্ভিরীলে সখিত্বং সুমতিং নিকামঃ | দেবৈরবো মিমীহি সং জরিত্রে রক্ষা চ নো দম্যেভিরনীকৈঃ ||","e":"I sacrificing serve thee with oblations and crave with longing thy good-will and friendship. Grant, with the Gods, thy grace to him who lauds thee, protect us with thy rays that guard the homestead.","mb":"যজমান আমি হব্যদ্বারা তোমার স্তুতি করছি, ধর্ম বিষয়ে বুদ্ধি লাভ করবার অভিলষে তোমার সাথে বন্ধুত্ব প্রার্থনা করছি। তুমি দেবতাগণের সাথে স্তুতিকারী আমার পশু প্রভৃতি রক্ষা কর ও দুর্দমমীয় তেজদ্বারা আমাদের রক্ষা কর।"},{"n":16,"d":"उपक्षेतारस्तव सुप्रणीते.अग्ने विश्वानि धन्या दधानाः | सुरेतसा शरवसा तुञ्जमाना अभि षयाम पर्तनायून्रदेवान ||","b":"উপক্ষেতারস্তব সুপ্রণীতে.অগ্নে বিশ্বানি ধন্যা দধানাঃ | সুরেতসা শরবসা তুঞ্জমানা অভি ষযাম পর্তনাযূন্রদেবান ||","e":"May we, O Agni, thou who leadest wisely, thy followers and masters of all treasures, Strong in the glory of our noble offspring, subdue the godless when they seek the battle.","mb":"হে সুনেতা অগ্নি! আমরা তোমার আশ্রয় গ্রহণ করি, সমস্ত ধন প্রাপ্তির হেতুভূত কর্ম করি ও হব্য প্রদান করি। আমরা যেন তোমাকে সুবীর্যকর অন্ন প্রদান করে অদেবগণকে ও অনিষ্টকারী শত্রুদের জয় করত পারি।"},{"n":17,"d":"आ देवानामभवः केतुरग्ने मन्द्रो विश्वानि काव्यानि विद्वान | परति मर्तानवासयो दमूना अनु देवान रथिरो यासिसाधन ||","b":"আ দেবানামভবঃ কেতুরগ্নে মন্দ্রো বিশ্বানি কাব্যানি বিদ্বান | পরতি মর্তানবাসযো দমূনা অনু দেবান রথিরো যাসিসাধন ||","e":"Ensign of Gods hast thou become, O Agni, joy-giver, knower of all secret wisdom. Friend of the homestead, thou hast lightened mortals: carborne thou goest to the Gods, fulfilling.","mb":"হে অগ্নি! তুমি দেবগণের স্তবনীয় দূত, তুমি সমস্ত স্তোত্র জান, তুমি মর্ত্যগণকে নিজ নিজ গৃহে বাস করাও, তুমি রথী, তুমি দেবতাগণের কার্যসাধন করে তাদের পিছনে যাও।"},{"n":18,"d":"नि दुरोणे अम्र्तो मर्त्यानां राजा ससाद विदथानि साधन | घर्तप्रतीक उर्विया वयद्यौदग्निर्विश्वानि काव्यानि विद्वान ||","b":"নি দুরোণে অম্র্তো মর্ত্যানাং রাজা সসাদ বিদথানি সাধন | ঘর্তপ্রতীক উর্বিযা বযদ্যৌদগ্নির্বিশ্বানি কাব্যানি বিদ্বান ||","e":"Within the house hath sate the King immortal of mortals, filling full their sacred synods. Bedewed with holy oil he shineth widely, Agni, the knower of all secret wisdom.","mb":"নিত্য রাজা অগ্নি যজ্ঞ সাধন করে মর্ত্যগণের গৃহে উপবেশন করেন। অগ্নি সমস্ত স্তোত্র জানেন, অগ্নির অবয়ব ঘৃতের দ্বারা দীপ্তিযুক্ত। বিস্তীর্ণ অগ্নি বিদ্যোতিত হচ্ছেন।"},{"n":19,"d":"आ नो गहि सख्येभिः शिवेभिर्महान महीभिरूतिभिः सरण्यन | अस्मे रयिं बहुलं सन्तरुत्रं सुवाचं भागं यशसं कर्धी नः ||","b":"আ নো গহি সখ্যেভিঃ শিবেভির্মহান মহীভিরূতিভিঃ সরণ্যন | অস্মে রযিং বহুলং সন্তরুত্রং সুবাচং ভাগং যশসং কর্ধী নঃ ||","e":"Come unto us with thine auspicious friendship, come speeding, Mighty, with thy mighty succours. Grant us abundant wealth that saves from danger, that brings a good repute, a glorious portion.","mb":"হে গমনেচ্ছু মহান অগ্নি! তুমি মঙ্গলকর সখ্য ও মহৎ রক্ষার সাথে আমাদের নিকট এস এবং আমাদের বহুল, উপদ্রবশূন্য শোভনস্তুতিযুক্ত ও কীর্তিযুক্ত ধন প্রদান কর। ২০। হে অগ্নি! তুমি পুরাতন, তোমার উদ্দেশে আমি এ সকল সনাতন ও নুতন স্তোত্র পাঠ করছি। সর্বভূতজ্ঞ অগ্নি মনুষ্যদের মধ্যে নিহিত আছেন। সেই অভীষ্টবর্ষী অগ্নির উদ্দেশে আমরা এ সকল সবন করেছি।"},{"n":20,"d":"एता ते अग्ने जनिमा सनानि पर पूर्व्याय नूतनानि वोचम | महान्ति वर्ष्णे सवना कर्तेमा जन्मञ-जन्मन निहितो जातवेदाः ||","b":"এতা তে অগ্নে জনিমা সনানি পর পূর্ব্যায নূতনানি বোচম | মহান্তি বর্ষ্ণে সবনা কর্তেমা জন্মঞ-জন্মন নিহিতো জাতবেদাঃ ||","e":"To thee who art of old these songs, O Agni, have I declared, the ancient and the later. These great libations to the Strong are offiered: in every birth is Jātavedas stablished.","mb":"হে অগ্নি, তোমার প্রাচীন এই জন্মকথা এবং নতুন স্তুতি আমি ঘোষণা করলাম। বলশালীর জন্য এই মহান সোমাহুতি অর্পিত হয়: প্রতিটি জন্মে জাতবেদা প্রতিষ্ঠিত।"},{"n":21,"d":"जन्मञ-जन्मन निहितो जातवेदा विश्वामित्रेभिरिध्यते अजस्रः | तस्य वयं सुमतौ यज्ञियस्यापि भद्रे सौमनसे सयाम ||","b":"জন্মঞ-জন্মন নিহিতো জাতবেদা বিশ্বামিত্রেভিরিধ্যতে অজস্রঃ | তস্য বযং সুমতৌ যজ্ঞিযস্যাপি ভদ্রে সৌমনসে সযাম ||","e":"Stablished in every birth is Jātavedas, kindled perpetual by the Viśvāmitras. May we rest ever in the loving-kindness, in the auspicious grace of him the Holy.","mb":"সমস্ত মনুষ্যে নিহিত সর্বভূতজ্ঞ অগ্নি বিশ্বামিত্র কর্তৃক অনবরত প্রদীপ্ত হন। আমরা যেন তার অনুগ্রহ প্রাপ্ত হয়ে যজ্ঞার্হ অগ্নির অভিলষণীয় অনুগ্রহ লাভ করতে পারি।"},{"n":22,"d":"इमं यज्ञं सहसावन तवं नो देवत्रा धेहि सुक्रतो रराणः | पर यंसि होतर्ब्र्हतीरिषो नो.अग्ने महि दरविनमा यजस्व ||","b":"ইমং যজ্ঞং সহসাবন তবং নো দেবত্রা ধেহি সুক্রতো ররাণঃ | পর যংসি হোতর্ব্র্হতীরিষো নো.অগ্নে মহি দরবিনমা যজস্ব ||","e":"This sacrifice of ours do thou, O Mighty, O truly Wise, bear to the Gods rejoicing. Grant us abundant food, thou priestly Herald, vouchsafe to give us ample wealth, O Agni.","mb":"হে বলবান শোভনকর্মবিশিষ্ট অগ্নি! তুমি সর্বদা বিহার করতে  করতে আমাদের যজ্ঞ দেবগণের নিকট বহন কর। হে দেবগণের আহ্বানকারী! তুমি আমাদের অন্ন দান কর। হে অগ্নি! তুমি আমাদের মহৎধন দান কর।"},{"n":23,"d":"इळामग्ने पुरुदंसं सनिं गोः शश्वत्तमं हवमानायसाध | सयान नः सूनुस्तनयो विजावाग्ने सा ते सुमतिर्भुत्वस्मे ||","b":"ইলামগ্নে পুরুদংসং সনিং গোঃ শশ্বত্তমং হবমানাযসাধ | সযান নঃ সূনুস্তনযো বিজাবাগ্নে সা তে সুমতির্ভুত্বস্মে ||","e":"As holy food, Agni, to thine'invoker give wealth in cattle, lasting, rich in marvels. To us he born a son, and spreading offspring. Agni, be this thy gracious will to us-ward.","mb":"হে অগ্নি! তুমি স্তোতাকে বহু কর্মের হেতুভূত ও ধেনুপ্রদাত্রী ভূমি চিরকাল প্রদান কর। আমাদের বংশ বিস্তারকারী এবং সন্তুতি জনয়িতা একটি পুত্র হোক। হে অগ্নি! আমাদের প্রতি তোমার অনুগ্রহ হোক।"}]},{"n":2,"t":"Agni","v":[{"n":1,"d":"वैश्वानराय धिषणां रताव्र्धे घर्तं न पूतमग्नयेजनामसि | दविता होतारं मनुषश्च वाघतो धिया रथंन कुलिशः सं रण्वति ||","b":"বৈশ্বানরায ধিষণাং রতাব্র্ধে ঘর্তং ন পূতমগ্নযেজনামসি | দবিতা হোতারং মনুষশ্চ বাঘতো ধিযা রথংন কুলিশঃ সং রণ্বতি ||","e":"To him, Vaiśvānara, who strengthens Holy Law, to Agni we present our praise like oil made pure. With thoughtful insight human priests bring him anear, our Herald from of old, as an axe forms a car.","mb":"আমরা যজ্ঞবর্ধক বৈশ্বানরের উদ্দেশে বিশুদ্ধ ঘৃতের ন্যায় প্রীতি জনক স্তুতি করব। কুঠার যেরূপ রথকে সংস্কার করে, সেরূপ মনুষ্য ও ঋত্বিকগণ দেবতাগণের আহ্বানকারী গার্হপত্য ও আহ্বনীয় দু প্রকার রূপবিশিষ্ট অগ্নিকে সংস্কার করে।"},{"n":2,"d":"स रोचयज्जनुषा रोदसी उभे स मात्रोरभवत पुत्र ईड्यः | हव्यवाळ अग्निरजरश्चनोहितो दूळभो विशामतिथिर्विभावसुः ||","b":"স রোচযজ্জনুষা রোদসী উভে স মাত্রোরভবত পুত্র ঈড্যঃ | হব্যবাল অগ্নিরজরশ্চনোহিতো দূলভো বিশামতিথির্বিভাবসুঃ ||","e":"He made the heaven and earth resplendent by his birth: Child of two Mothers he was meet to be implored, Agni, oblation-bearer, gracious, ever-young, infallible, rich in radiant light, the guest of men.","mb":"তিনি জন্মিবামাত্রেই দ্যাবাপৃথিবী উভয়কে প্রকাশিত করেন। তিনি পিতামাতার প্রশংসার যোগ্য পুত্র হয়েছিলেন। হব্যবাহী, জরারহিত, অন্নদাতা, অহিংসিত ও প্রভাধন অগ্নি মনুষ্যদের অতিথির ন্যায় পূজা হন।"},{"n":3,"d":"करत्वा दक्षस्य तरुषो विधर्मणि देवासो अग्निं जनयन्त चित्तिभिः | रुरुचानं भानुना जयोतिषा महामत्यं न वाजं सनिष्यन्नुप बरुवे ||","b":"করত্বা দক্ষস্য তরুষো বিধর্মণি দেবাসো অগ্নিং জনযন্ত চিত্তিভিঃ | রুরুচানং ভানুনা জযোতিষা মহামত্যং ন বাজং সনিষ্যন্নুপ বরুবে ||","e":"Within the range of their surpassinq power, by might, the Gods created Agni with inventive thought. I, eager to win strength, address him, like a steed, resplendent with his brilliance, with his ample light.","mb":"জ্ঞানবান দেবগণ বিপদ হতে উদ্ধারক বল দ্বারা যজ্ঞে অগ্নিকে উৎপাদক করেন। ভারসহ অশ্বের যেরূপ স্তুতি করি, সেরূপ আমি অন্নাভিলাষী হয়ে দীপ্তিমান তেজদ্বারা প্রকাশমান মহান অগ্নিকে স্তুতি করছি।"},{"n":4,"d":"आ मन्द्रस्य सनिष्यन्तो वरेण्यं वर्णीमहे अह्रयं वाजम्र्ग्मियम | रातिं भर्गूणामुशिजं कविक्रतुमग्निं राजन्तं दिव्येन शोचिषा ||","b":"আ মন্দ্রস্য সনিষ্যন্তো বরেণ্যং বর্ণীমহে অহ্রযং বাজম্র্গ্মিযম | রাতিং ভর্গূণামুশিজং কবিক্রতুমগ্নিং রাজন্তং দিব্যেন শোচিষা ||","e":"Eager to gain, we crave from him the friendly God strength confident, choiceworthy meet to be extolled: The Bhṛgus' bounty, willing, strong with sages' lore, even Agni shining forth with light that comes from heaven.","mb":"আমরা স্তুতিযোগ্য বৈশ্বানরের শ্রেষ্ঠ, অলজাবহ, প্রশংসনীয় অন্নের অভিলাষী হয়ে ভৃগু ঋষিগণের অভিলাষপ্রদ, অভিলষণীয়, প্রজ্ঞাবান এবং স্বগীয় দীপ্তিদ্বারা শোভমান অগ্নিকে ভজনা করছি।"},{"n":5,"d":"अग्निं सुम्नाय दधिरे पुरो जना वाजश्रवसमिह वर्क्तबर्हिषः | यतस्रुचः सुरुचं विश्वदेव्यं रुद्रं यज्ञानांसाधदिष्टिमपसाम ||","b":"অগ্নিং সুম্নায দধিরে পুরো জনা বাজশ্রবসমিহ বর্ক্তবর্হিষঃ | যতস্রুচঃ সুরুচং বিশ্বদেব্যং রুদ্রং যজ্ঞানাংসাধদিষ্টিমপসাম ||","e":"For happiness, men, having trimmed the sacred grass, set Agni glorious for his strength before them here; Yea, with raised ladles, him bright, dear to all the Gods, perfecting aims of works, Rudra of solemn rites.","mb":"ঋত্বিকগণ সুখলাভের জন্য কুশ বিস্তার করে ও স্রুক উত্তোলন ভজনা করছি। ঋত্বিকগণ সুখলাভের জন্য কুশ বিস্তার করে ও স্রুক উত্তোলন করে অন্নদাতা, অত্যন্ত দীপ্তিমান, সমস্ত দেবগণের হিতকারী, দুঃখনাশক এবং যজমানগণের যজ্ঞসাধক অগ্নিকে যজ্ঞে স্তব করে।"},{"n":6,"d":"पावकशोचे तव हि कषयं परि होतर्यज्ञेषु वर्क्तबर्हिषो नरः | अग्ने दुव इछमानास आप्यमुपासते दरविणं धेहि तेभ्यः ||","b":"পাবকশোচে তব হি কষযং পরি হোতর্যজ্ঞেষু বর্ক্তবর্হিষো নরঃ | অগ্নে দুব ইছমানাস আপ্যমুপাসতে দরবিণং ধেহি তেভ্যঃ ||","e":"Around thy dwelling-place, O brightly-shining Priest, are men at sacrifice, whose sacred grass is trimmed. Wishing to do thee service, Agni, they are there, desirous of thy friendship grant them store of wealth.","mb":"হে পবিত্র দীপ্তিবিশিষ্ট, দেবতাগণের আহ্বানকারী অগ্নি! তোমার পরিচর্যাভিলাষী যজমানগণ যজ্ঞে কুশবিস্তার করে তোমার যোগ্য যাগগৃহ সেবা করে। তাদরে ধন দান কর।"},{"n":7,"d":"आ रोदसी अप्र्णदा सवर्महज्जातं यदेनमपसो अधारयन | सो अध्वराय परि णीयते कविरत्यो न वाजसातयेचनोहितः ||","b":"আ রোদসী অপ্র্ণদা সবর্মহজ্জাতং যদেনমপসো অধারযন | সো অধ্বরায পরি ণীযতে কবিরত্যো ন বাজসাতযেচনোহিতঃ ||","e":"He hath filled heaven and earth and the great realm of light, when at his birth the skilful held him in their hold. He like a horse is led forth to the sacrifice Sage, graciously inclined, that he may win us strength.","mb":"তিনি দ্যাবাপৃথিবীকে পরিপূর্ণ করেছিলেন, বিস্তীর্ণ অন্তরীক্ষকেও পরিপূর্ণ করেছিলেন। যজমানগণ নবজাত এ অগ্নি ধারণ করেছিলেন; সর্বত্র ব্যাপ্ত অন্নদাতা এ অগ্নি অশ্বের ন্যায় অন্নলাভের জন্য আনীত হন।"},{"n":8,"d":"नमस्यत हव्यदातिं सवध्वरं दुवस्यत दम्यं जातवेदसम | रथीर्र्तस्य बर्हतो विचर्षणिरग्निर्देवानामभवत पुरोहितः ||","b":"নমস্যত হব্যদাতিং সবধ্বরং দুবস্যত দম্যং জাতবেদসম | রথীর্র্তস্য বর্হতো বিচর্ষণিরগ্নির্দেবানামভবত পুরোহিতঃ ||","e":"Honour the oblation-bearer, him who knows fair rites, serve ye the Household Friend who knows all things that be. He drives the chariot of the lofty ordinance: Agni most active, is the great High Priest of Gods.","mb":"নেতা ও মহৎ যজ্ঞের দর্শক যে অগ্নি দেবতাগণের সম্মুখে স্থাপিত হয়েছিলেন, সে হব্যদাতা, শোভনযজ্ঞবিশিষ্ট, গৃহের হিতকর, সর্বভূত অগ্নিকে পূজা কর তার পরিচর্যা কর।"},{"n":9,"d":"तिस्रो यह्वस्य समिधः परिज्मनो.अग्नेरपुनन्नुशिजो अम्र्त्यवः | तासामेकामदधुर्मर्त्ये भुजमु लोकमु दवे उप जामिमीयतुः ||","b":"তিস্রো যহ্বস্য সমিধঃ পরিজ্মনো.অগ্নেরপুনন্নুশিজো অম্র্ত্যবঃ | তাসামেকামদধুর্মর্ত্যে ভুজমু লোকমু দবে উপ জামিমীযতুঃ ||","e":"They who are free from death, fain for him, purified three splendours of the mighty Agni, circling all. To man, for his enjoyment, one of these they gave: the other two have passed into the sister sphere.","mb":"মৃত্যুরহিত দেবগণ অগ্নিকে অভিলাষ করে মহান জগৎব্যাপক অগ্নির  পার্থিব, বৈদ্যুত ও সূর্যরূপ তিনটি মূর্তিকে শোধিত করেছেন। তারা ওদের মধ্যে জগৎ পালিকা পার্থিব মুর্তিকে মর্ত্যলোকে রেখে অন্য দুটি অন্তরীক্ষে গমন করেছে।"},{"n":10,"d":"विशां कविं विश्पतिं मानुषीरिषः सं सीमक्र्ण्वन सवधितिं न तेजसे | स उद्वतो निवतो याति वेविषत स गर्भमेषु भुवनेषु दीधरत ||","b":"বিশাং কবিং বিশ্পতিং মানুষীরিষঃ সং সীমক্র্ণ্বন সবধিতিং ন তেজসে | স উদ্বতো নিবতো যাতি বেবিষত স গর্ভমেষু ভুবনেষু দীধরত ||","e":"Man's sacrificial food hath sharpened like an axe, for brightness, him the Sage of men, the people's Lord, Busied with sacred rites he mounts and he descends. He hath laid down his vital germ within these worlds.","mb":"ধনাভিলাষী প্রজাগণ প্রজাগনের প্রভূ মেধাবী অগ্নিকে অসির ন্যায় তীক্ষ্ম করাবর জন্য সংস্কৃত করেছিলেন। তিনি উন্নত ও নিম্নপ্রদেশ সকল ব্যপ্ত করে গমন করেন, তিনি সমস্ত ভূবনে গর্ভ ধারণ করেন।"},{"n":11,"d":"स जिन्वते जठरेषु परजज्ञिवान वर्षा चित्रेषु नानदन न सिंहः | वैश्वानरः पर्थुपाजा अमर्त्यो वसु रत्ना दयमानो वि दाशुषे ||","b":"স জিন্বতে জঠরেষু পরজজ্ঞিবান বর্ষা চিত্রেষু নানদন ন সিংহঃ | বৈশ্বানরঃ পর্থুপাজা অমর্ত্যো বসু রত্না দযমানো বি দাশুষে ||","e":"He stirs with life in wombs dissimilar in kind, born as a Lion or a loudly-bellowing Bull: Vaiśvānara immortal with wide-reaching might, bestowing goods and wealth on him who offiers gifts.","mb":"নবজাত অভীষ্টবর্ষী বৈশ্বানর নানাস্থানে সিংহের ন্যায় শব্দ করে নানা জঠরে বর্ধিত হন। তিনি অত্যন্ত তেজবিশিষ্ট ও মরণরহিত। তিনি যজমানকে রমণীয় বস্তু প্রদান করেন।"},{"n":12,"d":"वैश्वानरः परत्नथा नाकमारुहद दिवस पर्ष्ठं भन्दमानः सुमन्मभिः | स पूर्ववज्जनयञ जन्तवे धनं समानमज्मं पर्येति जाग्र्विः ||","b":"বৈশ্বানরঃ পরত্নথা নাকমারুহদ দিবস পর্ষ্ঠং ভন্দমানঃ সুমন্মভিঃ | স পূর্ববজ্জনযঞ জন্তবে ধনং সমানমজ্মং পর্যেতি জাগ্র্বিঃ ||","e":"Vaiśvānara, as of old, mounted the cope of heaven, heaven's ridge, well greeted, by those skilled in noble songs. He, as of old, producing riches for the folk, still watchful, traversesthe common way again.","mb":"স্তোতৃগণ কর্তৃক স্তুয়মান শ্বৈানর চিরন্তনের ন্যায় অন্তরিক্ষের পৃষ্ঠভূত স্বর্গে আরোহণ করেন। তিনি পুরাতন ঋষিগণের ন্যায় যজমানগণকেও ধন দান করে জাগ্রত হয়ে দেবগণের সাধারণ পথে সূর্যরূপে ভ্রমণ করেন।"},{"n":13,"d":"रतावानं यज्ञियं विप्रमुक्थ्यमा यं दधे मातरिश्वा दिवि कषयम | तं चित्रयामं हरिकेशमीमहे सुदीतिमग्निं सुविताय नव्यसे ||","b":"রতাবানং যজ্ঞিযং বিপ্রমুক্থ্যমা যং দধে মাতরিশ্বা দিবি কষযম | তং চিত্রযামং হরিকেশমীমহে সুদীতিমগ্নিং সুবিতায নব্যসে ||","e":"For new prosperity we seek to Agni, him whose course is splendid, gold-haired, excellently bright, Whom Mātariśvan stablished, dweller in the heaven, meet for high praise and holy, sage and true to Law.","mb":"বলবান যজ্ঞার্হ মেধাবী, স্তুতিযোগ্য, দ্যুলোকবাসী যে অগ্নিকে মাতরিশ্বা দ্যুলোক হতে এনে পৃথিবীতে সংস্থাপিত করেছেন (১) আমরা সে নানাবিধ গমনবিশিষ্ট, পিঙ্গলবর্ণ কিরণযুক্ত, দীপ্তিমান, অগ্নির নিকট নুতন ধন যাঞ্চা করি।"},{"n":14,"d":"शुचिं न यामन्निषिरं सवर्द्र्शं केतुं दिवो रोचनस्थामुषर्बुधम | अग्निं मूर्धानं दिवो अप्रतिष्कुतं तमीमहे नमसा वाजिनं बर्हत ||","b":"শুচিং ন যামন্নিষিরং সবর্দ্র্শং কেতুং দিবো রোচনস্থামুষর্বুধম | অগ্নিং মূর্ধানং দিবো অপ্রতিষ্কুতং তমীমহে নমসা বাজিনং বর্হত ||","e":"As pure and swift of course, beholder of the light, who stands in heaven's bright sphere a sign, who wakes at dawn, Agni, the head of heaven, whom none may turn aside-to him the Powerful with mighty prayer we seek.","mb":"দীপ্ত, যজ্ঞে গমনকারী সমস্ত পদার্থের জ্ঞানযুক্ত, দ্যুলোকের কেতুস্বরূপ, সূর্যে অবস্থিত উষাকালে জাগরুক, অন্নবান, মহান অগ্নিকে স্তোত্রদ্বারা যাঞ্চা করি।"},{"n":15,"d":"मन्द्रं होतारं शुचिमद्वयाविनं दमूनसमुक्थ्यं विश्वचर्षणिम | रथं न चित्रं वपुषाय दर्शतं मनुर्हितं सदमिद राय ईमहे ||","b":"মন্দ্রং হোতারং শুচিমদ্বযাবিনং দমূনসমুক্থ্যং বিশ্বচর্ষণিম | রথং ন চিত্রং বপুষায দর্শতং মনুর্হিতং সদমিদ রায ঈমহে ||","e":"The cheerful Priest, the pure, in whom no guile is found, Friend of the House, praise-worthy, dear to all mankind, Fair to behold for beauty like a splendid car,—Agni the Friend of men we ever seek for wealth.","mb":"স্তুতিযোগ্য দেবতাগণের আহ্বানকারী সর্বদা শুদ্ধ, কুঠিলতারহিত, দানশীল, শ্রেষ্ঠ, বিশ্বদর্শী রথের ন্যায় নানাবর্ণ বিশিষ্ট, দর্শনীয়াকৃতিসম্পন্ন ও সর্বদা মনুষ্যগণের কল্যাণকারী সে অগ্নির নিকট আমরা ধন যাঞ্চা করছি।"}]},{"n":3,"t":"Agni","v":[{"n":1,"d":"वैश्वानराय पर्थुपाजसे विपो रत्ना विधन्त धरुणेषु गातवे | अग्निर्हि देवानम्र्तो दुवस्यत्यथा धर्माणि सनता न दूदुषत ||","b":"বৈশ্বানরায পর্থুপাজসে বিপো রত্না বিধন্ত ধরুণেষু গাতবে | অগ্নির্হি দেবানম্র্তো দুবস্যত্যথা ধর্মাণি সনতা ন দূদুষত ||","e":"To him who shines afar, Vaiśvānara, shall bards give precious things that he may go on certain paths: For Agni the Immortal serves the Deities, and therefore never breaks their everlasting laws.","mb":"মেধাবী স্তোতাগণ সৎপথলাভের জন্য বহুবলশালী বৈশ্বানরের উদ্দেশে যজ্ঞে রমণীয় স্তোত্র সকল পাঠ করে। মরণরহিত অগ্নি হব্যপ্রদান দ্বারা দেবতাগণের পরিচর্যা করেন, অতএব কেউ সনাতন যজ্ঞকে দুষিত করতে পারে না।"},{"n":2,"d":"अन्तर्दूतो रोदसी दस्म ईयते होता निषत्तो मनुषः पुरोहितः | कषयं बर्हन्तं परि भूषति दयुभिर्देवेभिरग्निरिषितो धियावसुः ||","b":"অন্তর্দূতো রোদসী দস্ম ঈযতে হোতা নিষত্তো মনুষঃ পুরোহিতঃ | কষযং বর্হন্তং পরি ভূষতি দযুভির্দেবেভিরগ্নিরিষিতো ধিযাবসুঃ ||","e":"He, wondrous envoy, goes between the earth and heaven, firm seated as the Herald, great High Priest of men. He compassethwith rays the lofty dwelling-place, Agni, sent forward by the Gods, enriched with piayer.","mb":"দর্শনীয় হোতা অগ্নি দেবগণের দূত হয়ে দ্যাবাপৃথিবীর মধ্যে যান। দেবগণ কর্তৃক প্রেরিত ধীমান অগ্নি যজমানের সম্মুখে স্থাপিত ও উপবিষ্ট হয়ে মহৎ যজ্ঞগৃহকে অলঙ্কৃত করেন।"},{"n":3,"d":"केतुं यज्ञानां विदथस्य सा धनं विप्रासो अग्निं महयन्त चित्तिभिः | अपांसि यस्मिन्नधि सन्दधुर्गिरस्तस्मिन सुम्नानि यजमान आ चके ||","b":"কেতুং যজ্ঞানাং বিদথস্য সা ধনং বিপ্রাসো অগ্নিং মহযন্ত চিত্তিভিঃ | অপাংসি যস্মিন্নধি সন্দধুর্গিরস্তস্মিন সুম্নানি যজমান আ চকে ||","e":"Sages shall glorify Agni with earnest thoughts, ensign of sacrifice, who fills the synod full: In whom the singers have stored up their holy acts to him the worshipper looks for joy and happiness.","mb":"মেধাবীগণ যজ্ঞের কেতুস্বরূপ ও যজ্ঞের সাধনভূত অগ্নিকে স্বীয় স্বীয় কর্মদ্বারা পূজা করেন। স্তোতাগণ যে অগ্নিতে স্বীয় স্বীয় অনুষ্ঠেয় কর্ম সকল অর্পণ করে, যজমান সে অগ্নিতে সুখের আশা করে।"},{"n":4,"d":"पिता यज्ञानामसुरो विपश्चितां विमानमग्निर्वयुनं च वाघताम | आ विवेश रोदसी भूरिवर्पसा पुरुप्रियो भन्दते धामभिः कविः ||","b":"পিতা যজ্ঞানামসুরো বিপশ্চিতাং বিমানমগ্নির্বযুনং চ বাঘতাম | আ বিবেশ রোদসী ভূরিবর্পসা পুরুপ্রিযো ভন্দতে ধামভিঃ কবিঃ ||","e":"The Sire of sacrifice, great God of holy bards, Agni, the measure and the symbol of the priests, Hath entered heaven and earth that show in varied form: the Sage whom many love rejoiceth in his might.","mb":"যজ্ঞের পিতা, স্তোতৃগণের অসুর (১), ঋত্বিকগণের  জ্ঞান হেতু যজ্ঞাদি কর্মের সাধনভূত অগ্নি পার্থিব ও বৈদ্যুতাদি রূপদ্বারা দ্যাবাপৃথিবীতে প্রবেশ করেন। অত্যন্ত প্রিয় তেজবিশিষ্ট অগ্নি যজমান কর্তৃক স্তুত হচ্ছেন।"},{"n":5,"d":"चन्द्रमग्निं चन्द्ररथं हरिव्रतं वैश्वानरमप्सुषदं सवर्विदम | विगाहं तूर्णिं तविषीभिराव्र्तं भूर्णिं देवास इह सुश्रियं दधुः ||","b":"চন্দ্রমগ্নিং চন্দ্ররথং হরিব্রতং বৈশ্বানরমপ্সুষদং সবর্বিদম | বিগাহং তূর্ণিং তবিষীভিরাব্র্তং ভূর্ণিং দেবাস ইহ সুশ্রিযং দধুঃ ||","e":"Bright Agni with the bright car, Lord of green domains, Vaiśvānara dweller in the floods, who finds the light, Pervading, swift and wild, encompassed round with powers, him very glorious have the Gods established here.","mb":"আহলাদকর, ও অহলাদজনক রথবিশিষ্ট, পিঙ্গলবর্ণ জলমধ্যে নিবাসী, সর্বজ্ঞ সর্বত্র ব্যাপ্ত, শীঘ্রগামী, বলোপেত ভর্তা, দীপ্তিমান বৈশ্বানরকে দেবগণ ইহলোকে স্থাপিত করেছেন।"},{"n":6,"d":"अग्निर्देवेभिर्मनुषश्च जन्तुभिस्तन्वानो यज्ञं पुरुपेशसं धिया | रथीरन्तरीयते साधदिष्टिभिर्जीरो दमूना अभिशस्तिचातनः ||","b":"অগ্নির্দেবেভির্মনুষশ্চ জন্তুভিস্তন্বানো যজ্ঞং পুরুপেশসং ধিযা | রথীরন্তরীযতে সাধদিষ্টিভির্জীরো দমূনা অভিশস্তিচাতনঃ ||","e":"Agni, together with the Gods and Manu's folk by thought extending sacrifice in varied form, Goes, car-borne, to and fro with those who crown each rite, the fleet, the Household Friend, who turns the curse aside.","mb":"যিনি যজ্ঞসাধক দেবগণ ও ঋত্বিকগণের সাথে কর্মদ্বারা যজমানের নানাবিধ যজ্ঞ সম্পাদন করেন যিনি নেতা, শীঘ্রগামী, দানশীল এবং শত্রুগণের নাশক সে অগ্নি দ্যাবাপৃথিবীর মধ্যে গমন করেন।"},{"n":7,"d":"अग्ने जरस्व सवपत्य आयुन्यूर्जा पिन्वस्व समिषो दिदीहि नः | वयांसि जिन्व बर्हतश्च जाग्र्व उशिग देवानामसि सुक्रतुर्विपाम ||","b":"অগ্নে জরস্ব সবপত্য আযুন্যূর্জা পিন্বস্ব সমিষো দিদীহি নঃ | বযাংসি জিন্ব বর্হতশ্চ জাগ্র্ব উশিগ দেবানামসি সুক্রতুর্বিপাম ||","e":"Sing, Agni, for long life to us and noble sons: teem thou with plenty, shine upon us store of food. Increase the great man's strength, thou ever-vigilant: thou, longing for the Gods, knowest their hymns full well.","mb":"হে অগ্নি! আমরা সুপুত্র ও দীর্ঘায়ু: লাভ করতে পারব বলে তুমি দেবগণকে স্তব কর, অন্নদ্বারা তাদরে প্রতি কর, আমাদের শস্যের জন্য বৃষ্টিকে সম্যকরূপে দীপ্ত কর ও অন্ন দান কর। হে সর্বদা জাগরণশীল অগ্নি! তুমি মহান যজমানকে অন্নদান কর, কারণ তুমি সুকর্মা ও দেবগণের প্রিয়।"},{"n":8,"d":"विश्पतिं यह्वमतिथिं नरः सदा यन्तारं धीनामुशिजं च वाघताम | अध्वराणां चेतनं जातवेदसं पर शंसन्ति नमसा जूतिभिर्व्र्धे ||","b":"বিশ্পতিং যহ্বমতিথিং নরঃ সদা যন্তারং ধীনামুশিজং চ বাঘতাম | অধ্বরাণাং চেতনং জাতবেদসং পর শংসন্তি নমসা জূতিভির্ব্র্ধে ||","e":"The Mighty One, Lord of the people and their guest, the leader of their thoughts, devoted Friend of priests, Our solemn rites' announcer, Jātavedas, men with worship ever praise, with urgings for their weal.","mb":"মনুষ্যগণের পতি, মহান, অতিথিভূত বুদ্ধির নিয়ন্তা, ঋত্বিকগণের প্রিয়, যজ্ঞের জ্ঞাপক, বেগযুক্ত, সর্বভূত, অগ্নিকে নেতাগণ সমৃদ্ধির জন্য নমস্কার ও স্তুতিদ্বারা প্রশংসা করছে।"},{"n":9,"d":"विभावा देवः सुरणः परि कषितीरग्निर्बभूव शवसासुमद्रथः | तस्य वरतानि भूरिपोषिणो वयमुप भूषेमदम आ सुव्र्क्तिभिः ||","b":"বিভাবা দেবঃ সুরণঃ পরি কষিতীরগ্নির্বভূব শবসাসুমদ্রথঃ | তস্য বরতানি ভূরিপোষিণো বযমুপ ভূষেমদম আ সুব্র্ক্তিভিঃ ||","e":"Agni the God resplendent, giver of great joy, hath on his lovely car compassed the lands with, might. Let us with pure laudations in his house approach the high laws of the nourisher of multitudes.","mb":"দীপ্তিমান, স্তুয়মান, কমনীয়, সুন্দর রথবিশিষ্ট অগ্নি বলদ্বারা সমস্ত প্রজাদের ব্যাপ্ত করেন। আমরা অনেকের পালয়িতা ও যজ্ঞগৃহে বাসকারী অগ্নির কর্মসকল সুন্দর স্তোত্রদ্বারা প্রকাশ করব। ১০ হে বিজ্ঞ বৈশ্বানর! তুমি যে তেজদ্বারা সর্ববেত্তা হয়েছ, আমি তোমার সে তেজকে স্তব করি। তুমি জন্মানমাত্রই সমস্ত ভূতসমূহে ও দ্যাবাপৃথিবীতে ব্যাপ্ত হয়ে থাক। হে অগ্নি! তুমি স্বয়ং সমস্ত ভূতজাতকে ব্যাপ্ত করে থাক।"},{"n":10,"d":"वैश्वानर तव धामान्या चके येभिः सवर्विदभवो विचक्षण | जात आप्र्णो भुवनानि रोदसी अग्ने ता विस्वा परिभूरसि तमना ||","b":"বৈশ্বানর তব ধামান্যা চকে যেভিঃ সবর্বিদভবো বিচক্ষণ | জাত আপ্র্ণো ভুবনানি রোদসী অগ্নে তা বিস্বা পরিভূরসি তমনা ||","e":"I celebrate thy glories, O Vaiśvānara, wherewith thou, O farsighted God, has found the light. Thou filledst at thy birth both worlds, the earth and heaven: all this, O Agni, hast thou compassed of thyself.","mb":"হে বৈশ্বানর, তোমার সেই মহিমা আমি উদযাপন করি, যার দ্বারা তুমি, হে দূরদর্শী দেব, আলো খুঁজে পেয়েছো। জন্মে তুমি দুই জগৎ — পৃথিবী ও স্বর্গ — পূর্ণ করেছো: এই সব, হে অগ্নি, তুমি নিজেই পরিবেষ্টন করেছো।"},{"n":11,"d":"वैश्वानरस्य दंसनाभ्यो बर्हदरिणादेकः सवपस्यया कविः | उभा पितरा महयन्नजायताग्निर्द्यावाप्र्थिवी भूरिरेतसा ||","b":"বৈশ্বানরস্য দংসনাভ্যো বর্হদরিণাদেকঃ সবপস্যযা কবিঃ | উভা পিতরা মহযন্নজাযতাগ্নির্দ্যাবাপ্র্থিবী ভূরিরেতসা ||","e":"By his great skill the Sage alone hath brought to pass a great deed, mightier than Vaiśvānara's wondrous acts. Agni sprang into being, magnifying both his Parents, Heaven and Earth, rich in prolific seed.","mb":"বৈশ্বানরের সন্তোষজনক কর্ম হতে মহৎ ধন হয়। কারণ তিনি সুন্দর যজ্ঞাদি কর্মের ইচ্ছায় যজমানগণকে ধন দান করেন। তিনি প্রভূত রেতোবিশিষ্ট, পিতামাতা দ্যাবাপৃথিবী উভয়কেই পূজা করে উৎপন্ন হয়েছেন।"}]},{"n":4,"t":"Āprīs","v":[{"n":1,"d":"समित-समित सुमना बोध्यस्मे शुचा-शुचा सुमतिं रासि वस्वः | आ देव देवान यजथाय वक्षि सखा सखीन सुमना यक्ष्यग्ने ||","b":"সমিত-সমিত সুমনা বোধ্যস্মে শুচা-শুচা সুমতিং রাসি বস্বঃ | আ দেব দেবান যজথায বক্ষি সখা সখীন সুমনা যক্ষ্যগ্নে ||","e":"BE friendly with each kindled log of fuel, with every flash bestow the boon of riches. Bring thou the Gods, O God, unto our worship: serve, well-inclined, as Friend thy friends, O Agni.","mb":"হে সমদ্ধি অগ্নি! অনুকুলমনে জাগরিত, হও, তুমি অত্যন্ত প্রসর্পক তেজযুক্ত হয়ে আমাদের ধন বিষয়ে অনুগ্রহ কর। হে দ্যোতমান অগ্নি! তুমি দেবতাগণকে যজ্ঞে আন। হে অগ্নি! তুমি দেবতাগণের সখা, তুমি অনুকুলমনে সখা (দেবতাগণের) যজ্ঞ কর।"},{"n":2,"d":"यं देवासस्त्रिरहन्नायजन्ते दिवे-दिवे वरुणो मित्रो अग्निः | सेमं यज्ञं मधुमन्तं कर्धी नस्तनूनपाद घर्तयोनिं विधन्तम ||","b":"যং দেবাসস্ত্রিরহন্নাযজন্তে দিবে-দিবে বরুণো মিত্রো অগ্নিঃ | সেমং যজ্ঞং মধুমন্তং কর্ধী নস্তনূনপাদ ঘর্তযোনিং বিধন্তম ||","e":"Agni whom daily Varuṇa and Mitra the Gods bring thrice a day to this our worship, Tanūnapāt, enrich with meath our service that dwells with holy oil, that offers honour.","mb":"বরুণ মিত্র ও অগ্নি যে তনুনপাৎ নামক অগ্নিকে প্রতিদিবস দিনে তিনবার করে যজ্ঞ করেন, সে তনুনপাৎ উদকের কারণভূত আমাদের এ যজ্ঞে বৃষ্টি প্রভৃতি ফলযুক্ত করুন।"},{"n":3,"d":"पर दीधितिर्विश्ववारा जिगाति होतारमिळः परथमं यजध्यै | अछा नमोभिर्व्र्षभं वन्दध्यै स देवान यक्षदिषितो यजीयान ||","b":"পর দীধিতির্বিশ্ববারা জিগাতি হোতারমিলঃ পরথমং যজধ্যৈ | অছা নমোভির্ব্র্ষভং বন্দধ্যৈ স দেবান যক্ষদিষিতো যজীযান ||","e":"The thought that bringeth every boon proceedeth to worship first the Priest of the libation, That we may greet the Strong One with our homage. Urged, may he bring the Gods, best Sacrificer.","mb":"সর্বজনপ্রিয় স্তুতি দেবতাগণের আহ্বানকারী অগ্নির নিকট গমন করুক। অগ্নিরূপ ইলা প্রীতি উৎপাদন করবার জন্য প্রধান, অতন্ত অভীষ্টবর্ষী, বন্দনাযোগ্য অগ্নির নিকট যান। যজ্ঞকর্মে কুশল অগ্নি আমাদের কর্তৃক প্রেরিত হয়ে যজ্ঞ করুন।"},{"n":4,"d":"ऊर्ध्वो वां गातुरध्वरे अकार्यूर्ध्वा शोचींषि परस्थिता रजांसि | दिवो वा नाभा नयसादि होता सत्र्णीमहि देवव्यचा वि बर्हिः ||","b":"ঊর্ধ্বো বাং গাতুরধ্বরে অকার্যূর্ধ্বা শোচীংষি পরস্থিতা রজাংসি | দিবো বা নাভা নযসাদি হোতা সত্র্ণীমহি দেবব্যচা বি বর্হিঃ ||","e":"On high your way to sacrifice was made ready; the radiant flames went upward to the regions. Full in the midst of heaven the Priest is seated: sirew we the sacred grass where Gods may rest them.","mb":"অগ্নি ও বর্হিরূপ অগ্নির জন্য যজ্ঞে একটি উন্নত পথ করা হয়েছে। দীপ্তিযুত হব্য উর্ধ্বে প্রস্থিত হচ্ছে। হোতা দীপ্তিমান যাগ গৃহের নাভিদেশে উপবিষ্ট আছেন। আমরা দেবগণ কর্তৃক ব্যাপ্ত বর্হি বিস্তৃত করব।"},{"n":5,"d":"सप्त होत्राणि मनसा वर्णाना इन्वन्तो विश्वं परति यन्न्र्तेन | नर्पेशसो विदथेषु पर जाता अभीमं यज्ञं वि चरन्त पूर्वीः ||","b":"সপ্ত হোত্রাণি মনসা বর্ণানা ইন্বন্তো বিশ্বং পরতি যন্ন্র্তেন | নর্পেশসো বিদথেষু পর জাতা অভীমং যজ্ঞং বি চরন্ত পূর্বীঃ ||","e":"Claiming in mind the seven priests' burntoblations, inciting all, they came in settled order. To this our sacrifice approach the many who show in hero beauty at assemblies.","mb":"জলদ্বারা বিশ্বের প্রীতিপ্রদ দেবগণ সপ্ত যজ্ঞে গমন করেন; অকপট মনে যাচিত হয়ে অগ্নিরূপ যজ্ঞদ্বারদ্বয় প্রত্যক্ষ হয়ে আমাদের এ যজ্ঞে আসুন।"},{"n":6,"d":"आ भन्दमाने उषसा उपाके उत समयेते तन्वा विरूपे | यथा नो मित्रो वरुणो जुजोषदिन्द्रो मरुत्वानुत वा महोभिः ||","b":"আ ভন্দমানে উষসা উপাকে উত সমযেতে তন্বা বিরূপে | যথা নো মিত্রো বরুণো জুজোষদিন্দ্রো মরুত্বানুত বা মহোভিঃ ||","e":"Night and Dawn, lauded, hither come together, both smiling, different are their forms in colour, That Varuṇa and Mitra may accept us, and Indra, girt by Maruts, with his glories.","mb":"অগ্নিরূপ রাত্রি ও দিবা পরস্পর সঙ্গত হয়ে অথবা পৃথকরূপে সশরীরে প্রকাশিত হয়ে আসুন। মিত্র বরুণ অথবা মরুৎযুক্ত ইন্দ্র আমাদের যেরূপে অনুগৃহীত করেন, এরাও তেজদীপ্ত হয়ে সেরূপ করুন।"},{"n":7,"d":"दैव्या होतारा परथमा नय रञ्जे सप्त पर्क्षासः सवधयामदन्ति | रतं शंसन्त रतमित त आहुरनु वरतं वरतपा दीध्यानाः ||","b":"দৈব্যা হোতারা পরথমা নয রঞ্জে সপ্ত পর্ক্ষাসঃ সবধযামদন্তি | রতং শংসন্ত রতমিত ত আহুরনু বরতং বরতপা দীধ্যানাঃ ||","e":"I crave the grace of heaven's two chief Invokers: the seven swift steeds joy in their wonted manner. These speak of truth, praising the truth eternal, thinking on Order as the guards of Order.","mb":"দিব্য ও প্রধান, অগ্নিরূপ দেব হোতাদ্বয়কে আমি প্রসন্ন করি। যজ্ঞাভিলাষী, সপ্ত, অন্নবান ঋত্বিকগণ অগ্নিকে হব্যদ্বারা প্রমত্ত করেন। ব্রতের রক্ষক, দীপ্তিমান ঋত্বিকগণ প্রত্যেক ব্রতে যজ্ঞরূপ অগ্নিকে এ কথা বলেন।"},{"n":8,"d":"आ भारती भारतीभिः सजोषा इळा देवैर्मनुष्येभिरग्निः | सरस्वती सारस्वतेभिरर्वाक तिस्रो देवीर्बर्हिरेदं सदन्तु ||","b":"আ ভারতী ভারতীভিঃ সজোষা ইলা দেবৈর্মনুষ্যেভিরগ্নিঃ | সরস্বতী সারস্বতেভিরর্বাক তিস্রো দেবীর্বর্হিরেদং সদন্তু ||","e":"May Bhāratī with all her Sisters, Iḷā accordant with the Gods, with mortalls Agni, Sarasvatī with all her kindred Rivers, come to this grass, Three Goddesses, and seat them.","mb":"ভারতীগণের (২) সাথে সংগত অগ্নিরূপ ভারতী আসুন। দেবতা ও মানুষের সাথে অগ্নিরূপ ইলা আসুন, সরস্বতগণের (৩) সাথে অগ্নিরূপ সরস্বতীও আসুন। দেবীত্রয় আগমন করে সম্মুখে স্থিত এ কুশে উপবেশন করুন।"},{"n":9,"d":"तन नस्तुरीपमध पोषयित्नु देव तवष्टर्वि रराणः सयस्व | यतो वीरः कर्मण्यः सुदक्षो युक्तग्रावा जायते देवकामः ||","b":"তন নস্তুরীপমধ পোষযিত্নু দেব তবষ্টর্বি ররাণঃ সযস্ব | যতো বীরঃ কর্মণ্যঃ সুদক্ষো যুক্তগ্রাবা জাযতে দেবকামঃ ||","e":"Well pleased with us do thou O God, O Tvaṣṭar, give ready issue to our procreant vigour, Whence springs the hero, powerful, skilled in action, lover of Gods, adjuster of the press-stones.","mb":"হে দেব অগ্নিরূপ ত্বষ্টা! যা দিয়ে বীর কর্মকুশল, বলশালী ও সোমাভিষবের জন্য প্রস্তরহস্ত দেবাভিলাষী পুত্র উৎপন্ন হতে পারে, তুমি সন্তুষ্ট হয়ে আমাদরে তাদৃশ ত্রাণকুশল ও পুষ্টিকরী বীর্য দাও।"},{"n":10,"d":"वनस्पते.अव सर्जोप देवानग्निर्हविः शमिता सूदयाति | सेदु होता सत्यतरो यजाति यथा देवानां जनिमानि वेद ||","b":"বনস্পতে.অব সর্জোপ দেবানগ্নির্হবিঃ শমিতা সূদযাতি | সেদু হোতা সত্যতরো যজাতি যথা দেবানাং জনিমানি বেদ ||","e":"Send to the Gods the oblation, Lord of Forests; and let the Immolator, Agni, dress it. He as the truer Priest shall offer worship, for the Gods’ generations well he knoweth.","mb":"হে অগ্নিরূপ বনস্পতি! তুমি দেবতাগণকে নিকটে আন। পশুর সংস্করক অগ্নি বনস্পতি! দেবতাগণের উদ্দেশে হব্য প্রেরণ করুন। সে যজ্ঞরূপ দেবতাগণের আহ্বানকারী অগ্নি যজ্ঞ করুন, কারণ তিনিই দেবতাগণের জন্ম জানেন।"},{"n":11,"d":"आ याह्यग्ने समिधानो अर्वां इन्द्रेण देवैः सरथं तुरेभिः | बर्हिर्न आस्तामदितिः सुपुत्रा सवाहा देवा अम्र्तामादयन्ताम ||","b":"আ যাহ্যগ্নে সমিধানো অর্বাং ইন্দ্রেণ দেবৈঃ সরথং তুরেভিঃ | বর্হির্ন আস্তামদিতিঃ সুপুত্রা সবাহা দেবা অম্র্তামাদযন্তাম ||","e":"Come thou to us, O Agni, duly kindled, together with the potent Gods and Indra. On this our grass sit Aditi, happy Mother, and let our Hail delight the Gods Immortal.","mb":"হে অগ্নি! তুমি দীপ্তিযুক্ত হয়ে ইন্দ্র ও ত্বরান্বিত দেবগণের সাথে একরথে আমাদের অভিমুখে এস। সুপুত্রবিশিষ্টা অদিতি আমাদের কুশে উপবেশন করুন। নিত্য দেবগণ অগ্নিরূপ স্বহাকারযুক্ত হয়ে তৃপ্তিলাভ করুন।"}]},{"n":5,"t":"Agni","v":[{"n":1,"d":"परत्यग्निरुषसश्चेकितानो.अबोधि विप्रः पदवीः कवीनाम | पर्थुपाजा देवयद्भिः समिद्धो.अप दवारा तमसो वह्निरावः ||","b":"পরত্যগ্নিরুষসশ্চেকিতানো.অবোধি বিপ্রঃ পদবীঃ কবীনাম | পর্থুপাজা দেবযদ্ভিঃ সমিদ্ধো.অপ দবারা তমসো বহ্নিরাবঃ ||","e":"AGNI who shines against the Dawns is wakened. The holy Singer who precedes the sages. With far-spread lustre, kindled by the pious, the Priest hath thrown both gates of darkness open.","mb":"অগ্নি উষাকে জানেন, মেধাবী অগ্নি প্রজ্ঞাবানগণের পথে যাবার জন্য জাগরিত হচ্ছেন।  অত্যন্ত তেজবিশিষ্ট অগ্নি দেবাভিলাষী ব্যক্তিদের দ্বারা প্রদীপ্ত হয়ে অজ্ঞানের দ্বার উদ্ঘাটন করছেন।"},{"n":2,"d":"परेद वग्निर्वाव्र्धे सतोमेभिर्गीर्भि सतोतॄणां नमस्य उक्थैः | पूर्वीर्र्तस्य सन्द्र्शश्चकानः सं दूतो अद्यौदुषसो विरोके ||","b":"পরেদ বগ্নির্বাব্র্ধে সতোমেভির্গীর্ভি সতোতৄণাং নমস্য উক্থৈঃ | পূর্বীর্র্তস্য সন্দ্র্শশ্চকানঃ সং দূতো অদ্যৌদুষসো বিরোকে ||","e":"Agni hath waxen mighty by laudations, to be adored with hymns of those who praise him. Loving the varied shows of holy Order at the first flush of dawn he shines as envoy.","mb":"পূজ্য অগ্নি স্তোত্র, বাক্য ও উকথ দ্বারা বৃদ্ধি প্রাপ্ত হন। দেবতাগণের দূত অগ্নি বহুযজ্ঞে দীপ্তি লাভ করবার ইচ্ছায় প্রাত:কালে দ্যোতিত হন।"},{"n":3,"d":"अधाय्यग्निर्मानुषीषु विक्ष्वपां गर्भो मित्र रतेन साधन | आ हर्यतो यजतः सान्वस्थादभूदु विप्रो हव्योमतीनाम ||","b":"অধায্যগ্নির্মানুষীষু বিক্ষ্বপাং গর্ভো মিত্র রতেন সাধন | আ হর্যতো যজতঃ সান্বস্থাদভূদু বিপ্রো হব্যোমতীনাম ||","e":"Amid men's homes hath Agni been established, fulfilling with the Law, Friend, germ of waters. Loved and adored, the height he hath ascended, the Singer, object of our invocations.","mb":"যজমানদের মিত্র, যজ্ঞদ্বারা অভিলাষ পুরক এবং জলের পুত্র অগ্নি মনুষ্য লোকের মধ্যে সংস্থাপিত হয়েছেন। অগ্নি স্পৃহনীয় ও যজনীয়, তিনি উন্নত স্থানে অধিষ্ঠিত হয়েছেন; প্রজ্ঞাবান অগ্নি স্তোতাদের স্তুতির যোগ্য হয়েছেন।"},{"n":4,"d":"मित्रो अग्निर्भवति यत समिद्धो मित्रो होता वरुणो जातवेदाः | मित्रो अध्वर्युरिषिरो दमूना मित्रः सिन्धूनामुत पर्वतानाम ||","b":"মিত্রো অগ্নির্ভবতি যত সমিদ্ধো মিত্রো হোতা বরুণো জাতবেদাঃ | মিত্রো অধ্বর্যুরিষিরো দমূনা মিত্রঃ সিন্ধূনামুত পর্বতানাম ||","e":"Agni is Mitra when enkindled duly, Mitra as Priest, Varuṇa, Jātavedas; Mitra as active minister, and House-Friend, Mitra of flowing rivers and of mountains.","mb":"অগ্নি যখন সমিদ্ধ হন, তখন মিত্র হন। সে মিত্রই হোতা এবং সর্বভূতজ্ঞ বরুণ। সে মিত্রই  অধ্বর্যু ও দানশীল প্রেরক বায়ু (১), তিনি নদী ও পর্বতসমূহের মিত্র।"},{"n":5,"d":"पाति परियं रिपो अग्रं पदं वेः पाति यज्वश्चरञंसूर्यस्य | पाति नाभा सप्तशीर्षाणमग्निः पाति देवानामुपमादं रष्वः ||","b":"পাতি পরিযং রিপো অগ্রং পদং বেঃ পাতি যজ্বশ্চরঞংসূর্যস্য | পাতি নাভা সপ্তশীর্ষাণমগ্নিঃ পাতি দেবানামুপমাদং রষ্বঃ ||","e":"The Earth's, the Bird's dear lofty place he guardeth, he guardeth in his might the course of Sūrya, Guardeth the Seven-headed in the centre, guardeth sublime the Deities enjoyment.","mb":"সুন্দর অগ্নি সর্বব্যাপ্ত পৃথিবীর প্রিয় স্থান রক্ষা করেন। মহান অগ্নি সূর্যের বিচরণস্থল অন্তরীক্ষ রক্ষা করেন ও তার মরুৎগণকে রক্ষা করেন, তিনি দেবতাগণের হর্ষকর যজ্ঞ রক্ষা করেন।"},{"n":6,"d":"रभुश्चक्र ईड्यं चारु नाम विश्वानि देवो वयुनानि विद्वान | ससस्य चर्म घर्तवत पदं वेस्तदिदग्नी रक्षत्यप्रयुछन ||","b":"রভুশ্চক্র ঈড্যং চারু নাম বিশ্বানি দেবো বযুনানি বিদ্বান | সসস্য চর্ম ঘর্তবত পদং বেস্তদিদগ্নী রক্ষত্যপ্রযুছন ||","e":"The skilful God who knows all forms of knowledge made for himself a fair form, meet for worship. This Agni guards with care that never ceases the Soma's skin, the Bird's place rich in fatness.","mb":"মহান ও সমস্ত জ্ঞাতব্যের বেত্তা অগ্নি প্রশংসনীয় ও চারু জল উৎপাদন করেন। অগ্নি নিদ্রিত হলেও তার রূপ দীপ্তিমান থাকে; সে অগ্নি অপ্রমত্ত হয়ে তা রক্ষা করেন।"},{"n":7,"d":"आ योनिमग्निर्घ्र्तवन्तमस्थात पर्थुप्रगाणमुशन्तमुशानः | दीद्यानः शुचिर्र्ष्वः पावकः पुनः-पुनर्मातरा नव्यसी कः ||","b":"আ যোনিমগ্নির্ঘ্র্তবন্তমস্থাত পর্থুপ্রগাণমুশন্তমুশানঃ | দীদ্যানঃ শুচির্র্ষ্বঃ পাবকঃ পুনঃ-পুনর্মাতরা নব্যসী কঃ ||","e":"Agni hath entered longingly the longing shrine rich with fatness, giving easy access. Resplendent, pure, sublime and purifying, again, again he renovates his Mothers.","mb":"দীপ্তিমান বিশেষরূপে স্তুত ও স্বস্থানপ্রিয়, অগ্নি অধিরূঢ় হয়েছেন। দীপ্তিশালী, শুদ্ধ মহান ও পাবক অগ্নি পিতামাতাকে দ্যাবাপৃথিবীকে বার বার নুতনতর করেছেন।"},{"n":8,"d":"सद्यो जात ओषधीभिर्ववक्षे यदी वर्धन्ति परस्वो घर्तेन | आप इव परवता शुम्भमाना उरुश्यदग्निः पित्रोरुपस्थे ||","b":"সদ্যো জাত ওষধীভির্ববক্ষে যদী বর্ধন্তি পরস্বো ঘর্তেন | আপ ইব পরবতা শুম্ভমানা উরুশ্যদগ্নিঃ পিত্রোরুপস্থে ||","e":"Born suddenly, by plants he grew to greatness, when tender shoots with holy oil increased him, Like waters lovely when they hasten downward may Agni in his Parents' lap protect us.","mb":"অগ্নি জন্মানমাত্রেই ওষধি সকল কর্তৃক ধৃত হন, তখন পথপ্রবাহিত জলের ন্যায় শোভমান ওষধি সকল জলদ্বারা বর্ধিত হয়ে ফল প্রসব করে। অগ্নি পিতামাতার দ্যাবাপৃথিবীর উৎসঙ্গে বর্ধিত হয়ে আমাদের রক্ষা করুন।"},{"n":9,"d":"उदु षटुतः समिधा यह्वो अद्यौद वर्ष्मन दिवो अधि नाभा पर्थिव्याः | मित्रो अग्निरीड्यो मातरिश्वा दूतो वक्षद यजथाय देवान ||","b":"উদু ষটুতঃ সমিধা যহ্বো অদ্যৌদ বর্ষ্মন দিবো অধি নাভা পর্থিব্যাঃ | মিত্রো অগ্নিরীড্যো মাতরিশ্বা দূতো বক্ষদ যজথায দেবান ||","e":"Extolled, the Strong shone forth with kindled fuel to the earth's centre, to the height of heaven. May Agni, Friend, adorable Mātariśvan, as envoy bring the Gods unto our worship.","mb":"আমাদের  দ্বারা স্তুত ও দীপ্তিদ্বারা মহান অগ্নি পৃথিবীর নাভিতে অর্থাৎ বেদিতে অবস্থান করে অন্তরীক্ষ বিদ্যোতিত করেছেন। সকলের মিত্র, স্তুতিযোগ্য মাতরিশ্বা দেবগণের দূত হয়ে যজ্ঞে দেবগণকে আনুন।"},{"n":10,"d":"उदस्तम्भीत समिधा नाकं रष्वो.अग्निर्भवन्नुत्तमो रोचनानाम | यदी भर्गुभ्यः परि मातरिश्वा गुहा सन्तं हव्यवाहं समीधे ||","b":"উদস্তম্ভীত সমিধা নাকং রষ্বো.অগ্নির্ভবন্নুত্তমো রোচনানাম | যদী ভর্গুভ্যঃ পরি মাতরিশ্বা গুহা সন্তং হব্যবাহং সমীধে ||","e":"Best of all luminaries lofty Agni supported with his flame the height of heaven, When, far from Bhṛgus, Mātariśvan kindled the oblation-bearer where he lay in secret.","mb":"যখন মাতরিশ্বা ভৃগুদের জন্য গুহাস্থিত হব্যবাহক অগ্নিকে প্রজ্বলিত করেছিলেন (২), তখন তেজপদার্থের মধ্যে উৎকৃষ্টতম মহান অগ্নি স্বর্গকে তেজদ্বারা স্তুম্ভিত করেছিলেন।"},{"n":11,"d":"इळामग्ने ... ||","b":"ইলামগ্নে ... ||","e":"As holy food, Agni to thine invoker give wealth in cattle, lasting, rich in marvels. To us be born a son and spreading offspring. Agni, be this thy gracious will to us-word.","mb":"হে অগ্নি! তুমি স্তোতাকে বহুকর্মের হেতুভূত ও ধেনুপ্রদাত্রী ভূমি চিরকাল প্রদান কর। আমাদের বংশবিস্তারকারী এবং সন্তুতি জনয়িতা একটি পুত্র হোক। হে অগ্নি! আমাদের প্রতি তোমার অনুগ্রহ হোক।"}]},{"n":6,"t":"Agni","v":[{"n":1,"d":"पर कारवो मनना वच्यमाना देवद्रीचीं नयत देवयन्तः | दक्षिणावाड वाजिनी पराच्येति हविर्भरन्त्यग्नये घर्ताची ||","b":"পর কারবো মননা বচ্যমানা দেবদ্রীচীং নযত দেবযন্তঃ | দক্ষিণাবাড বাজিনী পরাচ্যেতি হবির্ভরন্ত্যগ্নযে ঘর্তাচী ||","e":"URGED on by deep devotion, O ye singers, bring, pious ones, the God-approaching ladle. Borne onward to the right it travels eastward, and, filled with oil, to Agni bears oblation.","mb":"হে যজ্ঞ কতৃাগণ! তোমরা দেবাভিলাষী, তোমরা মন্ত্রদ্বারা প্রেরিত হয়ে দেবাচৃনা সাধক স্রুক আন। আহবনীয় অগ্নির দক্ষিণদিকে যাকে বহন করা হচ্ছে, যাতে অন্ন আছে, যার অগ্রভাগ পূর্বদিকে রয়েছে, যা অগ্নির জন্য হব্য ধারণ করছে, সে ঘৃতযুক্ত স্রুক গমন করছে।"},{"n":2,"d":"आ रोदसी अप्र्णा जायमान उत पर रिक्था अध नु परयज्यो | दिवश्चिदग्ने महिना पर्थिव्या वच्यन्तां ते वह्नयः सप्तजिह्वाः ||","b":"আ রোদসী অপ্র্ণা জাযমান উত পর রিক্থা অধ নু পরযজ্যো | দিবশ্চিদগ্নে মহিনা পর্থিব্যা বচ্যন্তাং তে বহ্নযঃ সপ্তজিহ্বাঃ ||","e":"Thou at thy birth didst fill both earth and heaven, yea, Most Adorable, thou didst exceed them. Even through the heaven's and through the earth's expanses let thy swift seventongued flames roll on, O Agni.","mb":"হে অগ্নি! তুমি জন্মানমাত্রেই দ্যাবাপৃথিবীকে পরিপূর্ণ কর। হে যাগযোগ্য! তুমি মহিমা দ্বারা অন্তরিক্ষ ও পৃথিবী হতে প্রকৃষ্টতর হও। তোমার অংশভূত সপ্ত জিহ্বা বিশিষ্ট বহ্নিসকল পূজিত হোক।"},{"n":3,"d":"दयौश्च तवा पर्थिवी यज्ञियासो नि होतारं सादयन्ते दमाय | यदी विशो मानुषीर्देवयन्तीः परयस्वतीरीळते शुक्रमर्चिः ||","b":"দযৌশ্চ তবা পর্থিবী যজ্ঞিযাসো নি হোতারং সাদযন্তে দমায | যদী বিশো মানুষীর্দেবযন্তীঃ পরযস্বতীরীলতে শুক্রমর্চিঃ ||","e":"Both Heaven and Earth and Gods who should be worshipped establish thee as Priest for every dwelling, Whenever human families, God-devoted, bringing oblations; laud thy splendid lustre.","mb":"হে অগ্নি! তুমি হোতা, যখন দেবাভিলাষী হব্যযুক্ত মনুষ্য লোক তোমার দীপ্ত তেজের স্তব করে, তখন অন্তরীক্ষ পৃথিবী ও যজ্ঞার্হ দেবগণ যজ্ঞ সম্পাদনের জন্য তোমার স্তব করেন।"},{"n":4,"d":"महान सधस्थे धरुव आ निषत्तो.अन्तर्द्यावा माहिने हर्यमाणः | आस्क्रे सपत्नी अजरे अम्र्क्ते सबर्दुघे उरुगायस्यधेनू ||","b":"মহান সধস্থে ধরুব আ নিষত্তো.অন্তর্দ্যাবা মাহিনে হর্যমাণঃ | আস্ক্রে সপত্নী অজরে অম্র্ক্তে সবর্দুঘে উরুগাযস্যধেনূ ||","e":"Firm in the Gods’ home is the Mighty seated, between vast Heaven and Earth the well-beloved- Those Cows who yield, unharmed, their nectar, Spouses of the Far-Strider, everyoung, united.","mb":"মহান ও যজমানদের প্রিয় অগ্নি দ্যাবাপৃথিবীর মধ্যে মহিমাযুক্ত স্বকীয় স্থানে অচলভাবে উপবিষ্টি আছেন। আক্রমণশালী, স্বপত্নীভূতা, জরারহিতা, অহিংসিতা ক্ষীরপ্রসবিনী দ্যাবাপৃথিবী অত্যন্ত গমনশীল অগ্নির ধেনু।"},{"n":5,"d":"वरता ते अग्ने महतो महानि तव करत्वा रोदसी आ ततन्थ | तवं दूतो अभवो जायमानस्त्वं नेता वर्षभ चर्षणीनाम ||","b":"বরতা তে অগ্নে মহতো মহানি তব করত্বা রোদসী আ ততন্থ | তবং দূতো অভবো জাযমানস্ত্বং নেতা বর্ষভ চর্ষণীনাম ||","e":"Great are the deeds of thee, the Great, O Agni: thou by thy power hast spread out earth and heaven. As soon as thou wast born thou wast an envoy, thou, Mighty One, was Leader of the people.","mb":"হে অগ্নি! তুমি সর্বোৎকৃষ্ট, তোমার কর্ম মহৎ, তুমি ক্রতুদ্বারা দ্যাবাপৃথিবীকে বিস্তৃত করেছ, তুমি দূত। হে অভীষ্টবর্ষী অগ্নি! তুমি জন্মানমাত্রেই যজমানের নেতা হও।"},{"n":6,"d":"रतस्य वा केशिना योग्याभिर्घ्र्तस्नुवा रोहिता धुरि धिष्व | अथा वह देवान देव विश्वान सवध्वरा कर्णुहि जातवेदः ||","b":"রতস্য বা কেশিনা যোগ্যাভির্ঘ্র্তস্নুবা রোহিতা ধুরি ধিষ্ব | অথা বহ দেবান দেব বিশ্বান সবধ্বরা কর্ণুহি জাতবেদঃ ||","e":"Bind to the pole with cords of holy Order the long-maned ruddy steeds who sprinkle fatness. Bring hithier, O thou God, all Gods together: provide them noble worship, Jātavedas.","mb":"হে দ্যুতিমান অগ্নি! প্রশস্ত কেশবিশিষ্ট, রুজুযুক্ত, ঘৃতস্রাবী, রোহিত নামক অশ্বদ্বয়কে যজ্ঞের সম্মুখে যোজিত কর। অনন্তর তুমি সমস্ত দেবগণকে আনয়ন কর। হে সর্বভূতজ্ঞ! তুমি তাদের সুন্দর যজ্ঞযুক্ত কর।"},{"n":7,"d":"दिवश्चिदा ते रुचयन्ते रोका उषो विभातीरनु भासि पूर्वीः | अपो यदग्न उशधग वनेषु होतुर्मन्द्रस्य पनयन्त देवाः ||","b":"দিবশ্চিদা তে রুচযন্তে রোকা উষো বিভাতীরনু ভাসি পূর্বীঃ | অপো যদগ্ন উশধগ বনেষু হোতুর্মন্দ্রস্য পনযন্ত দেবাঃ ||","e":"Even from the sky thy brilliant lights shone hither: still hast thou beamed through many a radiant morning, That the Gods praised their joyous Herald's labour eagerly burning, Agni, in the forests.","mb":"হে াগ্নি! তুমি বিশেষরূপে প্রকাশমান পুরাতন উষার পশ্চাতে শোভিত হও। স্তোতগণ স্তুতিযোগ্য  হোতা অগ্নির স্তব করে।"},{"n":8,"d":"उरौ वा ये अन्तरिक्षे मदन्ति दिवो वा ये रोचने सन्ति देवाः | ऊमा वा ये सुहवासो यजत्रा आयेमिरे रथ्यो अग्ने अश्वाः ||","b":"উরৌ বা যে অন্তরিক্ষে মদন্তি দিবো বা যে রোচনে সন্তি দেবাঃ | ঊমা বা যে সুহবাসো যজত্রা আযেমিরে রথ্যো অগ্নে অশ্বাঃ ||","e":"The Gods who take delight in air's wide region, or those the dwellers in heaven's realm of brightness, Or those, the Holy, prompt to hear, our helpers, who, carborne, turn their horses hither, Agni—-","mb":"বিস্তীর্ণ অন্তরীক্ষে যে দেবগণ হৃষ্ট রয়েছেন, আকাশের দীপ্তিতে যে সকল দেবতা আছেন, উম নামক যে যজনীয় পিতৃগণ উত্তমরূপে আহুত হয়ে আগমন করেন, রথী অগ্নির যে সকল অশ্ব আছে।"},{"n":9,"d":"ऐभिरग्ने सरथं याह्यर्वां नानारथं वा विभवो हयश्वाः | पत्नीवतस्त्रिंशतं तरींश्च देवाननुष्वधमा वह मादयस्व ||","b":"ঐভিরগ্নে সরথং যাহ্যর্বাং নানারথং বা বিভবো হযশ্বাঃ | পত্নীবতস্ত্রিংশতং তরীংশ্চ দেবাননুষ্বধমা বহ মাদযস্ব ||","e":"With these, borne on one ear, Agni, approach us, or borne on many, for thy steeds are able. Bring, witb their Dames, the Gods, the Three and-Thirty, after thy Godlike nature, and be joyful.","mb":"হে অগ্নি! তুমি এ সকল দেবগণের সাথে একরথে অতবা নানা রথে আরোহণ করে আমাদের অভিমুখে এস, যেহেতু তোমার অশ্বগণ সমর্থ। ৩৩ জন দেবতাকে (১) হে অগ্নি! তুমি এ সকল দেবগণের সাথে একরথে অথবা নানা রথে আরোহণ করে আমাদরে অভিমুখে এস, যেহেতু তোমার অশ্বগণ সমর্থ। ৩৩ জন দেবতাকে (১) পত্নীগণের সাথে অন্নের জন্য আন ও হৃষ্ট কর।"},{"n":10,"d":"स होता यस्य रोदसी चिदुर्वी यज्ञं-यज्ञमभि वर्धे गर्णीतः | पराची अध्वरेव तस्थतुः सुमेके रतावरी रतजातस्य सत्ये ||","b":"স হোতা যস্য রোদসী চিদুর্বী যজ্ঞং-যজ্ঞমভি বর্ধে গর্ণীতঃ | পরাচী অধ্বরেব তস্থতুঃ সুমেকে রতাবরী রতজাতস্য সত্যে ||","e":"He is the Priest at whose repeated worship even wide Heaven and Earth sing out for increase. They fair and true and holy coming forward stand at his sacrifice who springs from Order.","mb":"বিস্তীর্ণা দ্যাবাপৃথিবী প্রত্যেক যজ্ঞে সমৃদ্ধির জন্য যে অগ্নির প্রশংসা করে, তিনিই দেবগণের হোতা। সুরুফা উদকবর্তী সত্যস্বরূপা দ্যাবাপৃথিবী যজ্ঞের ন্যায়, সত্য হতে জাত হোতা অগ্নির অনুকুল হয়ে থাকেন।"},{"n":11,"d":"इळामग्ने ... ||","b":"ইলামগ্নে ... ||","e":"As holy food, Agni, to thine invoker give wealth in cattle, lasting, rich in marvels. To us be born a son and spreading offspring. Agni, be this thy gracious will to usward.","mb":"হে অগ্নি! তুমি স্তোতাকে বহু কর্মের হেতুভূত ও ধেনু প্রদাত্রী ভূমি চিরকাল দান কর। আমাদের বংশ বিস্তারকারী এবং সন্তুতিজনয়িতা একটি পুত্র হোক। হে অগ্নি! আমাদরে প্রতি তোমার অনুগ্রহ হোক।"}]},{"n":7,"t":"","v":[{"n":1,"d":"पर य आरुः शितिप्र्ष्ठस्य धासेरा मातरा विविशुः सप्त वाणीः | परिक्षिता पितरा सं चरेते पर सर्स्राते दीर्घमायुः परयक्षे ||","b":"পর য আরুঃ শিতিপ্র্ষ্ঠস্য ধাসেরা মাতরা বিবিশুঃ সপ্ত বাণীঃ | পরিক্ষিতা পিতরা সং চরেতে পর সর্স্রাতে দীর্ঘমাযুঃ পরযক্ষে ||","e":"THE seven tones risen from the whitebacked viand have made their way between the pair of Mothers. Both circumjacent Parents come together to yield us length of days they hasten forward.","mb":"শ্বেত পৃষ্ঠবিশিষ্ট সকলের ধারক অগ্নির যে রশ্মি সকল প্রকর্ষরূপে উদ্গমন করে তারা পিতৃমাতৃভূত দ্যাবাপৃথিবীতে চতুর্দিকে প্রবিষ্ট হয়, সপ্ত নদীতেও প্রবিষ্ট হয়। চতুদিৃকে বর্তমান, পিতৃমাতৃভূত দ্যাবাপৃথিবী সম্যকরূপে প্রসূত হন এবং প্রকর্ষরূপে যজ্ঞ করবার জন্য অগ্নির দীর্ঘ আয়ু সম্পাদন করেন।"},{"n":2,"d":"दिवक्षसो धेनवो वर्ष्णो अश्वा देवीरा तस्थौ मधुमद वहन्तीः | रतस्य तवा सदसि कषेमयन्तं पर्येका चरति वर्तनिं गौः ||","b":"দিবক্ষসো ধেনবো বর্ষ্ণো অশ্বা দেবীরা তস্থৌ মধুমদ বহন্তীঃ | রতস্য তবা সদসি কষেমযন্তং পর্যেকা চরতি বর্তনিং গৌঃ ||","e":"The Male who dwells in heaven hath Mares and Milchkine: he came to Goddesses who bring sweet treasure. To thee safe resting in the seat of Order the Cow alone upon her way proceedeth.","mb":"দ্যুলোকবাসী ধেনুই অভীষ্টবর্ষী অগ্নির অশ্ব! অগ্নি মধুর জল বাহিনী দ্যুতিমতি নদী সকলে অধিষ্ঠান করেন। তুমি ঋতের সদনে আবাস ইচ্ছা কর এবং জ্বারা প্রেরণ কর, একটি গো তোমাকে সেবা করছে।"},{"n":3,"d":"आ सीमरोहत सुयमा भवन्तीः पतिश्चिकित्वान रयिविद रयीणाम | पर नीलप्र्ष्ठो अतसस्य धासेस्ता अवासयत पुरुधप्रतीकः ||","b":"আ সীমরোহত সুযমা ভবন্তীঃ পতিশ্চিকিত্বান রযিবিদ রযীণাম | পর নীলপ্র্ষ্ঠো অতসস্য ধাসেস্তা অবাসযত পুরুধপ্রতীকঃ ||","e":"Wise Master, wealthy finder-out of riches, he mounted those who may with case be guided. He, dark-backed, manifold with varied aspect, hath made them burst forth from their food the brush-wood.","mb":"ধনের মধ্যে শ্রেষ্ঠ ধনের স্বামী, জ্ঞানবান, অধিপতি অগ্নি সুখে সংযমনীয় বড়বা আরোহণ করলেন। নীল পৃষ্ঠবিশিষ্ট ও চতুর্দিকে প্রসৃত অগ্নি তাদরে সতত গমন করবার জন্য ছেড়ে দিলেন।"},{"n":4,"d":"महि तवाष्ट्रमूर्जयन्तीरजुर्यं सतभूयमानं वहतो वहन्ति | वयङगेभिर्दिद्युतानः सधस्थ एकामिव रोदसी आ विवेश ||","b":"মহি তবাষ্ট্রমূর্জযন্তীরজুর্যং সতভূযমানং বহতো বহন্তি | বযঙগেভির্দিদ্যুতানঃ সধস্থ একামিব রোদসী আ বিবেশ ||","e":"Strength-giving streams bear hither him eternal, fain to support the mighty work. of Tvaṣṭar. He, flashing in his home with all his members, hath entered both the worlds as they were single.","mb":"বলকারিণী, বহনশীলা নদীগণ অগ্নিকে ধারণ করে। তিনি মহান ত্বষ্টার পুত্র জরারহিত, ও লোক সকলকে ধারণ করতে অভিলাষী। (পুরুষ যেরূপ) একটি স্ত্রীর নিকট গমন করে সেরূপ তিনি জলের সমীপে দীপ্তাঙ্গ হয়ে দ্যাবাপৃথিবীতে প্রবেশ করেন।"},{"n":5,"d":"जानन्ति वर्ष्णो अरुषस्य शेवमुत बरध्नस्य शासने रणन्ति | दिवोरुचः सुरुचो रोचमाना इळा येषां गण्या माहिना गीः ||","b":"জানন্তি বর্ষ্ণো অরুষস্য শেবমুত বরধ্নস্য শাসনে রণন্তি | দিবোরুচঃ সুরুচো রোচমানা ইলা যেষাং গণ্যা মাহিনা গীঃ ||","e":"They know the red Bull's blessing, and are joyful under the flaming-coloured Lord's dominion: They who give shine from heavenwith fair effulgence, whose lofty song like Iḷā must be honoured.","mb":"লোকে অভীষ্টবর্ষী হিংসা রহিত অগ্নির আশ্রয় জনিত সুখ জানে এবং মহৎ জঅগ্নির আজ্ঞায় রত হয়। যে সকল মনুষ্যের মহৎ স্তুতিরূপ বাক্য গণনীয় হয়, তারা দ্যুলোকের  দীপ্তিকারী ও শোভন দীপ্তিবিশিষ্ট ও দেদীপ্যমান হন।"},{"n":6,"d":"उतो पित्र्भ्यां परविदानु घोषं महो महद्भ्यामनयन्त शूषम | उक्षा ह यत्र परि धानमक्तोरनु सवं धाम जरितुर्ववक्ष ||","b":"উতো পিত্র্ভ্যাং পরবিদানু ঘোষং মহো মহদ্ভ্যামনযন্ত শূষম | উক্ষা হ যত্র পরি ধানমক্তোরনু সবং ধাম জরিতুর্ববক্ষ ||","e":"Yea, by tradition from the ancient sages they brought great strength from the two mighty Parents, To where the singer's Bull, the night's dispeller, after his proper law hath waxen stronger.","mb":"মহান হতে ও মহত্তর পিতৃমাতৃস্থানীয় দ্যাবাপৃথিবীর অবগতির পর উচ্চৈ:স্বরে স্তুুতি জনিত সুখ অগ্নির নিকট নীত হয়। জলসেককারী অগ্নি রজনীর চতুর্দিকে ব্যাপ্ত স্বকীয় তেজ স্তোতার নিকটে বহন করেন।"},{"n":7,"d":"अध्वर्युभिः पञ्चभिः सप्त विप्राः परियं रक्षन्ते निहितं पदं वेः | पराञ्चो मदन्त्युक्षणो अजुर्या देवा देवानामनु हि वरता गुः ||","b":"অধ্বর্যুভিঃ পঞ্চভিঃ সপ্ত বিপ্রাঃ পরিযং রক্ষন্তে নিহিতং পদং বেঃ | পরাঞ্চো মদন্ত্যুক্ষণো অজুর্যা দেবা দেবানামনু হি বরতা গুঃ ||","e":"Seven holy singers guard with five Adhvaryus the Bird's beloved firmly-settled station. The willing Bulls, untouched by old, rejoice them: as Gods themselves the ways of Gods they follow.","mb":"পাঁচজন অধ্বর্যুর সাথে সাতজন হোতা গমনশীল অগ্নির প্রিয় স্থান রক্ষা করছেন। সোমপানের জন্য পূর্বমুখে গমনকারী, জরারহিত সোমরসবর্ষী স্তোতাগণ হৃষ্ট হচ্ছেন। কারণ দেবগণ, দেবতুল্য স্তোতার যজ্ঞে গিয়েছিলেন।"},{"n":8,"d":"दैव्या होतारा परथमा ... ||","b":"দৈব্যা হোতারা পরথমা ... ||","e":"I crave the grace of heaven's two chief Invokers: the seven swift steeds joy in their wonted manner. These speak of truth, praising the Truth Eternal, thinking on Order as the guards of Order.","mb":"দৈব্য হোতাদ্বয়স্বরূপ মুখ্য অগ্নিদ্বয়কে আমি অলঙ্কৃত করছি। সাতজন হোতা  সোমদ্বারা হৃষ্ট হচ্ছেন। স্তোত্রকারী, যজ্ঞরক্ষক, দীপ্তিযুক্ত হোতাগণ যজ্ঞে অগ্নিই সত্য এ কথা বলেন।"},{"n":9,"d":"वर्षायन्ते महे अत्याय पूर्वीर्व्र्ष्णे चित्राय रश्मयः सुयामाः | देव होतर्मन्द्रतरश्चिकित्वान महो देवान रोदसी एह वक्षि ||","b":"বর্ষাযন্তে মহে অত্যায পূর্বীর্ব্র্ষ্ণে চিত্রায রশ্মযঃ সুযামাঃ | দেব হোতর্মন্দ্রতরশ্চিকিত্বান মহো দেবান রোদসী এহ বক্ষি ||","e":"The many seek the great Steed as a stallion: the reins obey the Lord of varied colour. O heavenly Priest, most pleasant, full of wisdom, bring the great Gods to us, and Earth and Heaven.","mb":"হে দেদীপ্যমান ও দেবতাগণের আহ্বানকারী, অগ্নি! তুমি মহৎ, সকলকে অতিক্রম করে বর্তমান, নানাবিধ বর্ণবিশিষ্ট ও অভীষ্টবর্ষী। তোমার জন্য প্রভূত, অত্যন্ত বিস্তৃত ও সর্বত্র ব্যাপ্ত জ্বালা সকল বৃষের ন্যায় আচরণ করেছে। তুমি মাদয়িতা ও জ্ঞানী, তুমি পূজ্য দেবগণকে ও দ্যাবাপৃথিবীকে এ কর্মে আবাহন কর।"},{"n":10,"d":"पर्क्षप्रयजो दरविणः सुवाचः सुकेतव उषसो रेवदूषुः | उतो चिदग्ने महिना पर्थिव्याः कर्तं चिदेनः सं महे दशस्य ||","b":"পর্ক্ষপ্রযজো দরবিণঃ সুবাচঃ সুকেতব উষসো রেবদূষুঃ | উতো চিদগ্নে মহিনা পর্থিব্যাঃ কর্তং চিদেনঃ সং মহে দশস্য ||","e":"Rich Lord, the Mornings have gleamed forth in splendour, fair-rayed, fair-speaking, worshipped with all viands, Yea, with the glory of the earth, O Agni. Forgive us, for our weal, e’en sin cornmitted.","mb":"হে সততগমনশীল অগ্নি! যে উষাকালে প্রকর্ষরূপে অন্নদ্বারা যাগ করতে আরম্ভ করা হয়, যে উষাকালে শোভন বাক্যবিশিষ্ট ও পক্ষী মানবগণের শব্দদ্বারা সুচিহ্নিত সে উষাকাল সকল তোমাদের জন্য ধনযুক্ত হয়ে প্রকাশিত হচ্ছে। হে অগ্নি! তুমি বিস্তীর্ণ মহিমাদ্বারা যজমানের কত পাপ নাশ কর।"},{"n":11,"d":"इळामग्ने ... ||","b":"ইলামগ্নে ... ||","e":"As holy food, Agni, to thine invoker, give wealth in cattle, lasting, rich in marvels. To us be born a son, and spreading offspring Agni, be this thy gracious will to usward.","mb":"হে অগ্নি! তুমি  স্তোতাকে বহুকমেৃর হেতুভূত ও ধেনুপ্রদাত্র ভূমি চিরকাল প্রদান কর। আমাদের বংশবিস্তারকারী এবং সন্তুতি জনয়িতা এক পুত্র হোক। হে অগ্নি! আমাদের প্রতি তোমার অনুগ্রহ  হোক।"}]},{"n":8,"t":"Sacrificial Post","v":[{"n":1,"d":"अञ्जन्ति तवामध्वरे देवयन्तो वनस्पते मधुना दैव्येन | यदूर्ध्वस्तिष्ठा दरविणेह धत्ताद यद वा कषयो मातुरस्या उपस्थे ||","b":"অঞ্জন্তি তবামধ্বরে দেবযন্তো বনস্পতে মধুনা দৈব্যেন | যদূর্ধ্বস্তিষ্ঠা দরবিণেহ ধত্তাদ যদ বা কষযো মাতুরস্যা উপস্থে ||","e":"GOD-SERVING men, O Sovran of the Forest, with heavenly meath at sacrifice anoint thee. Grant wealth to us when thou art standing upright as when reposing on this Mother's bosom.","mb":"হে বনস্পতি! যজ্ঞে দেবতাগণের অভিলাষী অধ্বর্যুগণ দেব সম্বন্ধীয় মধুদ্বারা তোমাকে সিক্ত করছে। তুমি উন্নতভাবেই থাক অথবা মাতৃভূত পৃথিবীর উৎসঙ্গেই শয়ন করে থাক, আমাদের ধন দান কর।"},{"n":2,"d":"समिद्धस्य शरयमाणः पुरस्ताद बरह्म वन्वानो अजरं सुवीरम | आरे अस्मदमतिं बाधमान उच्छ्रयस्व महते सौभगाय ||","b":"সমিদ্ধস্য শরযমাণঃ পুরস্তাদ বরহ্ম বন্বানো অজরং সুবীরম | আরে অস্মদমতিং বাধমান উচ্ছ্রযস্ব মহতে সৌভগায ||","e":"Set up to eastward of the fire enkindled, accepting prayer that wastes not, rich in hero. Driving far from us poverty and famine, lift thyself up to bring us great good fortune.","mb":"হে যুপ! তুমিস সমিদ্ধ আহবনীয়াখ্য অগ্নির পূর্বদিকে বর্তমান হয়ে জরারহিত, সুন্দর ও অপত্যযুক্ত অন্নদান করে এবং আমাদের পাপ দূরে অপনোদন করে মহৎ সম্পত্তির জন্য উন্নত হও।"},{"n":3,"d":"उच्छ्रयस्व वनस्पते वर्ष्मन पर्थिव्या अधि | सुमिती मीयमानो वर्चो धा यज्ञवाहसे ||","b":"উচ্ছ্রযস্ব বনস্পতে বর্ষ্মন পর্থিব্যা অধি | সুমিতী মীযমানো বর্চো ধা যজ্ঞবাহসে ||","e":"Lord of the Forest, raise. thyself up on the loftiest spot of earth. Give splendour, fixt and measured well, to him who brings the sacrifice.","mb":"হে বনস্পতি! তুমি পৃথিবীতে উৎকৃষ্ট যজ্ঞপ্রদেশে উন্নত হও। তুমি সুন্দর পরিমাণ দ্বারা পরিচ্ছিদ্যমান, তুমি যজ্ঞ নির্বাহককে অন্ন দান কর।"},{"n":4,"d":"युवा सुवासाः परिवीत आगात स उ शरेयान भवति जायमानः | तं धीरासः कवय उन नयन्ति सवाध्यो मनसा देवयन्तः ||","b":"যুবা সুবাসাঃ পরিবীত আগাত স উ শরেযান ভবতি জাযমানঃ | তং ধীরাসঃ কবয উন নযন্তি সবাধ্যো মনসা দেবযন্তঃ ||","e":"Well-robed, enveloped he is come, the youthful: springing to life his glory waxeth greater. Contemplative in mind and God-adoring, sages of high intelligence upraise him.","mb":"দৃঢ়াঙ্গ ও সুন্দর রসনাযুক্ত ও রসনাদ্বারা পরিবেষ্টিত যুপ আসছে। সে যুপই সমস্ত বনস্পতি অপেক্ষা উৎকৃষ্টরূপে জাত হয়। প্রাজ্ঞ মেধাবীগণ মনে দেবতা অভিলাষ করে সুন্দর ধ্যানের সাথে একে উন্নত করেন।"},{"n":5,"d":"जातो जायते सुदिनत्वे अह्नां समर्य आ विदथे वर्धमानः | पुनन्ति धीरा अपसो मनीषा देवया विप्र उदियर्ति वाचम ||","b":"জাতো জাযতে সুদিনত্বে অহ্নাং সমর্য আ বিদথে বর্ধমানঃ | পুনন্তি ধীরা অপসো মনীষা দেবযা বিপ্র উদিযর্তি বাচম ||","e":"Sprung up he rises in the days' fair weather, increasing in the men-frequented synod. With song the wise and skilful consecrate him: his voice the God-adoring singer utters. 6, Ye whom religious men have firmly planted; thou Forest Sovran whom the axe hath fashioned,— Let those the Stakes divine which here are standing be fain to grant us wealth with store of children.","mb":"পৃথিবীতে বৃক্ষরূপে জাত যূপ মনুষ্যগণের সাথে যজ্ঞে শোভবান হয়ে দিবস  সমূহকে সুদিন করে। কর্মবান প্রজ্ঞাবিশিষ্ট অধ্বর্যুগণ যথাবুদ্ধি সে যুপকে প্রক্ষালন দ্বারাও বন্ধ করেন। দেবগণের যাগকারী, মেধাবী হোতা বাক্য উচ্চারণ করেন।"},{"n":6,"d":"यान वो नरो देवयन्तो निमिम्युर्वनस्पते सवधितिर्वा ततक्ष | ते देवासः सवरवस्तस्थिवांसः परजावदस्मे दिधिषन्तु रत्नम ||","b":"যান বো নরো দেবযন্তো নিমিম্যুর্বনস্পতে সবধিতির্বা ততক্ষ | তে দেবাসঃ সবরবস্তস্থিবাংসঃ পরজাবদস্মে দিধিষন্তু রত্নম ||","e":"O men who lift the ladles up, these hewn and planted in the ground, Bringing a blessing to the field, shall bear our precious gift to Gods.","mb":"হে মরুদ্গণ! দেবাভিলাষী, কর্মের নেতা অর্ধ্বর্যু প্রভৃতিরা তোমাদের গর্তমধ্যে প্রক্ষেপ করেছে, হে বনস্পতি! কুঠার তোমাদের ছেদন করেছে। তোমরা দীপ্তিমান ও কাষ্ঠখন্ডবিশিষ্ট, আমাদের অপত্যের সাথে উত্তম ধন দান কর।"},{"n":7,"d":"ये वर्क्णासो अधि कषमि निमितासो यतस्रुचः | ते नो वयन्तु वार्यं देवत्रा कषेत्रसाधसः ||","b":"যে বর্ক্ণাসো অধি কষমি নিমিতাসো যতস্রুচঃ | তে নো বযন্তু বার্যং দেবত্রা কষেত্রসাধসঃ ||","e":"Ādityas, Rudras, Vasus, careful leaders, Earth, Heaven, and Prthivi and Air's mid-region, Accordant Deities shall bless our worship and make our sacrifice's ensign lofty.","mb":"যারা পশু দ্বারা ভূমিতে ছিন্ন হয়, যারা যত স্রুক ঋত্বিকগণ কর্তৃক গর্তমধ্যে প্রক্ষিপ্ত হয় এবং যারা যজ্ঞের সাধক সে যূপ সকল দেবতাগণের নিকট আমাদের হব্য নিয়ে যাক।"},{"n":8,"d":"आदित्या रुद्रा वसवः सुनीथा दयावाक्षामा पर्थिवी अन्तरिक्षम | सजोषसो यज्ञमवन्तु देवा ऊर्ध्वं कर्ण्वन्त्वध्वरस्य केतुम ||","b":"আদিত্যা রুদ্রা বসবঃ সুনীথা দযাবাক্ষামা পর্থিবী অন্তরিক্ষম | সজোষসো যজ্ঞমবন্তু দেবা ঊর্ধ্বং কর্ণ্বন্ত্বধ্বরস্য কেতুম ||","e":"Like swan's that flee in lengthened line, the Pillars have come to us arrayed in brilliant coIour. They, lifted up on high, by sages, eastward, go forth as Gods to the God's dwelling-places.","mb":"সুনেতা আদিত্যগণ, রুদ্রগণ, বসুগণ, দ্যাবাপৃথিবী ও বিস্তীর্ণ অন্তরীক্ষ সকলে মিলিত হয়ে যজ্ঞ রক্ষা করুন এবং যজ্ঞের ধ্বজভূত যূপকে উন্নত করুন।"},{"n":9,"d":"हंसा इव शरेणिशो यतानाः शुक्रा वसानाः सवरवो नागुः | उन्नीयमानाः कविभिः पुरस्ताद देवा देवानामपि यन्ति पाथः ||","b":"হংসা ইব শরেণিশো যতানাঃ শুক্রা বসানাঃ সবরবো নাগুঃ | উন্নীযমানাঃ কবিভিঃ পুরস্তাদ দেবা দেবানামপি যন্তি পাথঃ ||","e":"Those Stakes upon the earth with rings that deck them seem to the eye like horns of horned creatures; Or, as upraised by priests in invocation, let them assist us in the rush to battle.","mb":"দীপ্ত বস্ত্রের দ্বারায় আচ্ছাদিত, হংসের ন্যায় শ্রেণীপূর্বক গমনকারীও খন্ডবিশিষ্ট যুপসকল আমাদরে নিকট আসুক। মেধাবী অধ্বর্যু প্রভৃতি কর্তৃক যজ্ঞের পূর্বভাগে উদীয়মান ও দীপ্তিমান যুপ সকল দেবগণের পথ প্রাপ্ত হয়।"},{"n":10,"d":"शर्ङगाणीवेच्छ्र्ङगिणां सं दद्र्श्रे चषालवन्तः सवरवः पर्थिव्याम | वाघद्भिर्वा विहवे शरोषमाणा अस्मानवन्तु पर्तनाज्येषु ||","b":"শর্ঙগাণীবেচ্ছ্র্ঙগিণাং সং দদ্র্শ্রে চষালবন্তঃ সবরবঃ পর্থিব্যাম | বাঘদ্ভির্বা বিহবে শরোষমাণা অস্মানবন্তু পর্তনাজ্যেষু ||","e":"Lord of the Wood, rise with a hundred branches. with thousand branches may we rise to greatness, Tlou whom this hatchct, with an edge well whetted for great felicity, hath brought before us.","mb":"স্বরুবিশিষ্ট এবং  মুক্ত কন্টক যুপ সকল পৃথিবীতে শৃঙ্গী পশুর শৃঙ্গের ন্যায় সম্যকরূপে দৃষ্ট হয়। যজ্ঞে ঋত্বিকগণের স্তুতি শ্রবণকারী যূপসক{ল যুদ্ধে আমাদের রক্ষা করুন।"},{"n":11,"d":"वनस्पते शतवल्शो वि रोह सहस्रवल्शा वि वयं रुहेम | यं तवामयं सवधितिस्तेजमानः परणिनाय महते सौभगाय ||","b":"বনস্পতে শতবল্শো বি রোহ সহস্রবল্শা বি বযং রুহেম | যং তবামযং সবধিতিস্তেজমানঃ পরণিনায মহতে সৌভগায ||","e":"Missing line from Griffith.","mb":"হে ছিন্নমুল স্থাণু! তোমাকে এই নিশিতধার পরশু মহৎ সৌভাগ্যলাভ করিয়েছে। তুমি শত শাখাবিশিষ্ট হয়ে বিশেষরূপে প্রাদুর্ভূত হও। আমরাও যেন সহস্র শাখাবিশিষ্ট হয়ে বিশেষরূপে প্রাদুর্ভূত হতে পারি।"}]},{"n":9,"t":"","v":[{"n":1,"d":"सखायस्त्वा वव्र्महे देवं मर्तास ऊतये | अपां नपातंसुभगं सुदीदितिं सुप्रतूर्तिमनेहसम ||","b":"সখাযস্ত্বা বব্র্মহে দেবং মর্তাস ঊতযে | অপাং নপাতংসুভগং সুদীদিতিং সুপ্রতূর্তিমনেহসম ||","e":"WE as thy friends have chosen thee, mortals a God, to be our help, The Waters’ Child, the blessed, the resplendent One, victorious and beyond compare.","mb":"অগ্নি তুমি জলের নপ্তা, সুন্দর ধনযুক্ত, দীপ্তিমান ও উপদ্রব রহিত  এবং লোকের অধিগম্য। আমরা তোমার মিত্রভূত মর্ত্য, আমরা রক্ষার নিমিত্ত তোমাকে বরণ করছি।"},{"n":2,"d":"कायमानो वना तवं यन मातॄरजगन्नपः | न तत तेग्ने परम्र्षे निवर्तनं यद दूरे सन्निहाभवः ||","b":"কাযমানো বনা তবং যন মাতৄরজগন্নপঃ | ন তত তেগ্নে পরম্র্ষে নিবর্তনং যদ দূরে সন্নিহাভবঃ ||","e":"Since thou delighting in the woods hast gone unto thy mother streams, Not to be scorned, Agni, is that return of thine when from afar thou now art here.","mb":"হে অগ্নি! তুমি বন সকলকে কামনা করে থাক তুমি মাতৃভূত জলমধ্যে প্রবিষ্ট হয়ে শন্ত হও, তোমার শান্তভাব হস্য করা যায় না। এই জন্য তুমি দুরে থেকেও আমাদের কাষ্ঠ মধ্যে উৎপন্ন হও।"},{"n":3,"d":"अति तर्ष्टं ववक्षिथाथैव सुमना असि | पर-परान्ये यन्ति पर्यन्य आसते येषां सख्ये असि शरितः ||","b":"অতি তর্ষ্টং ববক্ষিথাথৈব সুমনা অসি | পর-পরান্যে যন্তি পর্যন্য আসতে যেষাং সখ্যে অসি শরিতঃ ||","e":"O'er pungent smoke host thou prevailed, and thus art thou benevolent. Some go before, and others round about thee sit, they in whose friendship thou hast place.","mb":"হে অগ্নি! তুমি স্তোতার অভিলাষ অধিকরূপে বহন করতে ইচ্ছা করে থাক এবং তুমি সন্তুষ্ট মনে থাক। তুমি যে ঋত্বিকগণের সাথে বন্ধুত্বভাবে অবস্থিত থাক, তাদের মধ্যে কেউ কেউ বিশেষরূপে হোম করবার জন্য আসেন, অন্যেরা চতুর্দিকে উপবিষ্ট হয়ে থাকেন।"},{"n":4,"d":"ईयिवांसमति सरिधः शश्वतीरति सश्चतः | अन्वीमविन्दन निचिरासो अद्रुहो.अप्सु सिंहमिव शरितम ||","b":"ঈযিবাংসমতি সরিধঃ শশ্বতীরতি সশ্চতঃ | অন্বীমবিন্দন নিচিরাসো অদ্রুহো.অপ্সু সিংহমিব শরিতম ||","e":"Him who had passed beyond his foes, beyond continual pursuits, Him the unerring Ones, observant, found in floods, couched like a lion in his lair.","mb":"গৃহাস্থিত সিংহের ন্যায় জল মধ্যে লুকায়িত এবং শত্রু ও বহু সেনার পরাভবকারী অগ্নিকে দ্রোহরহিত চিরন্তন বিশ্বদেবগণ প্রাপ্ত হয়েছিলেন।"},{"n":5,"d":"सस्र्वांसमिव तमनाग्निमित्था तिरोहितम | ऐनं नयन मातरिश्वा परावतो देवेभ्यो मथितं परि ||","b":"সস্র্বাংসমিব তমনাগ্নিমিত্থা তিরোহিতম | ঐনং নযন মাতরিশ্বা পরাবতো দেবেভ্যো মথিতং পরি ||","e":"Him wandering at his own free will, Agni here hidden from our view, Him Mātariśvan brought to us from far away produced by friction, from the Gods.","mb":"পিতা যেরূপ স্বচ্ছন্দগামী পুত্রকে বলপূর্বক আয়ন করেন, সেরূপ মাতরিশ্বা স্বেচ্ছাপূর্বক তিরোহিত ও মন্থনদ্বারা নিষ্পাদিত এ অগ্নিকে দেবতাগণের জন্য আনয়ন করেছিলেন।"},{"n":6,"d":"तं तवा मर्ता अग्र्भ्णत देवेभ्यो हव्यवाहन | विश्वान यद्यज्ञानभिपासि मानुष तव करत्वा यविष्ठ्य ||","b":"তং তবা মর্তা অগ্র্ভ্ণত দেবেভ্যো হব্যবাহন | বিশ্বান যদ্যজ্ঞানভিপাসি মানুষ তব করত্বা যবিষ্ঠ্য ||","e":"O Bearer of Oblations, thus mortals received thee from the Gods, Whilst thou, the Friend of man, guardest each sacrifice with thine own power, Most Youthful One.","mb":"হে মনুষ্যদের হিতকারী, সদাতরুণ অগ্নি! তুমি তোমার মাহাত্ম্য দ্বারা সমস্ত যজ্ঞকে বিশেষরূপে পালন কর। অতএব, হে হব্যবাহন! মানুষেরা তোমাকে দেবগণের জন্য গ্রহণ করেছেন।"},{"n":7,"d":"तद भद्रं तव दंसना पाकाय चिच्छदयति | तवां यदग्ने पशवः समासते समिद्धमपिशर्वरे ||","b":"তদ ভদ্রং তব দংসনা পাকায চিচ্ছদযতি | তবাং যদগ্নে পশবঃ সমাসতে সমিদ্ধমপিশর্বরে ||","e":"Amid thy wonders this is good, yea, to the simple is it clear, When gathered round about thee, Agni, lie the herds where thou art kindled in the morn.","mb":"হে অগ্নি! যেহেতু তুমি সায়ংকালে সমিদ্ধ হলে তোমার নিকট পশু সকল উপবিষ্ট হয় অতএব তোমার এ সুন্দর কর্ম বালকের ন্যায় অজ্ঞকেও ফল প্রদান দ্বারা সন্তুষ্ট করে।"},{"n":8,"d":"आ जुहोता सवध्वरं शीरं पावकशोचिषम | आशुं दूतमजिरं परत्नमीड्यं शरुष्टी देवं सपर्यत ||","b":"আ জুহোতা সবধ্বরং শীরং পাবকশোচিষম | আশুং দূতমজিরং পরত্নমীড্যং শরুষ্টী দেবং সপর্যত ||","e":"Offer to him who knows fair rites, who burns with purifying glow, Swift envoy, active, ancient, and adorable: serve ye the God attentively.","mb":"পাবকদীপ্তিবিশিষ্ট, কাষ্ঠাদি মধ্যে শয়ান ও সুক্রতু অগ্নিকে হোম কর। বহু ব্যাপ্ত, দুতস্বরূপ, ক্ষিপ্রগামী, পুরাতন স্তুতিযোগ্য ও দীপ্তিমান অগ্নিকে সত্বর পূজা কর।"},{"n":9,"d":"तरीणि शता तरी सहस्राण्यग्निं तरिंशच्च देवा नवचासपर्यन | औक्षन घर्तैरस्त्र्णन बर्हिरस्मा आदिद धोतारं नयसादयन्त ||","b":"তরীণি শতা তরী সহস্রাণ্যগ্নিং তরিংশচ্চ দেবা নবচাসপর্যন | ঔক্ষন ঘর্তৈরস্ত্র্ণন বর্হিরস্মা আদিদ ধোতারং নযসাদযন্ত ||","e":"Three times a hundred Gods and thrice a thousand, and three times ten and nine have worshipped Agni, For him spread sacred grass, with oil bedewed him, and stablished him as Priest and Sacrificer.","mb":"তিন সহস্র তিনশতত্রিংশৎ ও নব সংখ্যক দেবগণ (১) অগ্নিকে পূজা করেছেন, ঘৃতদ্বারা শক্ত করেছেন এবং তার জন্য কুশ বিস্তৃত করেছেন। তৎসহ তাকে হোতারূপে কুশোপরি উপবেশন করিয়েছেন।"}]},{"n":10,"t":"Agni","v":[{"n":1,"d":"तवामग्ने मनीषिणः सम्राजं चर्षणीनाम | देवं मर्तास इन्धते समध्वरे ||","b":"তবামগ্নে মনীষিণঃ সম্রাজং চর্ষণীনাম | দেবং মর্তাস ইন্ধতে সমধ্বরে ||","e":"THEE Agni, God, Imperial Lord of all mankind, do mortal men With understanding kindle at the sacrifice.","mb":"হে অগ্নি! তুমি প্রজাগণের অধিপতি ও দীপ্তিমান, তোমাকে ধীমান মানুষেরা যজ্ঞে উদ্দীপিত করেন।"},{"n":2,"d":"तवां यज्ञेष्व रत्विजमग्ने होतारमीळते | गोपा रतस्य दीदिहि सवे दमे ||","b":"তবাং যজ্ঞেষ্ব রত্বিজমগ্নে হোতারমীলতে | গোপা রতস্য দীদিহি সবে দমে ||","e":"They laud thee in their solemn rites, Agni, as Minister and Priest, Shine forth in thine own home as guardian of the Law.","mb":"হে অগ্নি! তুমি হোতা ও ঋত্বিক, তোমাকে অধ্বর্যুগণ যজ্ঞে স্তব করেন। তুমি যজ্ঞের রক্ষক হয়ে স্বকীয় গৃহ যজ্ঞশালায় দীপত হও।"},{"n":3,"d":"स घा यस्ते ददाशति समिधा जातवेदसे | सो अग्ने धत्तेसुवीर्यं स पुष्यति ||","b":"স ঘা যস্তে দদাশতি সমিধা জাতবেদসে | সো অগ্নে ধত্তেসুবীর্যং স পুষ্যতি ||","e":"He, verily, who honours thee with fuel, Knower of all life, He, Agni! wins heroic might, he prospers well.","mb":"হে অগ্নি! তুমি জাতবেদা, তোমাকে যে যজমান সমিন্ধনকারী হব্য দান করেন, তিনি সুবীর্য পুত্র  ধারণ করেন ও পশু পুত্রাদিদ্বারা সমিদ্ধ হন।"},{"n":4,"d":"स केतुरध्वराणामग्निर्देवेभिरा गमत | अञ्जानः सप्त होत्र्भिर्हविष्मते ||","b":"স কেতুরধ্বরাণামগ্নির্দেবেভিরা গমত | অঞ্জানঃ সপ্ত হোত্র্ভির্হবিষ্মতে ||","e":"Ensign of sacrifices, he, Agni, with Gods is come to us, Decked by the seven priests, to him who bringeth gifts.","mb":"যজ্ঞের প্রজ্ঞাপক সে অগ্নি সপ্ত হোতা কর্তৃক সিক্ত হয়ে যজমানের জন্য দেবগণের সাথে আসুন।"},{"n":5,"d":"पर होत्रे पूर्व्यं वचो.अग्नये भरता बर्हत | विपां जयोतींषि बिभ्रते न वेधसे ||","b":"পর হোত্রে পূর্ব্যং বচো.অগ্নযে ভরতা বর্হত | বিপাং জযোতীংষি বিভ্রতে ন বেধসে ||","e":"To Agni, the Invoking Priest, offer your best, your lofty speech, To him Ordainer-like who brings the light of songs.","mb":"হে ঋত্বিকগণ! তোমরা মেধাবী ব্যক্তিদের তেজ ধারণকারী জগতের বিধানকতৃা, দেবগণের আহ্বানকারী অগ্নির উদ্দেশে মহৎ পুরাতন বাক্য সম্পাদন কর।"},{"n":6,"d":"अग्निं वर्धन्तु नो गिरो यतो जायत उक्थ्यः | महे वाजायद्रविणाय दर्शतः ||","b":"অগ্নিং বর্ধন্তু নো গিরো যতো জাযত উক্থ্যঃ | মহে বাজাযদ্রবিণায দর্শতঃ ||","e":"Let these our hymns make Agni grow, whence, meet for laud, he springs to life, To mighty strength and great possession, fair to see.","mb":"অগ্নি মহৎ অন্ন ও ধনের জন্য দর্শনীয়। তিনি যে বাক্যদ্বারা অত্যন্ত প্রশংসনীয় হন, আমাদের সে স্তুতিরূপ বাক্য তাকে বর্ধিত করুক।"},{"n":7,"d":"अग्ने यजिष्ठो अध्वरे देवान देवयते यज | होता मन्द्रो विराजस्यति सरिधः ||","b":"অগ্নে যজিষ্ঠো অধ্বরে দেবান দেবযতে যজ | হোতা মন্দ্রো বিরাজস্যতি সরিধঃ ||","e":"Best Sacrificer, bring the Gods, O Agni, to the pious man: A joyful Priest, thy splendour drive our foes afar","mb":"হে অগ্নি! তুমি যজ্ঞকারিগণের মধ্যে শ্রেষ্ঠ, তুমি যজ্ঞে যজমানদের জন্য দেবতাগণকে যাগ কর। হে অগ্নি! তুমি হোতা ও যজমানের হর্ষদাতা, তুমি শত্রুদের পরিভূত করে শোভা পাচ্ছ।"},{"n":8,"d":"स नः पावक दीदिहि दयुमदस्मे सुवीर्यम | भवा सतोत्र्भ्योन्तमः सवस्तये ||","b":"স নঃ পাবক দীদিহি দযুমদস্মে সুবীর্যম | ভবা সতোত্র্ভ্যোন্তমঃ সবস্তযে ||","e":"As such, O Purifier, shine on us heroic glorious might: Be nearest Friend to those who laud thee, for their weal.","mb":"হে পাবক! তুমি, আমাদের কান্তিযুক্ত ও শোভন সামর্থ্যযুক্ত ধন দান কর এবং স্তোতাগণের কল্রাণের জন্য তাদের অত্যন্ত সমীপবর্তী হও।"},{"n":9,"d":"तं तवा विप्रा विपन्यवो जाग्र्वांसः समिन्धते | हव्यवाहममर्त्यं सहोव्र्धम ||","b":"তং তবা বিপ্রা বিপন্যবো জাগ্র্বাংসঃ সমিন্ধতে | হব্যবাহমমর্ত্যং সহোব্র্ধম ||","e":"So, wakeful, versed in sacred hymns, the holy singers kindly thee. Oblation-bearer, deathless, cherisher of strength.","mb":"হে অগ্নি! তুমি হব্যবাহক, মরণরহিত ও (মথনরূপ) বলদ্বারা বর্ধমান; প্রবুদ্ধ মেধাবী স্তোতাগণ তোমাকে সমাকরূপে উদ্দীপিত করেন।"}]},{"n":11,"t":"Agni","v":[{"n":1,"d":"अग्निर्होता पुरोहितो.अध्वरस्य विचर्षणिः | स वेद यज्ञमानुषक ||","b":"অগ্নির্হোতা পুরোহিতো.অধ্বরস্য বিচর্ষণিঃ | স বেদ যজ্ঞমানুষক ||","e":"AGNI is Priest, the great High Priest of sacrifice, most swift in act: He knows the rite in constant course.","mb":"অগ্নি, হোতা পুরোহিত ও যজ্ঞের বিশেষরূপে দ্রষ্টা। তিনি যজ্ঞকে আনুপূর্বিক জানেন।"},{"n":2,"d":"स हव्यवाळ अमर्त्य उशिग दूतस चनोहितः | अग्निर्धिया सं रण्वति ||","b":"স হব্যবাল অমর্ত্য উশিগ দূতস চনোহিতঃ | অগ্নির্ধিযা সং রণ্বতি ||","e":"Oblation-bearer, deathless, well inclined, an eager messenger, Agni comes nigh us with the thought.","mb":"হব্যবাহক, মরণরহিত ও হব্যাভিলাষী এবং দেবগণের দূত, অন্নপ্রিয় অগ্নি প্রজ্ঞাযুক্ত হচ্ছেন।"},{"n":3,"d":"अग्निर्धिया स चेतति केतुर्यज्ञस्य पूर्व्यः | अर्थं हयस्य तरणि ||","b":"অগ্নির্ধিযা স চেততি কেতুর্যজ্ঞস্য পূর্ব্যঃ | অর্থং হযস্য তরণি ||","e":"Ensign of sacrifice from of old, Agni well knoweth with his thought To prosper this man's aim and hope.","mb":"যজ্ঞের কেতুস্বরূপ পুরাতন অগ্নি প্রজ্ঞাবলে সমস্ত জানেন। এ অগ্নির তেজ অন্ধকার বিনাশ করে।"},{"n":4,"d":"अग्निं सूनुं सनश्रुतं सहसो जातवेदसम | वह्निं देवाक्र्ण्वत ||","b":"অগ্নিং সূনুং সনশ্রুতং সহসো জাতবেদসম | বহ্নিং দেবাক্র্ণ্বত ||","e":"Agni, illustrious from old time, the Son of Strength who knows all life, The Gods have made to their Priest.","mb":"বলের পুত্র, সনাতন বলে প্রসিদ্ধ ও জাতবেদা অগ্নিকে দেবগণ হব্যের বাহক করেছেন।"},{"n":5,"d":"अदाभ्यः पुरेता विशामग्निर्मानुषीणाम | तूर्णी रथः सदा नवः ||","b":"অদাভ্যঃ পুরেতা বিশামগ্নির্মানুষীণাম | তূর্ণী রথঃ সদা নবঃ ||","e":"Infallible is Agni, he who goes before the tribes of men, A chariot swift and ever new.","mb":"মানুষ লোকের নেতা, ত্বরাযুক্ত, রথসদৃশ ও সর্বদা নুতন, অগ্নিকে কেউ হিংসা করতে পারে না।"},{"n":6,"d":"साह्वान विश्वा अभियुजः करतुर्देवानामम्र्क्तः | अग्निस्तुविश्रवस्तमः ||","b":"সাহ্বান বিশ্বা অভিযুজঃ করতুর্দেবানামম্র্ক্তঃ | অগ্নিস্তুবিশ্রবস্তমঃ ||","e":"Strength of the Gods which none may harm, subduing all his enemies, Agni is mightiest in fame.","mb":"সমস্ত শত্রুসৈন্যের পরাভবকারী, শত্রুকর্তৃক অহিংসিষ্ঠ ও দেবগণের পোষাক অগ্নি প্রচুর পরিমাণে বহুবিধ অন্নযুক্ত আছেন।"},{"n":7,"d":"अभि परयांसि वाहसा दाश्वानश्नोति मर्त्यः | कषयं पावकशोचिषः ||","b":"অভি পরযাংসি বাহসা দাশ্বানশ্নোতি মর্ত্যঃ | কষযং পাবকশোচিষঃ ||","e":"By offering sacred food to him the mortal worshipper obtains. A home from him whose light makes pure.","mb":"হব্যদাতা মানুষ হব্যবাহক অগ্নিকর্তৃক অন্ন সকল প্রাপ্ত হয় এবং পবিত্রকারক দীপ্তিবিশিষ্ট অগ্নির সকাশ হতে গৃহ প্রাপ্ত হয়।"},{"n":8,"d":"परि विश्वानि सुधिताग्नेरश्याम मन्मभिः | विप्रासो जातवेदसः ||","b":"পরি বিশ্বানি সুধিতাগ্নেরশ্যাম মন্মভিঃ | বিপ্রাসো জাতবেদসঃ ||","e":"From Agni, by our hymns, may we gain all things that bring happiness, Singers of him who knows all life.","mb":"মেধাবীগণ অর্থাৎ আমরা যেন জাতবেদা অগ্নি সম্বন্ধীয় স্তোত্রদ্বারা সমস্ত অভিলষিত ধন লাভ করতে পারি।"},{"n":9,"d":"अग्ने विश्वानि वार्या वाजेषु सनिषामहे | तवे देवास एरिरे ||","b":"অগ্নে বিশ্বানি বার্যা বাজেষু সনিষামহে | তবে দেবাস এরিরে ||","e":"O Agni, in our deeds of might may we obtain all precious things: Tle Gods are centred all in thee.","mb":"হে অগ্নি! আমরা যেন সমস্ত অভিলষণীয় ধন লাভ করতে পারি। দেবগণ তোমাতেই প্রবিষ্ট হয়েছেন।"}]},{"n":12,"t":"Indra-Agni","v":[{"n":1,"d":"इन्द्राग्नी आ गतं सुतं गीर्भिर्नभो वरेण्यम | अस्य पातं धियेषिता ||","b":"ইন্দ্রাগ্নী আ গতং সুতং গীর্ভির্নভো বরেণ্যম | অস্য পাতং ধিযেষিতা ||","e":"MOVED, Indra-Agni, by our hymn, come to the juice, the precious dew: Drink ye thereof, impelled by song.","mb":"হে ইন্দ্রাগ্নি! তোমরা স্তুতিদ্বারা আহুত হয়ে স্বর্গ হতে অভিষুত ও বরণীয় এ সোমের উদ্দেশে এস। আমাদের ভক্তি হেতু আগত হয়ে এ সোম পান কর।"},{"n":2,"d":"इन्द्राग्नी जरितुः सचा यज्ञो जिगाति चेतनः | अया पातमिमं सुतम ||","b":"ইন্দ্রাগ্নী জরিতুঃ সচা যজ্ঞো জিগাতি চেতনঃ | অযা পাতমিমং সুতম ||","e":"O Indra-Agni, with the man who lauds you comes the wakening rite: So drink ye both this juice assured.","mb":"হে ইন্দ্রাগ্নি। স্তোতার সহায়ভূত, যজ্ঞের সাধনভূত, ইন্দ্রিয়ের প্রীতিকর সোম গমন করছে, তোমরা এ অভিষূত সোম পান কর।"},{"n":3,"d":"इन्द्रमग्निं कविछदा यज्ञस्य जूत्या वर्णे | ता सोमस्येह तर्म्पताम ||","b":"ইন্দ্রমগ্নিং কবিছদা যজ্ঞস্য জূত্যা বর্ণে | তা সোমস্যেহ তর্ম্পতাম ||","e":"Through force of sacrifice I choose Indra-Agni who love the wise: With Soma let these sate them here.","mb":"আমি যজ্ঞের সাধনভূত সোম কর্তৃক প্রেরিত হয়ে স্তোতাগণের উপচ্ছন্দক ইন্দ্র ও অগ্নিকে ভজন্য করছি, তারা এ যজ্ঞে সোমপান দ্বারা তৃপ্ত হোন।"},{"n":4,"d":"तोशा वर्त्रहणा हुवे सजित्वानापराजिता | इन्द्राग्नी वाजसातमा ||","b":"তোশা বর্ত্রহণা হুবে সজিত্বানাপরাজিতা | ইন্দ্রাগ্নী বাজসাতমা ||","e":"Indra and Agni I invoke, joint-victors, bounteous, unsubdued, Foe-slayers, best to win the spoil.","mb":"আমি শত্রুনাশক বৃত্রহন্তা, জয়শীল, অপরাজিত ও প্রচুর পরিমাণে অন্নদাতা ইন্দ্রাগ্নিকে আহ্বান করছি।"},{"n":5,"d":"पर वामर्चन्त्युक्थिनो नीथाविदो जरितारः | इन्द्राग्नी इष आ वर्णे ||","b":"পর বামর্চন্ত্যুক্থিনো নীথাবিদো জরিতারঃ | ইন্দ্রাগ্নী ইষ আ বর্ণে ||","e":"Indra and Agni, singers skilled in melody hymn you, bringing lauds: I choose you for the sacred food.","mb":"হে ইন্দ্রাগ্নি। উকথ বিশিষ্ট হোতাগণ তোমাদের অর্চনা করে। স্তোত্রাভিজ্ঞঝ স্তোতাগণ তোমাদের অর্চনা করে। আমি অন্নলাভের জন্য তোমাদের পূজা করছি।"},{"n":6,"d":"इन्द्राग्नी नवतिं पुरो दासपत्नीरधूनुतम | साकमेकेन कर्मणा ||","b":"ইন্দ্রাগ্নী নবতিং পুরো দাসপত্নীরধূনুতম | সাকমেকেন কর্মণা ||","e":"Indra and Agni, ye cast down the ninety forts which Dāsas held, Together, with one mighty deed.","mb":"হে ইন্দ্রাগ্নি। তোমরা এক উদ্যোগ দ্বারাই দাসগণের নবতিসংখ্যক পুরী যুগপৎ কম্পিত করেছিলে।"},{"n":7,"d":"इन्द्राग्नी अपसस पर्युप पर यन्ति धीतयः | रतस्य पथ्या अनु ||","b":"ইন্দ্রাগ্নী অপসস পর্যুপ পর যন্তি ধীতযঃ | রতস্য পথ্যা অনু ||","e":"To Indra-Agni reverent thoughts go forward from the holy task Along the path of sacred Law.","mb":"হে ইন্দ্রাগ্নি। স্তোতাগণ, যজ্ঞের মার্গ লক্ষ্য করে আমাদের কর্মের চতুর্দিকে উপাগত হচ্ছে।"},{"n":8,"d":"इन्द्राग्नी तविषाणि वां सधस्थानि परयांसि च | युवोरप्तूर्यं हितम ||","b":"ইন্দ্রাগ্নী তবিষাণি বাং সধস্থানি পরযাংসি চ | যুবোরপ্তূর্যং হিতম ||","e":"O Indra-Agni, powers are yours, and dwellings and delightful food Good is your readiness to act.","mb":"হে ইন্দ্রাগ্নি। তোমাদের বল ও অন্ন তোমাদের দুজনের মধ্যে অবিযুক্তভাবে আছে এবং বৃষ্টি প্রেরণস্বরূপ কার্য তোমাদের দুজনেতেই নিহিত আছে।"},{"n":9,"d":"इन्द्राग्नी रोचना दिवः परि वाजेषु भूषथः | तद वांचेति पर वीर्यम ||","b":"ইন্দ্রাগ্নী রোচনা দিবঃ পরি বাজেষু ভূষথঃ | তদ বাংচেতি পর বীর্যম ||","e":"Indra and Agni, in your deeds of might ye deck heaven's lucid realms: Famed is that hero strength of yours.","mb":"হে ইন্দ্রাগ্নি! তোমরা স্বর্গের প্রকাশক, তোমরা সংগ্রামে সর্বত্র অলঙ্কৃত হও। তোমাদের সামর্থ্য, সে সংগ্রাম বিজয়কে বিশেষরূপে জ্ঞাপন করছে।"}]},{"n":13,"t":"Agni","v":[{"n":1,"d":"पर वो देवायाग्नये बर्हिष्ठमर्चास्मै | गमद देवेभिरास नो यजिष्ठो बर्हिरा सदत ||","b":"পর বো দেবাযাগ্নযে বর্হিষ্ঠমর্চাস্মৈ | গমদ দেবেভিরাস নো যজিষ্ঠো বর্হিরা সদত ||","e":"To Agni, to this God of yours I sing aloud with utmost power. May he come to us with the Gods, and sit, best Offerer, on the grass.","mb":"হে অধ্বর্যুগণ। অগ্নিদেবের উদ্দেশে প্রভূত স্তুতি উচ্চারণ কর, তিনি দেবগণের সাথে আমাদের নিকটে আসুন এবং যাজকশ্রেষ্ঠ অগ্নি কুশে উপবেশন করুন।"},{"n":2,"d":"रतावा यस्य रोदसी दक्षं सचन्त ऊतयः | हविष्मन्तस्तमीळते तं सनिष्यन्तो.अवसे ||","b":"রতাবা যস্য রোদসী দক্ষং সচন্ত ঊতযঃ | হবিষ্মন্তস্তমীলতে তং সনিষ্যন্তো.অবসে ||","e":"The Holy, whose are earth and heaven, and succour waits upon his strength; Him men who bring oblations laud, and they who wish to gain, for grace.","mb":"দ্যাবাপৃথিবী যার অধীন, দেবগণ যার বল সেবা করে, তার সংকল্প ব্যর্থ হয় না। হব্যবিশিষ্ট যজমানগণ ধনলাভে অভিলাষী হয়ে রক্ষার জন্য তাকে স্তুতি করে।"},{"n":3,"d":"स यन्ता विप्र एषां स यज्ञानामथा हि षः | अग्निं तं वो दुवस्यत दाता यो वनिता मघम ||","b":"স যন্তা বিপ্র এষাং স যজ্ঞানামথা হি ষঃ | অগ্নিং তং বো দুবস্যত দাতা যো বনিতা মঘম ||","e":"He is the Sage who guides these men, Leader of sacred rites is he. Him your own Agni, serve ye well, who winneth and bestoweth wealth.","mb":"মেধাবী সে অগ্নি এ সকল যজমানের প্রবর্তক, তিনি যজ্ঞের প্রবর্তক এবং সকলের প্রবর্তক, অগ্নি কর্মফল দাতা ও ধনদাতা; তোমরা সে অগ্নির পরিচর্যা কর।"},{"n":4,"d":"स नः शर्माणि वीतये.अग्निर्यछतु शन्तमा | यतो नःप्रुष्णवद वसु दिवि कषितिभ्यो अप्स्वा ||","b":"স নঃ শর্মাণি বীতযে.অগ্নির্যছতু শন্তমা | যতো নঃপ্রুষ্ণবদ বসু দিবি কষিতিভ্যো অপ্স্বা ||","e":"So may the gracious Agni grant most goodly shelter for our use; Whence in the heavens or in the floods he shall pour wealth upon our lands.","mb":"সে অগ্নি আমাদের ভোগের জন্য অতিশয় সুখকর গৃহ প্রদান করুন। সমুদ্ধিবিশিষ্ট, পৃথিবী আকাশ ও স্বর্গলোকের ধন অগ্নির নিকট হতে আমাদের নিকট আসে।"},{"n":5,"d":"दीदिवांसमपूर्व्यं वस्वीभिरस्य धीतिभिः | रक्वाणो अग्निमिन्धते होतारं विश्पतिं विशाम ||","b":"দীদিবাংসমপূর্ব্যং বস্বীভিরস্য ধীতিভিঃ | রক্বাণো অগ্নিমিন্ধতে হোতারং বিশ্পতিং বিশাম ||","e":"The singers kindle him, the Priest, Agni the Lord of tribes of men, Resplendent and without a peer through his own excellent designs.","mb":"স্তোতাগণ দীপ্তিমান, প্রতিক্ষণে নুতন, দেবগণের আহ্বানকারী ও প্রজাগণের পালক অগ্নিকে প্রশস্ত স্তুতিদ্বারা উদ্দীপিত করছে।"},{"n":6,"d":"उत नो बरह्मन्नविष उक्थेषु देवहूतमः | शं नः शोचामरुद्व्र्धो.अग्ने सहस्रसातमः ||","b":"উত নো বরহ্মন্নবিষ উক্থেষু দেবহূতমঃ | শং নঃ শোচামরুদ্ব্র্ধো.অগ্নে সহস্রসাতমঃ ||","e":"Help us, thou Brahman, best of all invokers of the Gods in song. Beam, Friend of Maruts, bliss on us, O Agni, a most liberal God.","mb":"হে অগ্নি। স্তোত্রকালে আমাদের রক্ষা কর। তুমি দেবগণের প্রধান আহ্বানকার, তুমি উকথ কালে আমাদের রক্ষা কর। তুমি সহস্র ধন দাতা, মরুৎগণ তোমাকে বর্ধিত করে, তুমি আমাদের সুখবৃদ্ধি কর।"},{"n":7,"d":"नू नो रास्व सहस्रवत तोकवत पुष्टिमद वसु | दयुमदग्ने सुवीर्यं वर्षिष्थमनुपक्षितम ||","b":"নূ নো রাস্ব সহস্রবত তোকবত পুষ্টিমদ বসু | দযুমদগ্নে সুবীর্যং বর্ষিষ্থমনুপক্ষিতম ||","e":"Yea, grant us treasure thousandfold with children and with nourishment, And, Agni, splendid hero strength, exalted, wasting not away.","mb":"হে অগ্নি। তুমি আমাদের পুত্রবিশিষ্ট, পুষ্টিকারক, দীপ্তিমান, সামর্থ্যবিশিষ্ট, অতিপ্রভূত ও অক্ষম সহস্র সংখ্যক ধন দান কর।"}]},{"n":14,"t":"Agni","v":[{"n":1,"d":"आ होता मन्द्रो विदथान्यस्थात सत्यो यज्वा कवितमः सवेधाः | विद्युद्रथः सहसस पुत्रो अग्निः शोचिष्केशः पर्थिव्यां पाजो अश्रेत ||","b":"আ হোতা মন্দ্রো বিদথান্যস্থাত সত্যো যজ্বা কবিতমঃ সবেধাঃ | বিদ্যুদ্রথঃ সহসস পুত্রো অগ্নিঃ শোচিষ্কেশঃ পর্থিব্যাং পাজো অশ্রেত ||","e":"THE pleasant Priest is come into the synod, true, skilled in sacrifice, most wise, Ordainer. Agni, the Son of Strength, whose car is lightning, whose hair is flame, hath shown on earth his lustre.","mb":"দেবগণের আহ্বানকারী, স্তোতৃগণের আনন্দবর্ধক, সত্যপ্রতিজ্ঞ, যজ্ঞকারী, অত্যন্ত মেধাবী ও জগতের বিধাতা অগ্নি আমাদের যজ্ঞে অবস্থিত করেন। তার রথ দ্যুতিমান, শিখা তার কেশ, তিনি বলের পুত্র, তিনি পৃথিবীতে প্রভা বিকাশ করেন।"},{"n":2,"d":"अयामि ते नमौक्तिं जुषस्व रतावस्तुभ्यं चेतते सहस्वः | विद्वाना वक्षि विदुषो नि षत्सि मध्य आ बर्हिरूतये यजत्र ||","b":"অযামি তে নমৌক্তিং জুষস্ব রতাবস্তুভ্যং চেততে সহস্বঃ | বিদ্বানা বক্ষি বিদুষো নি ষত্সি মধ্য আ বর্হিরূতযে যজত্র ||","e":"To thee I offer reverent speech: accept it: to thee who markest it, victorious, faithful! Bring, thou who knowest, those who know, and seat thee amid the sacred grass, for help, O Holy.","mb":"হে যজ্ঞবান অগ্নি। তোমার উদ্দেশে নমস্কার বাক্য উচ্চারণ করি, তুমি বলবান এবং কর্মপ্রজ্ঞাপক, তোমার উদ্দেশে নমস্কার বাক্য উচ্চারিত হচ্ছে, তুমি গ্রহণ কর। হে যজনীয়। তুমি বিদ্বান, বিদ্বানগণকে আন, আমাদের আশ্রয়দানের জন্য কুশমধ্যে উপবেশন কর।"},{"n":3,"d":"दरवतां त उषसा वाजयन्ती अग्ने वातस्य पथ्याभिरछ | यत सीमञ्जन्ति पूर्व्यं हविर्भिरा वन्धुरेव तस्थतुर्दुरोणे ||","b":"দরবতাং ত উষসা বাজযন্তী অগ্নে বাতস্য পথ্যাভিরছ | যত সীমঞ্জন্তি পূর্ব্যং হবির্ভিরা বন্ধুরেব তস্থতুর্দুরোণে ||","e":"The Two who show their vigour, Night and Morning, by the wind's paths shall haste to thee O Agni. When men adorn the Ancient with oblations, these seek, as on two chariot-seats, the dwelling.","mb":"অন্নসম্পাদিকা উষাদ্বয় (১), তোমার উদ্দেশে অভিগমন করছে। হে অগ্নি। তুমি বায়ুর পথে তাদের অভিমুখে যাও, যেহেতু, ঋত্বিকগণ পুরাতন অগ্নিকে হব্যদ্বারা সর্বতোভাবে সিক্ত করে যুগদ্বয়ের ন্যায় (পরস্পর সংসক্ত ঊষা ও নক্ত) আমাদের গৃহে বারবার এসে অবস্থিতি করুক।"},{"n":4,"d":"मित्रश्च तुभ्यं वरुणः सहस्वो.अग्ने विश्वे मरुतः सुम्नमर्चन | यच्छोचिषा सहसस पुत्र तिष्ठा अभि कषितीः परथयन सूर्यो नॄन ||","b":"মিত্রশ্চ তুভ্যং বরুণঃ সহস্বো.অগ্নে বিশ্বে মরুতঃ সুম্নমর্চন | যচ্ছোচিষা সহসস পুত্র তিষ্ঠা অভি কষিতীঃ পরথযন সূর্যো নৄন ||","e":"To thee, strong Agni! Varuṇa and Mitra and all the Maruts sang a song of triumph, What time unto the people's lands thou camest, spreading them as the Sun of men, with lustre.","mb":"হে বলবান অগ্নি! মিত্র, বরুণ ও সমস্ত দেবগণ তোমার উদ্দেশে স্তোত্র উচ্চারণ করছে। যেহেতু হে বলের পুত্র অগ্নি। তুমিই সূর্য, তুমি মানুষদের পথপ্রদর্শকস্বরূপ আপন রশ্মিসকল বিস্তার করে দীপ্তিতে সমান হয়ে আছ।"},{"n":5,"d":"वयं ते अद्य ररिमा हि काममुत्तानहस्ता नमसोपसद्य | यजिष्ठेन मनसा यक्षि देवानस्रेधता मन्मना विप्रो अग्ने ||","b":"বযং তে অদ্য ররিমা হি কামমুত্তানহস্তা নমসোপসদ্য | যজিষ্ঠেন মনসা যক্ষি দেবানস্রেধতা মন্মনা বিপ্রো অগ্নে ||","e":"Approaching with raised hands and adoration, we have this day fulfilled for thee thy longing. Worship the Gods with most devoted spirit, a Priest with no unfriendly thought, O Agni.","mb":"হে অগ্নি! আমরা হস্ত উত্তোলন করে অদ্য তোমায় কমনীয় হব্য প্রদান করব। তুমি মেধাবী, তুমি নমস্কারে প্রসন্ন হয়ে নে মনে যাগাভিলাষে, প্রভূত স্তোত্রদ্বারা দেবগণের পূজা কর।"},{"n":6,"d":"तवद धि पुत्र सहसो वि पूर्वीर्देवस्य यन्त्यूतयो वि वाजाः | तवं देहि सहस्रिणं रयिं नो.अद्रोघेण वचसा सत्यमग्ने ||","b":"তবদ ধি পুত্র সহসো বি পূর্বীর্দেবস্য যন্ত্যূতযো বি বাজাঃ | তবং দেহি সহস্রিণং রযিং নো.অদ্রোঘেণ বচসা সত্যমগ্নে ||","e":"For, Son of Strength, from thee come many succours, and powers abundant that a God possesses. Agni, to us with speech that hath no falsehood grant riches, real, to be told in thousands.","mb":"হে বলের পুত্র অগ্নি! তোমার নিকট হতে প্রভূত রক্ষা যজমানের নিকট যাচ্ছে, অন্নও যাচ্ছে। তুমি আমাদের প্রিয় বচনদ্বারা অচল, সহস্য সংখ্যক ধন দান কর।"},{"n":7,"d":"तुभ्यं दक्ष कविक्रतो यानीमा देव मर्तासो अध्वरे अकर्म | तवं विश्वस्य सुरथस्य बोधि सर्वं तदग्ने अम्र्त सवदेह ||","b":"তুভ্যং দক্ষ কবিক্রতো যানীমা দেব মর্তাসো অধ্বরে অকর্ম | তবং বিশ্বস্য সুরথস্য বোধি সর্বং তদগ্নে অম্র্ত সবদেহ ||","e":"Whatever, God, in sacrifice we mortals have wrought is all for thee, strong, wise of purpose! Be thou the Friend of each good chariot's master. All this enjoy thou here, immortal Agni.","mb":"হে সামর্থ্যবিশিষ্ট, সর্বজ্ঞ, দীপ্তিমান অগ্নি। আমরা মর্ত্য, আমরা তোমার উদ্দেশে যজ্ঞে এ যে হব্য ত্যাগ করছি, হে অমর! তুমি সমস্ত যজমানকে রক্ষা করবার জন্য জাগরিত হও এবং সমস্ত হব্য আস্বাদন কর।"}]},{"n":15,"t":"Agni","v":[{"n":1,"d":"वि पाजसा पर्थुना शोशुचानो बाधस्व दविषो रक्षसो अमीवाः | सुशर्मणो बर्हतः शर्मणि सयामग्नेरहं सुहवस्य परणीतौ ||","b":"বি পাজসা পর্থুনা শোশুচানো বাধস্ব দবিষো রক্ষসো অমীবাঃ | সুশর্মণো বর্হতঃ শর্মণি সযামগ্নেরহং সুহবস্য পরণীতৌ ||","e":"RESPLENDENT with thy wide-extending lustre, dispel the terrors of the fiends who hate us May lofty Agni be my guide and shelter, the easily-invoked, the good Protector.","mb":"হে অগ্নি! তুমি বিস্তীর্ণ তেজদ্বারা অত্যন্ত দীপ্তিমান, তুমি শত্রুদের এবং রোগরহিত রাক্ষসদের বিনাশ কর। অগ্নি উৎকৃষ্ট, সুখপ্রদ, মহান এবং উত্তম আহ্বানযুক্ত। আমি তারই রক্ষণে থাকব।"},{"n":2,"d":"तवं नो अस्या उषसो वयुष्टौ तवं सूर उदिते बोधि गोपाः | जन्मेव नित्यं तनयं जुषस्व सतोमं मे अग्ने तन्वा सुजात ||","b":"তবং নো অস্যা উষসো বযুষ্টৌ তবং সূর উদিতে বোধি গোপাঃ | জন্মেব নিত্যং তনযং জুষস্ব সতোমং মে অগ্নে তন্বা সুজাত ||","e":"Be thou To us, while now the morn is breaking, be thou a guardian when the Sun hath mounted.. Accept, as men accept a true-born infant, my laud, O Agni nobly born in body.","mb":"হে অগ্নি! তুমি, এ ঊষা প্রকাশিত হলে এবং সূর্য উদিত হলে, আমাদের রক্ষকভাবে জাগরিত হও। শরীরে সাথে সুজাত হয়েছ; পিতা যেরূপ পুত্রকে গ্রহণ করে, সেরূপ তুমি আমাদের স্তোত্র গ্রহণ কর।"},{"n":3,"d":"तवं नर्चक्षा वर्षभानु पूर्वीः कर्ष्णास्वग्ने अरुषो विभाहि | वसो नेषि च पर्षि चात्यंहः कर्धी नो राय उशिजो यविष्ठ ||","b":"তবং নর্চক্ষা বর্ষভানু পূর্বীঃ কর্ষ্ণাস্বগ্নে অরুষো বিভাহি | বসো নেষি চ পর্ষি চাত্যংহঃ কর্ধী নো রায উশিজো যবিষ্ঠ ||","e":"Bull, who beholdest men, through many mornings, among the dark ones shine forth red, O Agni. Lead us, good Lord, and bear us over trouble: Help us who long, Most Youthful God, to riches.","mb":"হে অভীষ্টবর্ষী অগ্নি! তুমি মানুষদের দর্শনকারী, তুমি অন্ধকার রাত্রে অধিকতর দীপ্তিমান। তুমি বহুতর জ্বালা বিস্তার কর। হে নিরাসয়িতা! আমাদের কর্ম ফল প্রদান কর, আমাদের পাপ নিবারণ কর। হে যুবা অগ্নি! তুমি আমাদের ধনাভিলাষী কর।"},{"n":4,"d":"अषाळ्हो अग्ने वर्षभो दिदीहि पुरो विश्वाः सौभगा संजिगीवान | यज्ञस्य नेता परथमस्य पायोर्जातवेदो बर्हतः सुप्रणीते ||","b":"অষাল্হো অগ্নে বর্ষভো দিদীহি পুরো বিশ্বাঃ সৌভগা সংজিগীবান | যজ্ঞস্য নেতা পরথমস্য পাযোর্জাতবেদো বর্হতঃ সুপ্রণীতে ||","e":"Shine forth, a Bull invincible, O Agni, winning by conquest all the forts and treasures, Thou Jātavedas who art skilled in guiding, the chief high saving sacrifice's Leader.","mb":"হে অগ্নি! শত্রুরা তোমাকে পরাজিত করতে পারে না, তুমি অভীষ্টবর্ষী, তুমি সমস্ত শত্রুপুরী ও ধন জয় করে প্রদীপ্ত হও। হে সুপ্রণীত, জাতবেদা অগ্নি! তুমি মহান আশ্রয় প্রদ ও প্রথম যজ্ঞের নির্বাহক হও।"},{"n":5,"d":"अछिद्रा शर्म जरितः पुरूणि देवानछा दीद्यानः सुमेधाः | रथो न सस्निरभि वक्षि वाजमगने तवं रोदसीनः सुमेके ||","b":"অছিদ্রা শর্ম জরিতঃ পুরূণি দেবানছা দীদ্যানঃ সুমেধাঃ | রথো ন সস্নিরভি বক্ষি বাজমগনে তবং রোদসীনঃ সুমেকে ||","e":"Lighting Gods hither, Agni, wisest Singer, bring thou to us many and flawless shelters. Bring vigour, like a car that gathers booty: bring us, O Agni, beauteous Earth and Heaven.","mb":"হে জগৎ জীর্ণকারী অগ্নি! তুমি সুমেধা ও দীপ্তিমান। তুমি দেবগণের জন্য সমস্ত কর্ম অচ্ছিদ্র কর। হে অগ্নি! তুমি এখানেই নিরুদ্ধ থেকে রথের ন্রায় দেবগণের উদ্দেশে আমাদরে হব্য বহন কর। তুমি এ দ্যাবাপৃথিবকে উত্তরমরূপবিশিষ্ট কর।"},{"n":6,"d":"पर पीपय वर्षभ जिन्व वाजानग्ने तवं रोदसी नः सुदोघे | देवेभिर्देव सुरुचा रुचानो मा नो मर्तस्य दुर्मतिः परि षठात ||","b":"পর পীপয বর্ষভ জিন্ব বাজানগ্নে তবং রোদসী নঃ সুদোঘে | দেবেভির্দেব সুরুচা রুচানো মা নো মর্তস্য দুর্মতিঃ পরি ষঠাত ||","e":"Swell, O thou Bull and give those powers an impulse, e’en Earth and Heaven who yield their milk in plenty, Shining, O God, with Gods in clear effulgence. Let not a mortal's evil will obstruct us.","mb":"হে অভীষ্টবর্ষী অগ্নি! তুমি আমাদের বর্ধিতকর, আমাদের অন্ন প্রদান কর। হে দেব! সুন্দর দীপ্তি দ্বারা শোভমান হয়ে দেবগণের সঙ্গে আমাদরে এ দ্যাবাপৃথিবীকে দোহন যোগ্য কর। মর্ত্যগণের দুর্মতি যেন আমাদরে নিকট আসতে না পারে।"},{"n":7,"d":"इळामग्ने ... ||","b":"ইলামগ্নে ... ||","e":"Agni, as holy food to thine invoker, give wealth in cattle, lasting, rich in marvels. To us be born a son and spreading offspring. Agni, be this thy gracious will to us-ward.","mb":"হে অগ্নি! তুমি স্তোতাকে বহুকর্মের হেতুভূত ও ধেনুপ্রদাত্রী ভূমি চিরকাল প্রদান কর। আমাদের বংশ বিস্তারকারী এবং সন্তুতি জনয়িতা একটি পুত্র হোক। হে অগ্নি! আমাদের প্রতি তোমার অনুগ্রহ হোক।"}]},{"n":16,"t":"Agni","v":[{"n":1,"d":"अयमग्निः सुवीर्यस्येशे महः सौभगस्य | राय ईशे सवपत्यस्य गोमत ईशे वर्त्रहथानाम ||","b":"অযমগ্নিঃ সুবীর্যস্যেশে মহঃ সৌভগস্য | রায ঈশে সবপত্যস্য গোমত ঈশে বর্ত্রহথানাম ||","e":"THIS Agni is the Lord of great felicity and hero Strength; Lord of wealth in herds of kine; Lord of the battles with the foe.","mb":"এ অগ্নি উৎকৃষ্ট সামর্থ্যবিশিষ্ট; মহাসৌভাগ্যের ঈশ্বর, গবাদিবিষ্টি ও অপত্যবিশিষ্ট ধনের ঈশ্বর এবং বৃত্রহন্তাদের ঈশ্বর।"},{"n":2,"d":"इमं नरो मरुतः सश्चता वर्धं यस्मिन रायः शेव्र्धासः | अभि ये सन्ति पर्तनासु दूढ्यो विश्वाहा शत्रुमादभुः ||","b":"ইমং নরো মরুতঃ সশ্চতা বর্ধং যস্মিন রাযঃ শেব্র্ধাসঃ | অভি যে সন্তি পর্তনাসু দূঢ্যো বিশ্বাহা শত্রুমাদভুঃ ||","e":"Wait, Maruts, Heroes, upon him the Prosperer in whom is bliss-increasing wealth; Who in fights ever conquer evil-hearted men, who overcome the enemy.","mb":"হে নেতা মরুৎগণ! তোমরা সৌভাগ্য বর্ধক অগ্নির সাথে মিলিত হও, অগ্নিতে সুখবর্ধক ধন আছে। মরুৎগণ নোবিশিষ্ট সংগ্রামে শত্রুদের অভিভব করেন ও সর্বদাই শত্রুদের হিংসা করেন।"},{"n":3,"d":"स तवं नो रायः शिशीहि मीढ्वो अग्ने सुविर्यस्य | तुविद्युम्न वर्षिष्ठस्य परजावतो.अनमीवस्य शुष्मिणः ||","b":"স তবং নো রাযঃ শিশীহি মীঢ্বো অগ্নে সুবির্যস্য | তুবিদ্যুম্ন বর্ষিষ্ঠস্য পরজাবতো.অনমীবস্য শুষ্মিণঃ ||","e":"As such, O Agni, deal us wealth and hero might, O Bounteous One! Most lofty, very glorious, rich in progeny, free from disease and full of power.","mb":"হে বহু ধনযুক্ত অভীষ্টবর্ষী অগ্নি! তুমি আমাদ রপ্রভূত প্রজা বিশিষ্ট, আরোগ্য বল ও সামর্থ্যের হেতুভূত, ধন দান করে তীক্ষ্ম কর।"},{"n":4,"d":"चक्रिर्यो विश्वा भुवनाभि सासहिश्चक्रिर्देवेष्वा दुवः | आ देवेषु यतत आ सुवीर्य आ शंस उत नर्णाम ||","b":"চক্রির্যো বিশ্বা ভুবনাভি সাসহিশ্চক্রির্দেবেষ্বা দুবঃ | আ দেবেষু যতত আ সুবীর্য আ শংস উত নর্ণাম ||","e":"He who made all that lives, who passes all in might, who orders service to the Gods, He works among the Gods, he works in hero strength, yea, also in the praise of men.","mb":"যে অগ্নি জগতের কর্তা, তিনি সমস্ত ভূবনে অনুপ্রবিষ্ট হচ্ছেন। কতৃা অগ্নি ভার সহ্য করে দেবগণের নিকট হব্য আনছেন। অগ্নি স্তোতৃগণের অভিমুখে আসছেন, যজ্ঞনেতাগণের স্তোত্রে এবং মনুষ্যগণের যুদ্ধে আসছেন।"},{"n":5,"d":"मा नो अग्ने.अमतये मावीरतायै रीरधः | मागोतायै सहसस पुत्र मा निदे.अप दवेषांस्या कर्धि ||","b":"মা নো অগ্নে.অমতযে মাবীরতাযৈ রীরধঃ | মাগোতাযৈ সহসস পুত্র মা নিদে.অপ দবেষাংস্যা কর্ধি ||","e":"Give us not up to indigence, Agni, nor want of hero sons, Nor, Son of Strength, to lack of cattle, nor to blame. Drive. thou our enemies away.","mb":"হে বলের পুত্র অগ্নি! তুমি আমাদের শত্রুগ্রস্ত বা বীরশূন্য বা পশুহীন বা নিন্দার্হ করো না। আমাদের প্রতি দ্বেষ ত্যাগ কর।"},{"n":6,"d":"शग्धि वाजस्य सुभग परजावतो.अग्ने बर्हतो अध्वरे | संराया भूयसा सर्ज मयोभुना तुविद्युम्न यशस्वता ||","b":"শগ্ধি বাজস্য সুভগ পরজাবতো.অগ্নে বর্হতো অধ্বরে | সংরাযা ভূযসা সর্জ মযোভুনা তুবিদ্যুম্ন যশস্বতা ||","e":"Help us to strength, blest Agni! rich in progeny, abundant, in our sacrifice. Flood us with riches yet more plenteous, bringing weal, with high renown, most Glorious One!","mb":"সে সুভগ অগ্নি! তুমি জ্ঞে প্রভূত, অপত্যবিশিষ্ট অন্নের ঈশ্বর। হে মহাধন! তুমি আমাদরে প্রভূত, সুখকর, যশস্কর ধন দান কর।"}]},{"n":17,"t":"Agni","v":[{"n":1,"d":"समिध्यमानः परथमानु धर्मा समक्तुभिरज्यते विश्ववारः | शोचिष्केशो घर्तनिर्णिक पावकः सुयज्ञो अग्निर्यजथाय देवान ||","b":"সমিধ্যমানঃ পরথমানু ধর্মা সমক্তুভিরজ্যতে বিশ্ববারঃ | শোচিষ্কেশো ঘর্তনির্ণিক পাবকঃ সুযজ্ঞো অগ্নির্যজথায দেবান ||","e":"DULY enkindled after ancient customs, bringing all treasures, he is balmed with unguents,— Flame-haired, oil-clad, the purifying Agni, skilled in fair rites, to bring the Gods for worship.","mb":"অগ্নি ধর্মধারক, জ্বালারূপ কেশবিশিষ্ট, সকলের বরণয় দীপ্তিরূপ, পাবক ও সুক্রতু। তিনি যজ্ঞের আরম্ভে ক্রমে প্রজ্বলিত হয়ে দেবগণের যজ্ঞের জন্য ঘৃতাদিদ্বারা সিক্ত হচ্ছেন।"},{"n":2,"d":"यथायजो होत्रमग्ने पर्थिव्या यथा दिवो जातवेदश्चिकित्वान | एवानेन हविषा यक्षि देवान मनुष्वद यज्ञं पर तिरेममद्य ||","b":"যথাযজো হোত্রমগ্নে পর্থিব্যা যথা দিবো জাতবেদশ্চিকিত্বান | এবানেন হবিষা যক্ষি দেবান মনুষ্বদ যজ্ঞং পর তিরেমমদ্য ||","e":"As thou, O Agni, skilful Jātavedas, hast sacrificed as Priest of Earth, of Heaven, So with this offering bring the Gods, and prosper this sacrifice today as erst for Manu.","mb":"হে অগ্নি! তুমি পৃথিবীর হব্য যেমন প্রদান করেছিলে, হে জাতবেদা! তুমি সর্বজ্ঞ, তুমি দ্যুলোকের হব্য যেমন প্রদান করেছিলে, সেরূপ আমাদের হব্যদ্বারা দেবগণকে যাগ কর। মনুর যজ্ঞের ন্রায় অদ্য আমাদের এ যজ্ঞ পূর্ণ কর।"},{"n":3,"d":"तरीण्यायूंषि तव जातवेदस्तिस्र आजानीरुषसस्ते अग्ने | ताभिर्देवानामवो यक्षि विद्वानथा भव यजमानाय शं योः ||","b":"তরীণ্যাযূংষি তব জাতবেদস্তিস্র আজানীরুষসস্তে অগ্নে | তাভির্দেবানামবো যক্ষি বিদ্বানথা ভব যজমানায শং যোঃ ||","e":"Three are thy times of life, O Jātavedas, and the three mornings are thy births, O Agni. With these, well-knowing, grant the Gods’ kind favour, and help in stir and stress the man who worships.","mb":"হে জাতবেদা! তোমার অন্ন তিন প্রকার। হে অগ্নি! তিন উষা (১) তোমার মাতা। তুমি তাদের সাথে দেবগণকে হব্য দান কর। তুমি বিদ্বান, তুমি যজমানের সুখহেতু ও কল্রাণহেতু হও।"},{"n":4,"d":"अग्निं सुदीतिं सुद्र्शं गर्णन्तो नमस्यामस्त्वेड्यं जातवेदः | तवां दूतमरतिं हव्यवाहं देवा अक्र्ण्वन्नम्र्तस्य नाभिम ||","b":"অগ্নিং সুদীতিং সুদ্র্শং গর্ণন্তো নমস্যামস্ত্বেড্যং জাতবেদঃ | তবাং দূতমরতিং হব্যবাহং দেবা অক্র্ণ্বন্নম্র্তস্য নাভিম ||","e":"Agni most bright and fair with song we honour, yea, the adorable, O Jātavedas. Thee, envoy, messenger, oblation-bearer, the Gods have made centre of life eternal.","mb":"হে জাতবেদা! তুমি দীপ্তিবিশিষ্ট,  সুদর্শন ও স্তুতিযোগ্য অগ্নি, আমরা তোমাকে নমস্কার করি। দেবগণ তোমাকে আসক্তিশূন্য হব্যবাহক দূত করেছেন, অমৃতের নাভি করেছেন,"},{"n":5,"d":"यस्त्वद धोता पूर्वो अग्ने यजीयान दविता च सत्ता सवधया च शम्भुः तस्यानु धर्म पर यजा चिकित्वो.अथ नो धा अध्वरं देववीतौ ||","b":"যস্ত্বদ ধোতা পূর্বো অগ্নে যজীযান দবিতা চ সত্তা সবধযা চ শম্ভুঃ তস্যানু ধর্ম পর যজা চিকিত্বো.অথ নো ধা অধ্বরং দেববীতৌ ||","e":"That Priest before thee, yet more skilled in worship, stablished of old, health-giver by his nature,— After his custom offer, thou who knowest, and lay our sacrifice where Gods may taste it.","mb":"হে অগ্নি! তোমা হতেও পূর্বকালবতৃী ও অধিক যাগকারী যে হোতা মধ্যম ও উত্তম এ দুটি স্থানে  স্বধার সাথে উপবিষ্ট হয়ে সুখকারী হয়েছিলেন; হে সর্বজ্ঞ অগ্নি! তার দর্মকে লক্ষ্য করে বিশেষরূপে যাগ কর। অনন্তর, হে অগ্নি! দেবগণের প্রিতির জন্য আমাদের এ যজ্ঞ ধারণ কর।"}]},{"n":18,"t":"Agni","v":[{"n":1,"d":"भवा नो अग्ने सुमना उपेतौ सखेव सख्ये पितरेव साधुः | पुरुद्रुहो हि कषितयो जनानां परति परतीचीर्दहतादरातीः ||","b":"ভবা নো অগ্নে সুমনা উপেতৌ সখেব সখ্যে পিতরেব সাধুঃ | পুরুদ্রুহো হি কষিতযো জনানাং পরতি পরতীচীর্দহতাদরাতীঃ ||","e":"AGNI, be kind to us when we approach thee good as a friend to friend, as sire and mother. The races of mankind are great oppressors burn up malignity that strives against us.","mb":"হে অগ্নি! আমাদের অভিমুখে আগমন বিষয়ে অনুকুল হয়ে সখা যেরূপ সখার প্রতি ও পিতামাতা যেরূপ পুত্রের প্রতি হিতকারী হয়, সেরূপ হিতকারী হও। মনুষ্যগণ মনুষ্যের দ্রোহকারী, অতএব তুমি প্রতিকুলাচারী শত্রুদের ভস্মসাৎ কর।"},{"n":2,"d":"तपो शवग्ने अन्तरानमित्रान तपा शंसमररुषः परस्य | तपो वसो चिकितानो अचित्तान वि ते तिष्ठन्तामजरा अयासः ||","b":"তপো শবগ্নে অন্তরানমিত্রান তপা শংসমররুষঃ পরস্য | তপো বসো চিকিতানো অচিত্তান বি তে তিষ্ঠন্তামজরা অযাসঃ ||","e":"Agni, burn up the unfriendly who are near us, burn thou the foeman's curse who pays no worship. Burn, Vasu, thou who markest well, the foolish: let thine eternal nimble beams surround thee.","mb":"হে অগ্নি! অভিভবকারী শত্রুদের উত্তমরূপে বাধা দাও, যে সকল শত্রু হব্য দান করে না তাদরে অভিলাষ ব্যর্থ কর। হে নিবাসপ্রদ, সর্বজ্ঞ অগ্নি! তুমি অস্থিরচিত্ত লোকদের সন্তপ্ত কর; অতএব তোমার রশ্মিসকল  জরারহিত ও প্রতিবন্ধকর হত হোক।"},{"n":3,"d":"इध्मेनाग्न इछमानो घर्तेन जुहोमि हव्यं तरसे बलाय | यावदीशे बरह्मणा वन्दमान इमां धियं शतसेयाय देवीम ||","b":"ইধ্মেনাগ্ন ইছমানো ঘর্তেন জুহোমি হব্যং তরসে বলায | যাবদীশে বরহ্মণা বন্দমান ইমাং ধিযং শতসেযায দেবীম ||","e":"With fuel, Agni, and with oil, desirous, mine offering I present for strength and conquest, With prayer, so far as I have power, adoring-this hymn divine to gain a hundred treasures.","mb":"হে অগ্নি! আমি ধনাভিলাষী হয়ে তোমার বেগ ও বলের জন্য সমিধ ও ঘৃতের সাথে হব্য প্রদান করি। স্তোত্রদ্বারা তোমার স্তব করে আমি যতক্ষণ বইতে পারি, ততক্ষণ ধন দাও। তুমি এ স্তুতিকে অপরিমিত ধন দানের জন্য দীপ্ত কর।"},{"n":4,"d":"उच्छोचिषा सहसस पुत्र सतुतो बर्हद वयः शशमानेषु धेहि | रेवदग्ने विश्वामित्रेषु शं योर्मर्म्र्ज्मा ते तन्वं भूरि कर्त्वः ||","b":"উচ্ছোচিষা সহসস পুত্র সতুতো বর্হদ বযঃ শশমানেষু ধেহি | রেবদগ্নে বিশ্বামিত্রেষু শং যোর্মর্ম্র্জ্মা তে তন্বং ভূরি কর্ত্বঃ ||","e":"Give with thy glow, thou Son of Strength, when lauded, great vital power to those who toil to serve thee. Give richly, Agni, to the Viśvāmitras in rest and stir. Oft have we decked thy body.","mb":"হে বলের পুত্র অগ্নি! তুমি আপনার দীপ্তিতে দীপ্তিমান হও, তুমি স্তুত হয়ে প্রশংসাকারী বিশ্বামিত্র বংশীয়গণকে ধনযুক্ত কর, প্রভূত অন্ন প্রদান কর এবং আরোগ্য ও অভয় প্রদান কর। হে কর্মকর্তা! তোমার শরীর আমরা বারবার মার্জনা করব।"},{"n":5,"d":"कर्धि रत्नं सुसनितर्धनानां स घेदग्ने भवसि यत समिद्धः | सतोतुर्दुरोणे सुभगस्य रेवत सर्प्रा करस्ना दधिषे वपूंषि ||","b":"কর্ধি রত্নং সুসনিতর্ধনানাং স ঘেদগ্নে ভবসি যত সমিদ্ধঃ | সতোতুর্দুরোণে সুভগস্য রেবত সর্প্রা করস্না দধিষে বপূংষি ||","e":"Give us, O liberal Lord, great store of riches, for, Agni, such art thou when duly kindled. Thou in the happy singer's home bestowest, amply with arms extended, things of beauty.","mb":"হে দাতা অগ্নি! তুমি ধনের মধ্যে উৎকৃষ্ট ধন প্রদান কর, তুমি যখন সমিদ্ধ হও তখনই সেরূপ ধন দাতা হও। তুমি ভাগ্যবান স্তোতার গৃহের দিকে তোমার রুপবৎ বাহুদ্বয় ধন প্রদানার্থে প্রসৃত কর।"}]},{"n":19,"t":"Agni","v":[{"n":1,"d":"अग्निं होतारं पर वर्णे मियेधे गर्त्सं कविं विश्वविदममूरम | स नो यक्षद देवताता यजीयान राये वाजाय वनतेमघानि ||","b":"অগ্নিং হোতারং পর বর্ণে মিযেধে গর্ত্সং কবিং বিশ্ববিদমমূরম | স নো যক্ষদ দেবতাতা যজীযান রাযে বাজায বনতেমঘানি ||","e":"AGNI, quick, sage, infallible, all-knowing, I choose to be our Priest at this oblation. In our Gods’ service he, best skilled, shall worship: may he obtain us boons for strength and riches.","mb":"দেবগণের স্ততিকারী, মেধাবী, সর্বজ্ঞঝ, অমূঢ় অগ্নিকে এ যজ্ঞে হোতারূপে  বরণ করছি। সে অগ্নি সর্বাপেক্ষা অধিক যাগশীল হয়ে আমাদের জন্য দেবগণের যাগ করুন। তিনি ধন ও অন্নের জন্য আমাদের হব্য গ্রহণ করুন।"},{"n":2,"d":"पर ते अग्ने हविष्मतीमियर्म्यछा सुद्युम्नां रातिनीं घर्ताचीम | परदक्षिणिद देवतातिमुराणः सं रातिभिर्वसुभिर्यज्ञमश्रेत ||","b":"পর তে অগ্নে হবিষ্মতীমিযর্ম্যছা সুদ্যুম্নাং রাতিনীং ঘর্তাচীম | পরদক্ষিণিদ দেবতাতিমুরাণঃ সং রাতিভির্বসুভির্যজ্ঞমশ্রেত ||","e":"Agni, to thee I lift the oil-fed ladle, bright, with an offering, bearing our oblation. From the right hand, choosing the Gods’ attendance, he with rich presents hath arranged the worship.","mb":"হে অগ্নি। আমি হব্যযুক্ত, তেজবিশিষ্ট, হব্যদায়ী, ঘৃতাম্বিত জুহু তোমার অভিমুখে প্রদান করছি। দেবগণের বহুমানকিারী অগ্নি আমাদের দেয় ধনের সাথে প্রদক্ষিণ করে যজ্ঞে সঙ্গত হোন।"},{"n":3,"d":"स तेजीयसा मनसा तवोत उत शिक्ष सवपत्यस्य शिक्षोः | अग्ने रायो नर्तमस्य परभूतौ भूयाम ते सुष्टुतयश्च वस्वः ||","b":"স তেজীযসা মনসা তবোত উত শিক্ষ সবপত্যস্য শিক্ষোঃ | অগ্নে রাযো নর্তমস্য পরভূতৌ ভূযাম তে সুষ্টুতযশ্চ বস্বঃ ||","e":"Of keenest spirit is the man thou aidest give us good offspring, thou who givest freely. In power of wealth most rich in men. O Agni, of thee, the Good, may we sing forth fair praises.","mb":"হে অগ্নি! তুমি যাকে রক্ষা কর তার মন অত্যন্ত তেজস্বী হয়, তাকে উত্তম অপত্যবিশিষ্ট ধন প্রদান কর। হে ফলদানেচ্ছু অগ্নি! তুমি অত্যন্ত ধন দাতা, আমরা তোমার মহিমায় রক্ষিত হব এবং তোমার স্তুতি করে ধনের অধিপতি হব।"},{"n":4,"d":"भूरीणि हि तवे दधिरे अनीकाग्ने देवस्य यज्यवो जनासः | स आ वह देवतातिं यविष्ठ शर्धो यदद्य दिव्यंयजासि ||","b":"ভূরীণি হি তবে দধিরে অনীকাগ্নে দেবস্য যজ্যবো জনাসঃ | স আ বহ দেবতাতিং যবিষ্ঠ শর্ধো যদদ্য দিব্যংযজাসি ||","e":"Men as they worship thee the God, O Agni, have set on thee full many a brilliant, aspect. So bring Most Youthful One, the Gods’ assembly, the Heavenly Host which thou to-day shalt honour.","mb":"হে দ্যুতিমান অগ্নি! যজ্ঞকারিগণ তোমাতে প্রভূত দীপ্তি বিধান করেছেন। হে যুবতম অগ্নি! যেহেতু এ যজ্ঞে স্বর্গীয় তেজের পূজা করছ, অতএব দেবগণকে আহ্বান কর।"},{"n":5,"d":"यत तवा होतारमनजन मियेधे निषादयन्तो यजथाय देवाः | स तवं नो अग्ने.अवितेह बोध्यधि शरवांसि धेहि नस्तनूषु ||","b":"যত তবা হোতারমনজন মিযেধে নিষাদযন্তো যজথায দেবাঃ | স তবং নো অগ্নে.অবিতেহ বোধ্যধি শরবাংসি ধেহি নস্তনূষু ||","e":"When Gods anoint thee Priest at their oblation, and seat thee for thy task as Sacrificer, O Agni, be thou here our kind defender, and to ourselves vouchsafe the gift of glory.","mb":"হে অগ্নি! যেহেতু যজ্ঞের জন্য উপবিষ্ট, দীপ্তিশালী ঋত্বিকগণ যজ্ঞে তোমাকে হোতা বলে সিক্ত করছে, অতএব তুমি আমাদের পালনার্থে জাগরিত হও, আমাদের পুত্রগণকে অধিক পরিমাণে অন্নদান কর।"}]},{"n":20,"t":"Agni","v":[{"n":1,"d":"अग्निमुषसमश्विना दधिक्रां वयुष्टिषु हवते वह्निरुक्थैः | सुज्योतिषो नः शर्ण्वन्तु देवाः सजोषसो अध्वरं वावशानाः ||","b":"অগ্নিমুষসমশ্বিনা দধিক্রাং বযুষ্টিষু হবতে বহ্নিরুক্থৈঃ | সুজ্যোতিষো নঃ শর্ণ্বন্তু দেবাঃ সজোষসো অধ্বরং বাবশানাঃ ||","e":"WITH lauds at break of morn the priest invoketh Agni, Dawn, Dadhikrās, and both the Aśvins. With one consent the Gods whose light is splendid, longing to taste our sacrifice, shall hear us.","mb":"হব্যবাহী ঊষা অন্ধকার অপসারিত হবার সময়ে অগ্নি ঊষা অশ্বিদ্বয় ও দধিক্রাকে (১) উকথ দ্বারা আহ্বান করছেন। সুন্দর দ্যুতিমান ও পরস্পর মিলিত দেবগণ আমাদরে যজ্ঞকামনা করে তা শ্রবণ করুণ।"},{"n":2,"d":"अग्ने तरी ते वाजिना तरी षधस्था तिस्रस्ते जिह्वा रतजात पूर्वीः | तिस्र उ ते तन्वो देववातास्ताभिर्नः पाहि गिरो अप्रयुछन ||","b":"অগ্নে তরী তে বাজিনা তরী ষধস্থা তিস্রস্তে জিহ্বা রতজাত পূর্বীঃ | তিস্র উ তে তন্বো দেববাতাস্তাভির্নঃ পাহি গিরো অপ্রযুছন ||","e":"Three are thy powers, O Agni, three thy stations, three are thy tongues, yea, many, Child of Order! Three bodies hast thou which the Gods delight in: with these protect our hymns with care unceasing.","mb":"হে অগ্নি! তোমার অন্ন তিন প্রকার, তোমার স্থান তিন প্রকার। যে যজ্ঞ সম্পাদক অগ্নি! তোমার দেবতাগণের উদর পূরক তিনটি জিহ্বা আছে। তোমার তিন প্রকার শরীর দেবগণের অভিলষিত; তুমি প্রমাদরহিত হয়ে সে তিন শরীর দ্বারা আমাদের স্তুতি পালন কর।"},{"n":3,"d":"अग्ने भूरीणि तव जातवेदो देव सवधावो.अम्र्तस्य नाम | याश्च माया मायिनां विश्वमिन्व तवे पूर्वीः सन्दधुःप्र्ष्टबन्धो ||","b":"অগ্নে ভূরীণি তব জাতবেদো দেব সবধাবো.অম্র্তস্য নাম | যাশ্চ মাযা মাযিনাং বিশ্বমিন্ব তবে পূর্বীঃ সন্দধুঃপ্র্ষ্টবন্ধো ||","e":"O Agni, many are the names thou bearest, immortal, God, Divine, and Jātavedas. And many charms of charmers, All-Inspirer! have they laid in thee, Lord of true attendants!","mb":"হে দ্যোতমান, জাতবেদা, মরণরহিত, অন্নবান অগ্নি! দেবতাগণ তোমাকে অনেক তেজ প্রদান করেছেন। হে বিশ্বের তৃপ্তিকারী, প্রার্থিত ফলদায়ী অগ্নি! মায়াবীগণের যে সকল মায়া দেবতারা তোমাকে প্রদান করেছিলেন সে সমস্ত তোমাতেই আছে।"},{"n":4,"d":"अग्निर्नेता भग इव कषितीनां दैवीनां देव रतुपा रतावा | स वर्त्रहा सनयो विश्ववेदाः पर्षद विश्वाति दुरिता गर्णन्तम ||","b":"অগ্নির্নেতা ভগ ইব কষিতীনাং দৈবীনাং দেব রতুপা রতাবা | স বর্ত্রহা সনযো বিশ্ববেদাঃ পর্ষদ বিশ্বাতি দুরিতা গর্ণন্তম ||","e":"Agni, like Bhaga, leads the godly people, he who is true to Law and guards the seasons. Ancient, all-knowing, he the Vṛtra-slayer shall bear the singer safe through every trouble.","mb":"ঋতুকারী সূর্যের ন্যায় যে অগ্নি মনুষ্য ও দেবগণের নিয়ামক, যে অগ্নি সত্যাকারী, বৃত্রহন্তা, সনাতন, সর্বজ্ঞ ও দ্যুতিমান, তিনি স্তুতিকারীকে সমস্ত দুরিত অতিক্রম করিয়ে পারে নিয়ে যান।"},{"n":5,"d":"ददहिक्रामग्निमुषसं च देवीं बर्हस्पतिं सवितारं चदेवम | अश्विना मित्रावरुणा भगं च वसून रुद्रानादित्यानिह हुवे ||","b":"দদহিক্রামগ্নিমুষসং চ দেবীং বর্হস্পতিং সবিতারং চদেবম | অশ্বিনা মিত্রাবরুণা ভগং চ বসূন রুদ্রানাদিত্যানিহ হুবে ||","e":"I call on Savitar the God, on Morning, Bṛhaspati, and Dadhikrās, and Agni, On Varuṇa and Mitra, on the Aśvins, Bhaga, the Vasus, Rudras and Ādityas.","mb":"আমি দধিক্রা, অগ্নি, দেবী ঊষা, বৃহস্পতি, দ্যুতিমান সবিতা, অশ্বিদ্বয়, ভগ, বসু, রুদ্র ও আদিত্যদের এ যজ্ঞে আহ্বান করি।"}]},{"n":21,"t":"Agni","v":[{"n":1,"d":"इमं नो यज्ञमम्र्तेषु धेहीमा हव्या जातवेदो जुषस्व | सतोकानामग्ने मेदसो घर्तस्य होतः पराशान परथमो निषद्य ||","b":"ইমং নো যজ্ঞমম্র্তেষু ধেহীমা হব্যা জাতবেদো জুষস্ব | সতোকানামগ্নে মেদসো ঘর্তস্য হোতঃ পরাশান পরথমো নিষদ্য ||","e":"SET this our sacrifice among the Immortals: be pleased with these our presents, Jātavedas. O Priest, O Agni, sit thee down before us, and first enjoy the drops of oil and fatness.","mb":"হে জাতবেদা অগ্নি! আমাদের এ যজ্ঞ অমরগণের নিকট সমর্পণ কর, আমাদের হব্য সেবা কর। হে হোতা! উপবিষ্ট হয়ে সকলের প্রথমে মেদ ও ঘৃতের বিন্দুসমূহ বিশেষরূপে ভক্ষণ কর।"},{"n":2,"d":"घर्तवन्तः पावक ते सतोका शचोतन्ति मेदसः | सवधर्मन देववीतये शरेष्ठं नो धेहि वार्यम ||","b":"ঘর্তবন্তঃ পাবক তে সতোকা শচোতন্তি মেদসঃ | সবধর্মন দেববীতযে শরেষ্ঠং নো ধেহি বার্যম ||","e":"For thee, O Purifier, flow the drops of fatness rich in oil. After thy wont vouchsafe to us the choicest boon that Gods may feast.","mb":"হে পাবক। এ সাঙ্গ যজ্ঞে ঘৃতবিশিষ্ট মেদোবিন্দু সকল তোমার ও দেবগণের পানার্থে রক্ষিত হচ্ছে, অতএব আমাদের শ্রেষ্ঠ ও বরণীয় ধন দান কর।"},{"n":3,"d":"तुभ्यं सतोका घर्तश्चुतो.अग्ने विप्राय सन्त्य | रषिः शरेष्ठः समिध्यसे यज्ञस्य पराविता भव ||","b":"তুভ্যং সতোকা ঘর্তশ্চুতো.অগ্নে বিপ্রায সন্ত্য | রষিঃ শরেষ্ঠঃ সমিধ্যসে যজ্ঞস্য পরাবিতা ভব ||","e":"Agni, Most Excellent! for thee the Sage are drops that drip with oil. Thou art enkindled as the best of Seers. Help thou the sacrifice.","mb":"হে ভজনীয় অগ্নি! তুমি মেধাবী, ঘৃতস্রাবী বিন্দু সকল তোমার জন্য; তুমি ঋষি ও শ্রেষ্ঠ, তুমি প্রজ্বলিত হচ্ছ। তুমি যজ্ঞের পালক হও।"},{"n":4,"d":"तुभ्यं शचोतन्त्यध्रिगो शचीव सतोकासो अग्ने मेदसो घर्तस्य | कविशस्तो बर्हता भानुनागा हव्या जुषस्व मेधिर ||","b":"তুভ্যং শচোতন্ত্যধ্রিগো শচীব সতোকাসো অগ্নে মেদসো ঘর্তস্য | কবিশস্তো বর্হতা ভানুনাগা হব্যা জুষস্ব মেধির ||","e":"To thee, O Agni, mighty and resistless, to thee stream forth the drops of oil and fatness. With great light art thou come, O praised by poets! Accept our offering, O thou Sage.","mb":"হে সতত গমনশীল ও শক্তিমান! তোমার জন্য মেদোরূপ হব্যের বিন্দুসকল ক্ষরিত হচ্ছে। কবিরা তোমার স্তব করে, মহত্তেজের সাথে আগমন কর, হে মেধাবী! আমাদের হব্য সেবা কর।"},{"n":5,"d":"ओजिष्ठं ते मध्यतो मेद उद्भ्र्तं पर ते वयं ददामहे | शचोतन्ति ते वसो सतोका अधि तवचि परति तान देवशो विहि ||","b":"ওজিষ্ঠং তে মধ্যতো মেদ উদ্ভ্র্তং পর তে বযং দদামহে | শচোতন্তি তে বসো সতোকা অধি তবচি পরতি তান দেবশো বিহি ||","e":"Fatness exceeding rich, extracted from the midst,—this as our gift we offer thee. Excellent God, the drops run down upon thy skin. Deal them to each among the Gods.","mb":"হে অগ্নি! আমরা মধ্য হতে অতিশয় সারযুক্ত মেদ পশুর মধ্যভাগ হতে উত্তোলন করে তোমাকে প্রদান করব। হে নিবাসপ্রদ অগ্নি! চর্মের উপর যে বিন্দু সকল তোমার জন্য ক্ষরিত হচ্ছে, তা দেবতাদের প্রত্যেককে বিভাগ করে দাও।"}]},{"n":22,"t":"Agni","v":[{"n":1,"d":"अयं सो अग्निर्यस्मिन सोममिन्द्रः सुतं दधे जठरे वावशानः | सहस्रिणं वाजमत्यं न सप्तिं ससवान सन सतूयसे जातवेदः ||","b":"অযং সো অগ্নির্যস্মিন সোমমিন্দ্রঃ সুতং দধে জঠরে বাবশানঃ | সহস্রিণং বাজমত্যং ন সপ্তিং সসবান সন সতূযসে জাতবেদঃ ||","e":"THIS is that Agni whence the longing Indra took the pressed Soma deep within his body. Winner of spoils in thousands, like a courser, with praise art thou exalted, Jātavedas.","mb":"সোমাভিলাষী ইন্দ্র যে অগ্নিতে অতিযুত সোম আপন উদয়ে রেখেছিলেন, এ সে অগ্নি। হে সর্বজ্ঞ অগ্নি!  হে হব্য নানারূপ অশ্বের ন্যায় বেগশালী, তুমি তা সেবা কর; লোকে তোমার স্তব করে।"},{"n":2,"d":"अग्ने यत ते दिवि वर्चः पर्थिव्यां यदोषधीष्वप्स्वा यजत्र | येनान्तरिक्षमुर्वाततन्थ तवेषः स भानुरर्णवो नर्चक्षाः ||","b":"অগ্নে যত তে দিবি বর্চঃ পর্থিব্যাং যদোষধীষ্বপ্স্বা যজত্র | যেনান্তরিক্ষমুর্বাততন্থ তবেষঃ স ভানুরর্ণবো নর্চক্ষাঃ ||","e":"That light of thine in heaven and earth, O Agni, in plants, O Holy One, and in the waters, Wherewith thou hast spread wide the air's mid-region-bright is that splendour, wavy, man-beholding.","mb":"হে যজনীয় অগ্নি! তোমার যে তেজ দ্যুলোকে, পৃথিবীতে, ওষধিসমূহে ও জলে রয়েছে, যা দিয়ে তুমি অন্তরীক্ষ ব্যাপ্ত করেছ, সে তেজ উজ্জ্বল, ও সমুদ্রের ন্যায় বিস্তীর্ণ এবং মনুষ্যগণের দর্শনকারী।"},{"n":3,"d":"अग्ने दिवो अर्णमछा जिगास्यछा देवानूचिषे धिष्ण्याये | या रोचने परस्तात सूर्यस्य याश्चावस्तादुपतिष्ठण्त आपः ||","b":"অগ্নে দিবো অর্ণমছা জিগাস্যছা দেবানূচিষে ধিষ্ণ্যাযে | যা রোচনে পরস্তাত সূর্যস্য যাশ্চাবস্তাদুপতিষ্ঠণ্ত আপঃ ||","e":"O Agni, to the sea of heaven thou goest: thou hast called hither Gods beheld in spirit. The waters, too, come hither, those up yonder in the Sun's realm of light, and those beneath it.","mb":"হে অগ্নি! তুমি দ্যুলোকের জলের অভিমুখে গমন করছ, ধিষ্ণ দেবগণকে একত্র করছ, সূর্যের উপস্থিত রোচন লোকে এবং সূর্যলোকের নীচে যে জল আছে তাদের উভয়কেই প্রেরণ করছ।"},{"n":4,"d":"पुरीष्यासो अग्नयः परावणेभिः सजोषसः | जुषन्तां यज्ञमद्रुहो.अनमीवा इषो महीः ||","b":"পুরীষ্যাসো অগ্নযঃ পরাবণেভিঃ সজোষসঃ | জুষন্তাং যজ্ঞমদ্রুহো.অনমীবা ইষো মহীঃ ||","e":"Let fires that dwell in mist, combined with those that have their home in floods, Guileless accept our sacrifice, great viands free from all disease.","mb":"পুরীষ্য অগ্নি অস্ত্রের সাথে মিলিত হয়ে এ যাগ সেবা করুন এবং দ্রোহ রহিত রোগাদি বর্জিত মহৎ অন্ন আমাদের দান করুন।"},{"n":5,"d":"इळामग्ने ... ||","b":"ইলামগ্নে ... ||","e":"Agni, as holy food to thine invoker give wealth in cattle, lasting, rich in marvels. To us be born a son and spreading offspring. Agni, be this thy gracious will to us-ward.","mb":"হে অগ্নি! তুমি স্তোতাকে বহুকর্মের হেতুভূত ও ধেনুপ্রদাত্রী ভূমি চিরকাল প্রদান কর। আমাদের বংশ বিস্তারকারী এবং সন্ততি জনয়িতা একটি পুত্র হোক। হে অগ্নি! আমাদের প্রতি তোমার অনুগ্রহ হোক।"}]},{"n":23,"t":"Agni","v":[{"n":1,"d":"निर्मथितः सुधित आ सधस्थे युवा कविरध्वरस्य परणेता | जूर्यत्स्वग्निरजरो वनेष्वत्रा दधे अम्र्तं जातवेदाः ||","b":"নির্মথিতঃ সুধিত আ সধস্থে যুবা কবিরধ্বরস্য পরণেতা | জূর্যত্স্বগ্নিরজরো বনেষ্বত্রা দধে অম্র্তং জাতবেদাঃ ||","e":"RUBBED into life, well stablished in the dwelling, Leader of sacrifice, the Sage, the youthful, Here in the wasting fuel Jātavedas, eternal, hath assumed immortal being.","mb":"যে অগ্নি নির্মথিত ও যজমান গৃহে স্থাপিত, যিনি যুবা, সর্বজ্ঞ, যজ্ঞের প্রণেতা, জাতবেদা এবং মহারণ্য নাশ করেও স্বয়ং অজর, সে অগ্নি এ যজ্ঞে অমৃত ধারণ করেন। ভরতের পুত্র দেবশ্রবা ও দেবরাত সুদক্ষ ও ধনবান অগ্নিকে মন্থন দ্বারা উৎপন্ন করছে। হে অগ্নি! তুমি প্রভূত ধনের সাথে আমাদের দিকে দেখ এবং প্রত্যহ আমাদের অন্ন আন।"},{"n":2,"d":"अमन्थिष्टां भारता रेवदग्निं देवश्रवा देववातः सुदक्षम | अग्ने वि पश्य बर्हताभि रायेषां नो नेता भवतादनु दयून ||","b":"অমন্থিষ্টাং ভারতা রেবদগ্নিং দেবশ্রবা দেববাতঃ সুদক্ষম | অগ্নে বি পশ্য বর্হতাভি রাযেষাং নো নেতা ভবতাদনু দযূন ||","e":"Both Bharatas, Devaśravas, Devāvata, have strongly rubbed to life effectual Agni. O Agni, look thou forth with ample riches: be, every day, bearer of food to feed us.","mb":"উভয় ভারত — দেবশ্রবা ও দেবাবত — প্রবলভাবে কার্যকর অগ্নি প্রজ্বলিত করেছেন। হে অগ্নি, প্রচুর ধনসম্পদ দিয়ে দৃষ্টিপাত করো: প্রতিদিন আমাদের পুষ্টির জন্য অন্ন বাহক হও।"},{"n":3,"d":"दश कषिपः पूर्व्यं सीमजीजनन सुजातं मात्र्षु परियम | अग्निं सतुहि दैववातं देवश्रवो यो जनानामसद वशी ||","b":"দশ কষিপঃ পূর্ব্যং সীমজীজনন সুজাতং মাত্র্ষু পরিযম | অগ্নিং সতুহি দৈববাতং দেবশ্রবো যো জনানামসদ বশী ||","e":"Him nobly born of old the fingers ten produced, him whom his Mothers counted dear. Praise Devāvata's Agni, thou Devaśravas, him who shall be the people's Lord.","mb":"দশ অঙ্গুলি এ পুরাতন কমনীয় অগ্নিকে উৎপন্ন করেছে। হে দেবশ্রবা! অরণিরূপ মাতৃগণের মধ্যে সূজাত, প্রিয় ও দেবরাত কর্তৃক উৎপাদিত অগ্নিকে স্তুতি কর। সে অগ্নি লোকের বশবর্তী হন।"},{"n":4,"d":"नि तवा दधे वर आ पर्थिव्या इळायास पदे सुदिनत्वे अह्नाम | दर्षद्वत्यां मानुष आपयायां सरस्वत्यां रेवदग्नेदिदीहि ||","b":"নি তবা দধে বর আ পর্থিব্যা ইলাযাস পদে সুদিনত্বে অহ্নাম | দর্ষদ্বত্যাং মানুষ আপযাযাং সরস্বত্যাং রেবদগ্নেদিদীহি ||","e":"He set thee in the earth's most lovely station, in Iḷā's place, in days of fair bright weather. On man, on Āpayā, Agni! on the rivers Dṛṣadvati, Sarasvatī, shine richly.","mb":"হে অগ্নি! সুদিন লাভের জন্য ইলারূপ পৃথিবীর উৎকৃষ্ট স্থানে তোমাকে স্থাপন করছি! হে অগ্নি! তুমি দৃষদ্বতী, আপষা ও সরস্বতী তীরস্থিত মনুষ্যের গৃহে ধন বিশিষ্ট হয়ে দীপ্ত হও।"},{"n":5,"d":"इळामग्ने ... ||","b":"ইলামগ্নে ... ||","e":"Agni, as holy food to thine invoker give wealth in cattle, lasting, rich in marvels. To us be born a son and spreading offspring Agni, be this thy gracious will to us-ward","mb":"হে অগ্নি! তুমি স্তোতাকে বহু কর্মের হেতভূত ও ধেনু প্রদাত্রী ভূমি চিরকাল প্রদান কর। আমাদের বংশ বিস্তারকারী এবং সন্তুতি জনয়িতা একটি পুত্র হোক। হে অগ্নি! আমাদের প্রতি তোমার অনুগ্রহ হোক।"}]},{"n":24,"t":"Agni","v":[{"n":1,"d":"अग्ने सहस्व पर्तना अभिमातीरपास्य | दुष्टरस्तरन्नरातीर्वर्चो धा यज्ञवाहसे ||","b":"অগ্নে সহস্ব পর্তনা অভিমাতীরপাস্য | দুষ্টরস্তরন্নরাতীর্বর্চো ধা যজ্ঞবাহসে ||","e":"AGNI, subdue opposing bands, and drive our enemies away. Invincible, slay godless foes: give splendour to the worshipper.","mb":"হে অগ্নি! তুমি শত্রুসেনাকে পরাভব কর, বিঘ্নকারীদের দূর করে দাও। তোমাকে কেউ পরাজয় করতে পারে না, তুমি শত্রুদের জয় করে যজমানকে অন্ন দান কর।"},{"n":2,"d":"अग्न इळा समिध्यसे वीतिहोत्रो अमर्त्यः | जुषस्व सू नो अध्वरम ||","b":"অগ্ন ইলা সমিধ্যসে বীতিহোত্রো অমর্ত্যঃ | জুষস্ব সূ নো অধ্বরম ||","e":"Lit with libation, Agni, thou, deathless, who callest Gods to feast, Accept our sacrifice with joy.","mb":"হে অগ্নি! তুমি যজ্ঞে প্রীতিমান ও মরণরহিত, তোমাকে উত্তরবেদিতে প্রজ্বালিত করে। তুমি আমাদের যজ্ঞকে সুন্দররূপে সেবা কর।"},{"n":3,"d":"अग्ने दयुम्नेन जाग्र्वे सहसः सूनवाहुत | एदं बर्हिः सदो ||","b":"অগ্নে দযুম্নেন জাগ্র্বে সহসঃ সূনবাহুত | এদং বর্হিঃ সদো ||","e":"With splendour, Agni, Son of Strength, thou who art worshipped, wakeful One. Seat thee on this my sacred grass.","mb":"হে অগ্নি! তুমি আপনার তেজে সর্বদা জাগরিত আছ, তুমি বলের পুত্র। আমি তোমাকে আহ্বান করছি, আমার এ কুশে উপবেশন কর।"},{"n":4,"d":"मम ||","b":"মম ||","e":"With all thy fires, with all the Gods, Agni, exalt the songs we sing. And living men in holy rites.","mb":"হে অগ্নি! যারা পুজক তাদের যজ্ঞে সমস্ত দ্যুতিমান অগ্নির সঙ্গে স্তুতির সম্মান রক্ষা কর।"},{"n":5,"d":"अग्ने विश्वेभिरग्निभिर्देवेभिर्महया गिरः | यज्ञेषु यौ चायवः ||","b":"অগ্নে বিশ্বেভিরগ্নিভির্দেবেভির্মহযা গিরঃ | যজ্ঞেষু যৌ চাযবঃ ||","e":"Grant, Agni, to the worshipper wealth rich in heroes, plenteous store, Make thou us rich with many sons.","mb":"হে অগ্নি! তুমি হব্যদায়ীকে বীর্যযুক্ত প্রভূত ধন দান কর। আমরা পুত্র পৌত্তবান, আমাদের তীক্ষ্ম কর।"},{"n":6,"d":"अग्ने दा दाशुषे रयिं वीरवन्तं परीणसम | शिशीहि नः सूनुमतः ||","b":"অগ্নে দা দাশুষে রযিং বীরবন্তং পরীণসম | শিশীহি নঃ সূনুমতঃ ||","e":"Missing Line From Griffith.","mb":"হে অগ্নি, দাতাকে বীরসন্তানসমৃদ্ধ ও প্রভূত ধন দাও। আমাদের সন্তানবানদের রক্ষা করো।"}]},{"n":25,"t":"Agni","v":[{"n":1,"d":"अगने दिवः सूनुरसि परचेतास्तना पर्थिव्या उत विश्ववेदाः | रधग देवानिह यजा चिकित्वः ||","b":"অগনে দিবঃ সূনুরসি পরচেতাস্তনা পর্থিব্যা উত বিশ্ববেদাঃ | রধগ দেবানিহ যজা চিকিত্বঃ ||","e":"THOU art the sapient Son of Dyaus, O Agni, yes and the Child of Earth, who knowest all things. Bring the Gods specially, thou Sage, for worship.","mb":"হে অগ্নি! তুমি সর্বজ্ঞ ও চিত্তবান, তুমি দ্যুদেবতার পুত্র ও পৃথিবীর তনয়। হে চেতনাবান অগ্নি! তুমি দেবগণের এ যজ্ঞে পৃথক পৃথক যাগ কর।"},{"n":2,"d":"अग्निः सनोति वीर्याणि विद्वान सनोति वाजमम्र्ताय भूषन | स नो देवानेह वहा पुरुक्षो ||","b":"অগ্নিঃ সনোতি বীর্যাণি বিদ্বান সনোতি বাজমম্র্তায ভূষন | স নো দেবানেহ বহা পুরুক্ষো ||","e":"Agni the wise bestows the might of heroes grants strengthening food, preparing it for nectar. Thou who art rich in food bring the Gods hither.","mb":"বিদ্বান অগ্নি সামর্থ্য পদান করেন। অগ্নি আপনাকে ভূষিত করে অমরগণকে অন্ন প্রদান করেন। হে বহুবিধ অন্নবিশিষ্ট অগ্নি। তুমি দেবগণকে আমাদের জন্য এ যজ্ঞে আন।"},{"n":3,"d":"अग्निर्द्यावाप्र्थिवी विश्वजन्ये आ भाति देवी अम्र्ते अमूरः | कषयन वाजैः पुरुश्चन्द्रो नमोभिः ||","b":"অগ্নির্দ্যাবাপ্র্থিবী বিশ্বজন্যে আ ভাতি দেবী অম্র্তে অমূরঃ | কষযন বাজৈঃ পুরুশ্চন্দ্রো নমোভিঃ ||","e":"Agni, infallible, lights Earth and Heaven, immortal Goddesses gracious to all men,— Lord through his strength, splendid through adorations.","mb":"সর্বজ্ঞ, জগৎপতি বহুদীপ্তিযুক্ত, বল ও অন্ন বিশিষ্ট অগ্নি জগতের জননী দ্যুতিমতি, মরণরহিতা দ্যাবাপৃথিবীকে প্রকাশিত করছেন।"},{"n":4,"d":"अग्न इन्द्रश्च दाशुषो दुरोने सुतावतो यज्ञमिहोप यातम | अमर्धन्ता सोमपेयाय देवा ||","b":"অগ্ন ইন্দ্রশ্চ দাশুষো দুরোনে সুতাবতো যজ্ঞমিহোপ যাতম | অমর্ধন্তা সোমপেযায দেবা ||","e":"Come to the sacrifice, Agni and Indra come to the offerer's house who hath the Soma. Come, friendly-minded, Gods, to drink the Soma.","mb":"হে অগ্নি। তুমি ও ইন্দ্র যজ্ঞ হিংসা না করে অভিষবপ্রদায়ীর এ গৃহে সোমপানের জন্য এস।"},{"n":5,"d":"अग्ने अपां समिध्यसे दुरोणे नित्यः सूनो सहसो जातवेदः | सधस्थानि महयमान ऊती ||","b":"অগ্নে অপাং সমিধ্যসে দুরোণে নিত্যঃ সূনো সহসো জাতবেদঃ | সধস্থানি মহযমান ঊতী ||","e":"In the floods' home art thou enkindled, Agni, O Jātavedas, Son of Strength, eternal, Exalting with thine help the gathering-places.","mb":"হে বলের পুত্র, নিত্য সর্বজ্ঞ অগ্নি। তুমি আশ্রয় দান দ্বারা জীবলোক সকলকে অলঙ্কৃত করে জলের স্থানভূত অন্তরীক্ষে শোভা পাচ্ছ।"}]},{"n":26,"t":"Agni","v":[{"n":1,"d":"वैश्वानरं मनसाग्निं निचाय्या हविष्मन्तो अनुषत्यं सवर्विदम | सुदानुं देवं रथिरं वसूयवो गीर्भी रण्वंकुशिकासो हवामहे ||","b":"বৈশ্বানরং মনসাগ্নিং নিচায্যা হবিষ্মন্তো অনুষত্যং সবর্বিদম | সুদানুং দেবং রথিরং বসূযবো গীর্ভী রণ্বংকুশিকাসো হবামহে ||","e":"REVERING in our heart Agni Vaiśvānara, the finder of the light, whose promises are true, The liberal, gladsome, car-borne God we Kuśikas invoke him with oblation, seeking wealth with songs.","mb":"আমরা কুশিক গোত্রোৎপন্ন, আমরা ধনাভিলাষে হব্য সংগ্রহ করে মনে মনে বৈশ্বানর নামক অগ্নি অবগত হয়ে স্তুতিদ্বারা তাকে আহ্বান করছি। তিনি সত্য দ্বারা অনুগত, স্বর্গের বিষয় জানেন ও যজ্ঞের ফলদান করেন; তার রথ আছে, তিনি যজ্ঞে আসছেন।"},{"n":2,"d":"तं शुभ्रमग्निमवसे हवामहे वैश्वानरं मातरिश्वानमुक्थ्यम | बर्हस्पतिं मनुषो देवतातये विप्रं शरोतारमतिथिं रघुष्यदम ||","b":"তং শুভ্রমগ্নিমবসে হবামহে বৈশ্বানরং মাতরিশ্বানমুক্থ্যম | বর্হস্পতিং মনুষো দেবতাতযে বিপ্রং শরোতারমতিথিং রঘুষ্যদম ||","e":"That Agni, bright, Vaiśvānara, we invoke for help, and Mātariśvan worthy of the song of praise; Bṛhaspati for man's observance of the Gods, the Singer prompt to hear, the swiftly-moving guest.","mb":"আমরা আশ্রয় প্রাপ্তির জন্য এবং যজমানের যজ্ঞের জন্য সেই শুভ্র, বৈশ্বানর, মাতরিশ্বা (১), উকথযোগ্য, যজ্ঞপতি, মেধাবী, শ্রোতা, অতিথি ও ক্ষিপ্রগামী অগ্নিকে আহ্বান করি।"},{"n":3,"d":"अश्वो न करन्दञ जनिभिः समिध्यते वैश्वानरः कुशिकेभिर्युगे-युगे | स नो अग्निः सुवीर्यं सवश्व्यं दधातु रत्नमम्र्तेषु जाग्र्विः ||","b":"অশ্বো ন করন্দঞ জনিভিঃ সমিধ্যতে বৈশ্বানরঃ কুশিকেভির্যুগে-যুগে | স নো অগ্নিঃ সুবীর্যং সবশ্ব্যং দধাতু রত্নমম্র্তেষু জাগ্র্বিঃ ||","e":"Age after age Vaiśvānara, neighing like a horse, is kindled with the women by the Kuśikas. May Agni, he who wakes among Immortal Gods, grant us heroic strength and wealth in noble steeds.","mb":"হেবারবকারী অশ্বশাবক যেমন জননী কর্তৃক বর্ধিত হয় সেরূপ বৈশ্বানর প্রতিদিন কৌশিকগণ কর্তৃক বর্ধিত হচ্ছেন। অমরগণের মধ্যে জাগরুক অগ্নি আমাদের উত্তম অশ্ব, উত্তম বীর্য ও উত্তম ধন প্রদান করুন।"},{"n":4,"d":"पर यन्तु वाजास्तविषीभिरग्नयः शुभे सम्मिष्लाः पर्षतीरयुक्षत | बर्हदुक्षो मरुतो विश्ववेदसः पर वेपयन्तिपर्वतानदाभ्याः ||","b":"পর যন্তু বাজাস্তবিষীভিরগ্নযঃ শুভে সম্মিষ্লাঃ পর্ষতীরযুক্ষত | বর্হদুক্ষো মরুতো বিশ্ববেদসঃ পর বেপযন্তিপর্বতানদাভ্যাঃ ||","e":"Let them go forth, the strong, as flames of fire with might. Gathered for victory they have yoked their spotted deer. Pourers of floods, the Maruts, Masters of all wealth, they who can ne’er be conquered, make the mountains shake.","mb":"অগ্নিরূপ অশ্ব সকল গমন করুন, বলবান মরুৎগণের সাথে জলে মিলিত হয়ে পৃষতী নামক বাহনদের সংযুক্ত করুন। সর্বজ্ঞ, অহিংসনীয় মরুৎগণ, প্রভূত জলশালী পর্বত সদৃশ মেঘকে কম্পিত করছেন।"},{"n":5,"d":"अग्निश्रियो मरुतो विश्वक्र्ष्टय आ तवेषमुग्रमव ईमहे वयम | ते सवानिनो रुद्रिया वर्षनिर्णिजः सिंहा न हेषक्रतवः सुदानवः ||","b":"অগ্নিশ্রিযো মরুতো বিশ্বক্র্ষ্টয আ তবেষমুগ্রমব ঈমহে বযম | তে সবানিনো রুদ্রিযা বর্ষনির্ণিজঃ সিংহা ন হেষক্রতবঃ সুদানবঃ ||","e":"The Maruts, Friends of men, are glorious as the fire: their mighty and resplendent succour we implore. Those storming Sons of Rudra clothed in robes of rain, boon-givers of good gifts, roar as the lions roar.","mb":"মরুৎগণ অগ্নির আশ্রিত ও জগতের আকর্ষক, সে মরুৎগণের দীপ্ত এবং উগ্র আশ্রয় আমরা সম্যকরূপে যাচঞ্চা করি। বর্ষণরূপধারী হ্রেষারবকারী, ও সিংসের ন্যায় শব্দকারী রূদ্রপুত্র মরুৎগণ বিশেষরূপে জল দান করেন।"},{"n":6,"d":"वरातं-वरातं गणं-गणं सुशस्तिभिरग्नेर्भामं मरुतामोज ईमहे | पर्षदश्वासो अनवभ्रराधसो गन्तारो यज्ञं विदथेषु धीराः ||","b":"বরাতং-বরাতং গণং-গণং সুশস্তিভিরগ্নের্ভামং মরুতামোজ ঈমহে | পর্ষদশ্বাসো অনবভ্ররাধসো গন্তারো যজ্ঞং বিদথেষু ধীরাঃ ||","e":"We, band on band and troop following troop, entreat with fair lauds Agni's splendour and the Maruts’ might, With spotted deer for steeds, with wealth that never fails, they, wise Ones, come to sacrifice at our gatherings.","mb":"আমরা দলে দলে এং গশে গণে স্তুতিমন্ত্র দ্বারা অগ্নির তেজ ও মরুতে বল যাচঞ্চা করি। বিন্দুচিহ্নিত বাহনবিশিষ্ট (২), অক্ষয় ধনযুক্ত ধীর মরুৎগণ যজ্ঞে হব্যের উদ্দেশে গমন করতেন।"},{"n":7,"d":"अग्निरस्मि जन्मना जातवेदा घर्तं मे चक्षुरम्र्तं म आसन | अर्कस्त्रिधातू रजसो विमानो.अजस्रो घर्मो हविरस्मि नाम ||","b":"অগ্নিরস্মি জন্মনা জাতবেদা ঘর্তং মে চক্ষুরম্র্তং ম আসন | অর্কস্ত্রিধাতূ রজসো বিমানো.অজস্রো ঘর্মো হবিরস্মি নাম ||","e":"Agni am I who know, by birth, all creatures. Mine eye is butter, in my mouth is nectar. I am light threefold, measurer of the region exhaustless heat am I, named burnt-oblation.","mb":"আমি অগ্নি, জন্ম হতেই জাতবেদা, ঘৃত আমার চক্ষু, অমৃত আমার মুখে আছে, আমার প্রাণ ত্রিবিধ, আমি অন্তীরক্ষের পরিমাণকারী, আমি অক্ষয় উত্তাপ, আমি হব্যস্বরূপ।"},{"n":8,"d":"तरिभिः पवित्रैरपुपोद धयर्कं हर्दा मतिं जयोतिरनु परजानन | वर्षिष्ठं रत्नमक्र्त सवधाभिरादिद दयावाप्र्थिवी पर्यपश्यत ||","b":"তরিভিঃ পবিত্রৈরপুপোদ ধযর্কং হর্দা মতিং জযোতিরনু পরজানন | বর্ষিষ্ঠং রত্নমক্র্ত সবধাভিরাদিদ দযাবাপ্র্থিবী পর্যপশ্যত ||","e":"Bearing in mind a thought with light accordant, he purified the Sun with three refinings; By his own nature gained the highest treasure, and looked abroad over the earth and heaven.","mb":"অগ্নি অন্ত:করণ দ্বারা মনোহর জ্যোতি বিশেষরূপে বিগত হয়ে তিন পবিত্র রূপদ্বারা (৩) অর্চনীয় আত্মাকে পবিত্র করেছেন। অগ্নি স্বীয় রূপ সমূহদ্বারা উৎকৃষ্ট রত্ন করেছিলেন এবং পরক্ষণেই দ্যাবাপৃথিবীকে অবলোকন করেছিলেন।"},{"n":9,"d":"शतधारमुत्समक्षीयमाणं विपश्चितं पितरं वक्त्वानाम | मेळिं मदन्तं पित्रोरुपस्थे तं रोदसी पिप्र्तं सत्यवाचम ||","b":"শতধারমুত্সমক্ষীযমাণং বিপশ্চিতং পিতরং বক্ত্বানাম | মেলিং মদন্তং পিত্রোরুপস্থে তং রোদসী পিপ্র্তং সত্যবাচম ||","e":"The Spring that fails not with a hundred streamlets, Father inspired of prayers that men should utter, The Sparkler, joyous in his Parents' bosorn, -him, the Truth-speaker, sate ye, Earth and Heaven.","mb":"শতধারা উঃসের ন্যায় অবিচ্ছিন্ন প্রবাহ বিশিষ্ট এবং বিপশ্চিৎ পালক, বাক্যের মেলক ও পিতামাতার ক্রোড়ে হর্ষযুক্ত এবং সত্যবাদীকে, হে দ্যাবাপৃথিবী! তোমরা পূর্ণ কর (৪)।"}]},{"n":27,"t":"Agni","v":[{"n":1,"d":"पर वो वाजा अभिद्यवो हविष्मन्तो घर्ताच्या | देवाञ जिगातिसुम्नयुः ||","b":"পর বো বাজা অভিদ্যবো হবিষ্মন্তো ঘর্তাচ্যা | দেবাঞ জিগাতিসুম্নযুঃ ||","e":"IN ladle dropping oil your food goes in oblation up to heaven, Goes to the Gods in search of bliss.","mb":"তোমার স্বর্গাভিমুখহবিম্মান ঘৃতস্পৃষ্ট শিখা স্বরূপ অশ্বগণ সুখ কামনায় দেবগণের নিকট যাচ্ছেন।"},{"n":2,"d":"ईळे अग्निं विपश्चितं गिरा यज्ञस्य साधनम | शरुष्टीवानं धितावानम ||","b":"ঈলে অগ্নিং বিপশ্চিতং গিরা যজ্ঞস্য সাধনম | শরুষ্টীবানং ধিতাবানম ||","e":"Agni I laud, the Sage inspired, crowner of sacrifice through song, Who listens and gives bounteous gifts.","mb":"মেধাবী যজ্ঞনির্বাহক, বেগবান, ধনবান অগ্নিকে স্তুতি বাক্যদ্বারা পূজা করি।"},{"n":3,"d":"अग्ने शकेम ते वयं यमं देवस्य वाजिनः | अति दवेषांसि तरेम ||","b":"অগ্নে শকেম তে বযং যমং দেবস্য বাজিনঃ | অতি দবেষাংসি তরেম ||","e":"O Agni, if we might obtain control of thee the potent God, Then should we overcome our foes.","mb":"হে দীপি্তিমান অগ্নি! আমরা হব্য প্রস্তুত করে তোমাকে এখানে রাখতে সমর্থ হব এবং পাপ হতে উত্তীর্ণ হব।"},{"n":4,"d":"समिध्यमानो अध्वरे.अग्निः पावक ईड्यः | शोचिष्केशस्तमीमहे ||","b":"সমিধ্যমানো অধ্বরে.অগ্নিঃ পাবক ঈড্যঃ | শোচিষ্কেশস্তমীমহে ||","e":"Kindled at sacrifices he is Agni, hallower, meet for praise, With flame for hair: to him we seek.","mb":"যজ্ঞকালে প্রজ্বলিত, জ্বালারূপ কেশবিশিষ্ট, পাবক ও পূজনীয় অগ্নির নিকট আমরা অভিলষিত ফল যাচ্ঞ্চা করি।"},{"n":5,"d":"पर्थुपाजा अमर्त्यो घर्तनिर्णिक सवाहुतः | अग्निर्यज्ञस्य हव्यवाट ||","b":"পর্থুপাজা অমর্ত্যো ঘর্তনির্ণিক সবাহুতঃ | অগ্নির্যজ্ঞস্য হব্যবাট ||","e":"Immortal Agni, shining far, enrobed with oil, well worshipped, bears The gifts of sacrifice away.","mb":"প্রভূত তেজবিশিষ্ট, মরণরহিত, ঘৃতশোধনকারী ও সম্যক পূজিত অগ্নি যজ্ঞের হব্য বহন করেন।"},{"n":6,"d":"तं सबाधो यतस्रुच इत्था धिया यज्ञवन्तः | आ चक्रुरग्निमूतये ||","b":"তং সবাধো যতস্রুচ ইত্থা ধিযা যজ্ঞবন্তঃ | আ চক্রুরগ্নিমূতযে ||","e":"The priests with ladles lifted up, worshipping here with holy thought, Have brought this Agni for our aid.","mb":"যজ্ঞবিঘ্ননাশক বলযুক্ত ঋত্বিকগণ স্রুক সংযত করে আশ্রয় লাভের জন্য এ প্রকার স্তুতিদ্বারা সে অগ্নিকে আপনাদের অভিমুখ করেছিল।"},{"n":7,"d":"होता देवो अमर्त्यः पुरस्तादेति मायया | विदथानि परचोदयन ||","b":"হোতা দেবো অমর্ত্যঃ পুরস্তাদেতি মাযযা | বিদথানি পরচোদযন ||","e":"Immortal, Sacrificer, God, with wondrous power he leads the way, Urging the great assembly on.","mb":"হোমনিষ্পাদক মরণরহিত, দ্যুতিমান অগ্নি যজ্ঞকার্যে লোককে উত্তেজিত করে যজ্ঞকার্যের অভিজ্ঞতা সহকারে অগ্রগামী হচ্ছেন।"},{"n":8,"d":"वाजी वाजेषु धीयते.अध्वरेषु पर णीयते | विप्रो यज्ञस्य साधनः ||","b":"বাজী বাজেষু ধীযতে.অধ্বরেষু পর ণীযতে | বিপ্রো যজ্ঞস্য সাধনঃ ||","e":"Strong, he is set on deeds ofstrength. In sacrifices led in front, As Singer he completes the rite.","mb":"বলবান অগ্নি যুদ্ধে অগ্রভাগ স্থাগিত হন, যজ্ঞকালে যথাস্থানে নিক্ষিপ্ত হন। তিনি মেধাবী ও যজ্ঞ সম্পাদক।"},{"n":9,"d":"धिया चक्रे वरेण्यो भूतानां गर्भमा दधे | दक्षस्यपितरं तना ||","b":"ধিযা চক্রে বরেণ্যো ভূতানাং গর্ভমা দধে | দক্ষস্যপিতরং তনা ||","e":"Excellent, he was made by thought. The Germ of beings have I gained, Yea, and die Sire of active strength.","mb":"যে অগ্নি কর্মদ্বারা বরণীয়, ভূত সমূহের গর্ভরূপে অবস্থিত ও পিতাস্বরূপ, দক্ষের তনয়া সে অগ্নিকে ধারণ করেন।"},{"n":10,"d":"नि तवा दधे वरेण्यं दक्षस्येळा सहस्क्र्त | अग्ने सुदीतिमुशिजम ||","b":"নি তবা দধে বরেণ্যং দক্ষস্যেলা সহস্ক্র্ত | অগ্নে সুদীতিমুশিজম ||","e":"Thee have I stablished, Excellent, O strengthened by the sage's prayer, Thee, Agni, longing, nobly bright.","mb":"হে বল স্মপাদিত অগ্নি! তুমি উত্তম দীপ্তিযুক্ত, হব্যাভিলাষী ও বরণীয়। তোমাকে দক্ষের কন্যা ইলা ধারণ করছে (১)।"},{"n":11,"d":"अग्निं यन्तुरमप्तुरं रतस्य योगे वनुषः | विप्रा वाजैः समिन्धते ||","b":"অগ্নিং যন্তুরমপ্তুরং রতস্য যোগে বনুষঃ | বিপ্রা বাজৈঃ সমিন্ধতে ||","e":"Agni, the swift and active One, singers, at time of sacrifice, Eagerly kindle with their food.","mb":"মেধাবী ভক্তগণ জগতের নিয়ন্তা ও জলের প্রেরক অগ্নিকে যজ্ঞ সম্পাদনার্থে অন্ন দ্বারা সম্যকরূপে উদ্দীপ্ত করছেন।"},{"n":12,"d":"ऊर्जो नपातमध्वरे दीदिवांसमुप दयवि | अग्निमीळे कविक्रतुम ||","b":"ঊর্জো নপাতমধ্বরে দীদিবাংসমুপ দযবি | অগ্নিমীলে কবিক্রতুম ||","e":"Agni the Son of Strength who shines up to the heaven in solemn rites, The wise of heart, I glorify.","mb":"অন্নের নপ্তা, অন্তরক্ষের সমীপে দীপ্যমান ও সর্বজ্ঞঝ অগ্নিকে যজ্ঞে স্তব করছি।"},{"n":13,"d":"ईळेन्यो नमस्यस्तिरस्तमांसि दर्शतः | समग्निरिध्यत ||","b":"ঈলেন্যো নমস্যস্তিরস্তমাংসি দর্শতঃ | সমগ্নিরিধ্যত ||","e":"Meet to be lauded and adored, showing in beauty through the dark, Agni, the Strong, is kindled well.","mb":"পূজনীয়, নমস্কারযোগ্য, দর্শনীয় অভীষ্টবর্ষী অগ্নি অন্ধকার দূর করে প্রজ্বলিত হচ্ছেন।"},{"n":14,"d":"ए वर्षा ||","b":"এ বর্ষা ||","e":"Agni is kindled as a bull, like a horsebearer of the Gods: Men with oblations worship him.","mb":"অভীষ্টবর্ষী এবং অশ্বের ন্যায় দেবগণের হব্যবাহক অগ্নি প্রজ্বলিত হচ্ছেন। হবিম্মান অগ্নিকে পূজা করছেন।"},{"n":15,"d":"वर्षो अग्निः समिध्यते.अश्वो न देववाहनः | तं हविष्मन्त ईळते ||","b":"বর্ষো অগ্নিঃ সমিধ্যতে.অশ্বো ন দেববাহনঃ | তং হবিষ্মন্ত ঈলতে ||","e":"Thee will we kindle as a bull, we who are Bulls ourselves, O Bull. Thee, Agni, shining mightily.","mb":"হে অভীষ্টবর্ষী অগ্নি! আমরা ঘৃতাদি সেক করি, তুমি জলসেক কর, আমরা তোমাকে দীপ্ত করছি, তুমি দীপ্তিমান ও বৃহৎ।"},{"n":16,"d":"वर्षणं तवा वयं वर्षन वर्षणः समिधीमहि | अग्ने दीद्यतं बर्हत ||","b":"বর্ষণং তবা বযং বর্ষন বর্ষণঃ সমিধীমহি | অগ্নে দীদ্যতং বর্হত ||","e":"Missing line from Griffith.","mb":"হে বৃষন, আমরা বৃষনগণ তোমাকে, বৃষনকে প্রজ্বলিত করি। হে অগ্নি, মহান জ্যোতিতে দীপ্তিমান হও।"}]},{"n":28,"t":"Agni","v":[{"n":1,"d":"अग्ने जुषस्व नो हविः पुरोळाशं जातवेदः | परातःसावेधियावसो ||","b":"অগ্নে জুষস্ব নো হবিঃ পুরোলাশং জাতবেদঃ | পরাতঃসাবেধিযাবসো ||","e":"AGNI who knowest all, accept our offering and the cake of meal, At dawn's libation, rich in prayer!","mb":"হে জাতবেদা অগ্নি! তোমার স্তোত্রই ধনপ্রদায়ক। তুমি প্রাত:সবনে আমাদের পুরোডাশ ও হব্য সেবা কর।"},{"n":2,"d":"पुरोळा अग्ने पचतस्तुभ्यं वा घा परिष्क्र्तः | तं जुषस्व यविष्ठ्य ||","b":"পুরোলা অগ্নে পচতস্তুভ্যং বা ঘা পরিষ্ক্র্তঃ | তং জুষস্ব যবিষ্ঠ্য ||","e":"Agni, the sacrificial cake hath been prepared and dressed for thee: Accept it, O Most Youthful God.","mb":"হে যুবতম অগ্নি! তোমার জন্য পুরোডাশ পাক করা হয়েছে ও সংস্কৃত করা হয়েছে, তুমি তা সেবা কর।"},{"n":3,"d":"अग्ने वीहि पुरोळाषमाहुतं तिरोह्न्यम | सहसः सूनुरस्यध्वरे हितः ||","b":"অগ্নে বীহি পুরোলাষমাহুতং তিরোহ্ন্যম | সহসঃ সূনুরস্যধ্বরে হিতঃ ||","e":"Agni, enjoy the cake of meal and our oblation three days old: Thou, Son of Strength, art stablished at our sacrifice.","mb":"হে অগ্নি! দিবসের শেষে সম্যক প্রদত্ত পুরোডাশ ভক্ষণ কর। তুমি বলের পুত্র ও তুমি যজ্ঞে নিহিত হও।"},{"n":4,"d":"माध्यन्दिने सवने जातवेदः पुरोळाशमिह कवे जुषस्व | अग्ने यह्वस्य तव भागधेयं न पर मिनन्ति विदथेषु धीराः ||","b":"মাধ্যন্দিনে সবনে জাতবেদঃ পুরোলাশমিহ কবে জুষস্ব | অগ্নে যহ্বস্য তব ভাগধেযং ন পর মিনন্তি বিদথেষু ধীরাঃ ||","e":"Here at the midday sacrifice enjoy thou the sacrificial cake, wise, Jātavedas! Agni, the sages in assemblies never minish the portion due to thee the Mighty.","mb":"হে জাতবেদা মেধাবী অগ্নি! এ মধ্যন্দিন সবনে পুরোডাশ সেবা কর। ধীর অধ্বর্যুগণ যজ্ঞে তোমার ভাগ নষ্ট করে না, তুমি মহান।"},{"n":5,"d":"अग्ने तर्तीये सवने हि कानिषः पुरोळाशं सहसः सूनवाहुतम | अथा देवेष्वध्वरं विपन्यया धा रत्नवन्तमम्र्तेषु जाग्र्विम ||","b":"অগ্নে তর্তীযে সবনে হি কানিষঃ পুরোলাশং সহসঃ সূনবাহুতম | অথা দেবেষ্বধ্বরং বিপন্যযা ধা রত্নবন্তমম্র্তেষু জাগ্র্বিম ||","e":"O Agni, at the third libation takewith joy the offered cake of sacrifice, thou, Son of Strength. Through skill in song bear to the Gods our sacrifice, watchful and fraught with riches, to Immortal God.","mb":"হে বলের পুত্র অগ্নি! তৃতীয় সবনে প্রদত্ত পুরোডাশ তুমি বাঞ্চা কর। অনন্তর অবিনাশী ও রত্নবান জাগরণকারী সোমকে স্তুতির সাথে মরণরহিত দেবগণের নিকট স্থাপন কর।"},{"n":6,"d":"अग्ने वर्धान आहुतिं पुरोळाशं जातवेदः | जुषस्व तिरोह्न्यम ||","b":"অগ্নে বর্ধান আহুতিং পুরোলাশং জাতবেদঃ | জুষস্ব তিরোহ্ন্যম ||","e":"O waxing Agni, knower, thou, of all, accept our gifts, the cake, And that prepared ere yesterday.","mb":"হে জাতবেদা অগ্নি! তুমি দিবসের শেষে পুরোডাশরূপ আহুতি সেবা কর।"}]},{"n":29,"t":"Agni","v":[{"n":1,"d":"अस्तीदमधिमन्थनमस्ति परजननं कर्तम | एतां विश्पत्नीमा भराग्निं मन्थाम पूर्वथा ||","b":"অস্তীদমধিমন্থনমস্তি পরজননং কর্তম | এতাং বিশ্পত্নীমা ভরাগ্নিং মন্থাম পূর্বথা ||","e":"HERE is the gear for friction, here tinder made ready for the spark. Bring thou the Matron: we will rub Agni in ancient fashion forth.","mb":"এ মন্থনের উপকরণ, এ অগ্নি উৎপত্তির উপকরণ, লোকের পালয়িত্তী অরণিকে আহরণ কর। আমরা পূর্বকালের ন্যায় অগ্নিকে মন্থন করব।"},{"n":2,"d":"अरण्योर्निहितो जातवेदा गर्भ इव सुधितो गर्भिणीषु | दिवे-दिव ईड्यो जाग्र्वद्भिर्हविष्मद्भिर्मनुष्येभिरग्निः ||","b":"অরণ্যোর্নিহিতো জাতবেদা গর্ভ ইব সুধিতো গর্ভিণীষু | দিবে-দিব ঈড্যো জাগ্র্বদ্ভির্হবিষ্মদ্ভির্মনুষ্যেভিরগ্নিঃ ||","e":"1n the two fire-sticks Jātavedas lieth, even as the well-set germ in pregnant women, Agni who day by day must be exalted by men who watch and worship with oblations.","mb":"গর্ভিণীতে সুসংস্থাপিত গর্ভের ন্যায় জাতবেদা অগ্নি অরণিদ্বয়ে নিহিত আছেন। অগ্নি স্বকর্মে জাগরুক হর্বিযুক্ত মানুষদের প্রতিদিন পূজনীয়।"},{"n":3,"d":"उत्तानायामव भरा चिकित्वान सद्यः परवीता वर्षणं जजान | अरुषस्तूपो रुशदस्य पाज इळायास पुत्रो वयुने.अजनिष्ट ||","b":"উত্তানাযামব ভরা চিকিত্বান সদ্যঃ পরবীতা বর্ষণং জজান | অরুষস্তূপো রুশদস্য পাজ ইলাযাস পুত্রো বযুনে.অজনিষ্ট ||","e":"Lay this with care on that which lies extended: straight hath she borne the Steer when made prolific. With his red pillar—radiant is his splendour—in our skilled task is born the Son of Iḷā.","mb":"হে জ্ঞানবান অধ্বর্যু! তুমি ঊর্ধ্বমুখ অরণিতে অধোমুখ অরণি ধারণ কর। তৎক্ষনাৎ গর্ভবতী অরণি অভীষ্টবর্ষী অগ্নিকে উৎপন্ন করল। অগ্নির দাহক তাতে ছিল। উজ্জ্বল তেজবিশিষ্ট ইলার পুত্র অগ্নি অরণিতে উৎপন্ন হলেন।"},{"n":4,"d":"इळायास्त्वा पदे वयं नाभा पर्थिव्या अधि | जातवेदो नि धीमह्यग्ने हव्याय वोळ्हवे ||","b":"ইলাযাস্ত্বা পদে বযং নাভা পর্থিব্যা অধি | জাতবেদো নি ধীমহ্যগ্নে হব্যায বোল্হবে ||","e":"In Iḷā's place we set thee down, upon the central point of earth, That, Agni Jātavedas, thou mayst bear our offerings to the Gods.","mb":"হে জাতবেদা অগ্নি! আমরা তোমাকে পৃথিবীর উপরে উত্তর বেদির নাভিস্থলে হব্য বহন করবার জন্য স্থাপন করছি।"},{"n":5,"d":"मन्थता नरः कविमद्वयन्तं परचेतसमम्र्तं सुप्रतीकम | यज्ञस्य केतुं परथमं पुरस्तादग्निं नरो जनयता सुशेवम ||","b":"মন্থতা নরঃ কবিমদ্বযন্তং পরচেতসমম্র্তং সুপ্রতীকম | যজ্ঞস্য কেতুং পরথমং পুরস্তাদগ্নিং নরো জনযতা সুশেবম ||","e":"Rub into life, ye men, the Sage, the guileless, Immortal, very wise and fair to look on. O men, bring forth the most propitious Agni, first ensign of the sacrifice to eastward.","mb":"হে নেতা অধ্বর্যুগণ! কবি, দ্বিধারহিত প্রকৃষ্ট জ্ঞঝানবান মরণরহিত ও সুন্দর শরীর বিশিষ্ট অগ্নিকে মন্থনদ্বারা উৎপন্ন কর। হে নেতা অধ্বর্যুগণ! যজ্ঞের সুচক, প্রথম ও সুখকর অগ্নিকে কর্মের প্রারম্ভে উৎপন্ন কর।"},{"n":6,"d":"यदी मन्थन्ति बाहुभिर्वि रोचते.अश्वो न वाज्यरुषो वनेष्वा | चित्रो न यामन्नश्विनोरनिव्र्तः परि वर्णक्त्यश्मनस्त्र्णा दहन ||","b":"যদী মন্থন্তি বাহুভির্বি রোচতে.অশ্বো ন বাজ্যরুষো বনেষ্বা | চিত্রো ন যামন্নশ্বিনোরনিব্র্তঃ পরি বর্ণক্ত্যশ্মনস্ত্র্ণা দহন ||","e":"When with their arms they rub him straight he shineth forth like a strong courser, red in colour, in the wood. Bright, checkless, as it were upon the Aśvins' path, he passeth by the stones and burneth up the grass.","mb":"যখন হস্তদ্বারা মন্থন করা যায়, তখন কাষ্ঠ হতে অগ্নি অশ্বের ন্যায় শোভমান হয়ে ও দ্রুতগামী অশ্বিদ্বয়ের বিচিত্র রথের ন্যায় শীঘ্র গমনশীল হয়ে শোভা পান। কেউ তার মনরোধ করতে পারে না। তিনি তৃণ ও উপল দগ্ধ করে সে স্থান পরিত্যাগ করেন।"},{"n":7,"d":"जातो अग्नी रोचते चेकितानो वाजी विप्रः कविशस्तः सुदानुः | यं देवास ईड्यं विश्वविदं हव्यवाहमदधुरध्वरेषु ||","b":"জাতো অগ্নী রোচতে চেকিতানো বাজী বিপ্রঃ কবিশস্তঃ সুদানুঃ | যং দেবাস ঈড্যং বিশ্ববিদং হব্যবাহমদধুরধ্বরেষু ||","e":"Agni shines forth when born, observant, mighty, the bountiful, the Singer praised by sages; Whom, as adorable and knowing all things, Gods set at solemn rites as offering-bearer.","mb":"জাত অগ্নিও সর্বজ্ঞ, অপ্রতিহতগমন, কর্মকুশল, অতএব মেধাবীরা তার স্তব করে। তিনি কর্মফল প্রদান করে শোভা পাচ্ছেন। দেবগণ পূজনীয়, সর্বজ্ঞ অগ্নিকে যজ্ঞে হব্যবাহক করেছেন।"},{"n":8,"d":"सीद होतः सव उ लोके चिकित्वान सादया यज्ञं सुक्र्तस्य योनौ | देवावीर्देवान हविषा यजास्यग्ने बर्हद यजमाने वयो धाः ||","b":"সীদ হোতঃ সব উ লোকে চিকিত্বান সাদযা যজ্ঞং সুক্র্তস্য যোনৌ | দেবাবীর্দেবান হবিষা যজাস্যগ্নে বর্হদ যজমানে বযো ধাঃ ||","e":"Set thee, O Priest, in, thine own place, observant: lay down the sacrifice in the home of worship. Thou, dear to Gods, shalt serve them with oblation: Agni, give long life to the sacrificer.","mb":"হে হোমনিষ্পাদক অগ্নি! তুমি স্বস্থানে উপবেশন কর। তুমি সর্বজ্ঞ, তুমি যজমানকে পুণ্যলোকে স্থাপন কর। তুমি দেবগণের রক্ষক, হব্যদ্বারা দেবগণের পূজা কর। আমি যজ্ঞঝ করছি, আমাকে প্রভূত অন্ন প্রদান কর।"},{"n":9,"d":"कर्णोत धूमं वर्षणं सखायो.अस्रेधन्त इतन वाजमछ | अयमग्निः पर्तनाषाट सुवीरो येन देवासो असहन्त दस्यून ||","b":"কর্ণোত ধূমং বর্ষণং সখাযো.অস্রেধন্ত ইতন বাজমছ | অযমগ্নিঃ পর্তনাষাট সুবীরো যেন দেবাসো অসহন্ত দস্যূন ||","e":"Raise ye a mighty smoke, my fellow-workers! Ye shall attain to wealth without obstruction. This Agni is the battle-winning Hero by whom the Gods have overcome the Dasyus.","mb":"হে অধ্বর্যুগণ! তোমরা অভীষ্টবর্ষী ধুম উৎপন্ন কর, তোমরা ক্ষীণ না হয়ে যুদ্ধের অভিমুখে যাও। এ অগ্নি বীরপ্রধান ও সেনাবিজয়ী এর সাহায্যেই দেবগণ দস্যুদের পরাজয়  করেছেন।"},{"n":10,"d":"अयं ते योनिर्र्त्वियो यतो जातो अरोचथाः | तं जानन्नग्न आ सीदाथा नो वर्धया गिरः ||","b":"অযং তে যোনির্র্ত্বিযো যতো জাতো অরোচথাঃ | তং জানন্নগ্ন আ সীদাথা নো বর্ধযা গিরঃ ||","e":"This is thine ordered place of birth whence sprung to life thou shonest forth. Knowing this, Agni, sit thee down, and prosper thou the songs we sing.","mb":"হে অগ্নি! ঋতু কাষ্ঠ সম্পন্ন এ অরণি তোমার উৎপত্তির স্থান! তা হতে উৎপন্ন হয়ে তুমি শোভা পাও। তুমি তা জেনে উপবেশন কর, আমাদের স্তুতি বর্ধিত কর।"},{"n":11,"d":"तनूनपादुच्यते गर्भ आसुरो नराशंसो भवति यद विजायते | मातरिश्वा यदमिमीत मातरि वातस्य सर्गो अभवत्सरीमणि ||","b":"তনূনপাদুচ্যতে গর্ভ আসুরো নরাশংসো ভবতি যদ বিজাযতে | মাতরিশ্বা যদমিমীত মাতরি বাতস্য সর্গো অভবত্সরীমণি ||","e":"As Germ Celestial he is called Tanūnapāt, and Narāśaṁsa born diffused in varied shape. Formed in his Mother he is Mātariśvan; he hath, in his course, become the rapid flight of wind.","mb":"গর্ভস্থ অগ্নিকে তনুনপাৎ বলে। অগ্নি যখন প্রত্যক্ষ হন তখন তিনি আসুর (১) নরাশংস হজন। যখন অন্তরীক্ষে তেজবিকাশ করেন তখন মাতরিশ্বা হন (২)। অগ্নি প্রসৃত হলে বায়ুর উৎপত্তি হয়।"},{"n":12,"d":"सुनिर्मथा निर्मथितः सुनिधा निहितः कविः | अग्ने सवध्वरा कर्णु देवान देवयते यज ||","b":"সুনির্মথা নির্মথিতঃ সুনিধা নিহিতঃ কবিঃ | অগ্নে সবধ্বরা কর্ণু দেবান দেবযতে যজ ||","e":"With strong attrition rubbed to life, laid down with careful hand, a Sage, Agni, make sacrifices good, and for the pious bring the Gods.","mb":"হে অগ্নি! তুমি মেধাবী ও মন্থন দ্বারা উৎপন্ন, তোমাকে অতি উত্তম স্থানে স্থাপন করেছে। তুমি আমাদের যজ্ঞ দ্বারা নির্বিঘ্ন কর এবং দেবাভিলাষীর জন্য দেবগণকে পূজা কর।"},{"n":13,"d":"अजीजनन्नम्र्तं मर्त्यासो.अस्रेमाणं तरणिं वीळुजम्भम | दश सवसारो अग्रुवः समीचीः पुमांसं जातमभि सं रभन्ते ||","b":"অজীজনন্নম্র্তং মর্ত্যাসো.অস্রেমাণং তরণিং বীলুজম্ভম | দশ সবসারো অগ্রুবঃ সমীচীঃ পুমাংসং জাতমভি সং রভন্তে ||","e":"Mortals have brought to life the God Immortal, the Conqueror with mighty jaws, unfailing. The sisters ten, unwedded and united, together grasp the Babe, the new-born Infant.","mb":"মর্ত্য ঋত্বিকগণ মরণরহিত, ক্ষয়রহিত, দৃঢ় দন্তবিশিষ্ট পাপতারক অগ্নিকে উৎপন্ন করেছে। পুত্রসন্তানের ন্যায় উৎপন্ন অগ্নির উদ্দেশে দশ ভগিনীরূপ অঙ্গুলি পরস্পর মিলিত হয়ে আনন্দসূচক শব্দ করছে।"},{"n":14,"d":"पर सप्तहोता सनकादरोचत मातुरुपस्थे यदशोचदूधनि | न नि मिषति सुरणो दिवे-दिवे यदसुरस्य जठरादजायत ||","b":"পর সপ্তহোতা সনকাদরোচত মাতুরুপস্থে যদশোচদূধনি | ন নি মিষতি সুরণো দিবে-দিবে যদসুরস্য জঠরাদজাযত ||","e":"Served by the seven priests, he shone forth from ancient time, when in his Mother's bosom, in her lap, he glowed. Giving delight each day he closeth not his eye, since from the Asura's body hewas brought to life.","mb":"অগ্নি সনাতন, যখন সাতজনে তার হোম করে, তখন তিনি শোভা পান। যখন তিনি মাতার স্তনে ও ক্রোড়ে শোভা পান, তখন তিনি দেখতে সুন্দর হন। তিনি প্রতিদিন উন্মেষিত থাকেন যেহেতু তিনি অসুরের কঠর হতে উৎপন্ন হয়েছেন।"},{"n":15,"d":"अमित्रायुधो मरुतामिव परयाः परथमजा बरह्मणो विश्वमिद विदुः | दयुम्नवद बरह्म कुशिकास एरिर एक-एको दमे अग्निं समीधिरे ||","b":"অমিত্রাযুধো মরুতামিব পরযাঃ পরথমজা বরহ্মণো বিশ্বমিদ বিদুঃ | দযুম্নবদ বরহ্ম কুশিকাস এরির এক-একো দমে অগ্নিং সমীধিরে ||","e":"Even as the Maruts, onslaughts who attack the foe, those born the first of all knew the full power of prayer. The Kuśikas have made the glorious hymn ascend, and, each one singly in his home, have kindled fire.","mb":"মরুৎগণের ন্যায় শত্রুর সাথে যুদ্ধকারী ও মন্ত্র হতে প্রথম উৎপন্ন, কুশিক গেহাত্রোৎপন্ন ঋষিগণ নিশ্চয়ই সমস্ত জগৎ জানেন। তারা অগ্নির উদ্দেশে হব্যযুক্ত স্তোত্র পাঠ করছেন এবং প্রত্যেকে আপন আপন গৃহে অগ্নিকে দীপ্ত করছেন।"},{"n":16,"d":"यदद्य तवा परयति यज्ञे अस्मिन होतश्चिकित्वो.अव्र्णीमहीह | धरुवमया धरुवमुताशमिष्ठाः परजानन विद्वानुप याहि सोमम ||","b":"যদদ্য তবা পরযতি যজ্ঞে অস্মিন হোতশ্চিকিত্বো.অব্র্ণীমহীহ | ধরুবমযা ধরুবমুতাশমিষ্ঠাঃ পরজানন বিদ্বানুপ যাহি সোমম ||","e":"As we, O Priest observant, have elected thee this day, what time the solemn sacrifice began, So surely hast thou worshipped, surely hast thou toiled: come thou unto the Soma, wise and knowing all.","mb":"হে হোমনিষ্পাদক বিদ্বান সর্বজ্ঞ অগ্নি! প্রবর্তিত যজ্ঞে তোমাকে বরণ করছি। অতএব তুমি এ যজ্ঞে দেবগণের হব্য প্রদান কর এবং নিত্য স্তব কর, সোমের বিষয় অবগত হয়ে তার নিকট এস।"}]},{"n":30,"t":"Indra","v":[{"n":1,"d":"इछन्ति तवा सोम्यासः सखायः सुन्वन्ति सोमं दधति परयांसि | तितिक्षन्ते अभिशस्तिं जनानामिन्द्र तवदा कश्चन हि परकेतः ||","b":"ইছন্তি তবা সোম্যাসঃ সখাযঃ সুন্বন্তি সোমং দধতি পরযাংসি | তিতিক্ষন্তে অভিশস্তিং জনানামিন্দ্র তবদা কশ্চন হি পরকেতঃ ||","e":"THE friends who offer Soma long to find thee: they pour forth Soma and present their viands. They bear unmoved the cursing of the people, for all our wisdom comes from thee, O Indra.","mb":"হে ইন্দ্র! সোমাহ ঋত্বিকগণ তোমাকে স্তব করতে ইচ্ছা করছেন। সখাগণ তোমার জন্য সোম অভিষবণ করছেন, অন্যান্য হব্য ধারণ করছেন, শত্রু লোকদের হিংসা সহ্য করছেন। কে তোমার চেয়ে জগতে অধিক প্রখ্যাত?"},{"n":2,"d":"न ते दूरे परमा चिद रजांस्या तु पर याहि हरिवो हरिभ्याम | सथिराय वर्ष्णे सवना कर्तेमा युक्ता गरावाणः समिधाने अग्नौ ||","b":"ন তে দূরে পরমা চিদ রজাংস্যা তু পর যাহি হরিবো হরিভ্যাম | সথিরায বর্ষ্ণে সবনা কর্তেমা যুক্তা গরাবাণঃ সমিধানে অগ্নৌ ||","e":"Not far for thee are mid-air's loftiest regions: start hither, Lord of Bays, with thy Bay Horses. Made for the Firm and Strong are these libations. The pressing-stones are set and fire is kindled.","mb":"হে হরিবর্ণ অশ্ববিশিষ্ট ইন্দ্র! দূরবর্তী স্থান সকলও তোমার পক্ষে দূরে নয়, তুমি হরিবর্ণ অশ্ব যুক্ত হয়ে শীঘ্র এস। তুমি দৃঢ়চিত্ত ও অভীষ্টবর্ষী। তোমার উদ্দেশে এ সকল সবন করা হয়েছে, অগ্নি সমিদ্ধ হলে সোমাভিষবের জন্য প্রস্তর খন্ডসকল প্রযুক্ত হয়েছে।"},{"n":3,"d":"इन्द्रः सुशिप्रो मघवा तरुत्रो महाव्रातस्तुविकूर्मिर्र्घावान | यदुग्रो धा बाधितो मर्त्येषु कव तया ते वर्षभ वीर्याणि ||","b":"ইন্দ্রঃ সুশিপ্রো মঘবা তরুত্রো মহাব্রাতস্তুবিকূর্মির্র্ঘাবান | যদুগ্রো ধা বাধিতো মর্ত্যেষু কব তযা তে বর্ষভ বীর্যাণি ||","e":"Fair cheeks hath Indra, Maghavan, the Victor, Lord of a great host, Stormer, strong in action. What once thou didst in might when mortals vexed thee,—where now, O Bull, are those thy hero exploits?","mb":"হে অভীষ্টবর্ষী ইন্দ্র! তুমি পরমেশ্বর্ষ সম্পন্ন, তোমার শিপ্র সুন্দর, তুমি ধনবান, জেতা, মহান মরুৎগণ সম্পন্ন ও সংগ্রামে নানাবিধ  কর্মকারী এবং শত্রুহিংসক ও ভয়ঙ্কর। তুমি সংগ্রামে বাধা পেয়ে মর্ত্যদের প্রতি যে বীর্য ধারণ করেছিলে, তোমার সে বীর্য কোথায়!"},{"n":4,"d":"तवं हि षमा चयावयन्नच्युतान्येको वर्त्रा चरसि जिघ्नमानः | तव दयावाप्र्थिवी पर्वतासो.अनु वरताय निमितेव तस्थुः ||","b":"তবং হি ষমা চযাবযন্নচ্যুতান্যেকো বর্ত্রা চরসি জিঘ্নমানঃ | তব দযাবাপ্র্থিবী পর্বতাসো.অনু বরতায নিমিতেব তস্থুঃ ||","e":"For, overthrowing what hath ne’er been shaken, thou goest forth alone destroying Vṛtras. For him who followeth thy Law the mountains and heaven and earth stand as if firmly stablished.","mb":"হে ইন্দ্র! তুমি একাকীই, দৃঢ়মুল রাক্ষসগণকে স্বস্থান হতে পতিত করেছ, বৃত্ত সকলকে হিংসা করেছ। তোমার আজ্ঞায় দ্যাবাপৃথিবী এবং পর্বত সকল নিশলের ন্যায় রয়েছে।"},{"n":5,"d":"उताभये पुरुहूत शरवोभिरेको दर्ळ्हमवदो वर्त्रहा सन | इमे चिदिन्द्र रोदसी अपारे यत संग्र्भ्णा मघवन काशिरित ते ||","b":"উতাভযে পুরুহূত শরবোভিরেকো দর্ল্হমবদো বর্ত্রহা সন | ইমে চিদিন্দ্র রোদসী অপারে যত সংগ্র্ভ্ণা মঘবন কাশিরিত তে ||","e":"Yea, Much-invoked! in safety through thy glories alone thou speakest truth as Vṛtra's slayer. E’en these two boundless worlds to thee, O Indra, what time thou graspest them, are but a handful.","mb":"হে ইন্দ্র! তুমি বহুলোকের আহুত ও বীর্যযুক্ত, তুমি একাকী বৃত্তকে বধ করে দেবতাগণকে যে অভয় বাক্য দান করেছিলে, তা সত্য। হে মঘবন! তুমি অপার দ্যাবাপৃথিবীকে সংযোজিত করছ। তোমার এ মহিমা প্রসিদ্ধ আছে।"},{"n":6,"d":"पर सू त इन्द्र परवता हरिभ्यां पर ते वज्रः परम्र्णन्नेतु शत्रून | जहि परतीचो अनूचः पराचो विश्वं सत्यंक्र्णुहि विष्टमस्तु ||","b":"পর সূ ত ইন্দ্র পরবতা হরিভ্যাং পর তে বজ্রঃ পরম্র্ণন্নেতু শত্রূন | জহি পরতীচো অনূচঃ পরাচো বিশ্বং সত্যংক্র্ণুহি বিষ্টমস্তু ||","e":"Forthwith thy Bay steeds down the steep, O Indra, forth, crushing foemen, go thy bolt of thunder! Slay those who meet thee, those who flee, who follow: make all thy promise true; be all completed.","mb":"হে ইন্দ্র! তোমার অশ্বযুক্ত রথ শত্রুকে লক্ষ্য করে নিষ্মপথে শীঘ্র আসুক, তোমার  বজ্র শত্রুকে বধ করতে করতে আসুক। তেমার সম্মুখে আগমনকারী শত্রুদের অনুগমনকারী শত্রুদের পলায়ন পর শত্রুদের বধ কর, জগৎকে সত্যভূত যজ্ঞ বিশিষ্ট কর। এই প্রকার সামর্থ্য তোমাতে বিনষ্ট হোক।"},{"n":7,"d":"यस्मै धायुरदधा मर्त्यायाभक्तं चिद भजते गेह्यं सः | भद्रा त इन्द्र सुमतिर्घ्र्ताची सहस्रदाना पुरुहूत रातिः ||","b":"যস্মৈ ধাযুরদধা মর্ত্যাযাভক্তং চিদ ভজতে গেহ্যং সঃ | ভদ্রা ত ইন্দ্র সুমতির্ঘ্র্তাচী সহস্রদানা পুরুহূত রাতিঃ ||","e":"The man to whom thou givest as Provider enjoys domestic plenty undivided. Blest, Indra, is thy favour dropping fatness: thy worship, Much-invoked! brings gifts in thousands.","mb":"হে ইন্দ্র! তুমি নিরন্তর ঐশ্বর্য ধারণ করছ, তুমি যে মানুষকে দান কর, সে পূর্বে অলব্ধ গৃহসম্বন্ধীর পশু সুবর্ণ প্রভৃতি ধন প্রাপ্ত হয়। হে বহুলোকের আহুত। তোমার অনুগ্রহ ঘৃতাদি হব্যযুক্ত হয়ে কল্যাণকর হয়, তোমার ধনদান শক্তি অপরিমিত।"},{"n":8,"d":"सहदानुं पुरुहूत कषियन्तमहस्तमिन्द्र सं पिणक कुणारुम | अभि वर्त्रं वर्धमानं पियारुमपादमिन्द्र तवसा जघन्थ ||","b":"সহদানুং পুরুহূত কষিযন্তমহস্তমিন্দ্র সং পিণক কুণারুম | অভি বর্ত্রং বর্ধমানং পিযারুমপাদমিন্দ্র তবসা জঘন্থ ||","e":"Thou, Indra, Much-invoked! didst crush to pieces Kunaru handless fiend who dwelt with Danu. Thou with might, Indra, smotest dead the scorner, the footless Vṛtra as he waxed in vigour.","mb":"হে বহুলোকের আহুত ইন্দ্র! তুমি দানবীর সাথে বর্তমান, বাধা জনক গর্জনশীল বৃত্রকে হস্তহীন করে বিচুর্ণিত করে ফেল। হে ইন্দ্র! তুমি বর্ধমান, হিস্রে বৃত্তকে পাদহীন করে বল দ্বারা বিনাশ করেছিলে।"},{"n":9,"d":"नि सामनामिषिरामिन्द्र भूमिं महीमपारां सदने ससत्थ | अस्तभ्नाद दयां वर्षभो अन्तरिक्षमर्षन्त्वापस्त्वयेह परसूताः ||","b":"নি সামনামিষিরামিন্দ্র ভূমিং মহীমপারাং সদনে সসত্থ | অস্তভ্নাদ দযাং বর্ষভো অন্তরিক্ষমর্ষন্ত্বাপস্ত্বযেহ পরসূতাঃ ||","e":"Thou hast established in her seat, O Indra, the level earth, vast, vigorous, unbounded. The Bull hath propped the heaven and air's mid-region. By thee sent onward let the floods flow hither.","mb":"হে ইন্দ্র! তুমি মহতী, অনন্ত, চলা পৃথিবীকে সমভাবাপন্ন করে স্বস্থানে নিবেশিত করেছিলে। অভীষ্টবর্ষী ইন্দ্র দ্যুলোক ও অন্তরীক্ষ যাতে পতিত না হয় এরূপে ধারণ করেছেন। হে ইন্দ্র! তোমার প্রেরিত জল পৃথিবীতে আসুক।"},{"n":10,"d":"अलात्र्णो वल इन्द्र वरजो गोः पुरा हन्तोर्भयमानो वयार | सुगान पथो अक्र्णोन निरजे गाः परावन वाणीः पुरुहूतं धमन्तीः ||","b":"অলাত্র্ণো বল ইন্দ্র বরজো গোঃ পুরা হন্তোর্ভযমানো বযার | সুগান পথো অক্র্ণোন নিরজে গাঃ পরাবন বাণীঃ পুরুহূতং ধমন্তীঃ ||","e":"He who withheld the kine, in silence I yielded in fear before thy blow, O Indra. He made paths easy to drive forth the cattle. Loud-breathing praises helped the Much-invoked One.","mb":"হে ইন্দ্র! বল নামক গোব্রজবজ্র প্রহারের পূর্বেই ভীত হয়ে বিশ্লিষ্ট হয়েছিল। ইন্দ্র গভীর নির্গমনের জন্য পথ সুগম করেছেন, রমণীয় শব্দায়মান জল সকল, বহুলোকের আহুত ইন্দ্রের অভিমুখে আগমন করেছিল।"},{"n":11,"d":"एको दवे वसुमती समीची इन्द्र आ पप्रौ पर्थिवीमुत दयाम | उतान्तरिक्षादभि नः समीक इषो रथीः सयुजः शूर वाजान ||","b":"একো দবে বসুমতী সমীচী ইন্দ্র আ পপ্রৌ পর্থিবীমুত দযাম | উতান্তরিক্ষাদভি নঃ সমীক ইষো রথীঃ সযুজঃ শূর বাজান ||","e":"Indra alone filled full the earth and heaven, the Pair who meet together, rich in treasures. Yea, bring thou near us from the air's mid-region strength, on thy car, and wholesome food, O Hero.","mb":"এক ইন্দ্রই পৃথিবী ও দ্যুলোক এ দুটিকে পরস্পর সঙ্গত ও ধনযুক্ত করে পরিপূর্ণ করেছেন। হে শুর! তুমি রথবান, তুমি আমাদের সমীপে অবস্থান করতে অভিলাষী হয়ে যোজিত অশ্বগণকে অন্তরীক্ষ হতে আমাদের অভিমুখে প্রেরণ কর।"},{"n":12,"d":"दिशः सूर्यो न मिनाति परदिष्टा दिवे-दिवे हर्यश्वप्रसूताः | सं यदानळ अध्वन आदिदश्वैर्विमोचनं कर्णुते तत तवस्य ||","b":"দিশঃ সূর্যো ন মিনাতি পরদিষ্টা দিবে-দিবে হর্যশ্বপ্রসূতাঃ | সং যদানল অধ্বন আদিদশ্বৈর্বিমোচনং কর্ণুতে তত তবস্য ||","e":"Sūrya transgresses not the ordered limits set daily by the Lord of Tawny Coursers. When to the goal he comes, his journey ended, his Steeds he looses: this is Indra's doing.","mb":"সূর্য, ইন্দ্র প্রেরিত এবং তার গমনার্থে প্রকাশিত দিক সকলকে প্রতিদিবস অনুসরণ করেন। যখন তিনি অশ্বদ্বারা পথ গমন শেষ করেন, তখন অশ্বদের ছেড়ে দেন, এও ইন্দ্রের জন্য।"},{"n":13,"d":"दिद्र्क्षन्त उषसो यामन्नक्तोर्विवस्वत्या महि चित्रमनीकम | विश्वे जानन्ति महिना यदागादिन्द्रस्य कर्म सुक्र्तापुरूणि ||","b":"দিদ্র্ক্ষন্ত উষসো যামন্নক্তোর্বিবস্বত্যা মহি চিত্রমনীকম | বিশ্বে জানন্তি মহিনা যদাগাদিন্দ্রস্য কর্ম সুক্র্তাপুরূণি ||","e":"Men gladly in the course of night would look on the broad bright front of the refulgent Morning; And all acknowledge, when she comes in glory, the manifold and goodly works of Indra.","mb":"গমনশীল রাত্রির পর ঊষা গত হলে সকলে মহৎ, চিত্র, সৌর, তেজ দর্শন করতে ইচ্ছা করে। যখন ঊষাকাল বিগত হয়, সকলে অগ্নিহোত্রাদি কমর্স কর্তব্য বলে বোধ করে। ইন্দ্রের সৎকার্য অনেক।"},{"n":14,"d":"महि जयोतिर्निहितं वक्षणास्वामा पक्वं चरति बिभ्रती गौः | विश्वं सवाद्म सम्भ्र्तमुस्रियायां यत सीमिन्द्रो अदधाद भोजनाय ||","b":"মহি জযোতির্নিহিতং বক্ষণাস্বামা পক্বং চরতি বিভ্রতী গৌঃ | বিশ্বং সবাদ্ম সম্ভ্র্তমুস্রিযাযাং যত সীমিন্দ্রো অদধাদ ভোজনায ||","e":"A mighty splendour rests upon her bosom: bearing ripe milk the Cow, unripe, advances. All sweetness is collected in the Heifer, sweetness which Indra made for our enjoyment.","mb":"ইন্দ্র নদী সকলে মহৎ তেজযুক্ত জল স্থাপিত করেছিলেন। ইন্দ্র জল অপেক্ষা স্বদুতর দধিঘৃত ক্ষীরাদি ভোজনের জন্য গাভীতে স্থাপন করেছেন। নবপ্রসুতা গাভী দুগ্ধ ধারণ করে বিচরণ করে।"},{"n":15,"d":"इन्द्र दर्ह्य यामकोशा अभूवन यज्ञाय शिक्ष गर्णते सखिभ्यः | दुर्मायवो दुरेवा मर्त्यासो निषङगिणो रिपवो हन्त्वासः ||","b":"ইন্দ্র দর্হ্য যামকোশা অভূবন যজ্ঞায শিক্ষ গর্ণতে সখিভ্যঃ | দুর্মাযবো দুরেবা মর্ত্যাসো নিষঙগিণো রিপবো হন্ত্বাসঃ ||","e":"Barring the way they come. Be firm, O Indra; aid friends to sacrifice and him who singeth. These must be slain by thee, malignant mortals, armed with ill arts, our quiverbearing foemen.","mb":"হে ইন্দ্র। তুমি দৃঢ় হও, শত্রুগণ পথ রোধ করেছে। তুমি, যজ্ঞকারী স্তুতিকারী ও সখাদের অভীষ্ট ফল দান কর। রিপুগণকে বধ করা উচিত। তারা মন্দভাবে অস্ত্র প্রক্ষেপ করে, মন্দভাবে গমন করে, তারা হত্যাকারী ও তুণীর বিশিষ্ট।"},{"n":16,"d":"सं घोषः शर्ण्वे.अवमैरमित्रैर्जही नयेष्वशनिं तपिष्ठाम | वर्श्चेमधस्ताद वि रुजा सहस्व जहि रक्षो मघवन रन्धयस्व ||","b":"সং ঘোষঃ শর্ণ্বে.অবমৈরমিত্রৈর্জহী নযেষ্বশনিং তপিষ্ঠাম | বর্শ্চেমধস্তাদ বি রুজা সহস্ব জহি রক্ষো মঘবন রন্ধযস্ব ||","e":"A cry is beard from enemies most near us: against them send thy fiercest-flaming weapon. Rend them from under, crush them and subdue them. Slay, Maghavan, and make the fiends our booty.","mb":"হে ইন্দ্র! আমরা সমীপন্থ শত্রুগণ কর্তৃক উৎসৃষ্ট অশনিশব্দ শুনতে পাচ্ছি। অত্যন্ত সন্তাপকর ঐ সকল অশনিকে এ সকল শত্রুদের অভিমুখেই স্থাপন করে এদের বধ কর, সমুলে ছেদন কর, বিশেষরূপে বাধা দাও ও অভিভূত কর। হে মঘবন, রাক্ষদের বধ কর, তারপর যজ্ঞ সম্পন্ন কর।"},{"n":17,"d":"उद वर्ह रक्षः सहमूलमिन्द्र वर्श्चा मध्यं परत्यग्रंश्र्णीहि | आ कीवतः सललूकं चकर्थ बरह्मद्विषे तपुषिं हेतिमस्य ||","b":"উদ বর্হ রক্ষঃ সহমূলমিন্দ্র বর্শ্চা মধ্যং পরত্যগ্রংশ্র্ণীহি | আ কীবতঃ সললূকং চকর্থ বরহ্মদ্বিষে তপুষিং হেতিমস্য ||","e":"Root up the race of Rākṣasas, O Indra rend it in front and crush it in the middle. How long hast thou bebaved as one who wavers? Cast thy hot dart at him who hates devotion:","mb":"হে ইন্দ্র! রাক্ষকুল সমুলে উৎপাটন কর, মধ্যভাগ ছেদন কর, অগ্রভাগ বিনাশ কর।  গমনশীল রাক্ষসকে দূর কর, যজ্ঞ বিদ্বেষীর প্রতি সন্তাপপ্রদ অস্ত্র প্রক্ষেপ কর।"},{"n":18,"d":"सवस्तये वाजिभिश्च परणेतः सं यन महीरिष आसत्सिपूर्वीः | रायो वन्तारो बर्हतः सयामास्मे अस्तु भग इन्द्रप्रजावान ||","b":"সবস্তযে বাজিভিশ্চ পরণেতঃ সং যন মহীরিষ আসত্সিপূর্বীঃ | রাযো বন্তারো বর্হতঃ সযামাস্মে অস্তু ভগ ইন্দ্রপ্রজাবান ||","e":"When borne by strong Steeds for our weal, O Leader, thou seatest thee at many noble viands. May we be winners of abundant riches. May Indra be our wealth with store of children.","mb":"হে জগতের নির্বাহক! আমাদের অশ্বযুক্ত কর ও অবিনাশী কর। তুমি যখন আমাদের নিকট থাক আমসরা মহৎ অন্ন ও প্রভূত ধন ভোগ করে বড় হতে পারব। আমাদের পুত্র পৌত্রাদিযুক্ত ধন হোক।"},{"n":19,"d":"आ नो भर भगमिन्द्र दयुमन्तं नि ते देष्णस्य धीमहि पररेके | ऊर्व इव पप्रथे कामो अस्मे तमा पर्ण वसुपते वसूनाम ||","b":"আ নো ভর ভগমিন্দ্র দযুমন্তং নি তে দেষ্ণস্য ধীমহি পররেকে | ঊর্ব ইব পপ্রথে কামো অস্মে তমা পর্ণ বসুপতে বসূনাম ||","e":"Bestow on us resplendent wealth. O Indra let us enjoy thine overflow of bounty. Wide as a sea our longing hath expanded, fulfil it, O thou Treasure-Lord of treasures.","mb":"হে ইন্দ্র! আমাদের জন্য দীপ্তিযুক্ত ধন আন। তুমি দানশীল আমরা তোমার দানের পাত্র, আমাদের অভিলাষ বড়বানলের ন্যায় বৃদ্ধি প্রাপ্ত  হয়েছে। হে ধনপতি! আমাদের অভিলাষ পূর্ণ কর।"},{"n":20,"d":"इमं कामं मन्दया गोभिरश्वैश्चन्द्रवता राधसा पप्रथश्च | सवर्यवो मतिभिस्तुभ्यं विप्रा इन्द्राय वाहःकुशिकासो अक्रन ||","b":"ইমং কামং মন্দযা গোভিরশ্বৈশ্চন্দ্রবতা রাধসা পপ্রথশ্চ | সবর্যবো মতিভিস্তুভ্যং বিপ্রা ইন্দ্রায বাহঃকুশিকাসো অক্রন ||","e":"With kine and horses satisfy this longing with very splendid bounty skill extend it. Seeking the light, with hymns to thee, O Indra, Kuśikas have brought their gift, the singers.","mb":"আমাদে এ অভিলাষ, গো, অশ্ব ও দীপ্তিযুক্ত ধন দ্বারা পূর্ণ কর এবং তা দিয়ে আমাদের বিখ্যাত কর। হে ইন্দ্র! স্বর্গাদিসুখাভিলাষী কর্মকুশল কুশিকনন্দনগণ মন্ত্রদ্বারা তোমার স্তোত্র করেছেন।"},{"n":21,"d":"आ नो गोत्रा दर्द्र्हि गोपते गाः समस्मभ्यं सनयो यन्तु वाजाः | दिवक्षा असि वर्षभ सत्यशुष्मो.अस्मभ्यं सु मघवन बोधि गोदाः ||","b":"আ নো গোত্রা দর্দ্র্হি গোপতে গাঃ সমস্মভ্যং সনযো যন্তু বাজাঃ | দিবক্ষা অসি বর্ষভ সত্যশুষ্মো.অস্মভ্যং সু মঘবন বোধি গোদাঃ ||","e":"Lord of the kine, burst the kine's stable open: cows shall be ours, and strength that wins the booty. Hero, whose might is true, thy home is heaven: to us, O Maghavan, grant gifts of cattle.","mb":"হে স্বর্গাধিপতি! মেঘ বিদীর্ণ করে আমাদের জল দান কর, উপভোগযোগ্য অন্ন আমাদের নিকট আসুক। হে অভীষ্টবর্ষী! তুমি দ্যুলোক ব্যাপ্ত করে আছ। হে সত্যবল মঘবন! তুমি আমাদের গো দান কর।"},{"n":22,"d":"शुनं हुवेम मघवानमिन्द्रमस्मिन भरे नर्तमं वाजसातौ | शर्ण्वन्तमुग्रमूतये समत्सु घनन्तं वर्त्राणि संजितं धनानाम ||","b":"শুনং হুবেম মঘবানমিন্দ্রমস্মিন ভরে নর্তমং বাজসাতৌ | শর্ণ্বন্তমুগ্রমূতযে সমত্সু ঘনন্তং বর্ত্রাণি সংজিতং ধনানাম ||","e":"Call we on Maghavan, auspicious Indra, best Hero in this fight where spoil is gathered, The Strong who listens, who gives aid in battles, who slays the Vṛtras, wins and gathers riches.","mb":"হে ইন্দ্র! তুমি অন্ন লাভ কর, যুদ্ধে উৎসাহজ দ্বারা প্রবৃদ্ধ, তুমি ধনবান, প্রভূত ঐশ্বর্য সম্পন্ন, নেতৃশ্রেষ্ঠ  স্তুতিশ্রবণকারী উগ্র, সংগ্রামে শত্রু বিনাশী ও ধনজেতা। আমরা আশ্রয় লাভের জন্য তোমাকে আহবান করছি।"}]},{"n":31,"t":"Indra","v":[{"n":1,"d":"शासद वह्निर्दुहितुर्नप्त्यं गाद विद्वान रतस्य दीधितिंसपर्यन | पिता यत्र दुहितुः सेकं रञ्जन सं शग्म्येन मनसा दधन्वे ||","b":"শাসদ বহ্নির্দুহিতুর্নপ্ত্যং গাদ বিদ্বান রতস্য দীধিতিংসপর্যন | পিতা যত্র দুহিতুঃ সেকং রঞ্জন সং শগ্ম্যেন মনসা দধন্বে ||","e":"WISE, teaching, following the thought of Order, the sonless gained a grandson from his daughter. Fain, as a sire, to see his child prolific, he sped to meet her with an eager spirit.","mb":"পুত্রহীন পিতা সমর্থ জামাতাকে সম্মানিত করে শাস্ত্রানুশাসনক্রমে দুহিতা জাত পৌত্র প্রাপ্ত হন। অপুত্ত পিতা দুহিতার গর্ভ হতে বিশ্বাস করে প্রসন্নমনে শরীর ধারণ করেন (১)।"},{"n":2,"d":"न जामये तान्वो रिक्थमारैक चकार गर्भं सनितुर्निधानम | यदी मातरो जनयन्त वह्निमन्यः कर्ता सुक्र्तोरन्य रन्धन ||","b":"ন জামযে তান্বো রিক্থমারৈক চকার গর্ভং সনিতুর্নিধানম | যদী মাতরো জনযন্ত বহ্নিমন্যঃ কর্তা সুক্র্তোরন্য রন্ধন ||","e":"The Son left not his portion to the brother, he made a home to hold him who should gain, it. What time his Parents gave the Priest his being, of the good pair one acted, one promoted.","mb":"ঔরসপুত্র দুহিতাকে পৈতৃক ধন দেন না। তিনি তাকে ভর্তার প্রণয়ের আধার করেন। যদি পিতামাতা পুত্র কন্যাং উভয়েই উৎপাদন করেন তা হলে তাদের মধ্যে একজন উৎকৃষ্ঠ ক্রিয়া কর্ম করেন, এর অন্যজন সম্মানিত হন (২)।"},{"n":3,"d":"अग्निर्जज्ञे जुह्वा रेजमानो महस पुत्रानरुषस्य परयक्षे | महान गर्भो मह्या जातमेषां मही परव्र्द धर्यश्वस्य यज्ञैः ||","b":"অগ্নির্জজ্ঞে জুহ্বা রেজমানো মহস পুত্রানরুষস্য পরযক্ষে | মহান গর্ভো মহ্যা জাতমেষাং মহী পরব্র্দ ধর্যশ্বস্য যজ্ঞৈঃ ||","e":"Agni was born trembling with tongue that flickered, so that the Red's great children should be honoured. Great is their germ, that born of them is mighty, great the Bays' Lord's approach through sacrifices.","mb":"হে ইন্দ্র! তুমি দীপ্তিযুক্ত তোমার যজ্ঞের জন্য জ্বালাদ্বারা ক্পমান অগ্নি প্রভূত পুত্ররূপ (রশ্মি সকলকে) উৎপাদন করেছে। এ সকল রশ্মির জলরূপ গর্ভ মহান ওষধিরূপ জন্ম মহান। হে হর্ষশ্ব। তেমার সোমাহুতি প্রযুক্ত এ সকল রশ্মির প্রবৃত্তি মহতী।"},{"n":4,"d":"अभि जैत्रीरसचन्त सप्र्धानं महि जयोतिस्तमसो निरजानन | तं जानतीः परत्युदायन्नुषासः पतिर्गवामभवदेक इन्द्रः ||","b":"অভি জৈত্রীরসচন্ত সপ্র্ধানং মহি জযোতিস্তমসো নিরজানন | তং জানতীঃ পরত্যুদাযন্নুষাসঃ পতির্গবামভবদেক ইন্দ্রঃ ||","e":"Conquering bands upon the Warrior waited: they recognized great light from out the darkness. The conscious Dawns went forth to meet his coming, and the sole Master of the kine was Indra.","mb":"জয়শীল মরুৎগণ বৃত্তের সাথে যুদ্ধকারী ইন্দ্রের সাথে সঙ্গত হয়েছিলেন। সূর্যাথ্য মহৎ তেজ তমোরূপ বৃত্ত হতে নির্গত হচ্ছে, মরুৎগণ তা জানতে পেরেছিলেন। ঊষাগণ, ইন্দ্রকে সূর্য বলে জেনে তার দিকে গিয়েছিল। এক ইন্দ্র রশ্মি সকলের গতি হয়েছিলেন।"},{"n":5,"d":"वीळौ सतीरभि धीरा अत्र्न्दन पराचाहिन्वन मनसा सप्तविप्राः | विश्वामविन्दन पथ्यां रतस्य परजानन्नित तानमसा विवेश ||","b":"বীলৌ সতীরভি ধীরা অত্র্ন্দন পরাচাহিন্বন মনসা সপ্তবিপ্রাঃ | বিশ্বামবিন্দন পথ্যাং রতস্য পরজানন্নিত তানমসা বিবেশ ||","e":"The sages freed them from their firmbuilt prison: the seven priests drove them forward with their spirit. All holy Order's pathway they discovered he, full of knowledge, shared these deeds through worship.","mb":"ধীমান, মেধাবী সপ্তসংখ্যক অঙ্গিরাগণ দস্যু পর্বতে নিরুদ্ধ গাভী সকলকে অন্বেষণ করে অপাবৃত করেছিলেন। তারা মনে মনে নিশ্চয় করে যে পথ দিয়ে প্রবেশ করেছিলেন সে পথে ফিরে এসেছিলেন। তারা যজ্ঞপথে সমস্ত গহাভীগণকে লাভ করেছিলেন। ইন্দ্র এ সকল জেনে নমস্কার দ্বারা অঙ্গিরাগণকে সম্ভাষণ করে পর্বত মধ্যে প্রবেশ করেছিলেন।"},{"n":6,"d":"विदद यदी सरमा रुग्णमद्रेर्महि पाथः पूर्व्यं सध्र्यक कः | अग्रं नयत सुपद्यक्षराणामछा रवं परथमा जानती गात ||","b":"বিদদ যদী সরমা রুগ্ণমদ্রের্মহি পাথঃ পূর্ব্যং সধ্র্যক কঃ | অগ্রং নযত সুপদ্যক্ষরাণামছা রবং পরথমা জানতী গাত ||","e":"When Saramā had found the mountain's fissure, that vast and ancient place she plundered thoroughly. In the floods' van she led them forth, light-footed: she who well knew came first unto their lowing.","mb":"যখন সরমা, পর্বতের ভগ্ন দ্বার প্রাপ্ত হল, তখন ইন্দ্র পূর্বে প্রতিজ্ঞাত প্রচুর অন্যান্য সামগ্রীর  সাথে তাকে দিলেন। উত্তম পাদযুক্ত সরমা শব্দ চিনতে  পেরে সেদিকে গিয়ে অক্ষয় গোসমূহের নিকটে উপস্থিত হলেন (৩)।"},{"n":7,"d":"अगछदु विप्रतमः सखीयन्नसूदयत सुक्र्ते गर्भमद्रिः | ससान मर्यो युवभिर्मखस्यन्नथाभवदङगिराः सद्यो अर्चन ||","b":"অগছদু বিপ্রতমঃ সখীযন্নসূদযত সুক্র্তে গর্ভমদ্রিঃ | সসান মর্যো যুবভির্মখস্যন্নথাভবদঙগিরাঃ সদ্যো অর্চন ||","e":"Longing for friendship came the noblest singer: the hill poured forth its treasure for the pious. The Hero with young followers fought and conquered, and straightway Aṅgiras was singing praises,","mb":"অতিশয় মেধবী ইন্দ্র অঙ্গিরাগণের সখ্যাভিলাষে গেলেন। পর্বতমহাযোদ্ধার জন্য গর্ভস্থিত গোধন বার করে দিল। শত্রুহন্তা তরুণবয়স্ক মরুৎগণের সাথে তাদের প্রাপত্ হলেন। অঙ্গিরা তৎক্ষনাৎ তাকে পুজা করলেন।"},{"n":8,"d":"सतः-सतः परतिमानं पुरोभूर्विश्वा वेद जनिमा हन्ति शुष्णम | पर णो दिवः पदवीर्गव्युरर्चन सखा सखीन्रमुञ्चन निरवद्यात ||","b":"সতঃ-সতঃ পরতিমানং পুরোভূর্বিশ্বা বেদ জনিমা হন্তি শুষ্ণম | পর ণো দিবঃ পদবীর্গব্যুরর্চন সখা সখীন্রমুঞ্চন নিরবদ্যাত ||","e":"Peer of each noble thing, yea, all excelling, all creatures doth he know, he slayeth Śuṣṇa. Our leader, fain for war, singing from heaven, as Friend he saved his lovers from dishonour.","mb":"যে ইন্দ্র উৎকৃষ্ট পদার্থের প্রতিনিধি, যিনি যুদ্ধে অগ্রগামী, যিনি সমস্ত জাতবস্তু অবগত আছেন, যিনি শুষ্যকে বধ করেছেন, সেই দুরর্শী গোধন অভিলাষী ইন্দ্র দ্যুলোক হতে সম্মান করে আমাদের পাপ হতে রক্ষা করুন।"},{"n":9,"d":"नि गव्यता मनसा सेदुरर्कैः कर्ण्वानासो अम्र्तत्वाय गातुम | इदं चिन नु सदनं भूर्येषां येन मासानसिषासन्न्र्तेन ||","b":"নি গব্যতা মনসা সেদুরর্কৈঃ কর্ণ্বানাসো অম্র্তত্বায গাতুম | ইদং চিন নু সদনং ভূর্যেষাং যেন মাসানসিষাসন্ন্র্তেন ||","e":"They sate them down with spirit fain for booty, making with hymns a way to life eternal. And this is still their place of frequent session, whereby they sought to gain the months through Order.","mb":"অঙ্গিরাগণ মনে মনে গোধন লাভের ইচ্ছা করে স্তোত্রদ্বারা অমরত্ব লাভের উপায় করে যজ্ঞকার্যে সমাসীন হয়েছিলেন। এদের এ যজ্ঞে উপবেশন প্রভূত, এরা সভ্যভূত এ যজ্ঞের দ্বারা মাস করল সংভক্ত করতে ইচ্ছা করেছিলেন।"},{"n":10,"d":"सम्पश्यमाना अमदन्नभि सवं पयः परत्नस्य रेतसो दुघानाः | वि रोदसी अतपद घोष एषां जाते निष्ठामदधुर्गोषु वीरान ||","b":"সম্পশ্যমানা অমদন্নভি সবং পযঃ পরত্নস্য রেতসো দুঘানাঃ | বি রোদসী অতপদ ঘোষ এষাং জাতে নিষ্ঠামদধুর্গোষু বীরান ||","e":"Drawing the milk of ancient seed prolific, they joyed as they beheld their own possession. Their shout of triumph heated earth and heaven. When the kine showed, they bade the heroes rouse them.","mb":"অঙ্গিরাগণ স্বীয় গোধন মক্ষ করে সন্দর্শন করে পুরাজাত পুত্রের ধারণার্থে দুগ্ধ দোহন করে হৃষ্ট হয়েছিলেন। তাদের আনন্দধ্বনি দ্যাবা পৃথিবীকে ব্যাপ্ত করেছিল। তারা জগতে পূর্বের ন্যায় অবস্থিতি করেছিলেন, গাভীগণের রক্ষার্থে বীরপুরুষদের নিযুক্ত করেছিলেন।"},{"n":11,"d":"स जातेभिर्व्र्त्रहा सेदु हव्यैरुदुस्रिया अस्र्जदिन्द्रो अर्कैः | उरूच्यस्मै घर्तवद भरन्ती मधु सवाद्म दुदुहे जेन्या गौः ||","b":"স জাতেভির্ব্র্ত্রহা সেদু হব্যৈরুদুস্রিযা অস্র্জদিন্দ্রো অর্কৈঃ | উরূচ্যস্মৈ ঘর্তবদ ভরন্তী মধু সবাদ্ম দুদুহে জেন্যা গৌঃ ||","e":"Indra drove forth the kine, that Vṛtra-slayer, while hymns of praise rose up and gifts were offered. For him the Cow, noble and far-extending, poured pleasant juices, bringing oil and sweetness.","mb":"ন্দ্রি সাহায্যার্থে জাত মরুৎগণের সাথে বৃত্তকে বধ করেন। তিনিই অর্চনীয় হোমার্হ, মরুৎগণের সাথে গো সকল যজ্ঞের জন্য দান করেছিলেন। ঘৃতযুক্ত মনোহারিণী, প্রভূত হবাদায়িনী, প্রশস্তা গাভী এর জন্য স্বাদুতর ক্ষীরাদি দোহন করেছিলেন।"},{"n":12,"d":"पित्रे चिच्चक्रुः सदनं समस्मै महि तविषीमत सुक्र्तो विहि खयन | विष्कभ्नन्त सकम्भनेना जनित्री आसीना ऊर्ध्वं रभसं वि मिन्वन ||","b":"পিত্রে চিচ্চক্রুঃ সদনং সমস্মৈ মহি তবিষীমত সুক্র্তো বিহি খযন | বিষ্কভ্নন্ত সকম্ভনেনা জনিত্রী আসীনা ঊর্ধ্বং রভসং বি মিন্বন ||","e":"They made a mansion for their Father, deftly provided him a great and glorious dwelling; With firm support parted and stayed the Parents, and, sitting, fixed him there erected, mighty.","mb":"অঙ্গিরাগণ পালক ইন্দ্রের জন্য মহৎ, দীপ্তিমান স্থান সংস্কার করেছিলেন। সুকর্মশাল অঙ্গিরাগণ ইন্দ্রের উপযুক্ত ঐ স্থানটিকে বিশেষরূপে দেখিয়েছিলেন। তারা যজ্ঞে উপবেশন করে জনয়িত্রী দ্যাবাপৃথিবীকে স্তম্ভরূপ অন্তরক্ষিদ্বারা স্তম্ভন করে বেগবান ইন্দ্রকে দ্যুলোকে সংস্থাপন করেছিলেন।"},{"n":13,"d":"मही यदि धिषणा शिश्नथे धात सद्योव्र्धं विभ्वं रोदस्योः | गिरो यस्मिन्ननवद्याः समीचीर्विश्वा इन्द्राय तविषीरनुत्ताः ||","b":"মহী যদি ধিষণা শিশ্নথে ধাত সদ্যোব্র্ধং বিভ্বং রোদস্যোঃ | গিরো যস্মিন্ননবদ্যাঃ সমীচীর্বিশ্বা ইন্দ্রায তবিষীরনুত্তাঃ ||","e":"What time the ample chalice had impelled him, swift waxing, vast, to pierce the earth and heaven,— Him in whom blameless songs are all united: all powers invincible belong to Indra.","mb":"দ্যাবাপৃথিবী পরস্পর বিশিষ্ট হলে যদি মহতী স্তুতি ্ন্দ্রিকে তৎক্ষনাৎ বৃদ্ধিপ্রাপ্ত ও ধারণক্ষম করে, তবে ইন্দ্রের প্রতি শুদ্ধস্তুতি সঙ্গত করা হয়। সুতরাং ইন্দ্রের সমস্ত বল স্বভাসিদ্ধ।"},{"n":14,"d":"मह्या ते सख्यं वश्मि शक्तीरा वर्त्रघ्ने नियुतो यन्ति पूर्वीः | महि सतोत्रमव आगन्म सूरेरस्माकं सु मघवन बोधि गोपाः ||","b":"মহ্যা তে সখ্যং বশ্মি শক্তীরা বর্ত্রঘ্নে নিযুতো যন্তি পূর্বীঃ | মহি সতোত্রমব আগন্ম সূরেরস্মাকং সু মঘবন বোধি গোপাঃ ||","e":"I crave thy powers, I crave thy mighty friendship: full many a team goes to the Vṛtra-slayer. Great is the laud, we seek the Princes' favour. Be thou, O Maghavan, our guard and keeper.","mb":"হে ইন্দ্র! আমি তোমার মহৎসখ্য প্রার্থনা করছি, তোমার শক্তি প্রার্থনা করছি। তুমি বৃত্রহন্তা, তোমার নিকট অনেক অশ্ব বহন করবার জন্য আসে। তুমি বিদ্বান, আমরা তোমাকে মহৎসখ্য স্তোত্র ও হব্য প্রদান করি। হে মঘবন! তুমি আমাদের পালক, এ জেনে।"},{"n":15,"d":"महि कषेत्रं पुरु शचन्द्रं विविद्वानादित सखिभ्यश्चरथं समैरत | इन्द्रो नर्भिरजनद दीद्यानः साकं सूर्यमुषसं गातुमग्निम ||","b":"মহি কষেত্রং পুরু শচন্দ্রং বিবিদ্বানাদিত সখিভ্যশ্চরথং সমৈরত | ইন্দ্রো নর্ভিরজনদ দীদ্যানঃ সাকং সূর্যমুষসং গাতুমগ্নিম ||","e":"He, having found great, splendid, rich dominion, sent life and motion to his friends and lovers. Indra who shone together with the Heroes begot the song, the fire, and Sun and Morning.","mb":"ইন্দ্র বিশেষরূপে অবগত থেকে মহৎ ক্ষেত্র ও প্রভূত হিরণ্য সখাদের দান করেছেন, অনন্তর তাদের গবাদিও দান করেছেন। তিনি দীপ্তিমান, নেতা মরুৎগণের সাথে তিনি সূর্য ঊষা, পৃথিবী ও অগ্নিকে উৎপাদন করেছেন।"},{"n":16,"d":"अपश्चिदेष विभ्वो दमूनाः पर सध्रीचीरस्र्जद विश्वश्चन्द्राः | मध्वः पुनानाः कविभिः पवित्रैर्द्युभिर्हिन्वन्त्यक्तुभिर्धनुत्रीः ||","b":"অপশ্চিদেষ বিভ্বো দমূনাঃ পর সধ্রীচীরস্র্জদ বিশ্বশ্চন্দ্রাঃ | মধ্বঃ পুনানাঃ কবিভিঃ পবিত্রৈর্দ্যুভির্হিন্বন্ত্যক্তুভির্ধনুত্রীঃ ||","e":"Vast, the House-Friend, he set the waters flowing, all-lucid, widely spread, that move together. By the wise cleansings of the meath made holy, through days, and nights they speed the swift streams onward.","mb":"অনন্তমনা এ ইন্দ্র বিস্তীর্ণ পরস্পর সঙ্গত ও বিশ্বের আনন্দকর, জল সমূহকে সৃষ্টি করেছেন। ওরা মাধুর্যযুক্ত সোমসমূহকে পবিত্রদ্বারা (৪) শোধিত করে ও সমস্ত জগৎকে প্রীত করে, রাত দিন জগৎকে স্ব স্ব ব্যাপারে প্রেরণ করছে।"},{"n":17,"d":"अनु कर्ष्णे वसुधिती जिहाते उभे सूर्यस्य मंहना यजत्रे | परि यत ते महिमानं वर्जध्यै सखाय इन्द्र काम्या रजिप्याः ||","b":"অনু কর্ষ্ণে বসুধিতী জিহাতে উভে সূর্যস্য মংহনা যজত্রে | পরি যত তে মহিমানং বর্জধ্যৈ সখায ইন্দ্র কাম্যা রজিপ্যাঃ ||","e":"To thee proceed the dark, the treasure-holders, both of them sanctified by Sūrya's bounty. The while thy ovely storming Friends, O Indra, fail to attain the measure of thy greatness.","mb":"সূর্যের মহিমায় সর্বপদার্থ ধারণকারী ও যজ্ঞার্হ অহোরাত্রি উভয়ে ক্রমাশ্বয়ে আবর্তন করছে। ঋজুগতি, মিত্রভূত, কমনীয় মরুৎগণ, শত্রুর পরাভবের জন্য তোমার সামর্থ্য অনুসরণ করতে সক্ষম।"},{"n":18,"d":"पतिर्भव वर्त्रहन सून्र्तानां गिरां विश्वायुर्व्र्षभो वयोधाः | आ नो गहि सख्येभिः शिवेभिर्महान महीभिरूतिभिः सरण्यन ||","b":"পতির্ভব বর্ত্রহন সূন্র্তানাং গিরাং বিশ্বাযুর্ব্র্ষভো বযোধাঃ | আ নো গহি সখ্যেভিঃ শিবেভির্মহান মহীভিরূতিভিঃ সরণ্যন ||","e":"Be Lord of joyous songs, O Vṛtra-slayer, Bull dear to all, who gives the power of living. Come unto us with thine auspicious friendship, hastening, Mighty One, with mighty succours.","mb":"হে বৃত্তহন! তুমি অবিনাশী, অভিষ্টবর্ষী ও অন্নদাতা; তুমি আমাদের প্রিয়তম স্তুতির স্বামী হও। তুমি মহজান, তুমি যজ্ঞে গমন করতে অভিলাষী। তুমি মহৎ আশ্রয় ও কল্যাণকর  সখ্যের সাথে আমাদের অভিমুখে এস।"},{"n":19,"d":"तमङगिरस्वन नमसा सपर्यन नव्यं कर्णोमि सन्यसे पुराजाम | दरुहो वि याहि बहुला अदेवीः सवश्च नो मघवन सातये धाः ||","b":"তমঙগিরস্বন নমসা সপর্যন নব্যং কর্ণোমি সন্যসে পুরাজাম | দরুহো বি যাহি বহুলা অদেবীঃ সবশ্চ নো মঘবন সাতযে ধাঃ ||","e":"Like Aṅgiras I honour him with worship, and renovate old song for him the Ancient. Chase thou the many godless evil creatures, and give us, Maghavan, heaven's light to help m.","mb":"হে ইন্দ্র! তুমি পুরাতন, অঙ্গিরাগণের ন্যায় আমি তোমাকে পূজা করছি, আমি তোমাকে ভজনা করবার জন্য নুতন করছি। তুমি, দেবশূন্য বহু দ্েোহকারিদের (৫) মেরে ফেল। হে মঘবন! আমাদের উপভোগ্য ধন দান কর। ২০। হে ইন্দ্র! পাবক জলসমূহ সর্বত্র প্রসৃত হয়েছে, আমাদের  জন্য এ অবিনাশী জল সমূহের তীর জলদ্বারা পূর্ণ কর। তুমি রথবান, আমাদের শত্রু হতে রক্ষা কর, আমাদের অতিশীঘ্র গাভীসমূহের জেতা কর।"},{"n":20,"d":"मिहः पावकाः परतता अभूवन सवस्ति नः पिप्र्हि पारमासाम | इन्द्र तवं रथिरः पाहि नो रिषो मक्षू-मक्षू कर्णुहि गोजितो नः ||","b":"মিহঃ পাবকাঃ পরততা অভূবন সবস্তি নঃ পিপ্র্হি পারমাসাম | ইন্দ্র তবং রথিরঃ পাহি নো রিষো মক্ষূ-মক্ষূ কর্ণুহি গোজিতো নঃ ||","e":"Far forth are spread the purifying waters convey thou us across them unto safety. Save us, our Charioteer, from harm, O Indra, soon, very soon, make us win spoil of cattle.","mb":"দূরে বিস্তৃত পবিত্র জলরাশি — আমাদের সেগুলি পার করে নিরাপদে পৌঁছে দাও। আমাদের রক্ষা করো, হে আমাদের সারথি, বিপদ থেকে, হে ইন্দ্র, শীঘ্র, অতি শীঘ্র আমাদের গোধন জয় করাও।"},{"n":21,"d":"अदेदिष्ट वर्त्रहा गोपतिर्गा अन्तः कर्ष्णानरुषैर्धामभिर्गात | पर सून्र्ता दिशमान रतेन दुरश्च विश्वा अव्र्णोदप सवाः ||","b":"অদেদিষ্ট বর্ত্রহা গোপতির্গা অন্তঃ কর্ষ্ণানরুষৈর্ধামভির্গাত | পর সূন্র্তা দিশমান রতেন দুরশ্চ বিশ্বা অব্র্ণোদপ সবাঃ ||","e":"His kine their Lord hath shown, e’en Vṛtra's slayer, through the black hosts he passed with red attendants. Teaching us pleasant things by holy Order, to, us hath he thrown open all his portals.","mb":"বৃত্রহন্তা ও গাভীগণের স্বামী ইন্দ্র আমাদের গাভী দান করুন, কৃষ্ণদের (৬) দীপ্তিযুক্ত তেজদ্বারা বিনাশ করুন। তিনি সত্যবাক্যে অঙ্গিরাগণকে প্রিয়তম গাভী সকল দান করে সমস্ত দ্বার বদ্ধ করে দিয়েছিলেন।"},{"n":22,"d":"शुनं हुवेम ... ||","b":"শুনং হুবেম ... ||","e":"Call we on Maghavan, auspicious Indra, best Hero in this fight where spoil is gathered. The Strong who listens, who gives aid in battles, who slays the Vṛtras, wins and gathers riches.","mb":"হে ইন্দ্র! তুমি অন্ন লাভ কর, যুদ্ধে উৎসাহদ্বারা প্রবৃদ্ধ, তুমি ধনবান, প্রভূত ঐশ্বর্যসম্পন্ন, নেতৃশ্রেষ্ঠ, স্তুতি  শ্রবণকারী, উগ্র সংগ্রামে শত্রু বিনাশী ও ধনজেতা। আমরা আশ্রয় লাভের জন্য তোমাকে আহ্বান করছি।"}]},{"n":32,"t":"Indra","v":[{"n":1,"d":"इन्द्र सोमं सोमपते पिबेमं माध्यन्दिनं सवनं चारु यत ते | परप्रुथ्या शिप्रे मघवन्न्र्जीषिन विमुच्या हरी इहमादयस्व ||","b":"ইন্দ্র সোমং সোমপতে পিবেমং মাধ্যন্দিনং সবনং চারু যত তে | পরপ্রুথ্যা শিপ্রে মঘবন্ন্র্জীষিন বিমুচ্যা হরী ইহমাদযস্ব ||","e":"DRINK thou this Soma, Indra, Lord of Soma; drink thou the draught of noonday which thou Iovest. Puffing thy cheeks, impetuous, liberal Giver, here loose thy two Bay Horses and rejoice thee.","mb":"হে সোমপতি ইন্দ্র! এ মাধান্দিন সকনে সোম পান কর, যেহেতু এ তোমার প্রিয়। হে ধনবান, ঋজীষসোমপায়ী ইন্দ্র! অশ্বদ্বয়কে রথ হতে খুলে দিয়ে, তাদরে হনুদ্বয়কে খাদ্যে পূর্ণ করে এ যজ্ঞে তাদের হৃষ্ট কর।"},{"n":2,"d":"गवाशिरं मन्थिनमिन्द्र शुक्रं पिबा सोमं ररिमा ते मदाय | बरह्मक्र्ता मारुतेना गणेन सजोषा रुद्रैस्त्र्पदाव्र्षस्व ||","b":"গবাশিরং মন্থিনমিন্দ্র শুক্রং পিবা সোমং ররিমা তে মদায | বরহ্মক্র্তা মারুতেনা গণেন সজোষা রুদ্রৈস্ত্র্পদাব্র্ষস্ব ||","e":"Quaff it pure, meal-blent, mixt with milk, O Indra; we have poured forth the Soma for thy rapture. Knit with the prayer-fulfilling band of Maruts, yea, with the Rudras, drink till thou art sated;","mb":"হে ইন্দ্র! গব্যমিশ্রিত, মন্থসংযুক্ত, অভিনব সোম পান কর, তোমার হর্ষের জন্য আমরা দান করছি। তুমি, স্তোত্রকারী মরুৎগণ ও রুদ্রগণের সাথে তৃপ্তি পর্যন্ত পান কর।"},{"n":3,"d":"ये ते शुष्मं ये तविषीमवर्धन्नर्चन्त इन्द्र मरुतस्तोजः | माध्यन्दिने सवने वज्रहस्त पिबा रुद्रेभिः सगणः सुशिप्र ||","b":"যে তে শুষ্মং যে তবিষীমবর্ধন্নর্চন্ত ইন্দ্র মরুতস্তোজঃ | মাধ্যন্দিনে সবনে বজ্রহস্ত পিবা রুদ্রেভিঃ সগণঃ সুশিপ্র ||","e":"Those who gave increase to thy strength and vigour; the Maruts singing forth thy might, O Indra. Drink thou, O fair of cheek, whose hand wields thunder, with Rudras banded, at our noon libation.","mb":"হে ইন্দ্র! যে মরুৎগণ তোমার শত্রুশোষক তেজ বর্ধিত করে, যে মরুৎগণ তোমার বল বর্ধিত করে, সে মরুৎগণ স্তব করে তোমার যুদ্ধ সামর্থ্য বর্ধিত করে। হে বজ্রহস্ত, শোভন হনুযুক্ত ইন্দ্র! রুদ্রগণের সাথে মাধ্যন্দিন সবনে সোমপান কর।"},{"n":4,"d":"त इन नवस्य मधुमद विविप्र इन्द्रस्य शर्धो मरुतो य आसन | येभिर्व्र्त्रस्येषितो विवेदामर्मणो मन्यमानस्य मर्म ||","b":"ত ইন নবস্য মধুমদ বিবিপ্র ইন্দ্রস্য শর্ধো মরুতো য আসন | যেভির্ব্র্ত্রস্যেষিতো বিবেদামর্মণো মন্যমানস্য মর্ম ||","e":"They, even the Maruts who were there, excited with song the meath-created strength of Indra. By them impelled to act he reached the vitals Of Vṛtra, though he deemed that none might wound him.","mb":"মরুৎগণ ইন্দ্রের বলভূত হয়েছিলেন। আমার মর্মস্থান কেউ জানে না, বৃত্ত এরূপ অভিমসান করাতে, ইন্দ্র মরুৎগণ কর্তৃক প্রেরিত হয়ে বৃত্তের মর্মস্থান জেনেছিলেন। সে মরুৎগণ তোমাকে শীঘ্র মাধুর্যযুক্ত উৎসাহ বাক্য বলেছিলেন।"},{"n":5,"d":"मनुष्वदिन्द्र सवनं जुषाणः पिबा सोमं शश्वते वीर्याय | स आ वव्र्त्स्व हर्यश्व यज्ञैः सरण्युभिरपो अर्णा सिसर्षि ||","b":"মনুষ্বদিন্দ্র সবনং জুষাণঃ পিবা সোমং শশ্বতে বীর্যায | স আ বব্র্ত্স্ব হর্যশ্ব যজ্ঞৈঃ সরণ্যুভিরপো অর্ণা সিসর্ষি ||","e":"Pleased, like a man, with our libation, Indra, drink, for enduring hero might, the Soma. Lord of Bays, moved by sacrifice come hither: thou with the Swift Ones stirrest floods and waters.","mb":"হে ইন্দ্র! তুমি মনুর যজ্ঞের ন্যায় আমার এ যজ্ঞ সেবা করে শাশ্বত বলের জন্য সোম পান কর। হে হর্যাশ্ব! তুমি যজ্ঞার্হ মরুৎগণের সাথে এস। গমনশীল মরুৎগণের সাথে অন্তরিক্ষ হতে জল প্রেরণ কর।"},{"n":6,"d":"तवमपो यद ध वर्त्रं जघन्वानत्यानिव परास्र्जः सर्तवाजौ | शयानमिन्द्र चरत वधेन वव्रिवांसं परि देवीरदेवम ||","b":"তবমপো যদ ধ বর্ত্রং জঘন্বানত্যানিব পরাস্র্জঃ সর্তবাজৌ | শযানমিন্দ্র চরত বধেন বব্রিবাংসং পরি দেবীরদেবম ||","e":"When thou didst loose the streams to run like racers in the swift contest, having smitten Vṛtra With flying weapon where he lay, O Indra, and, godless, kept the Goddesses encompassed.","mb":"হে ইন্দ্র! যেহেতু তুমি দীপ্তিমান জলের আবরণকারী, দীপ্তিরহিত ও শয়ান বৃত্তকে যুদ্ধে নিহত করেছ অতএব তুমি যুদ্ধকালে অশ্বের ন্যায় জল ছেড়ে দিয়েছ।"},{"n":7,"d":"यजाम इन नमसा वर्द्धमिन्द्रं बर्हन्तं रष्वमजरं युवानम | यस्य परिये ममतुर्यज्ञियस्य न रोदसी महिमानं ममाते ||","b":"যজাম ইন নমসা বর্দ্ধমিন্দ্রং বর্হন্তং রষ্বমজরং যুবানম | যস্য পরিযে মমতুর্যজ্ঞিযস্য ন রোদসী মহিমানং মমাতে ||","e":"With reverence let us worship mighty Indra, great and sublime, eternal, everyouthful, Whose greatness the dear world-halves have not measured, no, nor conceived the might of him the Holy.","mb":"অতএব আমরা হব্যদ্বারা প্রবৃদ্ধ ও মহান জরারহিত ও নিত্যতরুণ, স্তোতব্য ইন্দ্রের পূজা করি। পরিমাণরহিতা দ্যাবাপৃথিবী যজ্ঞার্হ ইন্দ্রের মহিমা পরিচ্ছেদ করতে পারে না।"},{"n":8,"d":"इन्द्रस्य कर्म सुक्र्ता पुरूणि वरतानि देवा न मिनन्ति विश्वे | दाधार यः पर्थिवीं दयामुतेमां जजान सूर्यमुषसं सुदंसाः ||","b":"ইন্দ্রস্য কর্ম সুক্র্তা পুরূণি বরতানি দেবা ন মিনন্তি বিশ্বে | দাধার যঃ পর্থিবীং দযামুতেমাং জজান সূর্যমুষসং সুদংসাঃ ||","e":"Many are Indra's nobly wrought achievements, and none of all the Gods transgress his statutes. He beareth up this earth and heaven, and, doer of marvels, he begot the Sun and Morning.","mb":"সমস্ত দেবগণ ইন্দ্রে রকর্ম সুকৃত ও বহুতর যজ্ঞাদি হিংসা করতে পারে না। এ ইন্দ্র ভুলোক, দ্যুলোক ও অন্তরীক্ষ লোক  ধারণ করে আছেন। তার কর্ম রমনীয়, তিনি সূর্য ও ঊষাকে উৎপন্ন করেছেন।"},{"n":9,"d":"अद्रोघ सत्यं तव तन महित्वं सद्यो यज्जातो अपिबो ह सोमम | न दयाव इन्द्र तवसस्त ओजो नाहा न मासाः शरदो वरन्त ||","b":"অদ্রোঘ সত্যং তব তন মহিত্বং সদ্যো যজ্জাতো অপিবো হ সোমম | ন দযাব ইন্দ্র তবসস্ত ওজো নাহা ন মাসাঃ শরদো বরন্ত ||","e":"Herein, O Guileless One, is thy true greatness, that soon as born thou drankest up the Soma. Days may not check the power of thee the Mighty, nor the nights, Indra, nor the months, nor autumns.","mb":"হে দৌরাত্মরহিত ইন্দ্র। তোমার মহিমাই যথার্থ মহিমা। যেহেতু তুমি উৎপন্ন হয়েই সোম পান কর। তুমি বলবান, স্বর্গাদিলোক তোমার তেজ নিবারণ করতে পারে না। দিন, মাস ও বৎসরও নিবারণ করত পারে না।"},{"n":10,"d":"तवं सद्यो अपिबो जात इन्द्र मदाय सोमं परमे वयोमन | यद ध दयावाप्र्थिवी आविवेषीरथाभवः पूर्व्यः कारुधायाः ||","b":"তবং সদ্যো অপিবো জাত ইন্দ্র মদায সোমং পরমে বযোমন | যদ ধ দযাবাপ্র্থিবী আবিবেষীরথাভবঃ পূর্ব্যঃ কারুধাযাঃ ||","e":"As soon as thou wast born in highest heaven thou drankest Soma to delight thee, Indra; And when thou hadst pervaded earth and heaven thou wast the first supporter of the singer.","mb":"হে ইন্দ্র! তুমি জাতমাত্র সর্বোচ্চ স্বর্গ প্রদেশে থেকেই সদ্য আনন্দের জন্য সোম পান করেছ, যখন তুমি দ্যাবাপৃথিবীতে অনুপ্রেবিষ্ট হয়েছ তখনই তুমি পুরাতন সৃষ্টি বিধাতা  হয়েছ।"},{"n":11,"d":"अहन्नहिं परिशयानमर्ण ओजायमानं तुविजात तव्यान | न ते महित्वमनु भूदध दयौर्यदन्यया सफिग्या कषामवस्थाः ||","b":"অহন্নহিং পরিশযানমর্ণ ওজাযমানং তুবিজাত তব্যান | ন তে মহিত্বমনু ভূদধ দযৌর্যদন্যযা সফিগ্যা কষামবস্থাঃ ||","e":"Thou, puissant God, more mighty, slewest. Ahi showing his strength when couched around the waters. The heaven itself attained not to thy greatness when with one hip of thine the earth was shadowed.","mb":"হে ইন্দ্র! অনেকে তোমা হইতে উৎপন্ন হয়েছে। যে অহি আপনাকে বলবান মনে করে জল পরিবেষ্টন করে অবস্থিতি করেছিল, সে অহিকে তুমি প্রবৃদ্ধ হয়ে বিনাশ করেছ। কিন্তু যখন তুমি এক কটিতে পৃথিবীকে লুকিয়ে অবস্থান কর, তখন স্বর্গ তোমার মহিমার ইয়ত্তা করতে পারে না।"},{"n":12,"d":"यज्ञो हि त इन्द्र वर्धनो भूदुत परियः सुतसोमो मियेधः | यज्ञेन यज्ञमव यज्ञियः सन यज्ञस्ते वज्रमहिहत्य आवत ||","b":"যজ্ঞো হি ত ইন্দ্র বর্ধনো ভূদুত পরিযঃ সুতসোমো মিযেধঃ | যজ্ঞেন যজ্ঞমব যজ্ঞিযঃ সন যজ্ঞস্তে বজ্রমহিহত্য আবত ||","e":"Sacrifice, Indra, made thee wax so mighty, the dear oblation with the flowing Soma. O Worshipful, with worship help our worship, for worship helped thy bolt when slaying Ahi.","mb":"হে ইন্দ্র! আমাদের যজ্ঞ তোমার বৃদ্ধি সম্পাদন করে। যে কার্যে সোম  অভিষুত হয় তা তোমার প্রিয়। হে যজ্ঞযোগ্য! তুমি যজ্ঞ হেতু তোমার যজমানকে রক্ষা কর। এ যজ্ঞ অহিকে বিনাশ করবার জন্য তোমার বজ্রকে দৃঢ় করুক।"},{"n":13,"d":"यज्ञेनेन्द्रमवसा चक्रे अर्वागैनं सुम्नाय नव्यसे वव्र्त्याम | य सतोमेभिर्वाव्र्धे पूर्व्येभिर्यो मध्यमेभिरुत नूतनेभिः ||","b":"যজ্ঞেনেন্দ্রমবসা চক্রে অর্বাগৈনং সুম্নায নব্যসে বব্র্ত্যাম | য সতোমেভির্বাব্র্ধে পূর্ব্যেভির্যো মধ্যমেভিরুত নূতনেভিঃ ||","e":"With sacrifice and wish have I brought Indra; still for new blessings may I turn him hither, Him magnified by ancient songs and praises, by lauds of later time and days yet recent.","mb":"পুরাতন, মধ্যতন ও অধুনাতন স্তোমদ্বারা যে ইন্দ্র বর্ধিত হন, যজমান রক্ষাকর যজ্ঞঝ দ্বারা সে ইন্দ্রকে আপনার অভিমুখে আনছে, নুতন ধনের জন্য তাকে আবর্তিত করছে।"},{"n":14,"d":"विवेष यन मा धिषणा जजान सतवै पुरा पार्यादिन्द्रमह्नः | अंहसो यत्र पीपरद यथा नो नावेव यान्तमुभये हवन्ते ||","b":"বিবেষ যন মা ধিষণা জজান সতবৈ পুরা পার্যাদিন্দ্রমহ্নঃ | অংহসো যত্র পীপরদ যথা নো নাবেব যান্তমুভযে হবন্তে ||","e":"I have brought forth a song when longing seized me: ere the decisive day will I laud Indra; Then may he safely bear us over trouble, as in a ship, when both sides invocate him.","mb":"যখনই আমি মনে মনে ইন্দ্রকে স্তব করবার ইচ্ছা করি, তখনই আমি স্তুতি করি। আমি দূরবর্তী অশূভ দিবসের পূর্বেই ইন্দ্রকে স্তব করি, তিনি যেন আমাদের দুঃখের পরে নিয়ে যান। এ জন্য উভয় কুলবর্তী লোক সকল নৌকারোহীকে যেরূপ আহ্বান করে, সেরূপ আমার উভয় কুলবর্তী লোক সকল ইন্দ্রকে আহ্বান করছে।"},{"n":15,"d":"आपूर्णो अस्य कलशः सवाहा सेक्तेव कोशं सिसिचे पिबध्यै | समु परिया आवव्र्त्रन मदाय परदक्षिणिदभि सोमासैन्द्रम ||","b":"আপূর্ণো অস্য কলশঃ সবাহা সেক্তেব কোশং সিসিচে পিবধ্যৈ | সমু পরিযা আবব্র্ত্রন মদায পরদক্ষিণিদভি সোমাসৈন্দ্রম ||","e":"Full is his chalice: Glory! Like a pourer I have filled up the vessel for his drinking. Presented on the right, dear Soma juices have brought us Indra, to rejoice him, hither.","mb":"ইন্দ্রের কলস পূর্ণ হয়েছে, পানার্থে স্বহাশব্দ উচ্চারিত হয়েছে। সেক্তা যেমন জলপাত্রে জলসেক করে আমি সেরূপ সোম সেচন করছি। সুস্বাদু সোম ইন্দ্রের অভিমুখে প্রদক্ষিণ করে তার হর্ষের জন্য যাচ্ছে।"},{"n":16,"d":"न तवा गभीरः पुरुहूत सिन्धुर्नाद्रयः परि षन्तो वरन्त | इत्था सखिभ्य इषितो यदिन्द्रा दर्ळ्हं चिदरुजो गव्यमूर्वम ||","b":"ন তবা গভীরঃ পুরুহূত সিন্ধুর্নাদ্রযঃ পরি ষন্তো বরন্ত | ইত্থা সখিভ্য ইষিতো যদিন্দ্রা দর্ল্হং চিদরুজো গব্যমূর্বম ||","e":"Not the deep-flowing flood, O Much-invoked One! not hills that compass thee about restrain thee, Since here incited, for thy friends, O Indra, thou breakest e’en the firm built stall of cattle.","mb":"হে বহুলোকের আহুত ইন্দ্র! গভীর সিন্ধু তোমাকে বিনারণ করতে পারে না, তার চতুর্দিকে বর্তমান অদ্রিসকল তোমাকে নিবারণ করতে পারে না। যেহেতু বন্ধুগণ কর্তৃক এ প্রকারে প্রার্থিত হয়ে অতি প্রবল, গব্য উর্বাকে নিবারণ করেছ।"},{"n":17,"d":"शुनं हुवेम ... ||","b":"শুনং হুবেম ... ||","e":"Call we on Maghavan, auspicious Indra, best Hero in this fight where spoil is gathered, The Strong who listens, who gives aid in battles, who slays the Vṛtras, wins and gathers riches.","mb":"হে ইন্দ্র! তুমি অন্ন লাভ কর, যুদ্ধে উৎসাহ দ্বারা প্রবৃদ্ধ, তুমি ধনবান প্রভূত ঐশ্বর্যসম্পন্ন, নেতৃশ্রেষ্ঠ স্তুতিশ্রবণকারী, উগ্র, সংগ্রামে শত্রুবিনাশী ও ধর্মজেতা। আমরা আশ্রয় লাভের জন্য তোমাকে আহ্বান করছি।"}]},{"n":33,"t":"Indra","v":[{"n":1,"d":"पर पर्वतानामुशती उपस्थादश्वे इव विषिते हासमाने | गावेव शुभ्रे मातरा रिहाणे विपाट छुतुद्री पयसाजवेते ||","b":"পর পর্বতানামুশতী উপস্থাদশ্বে ইব বিষিতে হাসমানে | গাবেব শুভ্রে মাতরা রিহাণে বিপাট ছুতুদ্রী পযসাজবেতে ||","e":"FORTH from the bosom of the mountains, eager as two swift mares with loosened rein contending, Like two bright mother cows who lick their youngling, Vipāś and Sutudri speed down their waters.","mb":"জলপ্রবাহবতী বিপাশ ও শুতুদ্রী নদীদ্বয় পর্বতের উৎসঙ্গ প্রদেশ হতে সাগর সঙ্গমাভিলাষিণী হয়ে  মন্দুরাবিমুক্ত ঘোটকীদবয়ের ন্যায় স্পর্ধা করে গোদ্বয়ের ন্যায় শোভমানা হয়ে বৎসলেহনাভিলাষিণী ধেনুদ্বয়ের ন্যায় বেগে গমন করছে (১)।"},{"n":2,"d":"इन्द्रेषिते परसवं भिक्षमाणे अछा समुद्रं रथ्येव याथः | समाराणे ऊर्मिभिः पिन्वमाने अन्या वामन्यामप्येति शुभ्रे ||","b":"ইন্দ্রেষিতে পরসবং ভিক্ষমাণে অছা সমুদ্রং রথ্যেব যাথঃ | সমারাণে ঊর্মিভিঃ পিন্বমানে অন্যা বামন্যামপ্যেতি শুভ্রে ||","e":"Impelled by Indra whom ye pray to urge you, ye move as ’twere on chariots to the ocean. Flowing together, swelling with your billows, O lucid Streams, each of you seeks the other.","mb":"হে নদীদ্বয়! ইন্দ্র তোমাদের প্রেরণ করছেন, তোমরা তার প্রার্থনা রক্ষা করছ ও রথীদ্বয়ের ন্যায় সমুদ্রাভিমুখে যাচ্ছ। তোমরা একযোগে প্রবাহিত হয়ে তরঙ্গদ্বারা বর্ধিত হয়ে পরস্পর পরস্পরের নিকট গিয়ে শোভা পাচ্ছ।"},{"n":3,"d":"अछा सिन्धुं मात्र्तमामयासं विपाशमुर्वीं सुभगामगन्म | वत्समिव मातरा संरिहाणे समानं योनिमनु संचरन्ती ||","b":"অছা সিন্ধুং মাত্র্তমামযাসং বিপাশমুর্বীং সুভগামগন্ম | বত্সমিব মাতরা সংরিহাণে সমানং যোনিমনু সংচরন্তী ||","e":"I have attained the most maternal River, we have approached Vipāś, the broad, the blessed. Licking as ’twere their calf the pair of Mothers flow onward to their common home together.","mb":"মাতৃসদৃশী শুতুদ্রী নদীর নিকট উপস্থিত হয়েছি। মহতী সৌভাগ্যবতী বিপাশ নদীর নিকট উপস্থিত হয়েছি। এরা উভয়ে বৎসলেহনাভিলাষিণী ধেনুর ন্যায় এক স্থানাভিমুখে যাচ্ছে।"},{"n":4,"d":"एन वयं पयसा पिन्वमाना अनु योनिं देवक्र्तं चरन्तीः | न वर्तवे परसवः सर्गतक्तः किंयुर्विप्रो नद्यो जोहवीति ||","b":"এন বযং পযসা পিন্বমানা অনু যোনিং দেবক্র্তং চরন্তীঃ | ন বর্তবে পরসবঃ সর্গতক্তঃ কিংযুর্বিপ্রো নদ্যো জোহবীতি ||","e":"We two who rise and swell with billowy waters move forward to the home which Gods have made us. Our flood may not be stayed when urged to motion. What would the singer, calling to the Rivers?","mb":"নদীদ্বয়: আমরা এ জল দ্বারা স্ফীত হয়ে দেবকৃত স্থানের অভিমুখে যাচ্ছি। আমাদের গমনের উদ্যোগ নিবৃত্ত হবার নয়। কি জন্য এ বিপ্র বার বার নদীগণকে আহ্বান করছে?"},{"n":5,"d":"रमध्वं मे वचसे सोम्याय रतावरीरुप मुहूर्तमेवैः | पर सिन्धुमछा बर्हती मनीषावस्युरह्वे कुशिकस्य सूनुः ||","b":"রমধ্বং মে বচসে সোম্যায রতাবরীরুপ মুহূর্তমেবৈঃ | পর সিন্ধুমছা বর্হতী মনীষাবস্যুরহ্বে কুশিকস্য সূনুঃ ||","e":"Linger a little at my friendly bidding rest, Holy Ones, a moment in your journey. With hymn sublime soliciting your favour Kuśika's son hath called unto the River.","mb":"বিশ্বামিত্র: হে জলবতী নদীদ্বয়! আমার সোম সম্পাদক বাক্যের জন্য মুহুর্তের জন্য গমন হতে বিরত হও। আমি কুশিকের পুত্র, আমি প্রসাদাভিলাষে মহতী স্তুতি দ্বারা নদীকে আমার উদ্দেশে আহ্বান করছি।"},{"n":6,"d":"इन्द्रो अस्मानरदद वज्रबाहुरपाहन वर्त्रं परिधिं नदीनाम | देवो.अनयत सवित सुपाणिस्तस्य वयं परसवे याम उर्वीः ||","b":"ইন্দ্রো অস্মানরদদ বজ্রবাহুরপাহন বর্ত্রং পরিধিং নদীনাম | দেবো.অনযত সবিত সুপাণিস্তস্য বযং পরসবে যাম উর্বীঃ ||","e":"Indra who wields the thunder dug our channels: he smote down Vṛtra, him who stayed our currents. Savitar, God, the lovely-handed, led us, and at his sending forth we flow expanded.","mb":"নদীদ্বয়: নদীগণের পরিবেষ্টক বৃত্তকে হনন করে বজ্রবাহু ইন্দ্র আমাদের খনন করছেন। জগৎপ্রেরক সুহস্ত, দ্যুতিমান ইন্দ্র আমাদের প্রেরণ করেছেন, তার আজ্ঞায় আমরা প্রভূত হয়ে গমন করছি।"},{"n":7,"d":"परवाच्यं शश्वधा वीर्यं तदिन्द्रस्य कर्म यदहिंविव्र्श्चत | वि वज्रेण परिषदो जघानायन्नापो.अयनमिछमानाः ||","b":"পরবাচ্যং শশ্বধা বীর্যং তদিন্দ্রস্য কর্ম যদহিংবিব্র্শ্চত | বি বজ্রেণ পরিষদো জঘানাযন্নাপো.অযনমিছমানাঃ ||","e":"That hero deed of Indra must be lauded for ever that he rent Ahi in pieces. He smote away the obstructors with his thunder, and eager for their course forth flowed the waters.","mb":"বিশ্বামিত্র: ইন্দ্র যে অহিকে বিদীর্ণ করেছিলেন, তার সে বীর কর্ম সর্বদা কীর্তন করা উচিত। ইন্দ্র চতুর্দিকে আসীম অর্থাৎ অবরোধকারীদের বজ্রদ্বারা বধ করছিলেন। গমনালাভিলাষী জলসমূহ এসেছিল।"},{"n":8,"d":"एतद वचो जरितर्मापि मर्ष्ठा आ यत ते घोषानुत्तरा युगानि | उक्थेषु कारो परति नो जुषस्व मा नो नि कः पुरुषत्रा नमस्ते ||","b":"এতদ বচো জরিতর্মাপি মর্ষ্ঠা আ যত তে ঘোষানুত্তরা যুগানি | উক্থেষু কারো পরতি নো জুষস্ব মা নো নি কঃ পুরুষত্রা নমস্তে ||","e":"Never forget this word of thine, O singer, which future generations shall reecho. In hymns, O bard, show us thy loving kindness. Humble us not mid men. To thee be honour!","mb":"নদীদ্বয়: হে স্তোতা! তুমি এই যে বাক্য ঘোষনা করছ, তা বিস্মৃত হয়ো না, ভবিষ্যৎ যজ্ঞ দিবসে তুমি উকথ রচনা করে আমাদের সেবা করো। আমরা তোমাকে নমস্কার করছি, আমাদের পুরুষের ন্যায় প্রগলভ করো না।"},{"n":9,"d":"ओ षु सवसारः कारवे शर्णोत ययौ वो दूरादनसा रथेन | नि षू नमध्वं भवता सुपारा अधोक्षाः सिन्धवःस्रोत्याभिः ||","b":"ও ষু সবসারঃ কারবে শর্ণোত যযৌ বো দূরাদনসা রথেন | নি ষূ নমধ্বং ভবতা সুপারা অধোক্ষাঃ সিন্ধবঃস্রোত্যাভিঃ ||","e":"List quickly, Sisters, to the bard who cometh to you from far away with car and wagon. Bow lowly down; be easy to be traversed stay, Rivers, with your floods below our axles.","mb":"বিশ্বামিত্র: হে ভগিনীভূত নদীদ্বয় আমি স্তব করছি। আমাকে প শ্রবণ কর। আমি দুরদেশ হতে রথ ও অশ্ব নিয়ে এসেছি। তোমরা অবনত হও, যাতে সুখে পার হওয়া যাবে। হে নদীদ্বয়! তোমরা স্রোতের জল নিয়ে রথচক্রের অক্ষের অধোদেশে যাও।"},{"n":10,"d":"आ ते कारो शर्णवामा वचांसि ययाथ दूरादनसा रथेन | नि ते नंसै पीप्यानेव योषा मर्यायेव कन्या शश्वचै ते ||","b":"আ তে কারো শর্ণবামা বচাংসি যযাথ দূরাদনসা রথেন | নি তে নংসৈ পীপ্যানেব যোষা মর্যাযেব কন্যা শশ্বচৈ তে ||","e":"Yea, we will listen to thy words, O singer. With wain and car from far away thou comest. Low, like a nursing mother, will I bend me, and yield me as a maiden to her lover.","mb":"নদীদ্বয়: হে স্তোতা! আমরা তোমার এ সকল বাক্য শুনলাম তুমি দুর হতে এসেছ, অতএব রথ ও শকটের সাথে যাও। মাতা যেমন পুত্রকে জন পান করাবার জন্য এবং যুবতী যেরূপ মানুষকে আলিঙ্গন করবা রজন্য অবনত হয়, সেরূপ আমরা তোমার জন্য অবনত হচ্ছি।"},{"n":11,"d":"यदङग तवा भरताः सन्तरेयुर्गव्यन गराम इषित इन्द्रजूतः | अर्षादह परसवः सर्गतक्त आ वो वर्णे सुमतिं यज्ञियानाम ||","b":"যদঙগ তবা ভরতাঃ সন্তরেযুর্গব্যন গরাম ইষিত ইন্দ্রজূতঃ | অর্ষাদহ পরসবঃ সর্গতক্ত আ বো বর্ণে সুমতিং যজ্ঞিযানাম ||","e":"Soon as the Bharatas have fared across thee, the warrior band, urged on and sped by Indra, Then let your streams flow on in rapid motion. I crave your favour who deserve our worship.","mb":"বিশ্বামিত্র: হে নদীদ্বয়! যেহেতু ভারতগণ (২) তোমাদের পার হবে, যেহেতু পার হতে অভিলাষী ভরত বংশীয়েরা ইন্দ্র কর্তৃক প্রেরিত ও তোমাদের কর্তৃক অনুজ্ঞাত হয়ে পার হবে, ও পার হবার উদ্যোগ করছে ও অনুমতি পেয়েছে, অতএব আমি সর্বত্র তোমাদের স্তুতি করব; তোমরা যজ্ঞার্হ।"},{"n":12,"d":"अतारिषुर्भरता गव्यवः समभक्त विप्रः सुमतिं नदीनाम | पर पिन्वध्वमिषयन्तीः सुराधा आ वक्षणाः पर्णध्वं यात शीभम ||","b":"অতারিষুর্ভরতা গব্যবঃ সমভক্ত বিপ্রঃ সুমতিং নদীনাম | পর পিন্বধ্বমিষযন্তীঃ সুরাধা আ বক্ষণাঃ পর্ণধ্বং যাত শীভম ||","e":"The warrior host, the Bharatas, fared over the singer won the favour of the Rivers. Swell with your billows, hasting, pouring riches. Fill full your channels, and roll swiftly onward.","mb":"গোধন অভিলাষী ভারতগণ পার হয়ে গেলেন, বিপ্র নদীগণের সুন্দর স্তুতি করছেন। তোমরা অন্নকারিণী ও ধনযুক্তা হয়ে ক্ষুদ্র ক্ষুদ্র নদী সকলকে তৃপ্ত কর ও পূর্ণ কর এবং শীঘ্র যাও।"},{"n":13,"d":"उद व ऊर्मिः शम्या हन्त्वापो योक्त्राणि मुञ्चत | मादुष्क्र्तौ वयेनसाघ्न्यौ शूनमारताम ||","b":"উদ ব ঊর্মিঃ শম্যা হন্ত্বাপো যোক্ত্রাণি মুঞ্চত | মাদুষ্ক্র্তৌ বযেনসাঘ্ন্যৌ শূনমারতাম ||","e":"So let your wave bear up the pins, and ye, O Waters, spare the thongs; And never may the pair of Bulls, harmless and sinless, waste away.","mb":"হে নদীদ্বয়! তোমাদের তরঙ্গ এরূপভাবে প্রবাহিত হোক, যে যুগকীল (৩) তার উপরে থাকুক তোমরা রজ্জু স্পর্শ করো না। পাপরহিতা, কল্যাণকারিণী, অনিন্দানীয়া বিপাশ ও শুততুদ্রু যেন এক্ষণে বর্ধিতা না হয়।"}]},{"n":34,"t":"Indra","v":[{"n":1,"d":"इन्द्रः पूर्भिदातिरद दासमर्कैर्विदद्वसुर्दयमानो विशत्रून | बरह्मजूतस्तन्वा वाव्र्धानो भूरिदात्र आप्र्णद रोदसी उभे ||","b":"ইন্দ্রঃ পূর্ভিদাতিরদ দাসমর্কৈর্বিদদ্বসুর্দযমানো বিশত্রূন | বরহ্মজূতস্তন্বা বাব্র্ধানো ভূরিদাত্র আপ্র্ণদ রোদসী উভে ||","e":"FORT-RENDER, Lord of Wealth, dispelling foemen, Indra with lightnings hath o’ercome the Dāsa. Impelled by prayer and waxen great in body, he hath filled earth and heaven, the Bounteous Giver.","mb":"পুরভেদী, মহিমাসূচক ধনযুক্ত ইন্দ্র, শত্রুদরে হিংসা করে তেজ দ্বারা দাসকে জয় করেছেন। স্তোত্র দ্বারা আকৃষ্ট, বর্ধিত শরীর ও বহু অস্ত্রধারী ইন্দ্র দ্যাবাপৃথিবীকে পরিপূর্ণ করেছেন।"},{"n":2,"d":"मखस्य ते तविषस्य पर जूतिमियर्मि वाचमम्र्ताय भूषन | इन्द्र कषितीनामसि मानुषीणां विशां दैवीनामुत पूर्वयावा ||","b":"মখস্য তে তবিষস্য পর জূতিমিযর্মি বাচমম্র্তায ভূষন | ইন্দ্র কষিতীনামসি মানুষীণাং বিশাং দৈবীনামুত পূর্বযাবা ||","e":"I stimulate thy zeal, the Strong, the Hero decking my song of praise forth; Immortal. O Indra, thou art equally the Leader of heavenly hosts and human generations.","mb":"হে ইন্দ্র! তুমি পূজনীয় ও বলবান, তোমাকে অলঙ্কৃত করে অন্নের জন্য তোমার প্রেরিত স্তুতি উচ্চারণ করছি। তুমি মানুষ এবং দেবগণের অগ্রগামী।"},{"n":3,"d":"इन्द्रो वर्त्रमव्र्णोच्छर्धनीतिः पर मायिनाममिनाद वर्पणीतिः | अहन वयंसमुशधग वनेष्वाविर्धेना अक्र्णोद राम्याणाम ||","b":"ইন্দ্রো বর্ত্রমব্র্ণোচ্ছর্ধনীতিঃ পর মাযিনামমিনাদ বর্পণীতিঃ | অহন বযংসমুশধগ বনেষ্বাবির্ধেনা অক্র্ণোদ রাম্যাণাম ||","e":"Leading, his band Indra encompassed Vṛtra; weak grew the wily leader of enchanters. He who burns fierce in forests slaughtered Vyaṁsa, and made the Milch-kine of the nights apparent.","mb":"হে ইন্দ্র! তোমার কর্ম প্রসিদ্ধ, তুমি বৃত্রকে অবরোধ করেছিলে। শত্রুদের আক্রমণ নিবারক ইন্দ্র মায়াবিদের বিশেষরূপে বধ করেছেন। শত্রুবধাভিলাষী ইন্দ্র বনে লুকায়িত স্বদ্ধহীন শত্রুকে বিনাশ করেছেন, রামাদের গাভী সকল আবিষ্কৃত করেছেন।"},{"n":4,"d":"इन्द्रः सवर्षा जनयन्नहानि जिगायोशिग्भिः पर्तना अभिष्टिः | परारोचयन मनवे केतुमह्नामविन्दज्ज्योतिर्ब्र्हतेरणाय ||","b":"ইন্দ্রঃ সবর্ষা জনযন্নহানি জিগাযোশিগ্ভিঃ পর্তনা অভিষ্টিঃ | পরারোচযন মনবে কেতুমহ্নামবিন্দজ্জ্যোতির্ব্র্হতেরণায ||","e":"Indra, light-winner, days' Creator, conquered, victorious, hostile bands with those who loved him. For man the days' bright ensign he illumined, and found the light for his joy and gladness.","mb":"স্বর্গপ্রদ ইন্দ্র দিবস উৎপন্ন করে যুদ্ধাভিলাষী অঙ্গিরাগণের সাথে পরকীয় সেনা অভিভব করে জয় করেলেন। মানুষের জন্য দিবসের কেতুস্বরূপ সূর্যকে প্রদীপ্ত করেছিলেন, মহাযুদ্ধের জন্য জ্যোতি প্রকাশ প্রাপ্ত হল।"},{"n":5,"d":"इन्द्रस्तुजो बर्हणा आ विवेश नर्वद दधानो नर्या पुरूणि | अचेतयद धिय इमा जरित्रे परेमं वर्णमतिरच्छुक्रमासाम ||","b":"ইন্দ্রস্তুজো বর্হণা আ বিবেশ নর্বদ দধানো নর্যা পুরূণি | অচেতযদ ধিয ইমা জরিত্রে পরেমং বর্ণমতিরচ্ছুক্রমাসাম ||","e":"Forward to fiercely falling blows pressed Indra, herolike doing many hero exploits. These holy songs he taught the bard who gaised him, and widely spread these Dawns' resplendent colour.","mb":"ইন্দ্র বহু ধন গ্রহণ করে বাধাদায়িনী ও বর্ধমানা শত্রু সেনায় মধ্যে প্রবেশ করলেন। তিনি স্তোতার জন্য উষাকে চৈতন্য প্রদান করেছেন এবং ওদের শুভ্র বর্ণ তেজ বর্ধিত করেছেন।"},{"n":6,"d":"महो महानि पनयन्त्यस्येन्द्रस्य कर्म सुक्र्ता पुरूणि | वर्जनेन वर्जिनान सं पिपेष मायाभिर्दस्यून्रभिभूत्योजाः ||","b":"মহো মহানি পনযন্ত্যস্যেন্দ্রস্য কর্ম সুক্র্তা পুরূণি | বর্জনেন বর্জিনান সং পিপেষ মাযাভির্দস্যূন্রভিভূত্যোজাঃ ||","e":"They laud the mighty acts of him the Mighty, the many glorious deeds performed by Indra. He in his strength, with all-surpassing prowess, through wondrous arts crushed the malignant Dasyus.","mb":"ইনদ্র মহান, উপাসকেরা তারা প্রতূত  সৎকার্যের প্রশংসা করছে। তিনি বলদ্বারা বলবানদের চুর্ণ করেছেন। পরাভবকারীতে জ্যাযুক্ত ্ন্দ্রি  দসূদের মায়াদ্বারা চূর্ণ করেছেন।"},{"n":7,"d":"युधेन्द्रो मह्ना वरिवश्चकार देवेभ्यः सत्पतिश्चर्षणिप्राः | विवस्वतः सदने अस्य तानि विप्रा उक्थेभिः कवयोग्र्णन्ति ||","b":"যুধেন্দ্রো মহ্না বরিবশ্চকার দেবেভ্যঃ সত্পতিশ্চর্ষণিপ্রাঃ | বিবস্বতঃ সদনে অস্য তানি বিপ্রা উক্থেভিঃ কবযোগ্র্ণন্তি ||","e":"Lord of the brave, Indra who rules the people gave freedom to the Gods by might and battle. Wise singers glorify with chanted praises these his achievements in Vivasvān's dwelling.","mb":"দেবপতি ও মনুষ্যদের বরপ্রদ ইন্দ্র মহাযুদ্ধে ধনলাভ করে স্তোতাগণকে দান করলেন। মেধাবী স্তোতাগণ যজমানের গৃহে উকথদ্বারা ইন্দ্রের কীর্তি সকল স্তব করছেন।"},{"n":8,"d":"सत्रासाहं वरेण्यं सहोदां ससवांसं सवरपश्च देवीः | ससान यः पर्थिवीं दयामुतेमामिन्द्रं मदन्त्यनु धीरणासः ||","b":"সত্রাসাহং বরেণ্যং সহোদাং সসবাংসং সবরপশ্চ দেবীঃ | সসান যঃ পর্থিবীং দযামুতেমামিন্দ্রং মদন্ত্যনু ধীরণাসঃ ||","e":"Excellent, Conqueror, the victory-giver, the winner of the light and Godlike Waters, He who hath won this broad earth and this heaven, -in Indra they rejoice who love devotions.","mb":"স্তোতাগণ সকলের জেতা, বরণীয়, বলপ্রদ, স্বর্গ এবং স্বর্গীয় জলের স্বামী ইন্দ্রের আনন্দে আনন্দিত হচ্ছেন। ইন্দ্র পৃথিবী, অন্তরিক্ষ এবং স্বর্গ দান করেছেন।"},{"n":9,"d":"ससानात्यानुत सूर्यं ससानेन्द्रः ससान पुरुभोजसं गाम | हिरण्ययमुत भोगं ससान हत्वी दस्यून परार्यंवर्णमावत ||","b":"সসানাত্যানুত সূর্যং সসানেন্দ্রঃ সসান পুরুভোজসং গাম | হিরণ্যযমুত ভোগং সসান হত্বী দস্যূন পরার্যংবর্ণমাবত ||","e":"He gained possession of the Sun and Horses, Indra obtained the Cow who feedeth many. Treasure of gold he won; he smote the Dasyus, and gave protection to the Āryan colour.","mb":"্ন্দ্র অশ্বদান করেছেন, সূর্য দান করেছেন, বহু লোকরে উপভোগযোগ্য গোধন দান করেছেন, সুবর্ণময় ধন দান করেছেন, দস্যুদের বধ করে আর্যবর্ণকে রক্ষা করেছেন (১)।"},{"n":10,"d":"इन्द्र ओषधीरसनोदहानि वनस्पतीन्रसनोदन्तरिक्षम | बिभेद वलं नुनुदे विवाचो.अथाभवद दमितद्भिक्रतूनाम ||","b":"ইন্দ্র ওষধীরসনোদহানি বনস্পতীন্রসনোদন্তরিক্ষম | বিভেদ বলং নুনুদে বিবাচো.অথাভবদ দমিতদ্ভিক্রতূনাম ||","e":"He took the plants and days for his possession; he gained the forest trees and air's mid-region. Vala he cleft, and chased away opponents: thus was he tamer of the overweening.","mb":"ইন্দ্র, ওষধি প্রদান করেছেন, দিবস প্রদান করেছেন বনস্পতি ও অন্তরীক্ষদের প্রদান করেছেন। তিনি মেঘ ভেদ করেছেন, বিরুদ্ধ বাদীদের বধ করেছেন, যারা অভিমুখে যুদ্ধ করতে আসে তাদরে বধ করেছেন।"},{"n":11,"d":"शुनं हुवेम ... ||","b":"শুনং হুবেম ... ||","e":"Call we on Maghavan, auspicious Indra, best Hero in the fight where spoil is gathered, The Strong, who listens, who gives aid in battles, who slays the Vṛtras, wins and gathers treasures.","mb":"হে ইন্দ্র! তুমি অন্নলাভ কর, যুদ্ধে উৎসাহ দ্বারা প্রবৃদ্ধ, তুমি ধনবান প্রভূত ঐশ্বর্য সম্পন্ন, নেতৃশ্রেষ্ঠ, স্তুতিশ্রবণকারী, উগ্র সংগ্রামী শত্রুবিনাশী এবং ধনজেতা। আমরা আশ্রয় লাভের জন্য তোমাকে আহ্বান করছি।"}]},{"n":35,"t":"Indra","v":[{"n":1,"d":"तिष्ठा हरी रथ आ युज्यमाना याहि वायुर्न नियुतो नो अछ | पिबास्यन्धो अभिस्र्ष्टो अस्मे इन्द्र सवाहा ररिमाते मदाय ||","b":"তিষ্ঠা হরী রথ আ যুজ্যমানা যাহি বাযুর্ন নিযুতো নো অছ | পিবাস্যন্ধো অভিস্র্ষ্টো অস্মে ইন্দ্র সবাহা ররিমাতে মদায ||","e":"MOUNT the Bay Horses to thy chariot harnessed, and come to us like Vāyu with his coursers. Thou, hastening to us, shalt drink the Soma. Hail, Indra. We have poured it for thy rapture.","mb":"হে ইন্দ্র! হরিনামক অশষ্বদ্বয় রথে যোজিত হচ্ছে। তুমি তাদরে জন্য বায়ু যেরূপ নিষুতের জন্য অপেক্ষা করে, সেরূপ কিয়ৎক্ষণ অপেক্ষা করে আমাদের অভিমুখে এস। আমাদের প্রদত্ত সোম পান কর, আমরা স্বাহা শব্দ উচ্চারণ করে তোমার আনন্দের জন্য সোমপান করছি।"},{"n":2,"d":"उपाजिरा पुरुहूताय सप्ती हरी रथस्य धूर्ष्वा युनज्मि | दरवद यथा सम्भ्र्तं विश्वतश्चिदुपेमं यज्ञमावहात इन्द्रम ||","b":"উপাজিরা পুরুহূতায সপ্তী হরী রথস্য ধূর্ষ্বা যুনজ্মি | দরবদ যথা সম্ভ্র্তং বিশ্বতশ্চিদুপেমং যজ্ঞমাবহাত ইন্দ্রম ||","e":"For him, the God who is invoked by many, the two swift Bay Steeds to the pole I harness, That they in fleet course may bring Indra hither, e’en to this sacrifice arranged completely.","mb":"হু লোকরে আহুত ইন্দ্রের শীঘ্র গমনার্থে রথের অগ্রভাগে দ্রুতগামী অশ্বদ্বয় সংযোজিত করছি। অশ্দ্বয় সর্বতোভাবে অনুষ্ঠিত এ যজ্ঞের প্রতি ইন্দ্রকে শীঘ্র আনুক।"},{"n":3,"d":"उपो नयस्व वर्षणा तपुष्पोतेमव तवं वर्षभ सवधावः | गरसेतामश्वा वि मुचेह शोणा दिवे-दिवे सद्र्शीरद्धिधानाः ||","b":"উপো নযস্ব বর্ষণা তপুষ্পোতেমব তবং বর্ষভ সবধাবঃ | গরসেতামশ্বা বি মুচেহ শোণা দিবে-দিবে সদ্র্শীরদ্ধিধানাঃ ||","e":"Bring the strong Steeds who drink the warm libation, and, Bull of Godlike nature, be thou gracious. Let thy Steeds eat; set free thy Tawny Horses, and roasted grain like this consume thou daily.","mb":"হে অভীষ্টবর্ষী অন্নবান ইন্দ্র! তোমার বীর্যবান শত্রুভয়ত্তাতা অশ্বদ্বয়কে আমাদের নিকট আন, তুমি এ যজমানকে রক্ষা কর। রক্তবর্ণ অশ্বদ্বয়কে এ দেবযজনে ছেড়ে দাও, তারা ভক্ষণ করুক। তুমি সমান  রূপবিশিষ্ট উপযুক্ত ধান্য ভক্ষণ কর (১)।"},{"n":4,"d":"बरह्मणा ते बरह्मयुजा युनज्मि हरी सखाया सधमाद आशू | सथिरं रथं सुखमिन्द्राधितिष्ठन परजानन विद्वानुप याहि सोमम ||","b":"বরহ্মণা তে বরহ্মযুজা যুনজ্মি হরী সখাযা সধমাদ আশূ | সথিরং রথং সুখমিন্দ্রাধিতিষ্ঠন পরজানন বিদ্বানুপ যাহি সোমম ||","e":"Those who are yoked by prayer I harness, fleet friendly Bays who take their joy together. Mounting thy firm and easy car, O Indra, wise and all-knowing come thou to the Soma.","mb":"হে ইন্দ্র! তোমার যে অশ্বদ্বয় মন্ত্রদ্বারা যোজিত হয় এবং যুদ্ধে যাদের সমান প্রসিদ্ধি, মন্ত্রবলে সে অশ্বদ্বয়কে যোজিত করছি। হে ইন্দ্র! তুমি বিদ্বান, তুমি জেনে সুদৃঢ় এবং সুখকর রথে আরোহণ করে সোমের নিকট এস।"},{"n":5,"d":"मा ते हरी वर्षणा वीतप्र्ष्ठा नि रीरमन यजमानासो अन्ये | अत्यायाहि शश्वतो वयं ते.अरं सुतेभिः कर्णवामसोमैः ||","b":"মা তে হরী বর্ষণা বীতপ্র্ষ্ঠা নি রীরমন যজমানাসো অন্যে | অত্যাযাহি শশ্বতো বযং তে.অরং সুতেভিঃ কর্ণবামসোমৈঃ ||","e":"No other worshippers must stay beside them thy Bays, thy vigorous and smooth-backed Coursers. Pass by them all and hasten onward hither: with Soma pressed we will prepare to feast thee.","mb":"হে ইন্দ্র! অন্য যজমানগণ যেন তোমার বীর্যবান ও কমনীয় পৃষ্ঠ বিশিষ্ট হরিদ্বয়কে আনন্দিত না করে। আমরা অভিষুত সোমদ্বারা পর্যাপ্তরূপে তোমার তৃপ্তিসাধন করব, তুমি বহুতর যজমানকে অতিক্রম করে শীঘ্র এস।"},{"n":6,"d":"तवायं सोमस्त्वमेह्यर्वां छश्वत्तमं सुमना अस्यपाहि | अस्मिन यज्ञे बर्हिष्या निषद्या दधिष्वेमं जठर इन्दुमिन्द्र ||","b":"তবাযং সোমস্ত্বমেহ্যর্বাং ছশ্বত্তমং সুমনা অস্যপাহি | অস্মিন যজ্ঞে বর্হিষ্যা নিষদ্যা দধিষ্বেমং জঠর ইন্দুমিন্দ্র ||","e":"Thine is this Soma: hasten to approach it. Drink thou thereof, benevolent, and cease not. Sit on the sacred grass at this our worship, and take these drops into thy belly, Indra.","mb":"এ সোম তোমার, তুমি এর অভিমুখে এস। প্রীতমনে এ প্রভূত সোম পান কর। হে ইন্দ্র! এ যজ্ঞে কুশোপরি উপবেশন করে এ সোমকে জঠরে স্থাপন কর।"},{"n":7,"d":"सतीर्णं ते बर्हिः सुत इन्द्र सोमः कर्ता धाना अत्तवे तेहरिभ्याम | तदोकसे पुरुशाकाय वर्ष्णे मरुत्वते तुभ्यंराता हवींषि ||","b":"সতীর্ণং তে বর্হিঃ সুত ইন্দ্র সোমঃ কর্তা ধানা অত্তবে তেহরিভ্যাম | তদোকসে পুরুশাকায বর্ষ্ণে মরুত্বতে তুভ্যংরাতা হবীংষি ||","e":"The grass is strewn for thee, pressed is the Soma; the grain is ready for thy Bays to feed on. To thee who lovest them, the very mighty, strong, girt by Maruts, are these gifts presented.","mb":"হে ্ন্দ্রি! তোমার জন্য কুশ বিস্তৃত করা হয়েছে, সোম অভিষুত হয়েছে, তোমার অশ্বদ্বয়ের ভোজনের জন্য ধান্য প্রস্তুত হয়েছে। কুশ তোমার আসন, অনেকে তোমার স্তব করে, তুমি অভীষ্টবর্ষী, তোমার মরুৎ সেনা আছে, তোমার জন্য হব্য সকল বিস্তৃত হয়েছে।"},{"n":8,"d":"इमं नरः पर्वतास्तुभ्यमापः समिन्द्र गोभिर्मधुमन्तमक्रन | तस्यागत्या सुमना रष्व पाहि परजानन विद्वान पथ्या अनु सवाः ||","b":"ইমং নরঃ পর্বতাস্তুভ্যমাপঃ সমিন্দ্র গোভির্মধুমন্তমক্রন | তস্যাগত্যা সুমনা রষ্ব পাহি পরজানন বিদ্বান পথ্যা অনু সবাঃ ||","e":"This the sweet draught, with cows, the men, the mountains, the waters, Indra, have for thee made ready. Come, drink thereof, Sublime One, friendly-minded, foreseeing, knowing well the ways thou goest.","mb":"হে ইন্দ্র! তোমার জন্য অধ্বর্যুগণ প্রস্তর ও জল এ সোম  দুগ্ধকে মধুর রসবিশিষ্ট করেছে। হে দর্শনীয় ও বিদ্বান ইন্দ্র! তুমি প্রসন্ন মনে আপন হিতকর স্তুতি অবগত হয়ে সোম পান কর।"},{"n":9,"d":"यानाभजो मरुत इन्द्र सोमे ये तवामवर्धन्नभवन गणस्ते | तेभिरेतं सजोषा वावशानो.अग्नेः पिब जिह्वयासोममिन्द्र ||","b":"যানাভজো মরুত ইন্দ্র সোমে যে তবামবর্ধন্নভবন গণস্তে | তেভিরেতং সজোষা বাবশানো.অগ্নেঃ পিব জিহ্বযাসোমমিন্দ্র ||","e":"The Maruts, they with whom thou sharedst Soma, Indra, who made thee strong and were thine army,— With these accordant, eagerly desirous drink thou this Soma with the tongue of Agni.","mb":"হে ইন্দ্র! সোমপান কালে যে মরুৎগণকে সম্ভাবিত কর, যারা যুদ্ধে তোমাকে বর্ধিত করে ও তোমার সহায় হয়, সে সকল মরুৎগণের সাথে মিলিত হয়ে সোমপানাভিলাষী হয়ে অগ্নির জিহ্বা দ্বারা পান কর।"},{"n":10,"d":"इन्द्र पिब सवधया चित सुतस्याग्नेर्वा पाहि जिह्वया यजत्र | अध्वर्योर्वा परयतं शक्र हस्ताद धोतुर्वा यज्ञं हविषो जुषस्व ||","b":"ইন্দ্র পিব সবধযা চিত সুতস্যাগ্নের্বা পাহি জিহ্বযা যজত্র | অধ্বর্যোর্বা পরযতং শক্র হস্তাদ ধোতুর্বা যজ্ঞং হবিষো জুষস্ব ||","e":"Drink, Indra, of the juice by thine own nature, or by the tongue of Agni, O thou Holy. Accept the sacrificial gift, O Śakra, from the Adhvaryu's hand or from the Hotar's.","mb":"হে যজনীয় ইন্দ্র! স্বধাদ্বারা অথবা অগ্নির জিহ্বাদ্বারা অভিষুত সোম পান কর। হে শক্রু! অধুর্ষুর হস্ত দ্বারা প্রদত্ত সোম অথবা হোতার যজনীয় হব্য সেবা কর।"},{"n":11,"d":"शुनं हुवेम ... ||","b":"শুনং হুবেম ... ||","e":"Call we on Maghavan, auspicious Indra, best Hero in the fight where spoil is gathered, The Strong, who listens, who.gives aid in battles, who slays the Vṛtras, wins and gathers riches.","mb":"হে ইন্দ্র! তুমি অন্নলাভকর যুদ্ধে উৎসাহ দ্বারা প্রবৃদ্ধ: তুমি ধনবান প্রভূত ঐশ্বর্যসম্পন্ন, নেতৃশ্রেষ্ঠ, স্তুতিশ্রবণকারী উগ্র, সংগ্রামে শত্রু বিনাশী এবং ধনজেতা। আমরা আশ্রয় লাভের জন্য তোমাকে আহ্বান করছি।"}]},{"n":36,"t":"Indra","v":[{"n":1,"d":"इमामू षु परभ्र्तिं सातये धाः शश्वचः छश्वदूतिभिर्यादमानः | सुते-सुते वाव्र्धे वर्धनेभिर्यः कर्मभिर्महद्भिः सुश्रुतो भूत ||","b":"ইমামূ ষু পরভ্র্তিং সাতযে ধাঃ শশ্বচঃ ছশ্বদূতিভির্যাদমানঃ | সুতে-সুতে বাব্র্ধে বর্ধনেভির্যঃ কর্মভির্মহদ্ভিঃ সুশ্রুতো ভূত ||","e":"WITH constant succours, fain thyself to share it, make this oblation which we bring effective. Grown great through strengthening gifts at each libation, he hath become renowned by mighty exploits.","mb":"হে ইন্দ্র! মরুৎগণের সঙ্গে সর্বদা এসে বিশেষরূপে প্রস্তুত সোম ধন দানের জন্য ধারণ কর। যে ইন্দ্র বৃহৎ কর্মদ্বারা প্রখ্যাত হয়েছে তিনি প্রত্যেক সোমাভিষবে পুষ্টিসাধক হব্য দ্বারা বর্ধিত হয়েছেন।"},{"n":2,"d":"इन्द्राय सोमाः परदिवो विदाना रभुर्येभिर्व्र्षपर्वा विहायाः | परयम्यमानान परति षू गर्भायेन्द्र पिब वर्षधूतस्य वर्ष्णः ||","b":"ইন্দ্রায সোমাঃ পরদিবো বিদানা রভুর্যেভির্ব্র্ষপর্বা বিহাযাঃ | পরযম্যমানান পরতি ষূ গর্ভাযেন্দ্র পিব বর্ষধূতস্য বর্ষ্ণঃ ||","e":"For Indra were the Somas erst- discovered, whereby he grew strong-jointed, vast, and skilful. Indra , take quickly these presented juices: drink of the strong, that which the strong have shaken.","mb":"পূর্বকালে ইন্দ্রের উদ্দেশে সোম প্রদত্ত হয়েছে, যা দিয়ে তিনি কালাত্মক, দীপ্ত ও মহান হয়েছেন। হে ্ন্দ্রি! তুমি এ প্রদত্ত সোম গ্রহণ কর এবং স্বর্গাদি ফলপ্রদ প্রস্তর দ্বারা অভিষুত সোম পান কর।"},{"n":3,"d":"पिबा वर्धस्व तव घा सुतास इन्द्र सोमासः परथमा उतेमे | यथापिबः पूर्व्यानिन्द्र सोमानेवा पाहि पन्यो अद्या नवीयान ||","b":"পিবা বর্ধস্ব তব ঘা সুতাস ইন্দ্র সোমাসঃ পরথমা উতেমে | যথাপিবঃ পূর্ব্যানিন্দ্র সোমানেবা পাহি পন্যো অদ্যা নবীযান ||","e":"Drink and wax great. Thine are the juices, Indra, both Somas of old time and these we bring thee. Even as thou drankest, Indra, earlier Somas, so drink to-day, a new guest, meet for praises.","mb":"হে ইন্দ্র! পান কর  ও পরিপুষ্ট হও। তোমার জন্য প্রাচীন ও নুতন সোম অভিষুত হয়েছে। হে ইন্দ্র! তুমি স্তুতিযোগ্য তুমি পুরাতন সোম যেরূপ পান করেছিলে সেরূপ এক্ষণে নূতন সোম পান কর।"},{"n":4,"d":"महानमत्रो वर्जने विरप्श्युग्रं शवः पत्यते धर्ष्ण्वोजः | नाह विव्याच पर्थिवी चनैनं यत सोमासो हर्यश्वममन्दन ||","b":"মহানমত্রো বর্জনে বিরপ্শ্যুগ্রং শবঃ পত্যতে ধর্ষ্ণ্বোজঃ | নাহ বিব্যাচ পর্থিবী চনৈনং যত সোমাসো হর্যশ্বমমন্দন ||","e":"Great and impetuous, mighty-voiced in battle, surpassing power is his, and strength resistless. Him the broad earth hath never comprehended when Somas cheered the Lord of Tawny Coursers.","mb":"যে ইন্দ্র অতিশয় সামর্থ্যবান, যুদ্ধে শত্রুদের অভিভবিতা এবং শত্রুদের আহ্বান কারী, সে ইন্দ্রের উগ্রবল ও দুর্ধর্ষতেজ সর্বত্র বিস্তৃত হচ্ছে; যখন সোমরস হর্যশ্ব ইন্দ্রকে হষ্ট করে তখন পৃথিবী এবং স্বর্গও তাকে ধারণ করতে পারে না।"},{"n":5,"d":"महानुग्रो वाव्र्धे वीर्याय समाचक्रे वर्षभः काव्येन | इन्द्रो भगो वाजदा अस्य गावः पर जायन्ते दक्षिणा अस्य पूर्वीः ||","b":"মহানুগ্রো বাব্র্ধে বীর্যায সমাচক্রে বর্ষভঃ কাব্যেন | ইন্দ্রো ভগো বাজদা অস্য গাবঃ পর জাযন্তে দক্ষিণা অস্য পূর্বীঃ ||","e":"Mighty and strong he waxed for hero exploit: the Bull was furnished a Sage's wisdom. Indra is our kind Lord; his steers have vigour; his cows are many with abundant offspring.","mb":"বলবান, উগ্র, অভীষ্টবর্ষী ও দাতা ইন্দ্র, বীরকীর্তির জন্য প্রবৃদ্ধ হয়েছেন, স্তোত্রের সঙ্গে মিলিত হয়েছেন। ইন্দ্রের গো সকল ক্ষীরপ্রদ হয়ে জন্মগ্রহণ করেছে, ইন্দ্রের দান প্রভূত ।"},{"n":6,"d":"पर यत सिन्धवः परसवं यथायन्नापः समुद्रं रथ्येव जग्मुः | अतश्चिदिन्द्रः सदसो वरीयान यदीं सोमः पर्णति दुग्धो अंशुः ||","b":"পর যত সিন্ধবঃ পরসবং যথাযন্নাপঃ সমুদ্রং রথ্যেব জগ্মুঃ | অতশ্চিদিন্দ্রঃ সদসো বরীযান যদীং সোমঃ পর্ণতি দুগ্ধো অংশুঃ ||","e":"As floods according to their stream flow onward, so to the sea, as borne on cars, the waters. Vaster is Indra even than his dwelling, what time the stalk milked out, the Soma, fills him.","mb":"নদীগণ যখন প্রসব অনুসরণ করে দূরবর্তী সমূদ্রেযায় তখন জল রথীর ন্যায গমন করে। সেরূপ বরীয়ান ইন্দ্র এ অন্তরীক্ষ হতে অবিষুত লতাখন্ডরূপে অল্প সোমের দিকে ধাবিত হন।"},{"n":7,"d":"समुद्रेण सिन्धवो यादमाना इन्द्राय सोमं सुषुतं भरन्तः अंशुं | दुहन्ति हस्तिनो भरित्रैर्मध्वः पुनन्ति धारया पवित्रैः ||","b":"সমুদ্রেণ সিন্ধবো যাদমানা ইন্দ্রায সোমং সুষুতং ভরন্তঃ অংশুং | দুহন্তি হস্তিনো ভরিত্রৈর্মধ্বঃ পুনন্তি ধারযা পবিত্রৈঃ ||","e":"Eager to mingle with the sea, the rivers carry the well-pressed Soma juice to Indra. They drain the stalk out with their arms, quick-banded, and cleanse it with a stream of mead and filters.","mb":"সমুদ্র সঙ্গমাভিলাষী নদীগণ যেরূপ সমুদ্রকে পূর্ণ করে, সেরূপ অধ্বর্যুগণ ইন্দ্রের জন্য অভিষুত সোম সম্পাদন করে হস্তাদ্বারা লতা দোহন করে ও পবিত্রদ্বারা ধারারূপ মধুর সোমরস শোধন করে।"},{"n":8,"d":"हरदा इव कुक्षयः सोमधानाः समी विव्याच सवना पुरूणि | अन्ना यदिन्द्रः परथमा वयाश वर्त्रं जघन्वानव्र्णीत सोमम ||","b":"হরদা ইব কুক্ষযঃ সোমধানাঃ সমী বিব্যাচ সবনা পুরূণি | অন্না যদিন্দ্রঃ পরথমা বযাশ বর্ত্রং জঘন্বানব্র্ণীত সোমম ||","e":"Like lakes appear his flanks filled full with Soma: yea, he contains libations in abundance. When Indra had consumed the first sweet viands, he, after slaying Vṛtra, claimed the Soma.","mb":"ইন্দ্রের উদর হ্রদের ন্যায় সোমের আধার। তিনি বহু যজ্ঞ একবারে ব্যাপ্ত করেন। যেহেতু ইন্দ্র প্রথম ভক্ষনীয় সোমাদি ভক্ষণ করেছেন, পরে বৃত্তকে নিহত করে দেবগণকে ভাগ করে দিয়েছেন (৯) হে ইন্দ্র! শীঘ্র ধন প্রদান কর। তোমার এ ধনকে বন্ধ করতে পারে? আমরা তোমাকে ধনের স্বামী বলে জানি। তোমার যে মহনীয় ধন আছে; হে ইন্দ্র! তা আমাদের প্রদান কর।"},{"n":9,"d":"आ तू भर माकिरेतत परि षठाद विद्मा हि तवा वसुपतिं वसूनाम | इन्द्र यत ते माहिनं दत्रमस्त्यस्मभ्यं तद धर्यश्व पर यन्धि ||","b":"আ তূ ভর মাকিরেতত পরি ষঠাদ বিদ্মা হি তবা বসুপতিং বসূনাম | ইন্দ্র যত তে মাহিনং দত্রমস্ত্যস্মভ্যং তদ ধর্যশ্ব পর যন্ধি ||","e":"Then bring thou hither, and let none prevent it: we know thee well, the Lord of wealth and treasure. That splendid gift which is thine own, O Indra, vouchsafe to us, Lord of the Tawny Coursers.","mb":"তুমি নিয়ে এসো, কেউ যেন বাধা না দেয়: আমরা তোমাকে ভালো করেই জানি, ধনসম্পদের প্রভু। হে ইন্দ্র, তোমার যে মহান দান নিজের, তা আমাদের দাও, হে পিঙ্গল অশ্বপতি।"},{"n":10,"d":"अस्मे पर यन्धि मघवन्न्र्जीषिन्निन्द्र रायो विश्ववारस्य भूरेः | अस्मे शतं शरदो जीवसे धा अस्मे वीरान छश्वत इन्द्र शिप्रिन ||","b":"অস্মে পর যন্ধি মঘবন্ন্র্জীষিন্নিন্দ্র রাযো বিশ্ববারস্য ভূরেঃ | অস্মে শতং শরদো জীবসে ধা অস্মে বীরান ছশ্বত ইন্দ্র শিপ্রিন ||","e":"O Indra, Maghavan, impetuous mover, grant us abundant wealth that brings all blessings. Give us a hundred autumns for our lifetime: give us, O fair-checked Indra, store of heroes.","mb":"যে মঘবন! হে ঋজীষী সোমবিশিষ্ট ইনদ্র! তুমি সকলের বরণীয় প্রভূত ধন দান কর আমাদের জীবনের জন্য শত বৎসর প্রদান কর (১)। হে সুন্দর হনুবিশিষ্ট ইন্দ্র! আমসাদের বহু বীর পুত্র প্রদান কর।"},{"n":11,"d":"शुनं हुवेम ... ||","b":"শুনং হুবেম ... ||","e":"Call we on Indra, Maghavan, auspicious, best Hero in the fight where spoil is gathered, The Strong, who listens, who gives aid in battles, who slays the Vṛtras, wins and gathers riches.","mb":"হে ইন্দ্র! তুমি অন্নলাভকর যুদ্ধে উৎসাহদ্বারা প্রবৃদ্ধ, তুমি ধনবান, প্রভূত ঐশ্বর্যসম্পন্ন, নেতৃশ্রেষ্ঠ, স্তুতিশ্রবণকারী, উগ্র, সংগ্রামে শত্রুবিনাশী এবং ধনজেতা। আমরা আশ্রয়লাভের জন্য তোমাকে আহ্বান করছি।"}]},{"n":37,"t":"Indra","v":[{"n":1,"d":"वार्त्रहत्याय शवसे पर्तनाषाह्याय च | इन्द्र तवा वर्तयामसि ||","b":"বার্ত্রহত্যায শবসে পর্তনাষাহ্যায চ | ইন্দ্র তবা বর্তযামসি ||","e":"O INDRA, for the strength that slays Vṛtra and conquers in the fight, We turn thee hitherward to us.","mb":"হে ইনদ্র! বৃত্ত বিনাশ কর বল লাভের জন্য ও শত্রু সেনার অভিভবের জন্য তোমাকে প্রবর্তিত করছি।"},{"n":2,"d":"अर्वाचीनं सु ते मन उत चक्षुः शतक्रतो | इन्द्र कर्ण्वन्तु वाघतः ||","b":"অর্বাচীনং সু তে মন উত চক্ষুঃ শতক্রতো | ইন্দ্র কর্ণ্বন্তু বাঘতঃ ||","e":"O Indra, Lord of Hundred Powers, may those who praise thee hitherward. Direct thy spirit and thine eye.","mb":"হে শতক্রতু! স্তোতাগণ তোমার মন চক্ষু প্রীত করে আমাদের অভিমুখে প্রেরণ করুক।"},{"n":3,"d":"नामानि ते शतक्रतो विश्वाभिर्गीर्भिरीमहे | इन्द्राभिमातिषाह्ये ||","b":"নামানি তে শতক্রতো বিশ্বাভির্গীর্ভিরীমহে | ইন্দ্রাভিমাতিষাহ্যে ||","e":"O Indra, Lord of Hundred Powers, with all our songs we invocate Thy names for triumph over foes.","mb":"হে শতক্রতু! আমরা গর্বিত  শত্রুদের অভিভবকর যুদ্ধে সমস্ত স্তুতিদ্বারা তোমার নাম কীর্তন করব।"},{"n":4,"d":"पुरुष्टुतस्य धामभिः शतेन महयामसि | इन्द्रस्य चर्षणीध्र्तः ||","b":"পুরুষ্টুতস্য ধামভিঃ শতেন মহযামসি | ইন্দ্রস্য চর্ষণীধ্র্তঃ ||","e":"We strive for glory through the powers immense of him whom many praise, Of Indra who supports mankind.","mb":"ইন্দ্র সকলের স্তুতি যোগ্য, অপরিমিত তেজবিশিষ্ট এবং মনুষ্যদের স্বামী, আমরা তার স্তুতি করছি।"},{"n":5,"d":"इन्द्रं वर्त्राय हन्तवे पुरुहूतमुप बरुवे | भरेषु वाजसातये ||","b":"ইন্দ্রং বর্ত্রায হন্তবে পুরুহূতমুপ বরুবে | ভরেষু বাজসাতযে ||","e":"For Vṛtra's slaughter I address Indra whom many invocate, To win us booty in the wars.","mb":"হে ইনদ্র! বৃত্তকে বিনাশ করবার জন্য এবং যুদ্ধে ধন লাভের জন্য বহু লোকরে আহূত ইন্দ্রকে আহ্বান করছি।"},{"n":6,"d":"वाजेषु सासहिर्भव तवामीमहे शतक्रतो | इन्द्र वर्त्रायहन्तवे ||","b":"বাজেষু সাসহির্ভব তবামীমহে শতক্রতো | ইন্দ্র বর্ত্রাযহন্তবে ||","e":"In battles be victorious. We seek thee, Lord of Hundred Powers, Indra, that Vṛtra may be slain.","mb":"হে শতক্রতা! তুমি যুদ্ধে শত্রুদের অভিভবকারী হও, বৃত্তকে বিনাশ করবার জন্য আমরা তোমাকে প্রার্থনা করছি।"},{"n":7,"d":"दयुम्नेषु पर्तनाज्ये पर्त्सुतूर्षु शरवस्सु च | इन्द्र साक्ष्वाभिमातिषु ||","b":"দযুম্নেষু পর্তনাজ্যে পর্ত্সুতূর্ষু শরবস্সু চ | ইন্দ্র সাক্ষ্বাভিমাতিষু ||","e":"In splendid combats of the hosts, in glories where the fight is won. Indra, be victor over foes.","mb":"হে ইন্দ্র! যারা ধনে, যুদ্ধে, বীরসমূহে ও বলে আমাদের অভিমানী শত্রু তাদরে পরাজয় কর।"},{"n":8,"d":"शुष्मिन्तमं न ऊतये दयुम्निनं पाहि जाग्र्विम | इन्द्र सोमंशतक्रतो ||","b":"শুষ্মিন্তমং ন ঊতযে দযুম্নিনং পাহি জাগ্র্বিম | ইন্দ্র সোমংশতক্রতো ||","e":"Drink thou the Soma for our help, bright, vigilant, exceeding strong, O Indra, Lord of Hundred Powers.","mb":"হে শতক্রতু! আমাদের আশ্রয় দানের জন্য অতিশয় বলবান, দীপ্তি যুক্ত, স্বপ্ননিবারক সোম পান কর।"},{"n":9,"d":"इन्द्रियाणि शतक्रतो या ते जनेषु पञ्चसु | इन्द्र तानि ता वर्णे ||","b":"ইন্দ্রিযাণি শতক্রতো যা তে জনেষু পঞ্চসু | ইন্দ্র তানি তা বর্ণে ||","e":"O Śatakratu, powers which thou mid the Five Races hast displayed- These, Indra, do I claim of thee.","mb":"হে শতক্রতু, পঞ্চজনে যে সকল ইন্দ্রিয় আছে, আমি সেগুলি তোমারই বলে জানি।"},{"n":10,"d":"अगन्निन्द्र शरवो बर्हद दयुम्नं दधिष्व दुष्टरम | उत ते शुष्मं तिरामसि ||","b":"অগন্নিন্দ্র শরবো বর্হদ দযুম্নং দধিষ্ব দুষ্টরম | উত তে শুষ্মং তিরামসি ||","e":"Indra, great glory hast thou gained. Win splendid fame which none may mar We make thy might perpetual.","mb":"হে ইন্দ্র! প্রভূত অন্ন তোমার নিকট গমন করুক, শত্রুদের দুর্ধর্ষ ধন আমাদের প্রদান কর। আমরা তোমার উৎকৃষ্ট বল বর্ধিত করব।"},{"n":11,"d":"अर्वावतो न आ गह्यथो शक्र परावतः | उ लोको यस्ते अद्रिव इन्द्रेह तत आ गहि ||","b":"অর্বাবতো ন আ গহ্যথো শক্র পরাবতঃ | উ লোকো যস্তে অদ্রিব ইন্দ্রেহ তত আ গহি ||","e":"Come to us either from anear, Or, Śakra, come from far away. Indra, wherever be thy home, come to us thence, O Thunder-armed.","mb":"হে  শক্র! নিকট অথবা দুরদেশ হতে আমাদের অভিমুখে এস। হে বজ্রবান ইন্দ্র! তোমার যে উৎকৃষ্ট স্থান আছে সেখান হতে এ যজ্ঞে এস।"}]},{"n":38,"t":"Indra","v":[{"n":1,"d":"अभि तष्टेव दीधया मनीषामत्यो न वाजी सुधुरो जिहानः | अभि परियाणि मर्म्र्शत पराणि कवीन्रिछामि सन्द्र्शे सुमेधाः ||","b":"অভি তষ্টেব দীধযা মনীষামত্যো ন বাজী সুধুরো জিহানঃ | অভি পরিযাণি মর্ম্র্শত পরাণি কবীন্রিছামি সন্দ্র্শে সুমেধাঃ ||","e":"HASTING like some strong courser good at drawing, a thought have I imagined like a workman. Pondering what is dearest and most noble, I long to see the sages full of wisdom.","mb":"হে স্তোতা! ত্বষ্টার ন্যায় ইন্দ্রের স্তুতি প্রদীপ্ত কর। উৎকৃষ্ঠ ভারবাহী দ্রুতগামী অশ্বের ন্যায় কর্মে প্রবৃত্ত হয়ে ইন্দ্রের প্রিয়কর্ম বিষয়ে চিন্তা করে আমি মেধাবান হয়ে স্বর্গগত কবিগণকে দেখবার ইচ্ছা করছি।"},{"n":2,"d":"इनोत पर्छ जनिमा कवीनां मनोध्र्तः सुक्र्तस्तक्षत दयाम | इमा उ ते परण्यो वर्धमाना मनोवाता अध नु धर्मणिग्मन ||","b":"ইনোত পর্ছ জনিমা কবীনাং মনোধ্র্তঃ সুক্র্তস্তক্ষত দযাম | ইমা উ তে পরণ্যো বর্ধমানা মনোবাতা অধ নু ধর্মণিগ্মন ||","e":"Ask of the sages' mighty generations firm-minded and devout they framed the heaven. These are thy heart-sought strengthening directions, and they have come to be sky's upholders.","mb":"হে ইন্দ্র! কবিগণের জন্মবিষয়ে গুরুগণকে জিজ্ঞাসা কর, যারা মন:সংযম ও পুণ্য কার্য দ্বারা স্বর্গ নির্মাণ করেছিলেন। এক্ষেত্রে এ যজ্ঞে তোমার জন্য প্রনীত স্তুতিসমূহ বর্ধমান হয়ে মনের ন্যায় বেগে যেন যায়।"},{"n":3,"d":"नि षीमिदत्र गुह्या दधाना उत कषत्राय रोदसी समञ्जन | सं मात्राभिर्ममिरे येमुर उर्वी अन्तर मही सम्र्ते धायसे धुः ||","b":"নি ষীমিদত্র গুহ্যা দধানা উত কষত্রায রোদসী সমঞ্জন | সং মাত্রাভির্মমিরে যেমুর উর্বী অন্তর মহী সম্র্তে ধাযসে ধুঃ ||","e":"Assuming in this world mysterious natures, they decked the heaven and earth for high dominion, Measured with measures, fixed their broad expanses, set the great worlds apart held firm for safety.","mb":"কবিগণ এ ভুলোকের সর্বত্র গুঢ় কর্ম নিধান করে পৃথিবী ও স্বর্গকে বল লাভের জন্য অলঙ্কৃত করেছন। ওরা মাত্রাদ্বারা (১) পৃথিবী ও স্বর্গের পরিমাণ করেছেন। পরস্পর সঙ্গতা বিস্তীর্ণা মহতী দ্যাবা পৃথিবীকে মিলিত করেছেন এবং তাদের মধ্যে ধারণার্থে অন্তরীক্ষকে স্থাপন করেছেন।"},{"n":4,"d":"आतिष्ठन्तं परि विश्वे अभूषञ्छ्रियो वसानश्चरति सवरोचिः | महत तद वर्ष्णो असुरस्य नामा विश्वरूपो अम्र्तानि तस्थौ ||","b":"আতিষ্ঠন্তং পরি বিশ্বে অভূষঞ্ছ্রিযো বসানশ্চরতি সবরোচিঃ | মহত তদ বর্ষ্ণো অসুরস্য নামা বিশ্বরূপো অম্র্তানি তস্থৌ ||","e":"Even as he mounted up they all adorned him: self-luminous he travels clothed in splendour. That is the Bull's, the Asura's mighty figure: he, omniform, hath reached the eternal waters.","mb":"সমস্ত কবিগণ, রথস্থিত ইন্দ্রকে পরিভূষিত করেছিলেন। স্বভাবত: দীপ্তিমান ইন্দ্র দীপ্তিতে আচ্ছাদিত হয়ে রয়েছেন। অভীষ্টবর্ষী ও অসুর ইন্দ্রের কীর্তি অদ্ভুত। তিনি বিশ্বরূপ ধারণ করে অমৃতে অধিষ্ঠান করছেন।"},{"n":5,"d":"असूत पूर्वो वर्षभो जयायानिमा अस्य शुरुधः सन्ति पूर्वीः | दिवो नपाता विदथस्य धीभिः कषत्रं राजाना परदिवो दधाथे ||","b":"অসূত পূর্বো বর্ষভো জযাযানিমা অস্য শুরুধঃ সন্তি পূর্বীঃ | দিবো নপাতা বিদথস্য ধীভিঃ কষত্রং রাজানা পরদিবো দধাথে ||","e":"First the more ancient Bull engendered offspring; these are his many draughts that lent him vigour. From days of old ye Kings, two Sons of Heaven, by hymns of sacrifice have won dominion.","mb":"অভীষ্টবর্ষী সনাতন সর্বজ্যেষ্ঠ ইন্দ্র জল সৃষ্টি করলেন। এ প্রভূত জল তার পিপাসা রোধ করল। স্বর্গের পৌত্র স্বরূপ শোভমান ইন্দ্র ও বরুণ দ্যোতমান যজ্ঞকারীর স্তুতিদ্বারা লাভযোগ্য ধন আমাদের জন্য ধারণ করেছেন।"},{"n":6,"d":"तरीणि राजाना विदथे पुरूणि परि विश्वानि भूषथः सदांसि | अपश्यमत्र मनसा जगन्वान वरते गन्धर्वानपि वायुकेशान ||","b":"তরীণি রাজানা বিদথে পুরূণি পরি বিশ্বানি ভূষথঃ সদাংসি | অপশ্যমত্র মনসা জগন্বান বরতে গন্ধর্বানপি বাযুকেশান ||","e":"Three seats ye Sovrans, in the Holy synod, many, yea, all, ye honour with your presence. There saw I, going thither in the spirit, Gandharvas in their course with wind-blown tresses.","mb":"হে রাজা ইন্দ্র ও বরুণ! পরিব্যাপ্ত ও সম্পূর্ণ সবনত্রয়কে এ যজ্ঞে অলঙ্কৃত কর। হে ইন্দ্র! তুমি যজ্ঞে গমন করেছ, যেহেতু আমি এ যজ্ঞে বায়ু বৎ কেশবিশিষ্ট গন্ধর্বগণকে মনে মনে দেখছি। (২)"},{"n":7,"d":"तदिन नवस्य वर्षभस्य धेनोरा नामभिर्ममिरे सक्म्यंगोः | अन्यद-अन्यदसुर्यं वसाना नि मायिनो ममिरे रूपमस्मिन ||","b":"তদিন নবস্য বর্ষভস্য ধেনোরা নামভির্মমিরে সক্ম্যংগোঃ | অন্যদ-অন্যদসুর্যং বসানা নি মাযিনো মমিরে রূপমস্মিন ||","e":"That same companionship of her, the Milch-cow, here with the strong Bull's divers forms they stablished. Enduing still some new celestial figure, the skilful workers shaped a form around him.","mb":"যে যজমানগণ অভিমত ফলপ্রদ ইন্দ্রের জন্য গোসমূহের ভোগার্থে হব্য শীঘ্র দোহন করে যাদের অনেক নাম আছে, তারা নুতন অসুর্য (৩) বল ধারণ করে ও মায়া বিকাশ করে আপন আপন রূপ ইন্দ্রের সমর্পণ করেছিল।"},{"n":8,"d":"तदिन नवस्य सवितुर्नकिर्मे हिरण्ययीममतिं यामशिश्रेत | आ सुष्टुती रोदसी विश्वमिन्वे अपीव योषा जनिमानि वव्रे ||","b":"তদিন নবস্য সবিতুর্নকির্মে হিরণ্যযীমমতিং যামশিশ্রেত | আ সুষ্টুতী রোদসী বিশ্বমিন্বে অপীব যোষা জনিমানি বব্রে ||","e":"Let no one here debar me from enjoying the golden light which Savitar diffuses. He covers both all-fostering worlds with praises even as a woman cherishes her children.","mb":"অতএব সবিতার সুবর্ণময়ী দীপ্তিকে কেউই ইয়ত্তা করতে পারে না। এ দীপ্তিকে যিনি আশ্রয় করেন তিনি উত্তম স্তুতিদ্বারা স্তুত হয়ে মাতা যেরূপ সন্তানকে আলিঙ্গন ক,ে সেরূপ সর্ব ব্যাপক দ্যাবাপৃথিবীকে আলিঙ্গন করেন।"},{"n":9,"d":"युवं परत्नस्य साधथो महो यद दैवी सवस्तिः परि णः सयातम | गोपाजिह्वस्य तस्थुषो विरूपा विश्वे पश्यन्ति मायिनः कर्तानि ||","b":"যুবং পরত্নস্য সাধথো মহো যদ দৈবী সবস্তিঃ পরি ণঃ সযাতম | গোপাজিহ্বস্য তস্থুষো বিরূপা বিশ্বে পশ্যন্তি মাযিনঃ কর্তানি ||","e":"Fulfil, ye twain, his work, the Great, the Ancient: as heavenly blessing keep your guard around us. All the wise Gods behold his varied actions who stands erect, whose voice is like a herdsman's.","mb":"হে ইন্দ্র ও বরুণ! তোমরা দুজনে প্রাচীন স্তোতার শ্রেয়: সম্পাদন কর  অর্থাৎ তাকে স্বর্গীয় মঙ্গলরূপ শ্রেয়: প্রদান কর। আমাদের চার  দিক হতে রক্ষা কর। ইন্দ্রের জিহ্বা সকলকে অভয়দান করে এবং  ইন্দ্র স্থিরতর! সমস্ত মায়াবিগণ তার নানাবিধ কীর্তি দর্শন করছে।"},{"n":10,"d":"शुनं हुवेम ... ||","b":"শুনং হুবেম ... ||","e":"Call we on Indra, Maghavan, auspicious, best Hero in the fight where spoil is gathered, The Strong, who listens, who gives aid in battles, who slays the Vṛtras, wins and gathers riches.","mb":"হে ইন্দ্র! তুমি অন্নলাভ কর, যুদ্ধে উৎসাহদ্বারা প্রবৃদ্ধ, তুমি ধনবান, প্রভূত ঐশ্বর্যসম্পন্ন, নেতৃশ্রেষ্ঠ, স্তুতিশ্রবণকারী, উগ্র, সংগ্রামে শত্রুবিনাশী এবং ধনজেতা। আমরা আশ্রয় লাভের জন্য তোমাকে আহ্বান করছি।"}]},{"n":39,"t":"Indra","v":[{"n":1,"d":"इन्द्रं मतिर्ह्र्द आ वच्यमानाछा पतिं सतोमतष्टा जिगाति | या जाग्र्विर्विदथे शस्यमानेन्द्र यत ते जायते विद्धि तस्य ||","b":"ইন্দ্রং মতির্হ্র্দ আ বচ্যমানাছা পতিং সতোমতষ্টা জিগাতি | যা জাগ্র্বির্বিদথে শস্যমানেন্দ্র যত তে জাযতে বিদ্ধি তস্য ||","e":"To Indra from the heart the hymn proceedeth, to him the Lord, recited, built with praises; The wakening song sung forth in holy synod: that which is born for thee, O Indra, notice.","mb":"হে ইন্দ্র! তুমি জগৎপতি, হৃদয় হতে উচ্চারিত ও স্তোতৃসম্পদিত স্তোত্র তোমার অভিমুখে যাচ্ছে। যে স্তুতি তোমাকে জাগরিত করে যজ্ঞ উচ্চারিত হচ্ছে এবং আমা হতেই উৎপন্ন হচ্ছে, তুমি তা জান।"},{"n":2,"d":"दिवश्चिदा पूर्व्या जायमाना वि जाग्र्विर्विदथे शस्यमाना | भद्रा वस्त्राण्यर्जुना वसाना सेयमस्मे सनजापित्र्या धीः ||","b":"দিবশ্চিদা পূর্ব্যা জাযমানা বি জাগ্র্বির্বিদথে শস্যমানা | ভদ্রা বস্ত্রাণ্যর্জুনা বসানা সেযমস্মে সনজাপিত্র্যা ধীঃ ||","e":"Born from the heaven e’en in the days aforetime, wakening, sting aloud in holy synod, Auspicious, clad in white and shining raiment, this is the ancient hymn of our forefathers.","mb":"হে ইন্দ্র! সূর্য হতেও পূর্বকালে উৎপন্ন যে স্তুতি যজ্ঞে উচ্চারিত হয়ে  তোমাকে জাগরিত করে সে স্তুতি কল্যাণকর শুক্র বস্ত্র পরিধন করে আমাদেরই পতৃগণের নিকট হতে আগত ও পুরাতন।"},{"n":3,"d":"यमा चिदत्र यमसूरसूत जिह्वाया अग्रं पतदा हयस्थात | वपूंषि जाता मिथुना सचेते तमोहना तपुषो बुध्न एता ||","b":"যমা চিদত্র যমসূরসূত জিহ্বাযা অগ্রং পতদা হযস্থাত | বপূংষি জাতা মিথুনা সচেতে তমোহনা তপুষো বুধ্ন এতা ||","e":"The Mother of the Twins hath borne Twin Children: my tongue's tip raised itself and rested silent. Killing the darkness at the light's foundation, the Couple newly born attain their beauty.","mb":"যমক পুত্রের মাতা  যমক পুত্রদ্বয় অশ্বিদ্বয়কে প্রস্রব করল (১) তাদের প্রশংসা করবার জন্য আমার জিহ্বার অগ্রভাগ চঞ্চল হয়েছে। অন্ধকারানাশক দিবসের আদিতে আগত মিথুন জন্মিবামাত্র স্তোত্রে মিলিত হচ্ছে।"},{"n":4,"d":"नकिरेषां निन्दिता मर्त्येषु ये अस्माकं पितरो गोषु योधाः | इन्द्र एषां दरंहिता माहिनावानुद गोत्राणि सस्र्जे दंसनावान ||","b":"নকিরেষাং নিন্দিতা মর্ত্যেষু যে অস্মাকং পিতরো গোষু যোধাঃ | ইন্দ্র এষাং দরংহিতা মাহিনাবানুদ গোত্রাণি সস্র্জে দংসনাবান ||","e":"Not one is found among them, none of mortals, to blame our sires who fought to win the cattle. Their strengthener was Indra the Majestic he spread their stalls of kine the Wonder-Worker.","mb":"হে ইন্দ্র! আমাদের যে  পিতৃগণ গোধনের নিমিত্ত যুদ্ধ করেছিলেন, পৃথিবীতে কেউ তাদের ন্দিুক নেই। মহিমান্বিত কীর্তিমান ইন্দ্র অঙ্গিরাগণের সমিদ্ধ গোবৃন্দ দিয়েছিলেন।"},{"n":5,"d":"सखा ह यत्र सखिभिर्नवग्वैरभिज्ञ्वा सत्वभिर्गा अनुग्मन | सत्यं तदिन्द्रो दसभिर्दशग्भिः सूर्यं विवेदतमसि कषियन्तम ||","b":"সখা হ যত্র সখিভির্নবগ্বৈরভিজ্ঞ্বা সত্বভির্গা অনুগ্মন | সত্যং তদিন্দ্রো দসভির্দশগ্ভিঃ সূর্যং বিবেদতমসি কষিযন্তম ||","e":"Where as a Friend with friendly men, Navagvas, with heroes, on his knees he sought the cattle. There, verily with ten Daśagvas Indra found the Sun lying hidden in the darkness.","mb":"নবগ্ব অঙ্গিরাগণের সখা ইন্দ্র যখন জানুর উপরে ভর করে গোধনাভিমুখে গিয়েছিলেন, তখন দশগ্ব অঙ্গিরাগণের সাথে অন্ধকার মধ্যে লুক্কায়িত সূর্যকে দেখতে পেয়েছিলেন।"},{"n":6,"d":"इन्द्रो मधु सम्भ्र्तमुस्रियायां पद्वद विवेद शफवन नमेगोः | गुहा हितं गुह्यं गूळ्हमप्सु हस्ते दधे दक्षिणे दक्षिणावान ||","b":"ইন্দ্রো মধু সম্ভ্র্তমুস্রিযাযাং পদ্বদ বিবেদ শফবন নমেগোঃ | গুহা হিতং গুহ্যং গূল্হমপ্সু হস্তে দধে দক্ষিণে দক্ষিণাবান ||","e":"Indra found meath collected in the milch-cow, by foot and hoof, in the cow's place of pasture. That which lay secret, hidden in the waters, he held in his right hand, the rich rewarder.","mb":"ইন্দ্র ক্ষীরপ্রসবিনী গাভীতে মধু সঞ্চিত করেছেন, পরে পাদযুক্ত ও ক্ষুরযুক্ত ধন আনলেন। ঔদার্যবান ইন্দ্র  গুহামধ্যে স্থিত, প্রসন্ন, অন্তরীক্ষে লুক্কায়িত মায়াবীকে দক্ষিণ হস্তে ধারণ করলেন।"},{"n":7,"d":"जयोतिर्व्र्णीत तमसो विजानन्नारे सयाम दुरितादभीके | इमा गिरः सोमपाः सोमव्र्द्ध जुषस्वेन्द्र पुरुतमस्य कारोः ||","b":"জযোতির্ব্র্ণীত তমসো বিজানন্নারে সযাম দুরিতাদভীকে | ইমা গিরঃ সোমপাঃ সোমব্র্দ্ধ জুষস্বেন্দ্র পুরুতমস্য কারোঃ ||","e":"He took the light, discerning it from darkness: may we be far removed from all misfortune. These songs, O Soma-drinker, cheered by Soma, Indra, accept from thy most zealous poet.","mb":"ইন্দ্র রাত্রি হতে প্রাদুর্ভূত হয়ে জ্যোতি ধারণ করলেন। আমরা পাপ হতে দুরে ভয়রহিত স্থানে থাকব। হে সোমপা ও সোমপুষ্ট ইন্দ্র! বহু শত্রুবিনাশক স্তোত্রকারীর এ স্তুতি সেবা কর।"},{"n":8,"d":"जयोतिर्यज्ञाय रोदसी अनु षयादारे सयाम दुरितस्य भूरेः | भूरि चिद धि तुजतो मर्त्यस्य सुपारासो वसवो बर्हणावत ||","b":"জযোতির্যজ্ঞায রোদসী অনু ষযাদারে সযাম দুরিতস্য ভূরেঃ | ভূরি চিদ ধি তুজতো মর্ত্যস্য সুপারাসো বসবো বর্হণাবত ||","e":"Let there be light through both the worlds for worship: may we be far from most overwhelming evil. Great woe comes even from the hostile mortal, piled up; but good at rescue are the Vasus.","mb":"সূর্য যজ্ঞের জন্য দ্যাবাপৃথিবী প্রকাশিত করুক, আমরা প্রভূত পাপ হত্তে দূরে অবস্থান করব। হে বসুগণ! স্তুতিদ্বারা তোমাদের অভিমুখ করতে পারা যায়, তোমরা অতি প্রভূত ও সমৃদ্ধ ধন প্রভূত দানশীল মর্ত্যকে প্রদান কর।"},{"n":9,"d":"शुनं हुवेम ... ||","b":"শুনং হুবেম ... ||","e":"Call we on Maghavan, auspicious Indra, best Hero in the fight where spoil is gathered, The Strong, who listens, who gives aid in battles, who slays the Vṛtras, wins and gathers riches.","mb":"হে ইন্দ্র! তুমি অন্নলাভ কর, যুদ্ধে উৎসাহদ্বারা প্রবৃদ্ধ, তুমি ধনবান, প্রভূত ঐর্শ্যসম্পন্ন, নেতৃশ্রেষ্ঠ, স্তুতি শ্রবণকারী, উগ্র, সংগ্রামে শত্রুবিনাশী এবং ধনজেতা। আমরা আশ্রয় লাভের জন্য তোমাকে আহ্বান করছি।"}]},{"n":40,"t":"Indra","v":[{"n":1,"d":"इन्द्र तवा वर्षभं वयं सुते सोमे हवामहे | स पाहि मध्वो अन्धसः ||","b":"ইন্দ্র তবা বর্ষভং বযং সুতে সোমে হবামহে | স পাহি মধ্বো অন্ধসঃ ||","e":"THEE, Indra, we invoke, the Bull, what time the Soma is expressed. So drink thou of the savoury juice.","mb":"হে ইন্দ্র! তুমি অভীষ্টবর্ষী, আমরা তোমাকে অভিষুত সোম পানের জন্য আহ্বান করছি। তুমি হর্ষকর সোম পান কর।"},{"n":2,"d":"इन्द्र करतुविदं सुतं सोमं हर्य पुरुष्टुत | पिबा वर्षस्व तात्र्पिम ||","b":"ইন্দ্র করতুবিদং সুতং সোমং হর্য পুরুষ্টুত | পিবা বর্ষস্ব তাত্র্পিম ||","e":"Indra, whom many laud, accept the strength-conferring Soma juice: Quaff, pour down drink that satisfies.","mb":"হে ইন্দ্র! প্রজ্ঞাপ্রদ অভিষুত সোম পান করতে অভিলাষী হও। হে বহুজন স্তুত! তৃপ্তিকর সোম পন কর, জঠরে সেক কর।"},{"n":3,"d":"इन्द्र पर णो धितावानं यज्ञं विश्वेभिर्देवेभिः | तिर सतवान विश्पते ||","b":"ইন্দ্র পর ণো ধিতাবানং যজ্ঞং বিশ্বেভির্দেবেভিঃ | তির সতবান বিশ্পতে ||","e":"Indra, with all the Gods promote our wealth-bestowing sacrifice, Thou highly-lauded Lord of men.","mb":"হে স্তুয়মান, মরুৎগণপতি ্ন্দ্রি! তুমি সমস্ত দেবগণের সঙ্গে আমাদের হব্যযুক্ত সজ্ঞকে বিশেষরূপে বর্ধিত কর।"},{"n":4,"d":"इन्द्र सोमाः सुता इमे तव पर यन्ति सत्पते | कषयं चन्द्रास इन्दवः ||","b":"ইন্দ্র সোমাঃ সুতা ইমে তব পর যন্তি সত্পতে | কষযং চন্দ্রাস ইন্দবঃ ||","e":"Lord of the brave, to thee proceed these drops of Soma juice expressed, The bright drops to thy dwelling-place.","mb":"হে সৎপতি ইন্দ্র! আহ্লাদক, দীপ্ত, অভিষুত এ সকল সোমরস তোমার জঠরে যাচ্ছে।"},{"n":5,"d":"दधिष्वा जठरे सुतं सोममिन्द्र वरेण्यम | तव दयुक्षास इन्दवः ||","b":"দধিষ্বা জঠরে সুতং সোমমিন্দ্র বরেণ্যম | তব দযুক্ষাস ইন্দবঃ ||","e":"Within thy belly, Indra, take juice, Soma the most excellent: Thine are the drops celestial.","mb":"হে ইন্দ্র! বরণীয়, অভিষুত সোম জঠরে ধারন কর। দীপ্ত এ সকল সোমরস তোমার সঙ্গে দ্যুলোকে বাস করে।"},{"n":6,"d":"गिर्वणः पाहि नः सुतं मधोर्धाराभिरज्यसे | इन्द्र तवादातमिद यशः ||","b":"গির্বণঃ পাহি নঃ সুতং মধোর্ধারাভিরজ্যসে | ইন্দ্র তবাদাতমিদ যশঃ ||","e":"Drink our libation, Lord of hymns: with streams of meath thou art bedewed Our glory, Indra, is thy gift.","mb":"হে স্তুতিভাজন ইন্দ্র! তুমি আমাদের অভিষুত সোম পান কর, যেহেতু তুমি মদকর সোমের ধারাদ্বারা সিক্ত হয়ে থাক। হে ইন্দ্র! তেমার দ্বারা অন্ন শোধিত হয়। ৭ । যজমানের দ্যুতিমান, ক্ষয়রহিত সোম প্রভৃতি হব্য ইন্দ্রের অভিমুখে যায়, ইন্দ্র সোম পান করে বর্ধিত হন।"},{"n":7,"d":"अभि दयुम्नानि वनिन इन्द्रं सचन्ते अक्षिता | पीत्वी सोमस्य वाव्र्धे ||","b":"অভি দযুম্নানি বনিন ইন্দ্রং সচন্তে অক্ষিতা | পীত্বী সোমস্য বাব্র্ধে ||","e":"To Indra go the treasures of the worshipper, which never fail: He drinks the Soma and is strong","mb":"উপাসকের অক্ষয় ধনসম্পদ ইন্দ্রের কাছে যায়। তিনি সোমপান করে শক্তিশালী হন।"},{"n":8,"d":"अर्वावतो न आ गहि परावतश्च वर्त्रहन | इमा जुषस्व नो गिरः ||","b":"অর্বাবতো ন আ গহি পরাবতশ্চ বর্ত্রহন | ইমা জুষস্ব নো গিরঃ ||","e":"From far away, from near at hand, O Vṛtra-slayer, come to us: Accept the songs we sing to thee.","mb":"হে বৃত্রহন! সমীপদেশ অথবা দুরদেশ হতে আমাদের অভিমুখে এসে আমাদের স্তুতি গ্রহণ কর।"},{"n":9,"d":"यदन्तरा परावतमर्वावतं च हूयसे | इन्द्रेह तत आ गहि ||","b":"যদন্তরা পরাবতমর্বাবতং চ হূযসে | ইন্দ্রেহ তত আ গহি ||","e":"When from the space between the near and far thou art invoked by us, Thence, Indra. come thou hitherward.","mb":"হে ইন্দ্র! তুমি যদিও দুরদেশে, সমীপবর্তী দেশে অথবা মধ্যদেশে আহুত হয়ে থাক, তথাপি ঐ স্থান হতে এ যজ্ঞে এস।"}]},{"n":41,"t":"Indra","v":[{"n":1,"d":"आ तू न इन्द्र मद्र्यग घुवानः सोमपीतये | हरिभ्यां याह्यद्रिवः ||","b":"আ তূ ন ইন্দ্র মদ্র্যগ ঘুবানঃ সোমপীতযে | হরিভ্যাং যাহ্যদ্রিবঃ ||","e":"INVOKED to drink the Soma juice, come with thy Bay Steeds, Thunder-armed Come, Indra, hitherward to me.","mb":"হে বজ্রী ইন্দ্র! তুমি আহূত হচ্ছ, তুমি আমার অভিমুখে আমাদের যজ্ঞে সোমপানের জন্য শীঘ্র এস।"},{"n":2,"d":"सत्तो होता न रत्वियस्तिस्तिरे बर्हिरानुषक | अयुज्रन परातरद्रयः ||","b":"সত্তো হোতা ন রত্বিযস্তিস্তিরে বর্হিরানুষক | অযুজ্রন পরাতরদ্রযঃ ||","e":"Our priest is seated, true to time; the grass is regularly strewn; The pressing-stones were set at morn.","mb":"আমাদের যজ্ঞে হোতা যথাসময়ে উপবিষ্ট  হয়েছেন, কুশ সকল পরস্পর সংসক্ত করে বিস্তীর্ণ করা হয়েছে, প্রাত:সবনে সোমাভিষবের জন্য প্রস্তর সকল পরস্পর সংসক্ত করা হয়েছে।"},{"n":3,"d":"इमा बरह्म बरह्मवाहः करियन्त आ बर्हिः सीद | वीहि शूर पुरोळाशम ||","b":"ইমা বরহ্ম বরহ্মবাহঃ করিযন্ত আ বর্হিঃ সীদ | বীহি শূর পুরোলাশম ||","e":"These prayers, O thou who hearest prayer are offered: seat thee on the grass. Hero, enjoy the offered cake.","mb":"হে স্তোত্রবাহক! তোমাকে আমরা এ সকল স্তুতি করছি, কুশোপরি উপবেশন কর। হে শুর! পুরোডাশ ভক্ষণ কর।"},{"n":4,"d":"रारन्धि सवनेषु ण एषु सतोमेषु वर्त्रहन | उक्थेष्विन्द्र गिर्वणः ||","b":"রারন্ধি সবনেষু ণ এষু সতোমেষু বর্ত্রহন | উক্থেষ্বিন্দ্র গির্বণঃ ||","e":"O Vṛtra-slayer, be thou pleased with these libations, with these hymns, Song-loving Indra, with our lauds.","mb":"হে স্তুতিভাজন বৃত্রহা ইন্দ্র! তুমি আমাদের সবনত্রয়ে উচ্চার্যমান স্তোম ও উকথ সকলে অনুরক্ত হও।"},{"n":5,"d":"मतयः सोमपामुरुं रिहन्ति शवसस पतिम | इन्द्रं वत्सं न मातरः ||","b":"মতযঃ সোমপামুরুং রিহন্তি শবসস পতিম | ইন্দ্রং বত্সং ন মাতরঃ ||","e":"Our hymns caress the Lord of Strength, vast, drinker of the Soma's juice, Indra, as mother-cows their calf.","mb":"ধেনুগণ যেরূপ বৎসকে লেহন করে, সেরুপ স্তুতি সকল  মহান, সোমপা, বলপতি ইন্দ্রকে লেহন করছে।"},{"n":6,"d":"स मन्दस्वा हयन्धसो राधसे तन्वा महे | न सतोतारं निदे करः ||","b":"স মন্দস্বা হযন্ধসো রাধসে তন্বা মহে | ন সতোতারং নিদে করঃ ||","e":"Delight thee with the juice we pour for thine own great munificence: Yield not thy singer to reproach.","mb":"হে ইন্দ্র! তুমি প্রভূত ধনদানের জন্য সোমদ্বারা শরীরে হৃষ্ট হও, স্তোতাকে নিন্দার পাত্র করো না।"},{"n":7,"d":"वयमिन्द्र तवायवो हविष्मन्तो जरामहे | उत तवमस्मयुर्वसो ||","b":"বযমিন্দ্র তবাযবো হবিষ্মন্তো জরামহে | উত তবমস্মযুর্বসো ||","e":"We, Indra, dearly loving thee, bearing oblation, sing thee hymns Thou, Vasu, dearly lovest us.","mb":"হে ইনদ্র! আমরা তোমাকে কামনা করে হব্যযুক্ত হয়ে স্তুতি করছি। হে নিরাসয়িতা! তুমিও আমাদের হবি স্বীকারের জন্য অভিলাষী হও।"},{"n":8,"d":"मारे अस्मद वि मुमुचो हरिप्रियार्वां याहि | इन्द्र सवधावोमत्स्वेह ||","b":"মারে অস্মদ বি মুমুচো হরিপ্রিযার্বাং যাহি | ইন্দ্র সবধাবোমত্স্বেহ ||","e":"O thou to whom thy Bays are dear, loose not thy Horses far from us: Here glad thee, Indra, Lord divine.","mb":"হে অশ্বপ্রিয় ইন্দ্র! আমাদের নিকট হতে দূরে অশ্ব মোচন করো না, আমাদের অভিমুখে এস। হে সোমবান ইনদ্র! এ যজ্ঞে হৃষ্ট হও।"},{"n":9,"d":"अर्वाञ्चं तवा सुखे रथे वहतामिन्द्र केशिना | घर्तस्नूबर्हिरासदे ||","b":"অর্বাঞ্চং তবা সুখে রথে বহতামিন্দ্র কেশিনা | ঘর্তস্নূবর্হিরাসদে ||","e":"May long-maned Coursers, dropping oil, bring thee on swift car hitherward, Indra, to seat thee on the grass.","mb":"হে ইন্দ্র! শ্রমজলযুক্ত, লম্বমান কেশবিশিষ্ট অশ্বদ্বয় উপবেশনযোগ্য কুশাভিমুখে তোমাকে সুখকর  রথে করে আমাদের নিকট আনুক।"}]},{"n":42,"t":"Indra","v":[{"n":1,"d":"उप नः सुतमा गहि सोममिन्द्र गवाशिरम | हरिभ्यां यस्ते अस्मयुः ||","b":"উপ নঃ সুতমা গহি সোমমিন্দ্র গবাশিরম | হরিভ্যাং যস্তে অস্মযুঃ ||","e":"COME to the juice that we have pressed, to Soma, Indra, bleat with milk: Come, favouring us, thy Bay-drawn car!","mb":"হে ইন্দ্র! তুমি আমাদের গব্যমিশ্রিত, অভিষুত সোমের সমীপে এস। যেহেতু তোমার অশ্বদ্বয়যুক্ত রথ আমাদের কামনা করছে।"},{"n":2,"d":"तमिन्द्र मदमा गहि बर्हिष्ठां गरावभिः सुतम | कुविन नवस्य तर्प्णवः ||","b":"তমিন্দ্র মদমা গহি বর্হিষ্ঠাং গরাবভিঃ সুতম | কুবিন নবস্য তর্প্ণবঃ ||","e":"Come, Indra, to this gladdening drink, placed on the grass, pressed out with stones: Wilt thou not drink thy fill thereof?","mb":"হে ইন্দ্র! তুমি, প্রস্তর দ্বারা অভিষুত, কুশোপরি স্থিত সোমের নিকট এস, প্রচুর পরিমাণে সোম পান করে শীঘ্র তৃপ্ত হও।"},{"n":3,"d":"इन्द्रमित्था गिरो ममाछागुरिषिता इतः | आव्र्ते सोमपीतये ||","b":"ইন্দ্রমিত্থা গিরো মমাছাগুরিষিতা ইতঃ | আব্র্তে সোমপীতযে ||","e":"To Indra have my songs of praise gone forth, thus rapidly sent hence, To turn him to the Soma-draught.","mb":"ইন্দ্রের উদ্দেশে প্রেরিত আমার এ স্তুতি ইন্দ্রকে সোমপানার্থে আনার জন্য এ যজ্ঞ প্রদেশ হতে ইন্দ্রের নিকট  যাক।"},{"n":4,"d":"इन्द्रं सोमस्य पीतये सतोमैरिह हवामहे | उक्थेभिः कुविदागमत ||","b":"ইন্দ্রং সোমস্য পীতযে সতোমৈরিহ হবামহে | উক্থেভিঃ কুবিদাগমত ||","e":"Hither with songs of praise we call Indra to drink the Soma juice: Will he not come to us by lauds?","mb":"আমরা এ যজ্ঞে স্তোম এবং উকথ দ্বারা ইন্দ্রকে সোমপানার্থে আহ্বান করছি। বহুবার আহুত ইন্দ্র আসুন।"},{"n":5,"d":"इन्द्र सोमाः सुता इमे तान दधिष्व शतक्रतो | जठरे वाजिनीवसो ||","b":"ইন্দ্র সোমাঃ সুতা ইমে তান দধিষ্ব শতক্রতো | জঠরে বাজিনীবসো ||","e":"Indra, these Somas are expressed. Take them within thy belly, Lord Of Hundred Powers, thou Prince of Wealth.","mb":"হে শতক্রতু ইন্দ্র! এ সোম অভিষুত হয়েছে, হে অন্নধন। এ জঠরে ধারণ কর।"},{"n":6,"d":"विद्मा हि तवा धनंजयं वाजेषु दध्र्षं कवे | अधा तेसुम्नमीमहे ||","b":"বিদ্মা হি তবা ধনংজযং বাজেষু দধ্র্ষং কবে | অধা তেসুম্নমীমহে ||","e":"We know thee winner of the spoil, and resolute in battles, Sage! Therefore thy blessing we implore.","mb":"হে কবি! আমরা তোমাকে যুদ্ধে অভিভবিতা ও ধনজেতা বলে জানি। অতএব আমরা তোমার নিকট ধন যাচ এস করছি।"},{"n":7,"d":"इममिन्द्र गवाशिरं यवाशिरं च नः पिब | आगत्या वर्षभिः सुतम ||","b":"ইমমিন্দ্র গবাশিরং যবাশিরং চ নঃ পিব | আগত্যা বর্ষভিঃ সুতম ||","e":"Borne hither by thy Stallions, drink, Indra, this juice which we have pressed, Mingled with barley and with milk.","mb":"হে ইন্দ্র! আমাদের গব্যমিশ্রিত, যবমিশ্রিত, গ্রীবাদ্বারা অভিষুত এ সোম এসে পান কর।"},{"n":8,"d":"तुभ्येदिन्द्र सव ओक्ये सोमं चोदामि पीतये | एष रारन्तु ते हर्दि ||","b":"তুভ্যেদিন্দ্র সব ওক্যে সোমং চোদামি পীতযে | এষ রারন্তু তে হর্দি ||","e":"Indra, for thee, in thine own place, I urge the Soma for thy draught: Deep in thy heart let it remain,","mb":"হে ইন্দ্র! তোমার পানার্থেই, আমি এ অভিষুত সোম তোমার স্বীয় জঠরে প্রেরণ করছি। এ তোমার হৃদয়ে তৃপ্তিকর হোক।"},{"n":9,"d":"तवां सुतस्य पीतये परत्नमिन्द्र हवामहे | कुशिकासो अवस्यवः ||","b":"তবাং সুতস্য পীতযে পরত্নমিন্দ্র হবামহে | কুশিকাসো অবস্যবঃ ||","e":"We call on thee, the Ancient One, Indra, to drink the Soma juice, We Kuśikas who seek thine aid.","mb":"হে পুরাতন ইন্দ্র! আমরা কুশিকবংশোৎপন্ন। আমরা আশ্রয় লাভের জন্য তোমাকে সোম পানে আহ্বান করছি।"}]},{"n":43,"t":"Indra","v":[{"n":1,"d":"आ याह्यर्वां उप वन्धुरेष्ठास्तवेदनु परदिवः सोमपेयम | परिया सखाया वि मुचोप बर्हिस्त्वामिमे हव्यवाहो हवन्ते ||","b":"আ যাহ্যর্বাং উপ বন্ধুরেষ্ঠাস্তবেদনু পরদিবঃ সোমপেযম | পরিযা সখাযা বি মুচোপ বর্হিস্ত্বামিমে হব্যবাহো হবন্তে ||","e":"MOUNTED upon thy chariot-seat approach us: thine is the Soma-draught from days aforetime. Loose for the sacred grass thy dear companions. These men who bring oblation call thee hither.","mb":"হে ইন্দ্র! তুমি রথে করে আমাদের অভিমুখে এস, সোমপান প্রাচীন কাল হতে তোমারই। তেমার প্রিয়তম সখিভূত অশ্বদ্বয়কে কুশের সমীপে বিমোচন কর, এ সকল ঋত্বিকগণ তোমাকে আহ্বান করছে।"},{"n":2,"d":"आ याहि पूर्वीरति चर्षणीरानर्य आशिष उप नो हरिभ्याम | इमा हि तवा मतय सतोमतष्टा इन्द्र हवन्ते सख्यं जुषाणाः ||","b":"আ যাহি পূর্বীরতি চর্ষণীরানর্য আশিষ উপ নো হরিভ্যাম | ইমা হি তবা মতয সতোমতষ্টা ইন্দ্র হবন্তে সখ্যং জুষাণাঃ ||","e":"Come our true Friend, passing by many people; come with thy two Bay Steeds to our devotions; For these our hymns are calling thee, O Indra, hymns formed for praise, soliciting thy friendship.","mb":"হে স্বামী ইন্দ্র! তুমি সমস্ত লোককে অতিক্রম করে এস, আমরা প্রার্থনা করছি জঅশ্বযুক্ত হয়ে এস। যেহেতু স্তোতৃগণকৃত এ স্তুতিসমূহ সখাভিলাষী হয়ে তোমাকে আহ্বান করছে।"},{"n":3,"d":"आ नो यज्ञं नमोव्र्धं सजोषा इन्द्र देव हरिभिर्याहि तूयम | अहं हि तवा मतिभिर्जोहवीमि घर्तप्रयाः सधमादे मधूनाम ||","b":"আ নো যজ্ঞং নমোব্র্ধং সজোষা ইন্দ্র দেব হরিভির্যাহি তূযম | অহং হি তবা মতিভির্জোহবীমি ঘর্তপ্রযাঃ সধমাদে মধূনাম ||","e":"Pleased, with thy Bay Steeds, Indra, God, come quickly to this our sacrifice that heightens worship; For with my thoughts, presenting oil to feed thee, I call thee to the feast of sweet libations.","mb":"হে দ্যুতিমান ইন্দ্র! অশ্বগণের ন্যায় আনন্দিত হ{েয় আমাদের এ অন্নবর্ধক যজ্ঞে শীঘ্র এস, আমি ঘৃত বিশিষ্ট অন্নযুক্ত হয়ে সোমগৃহে স্তুতিদ্বারা তোমাকে বারবার আহ্বান করছি।"},{"n":4,"d":"आ च तवामेता वर्षणा वहातो हरी सखाया सुधुरा सवङगा | धानावदिन्द्रः सवनं जुषाणः सखा सख्युः शर्णवद वन्दनानि ||","b":"আ চ তবামেতা বর্ষণা বহাতো হরী সখাযা সুধুরা সবঙগা | ধানাবদিন্দ্রঃ সবনং জুষাণঃ সখা সখ্যুঃ শর্ণবদ বন্দনানি ||","e":"Yea, let thy two Bay Stallions bear thee hither, well limbed and good to draw, thy dear companions. Pleased with the corn-blent offering which we bring thee, may Indra, Friend, hear his friend's adoration.","mb":"হে ইন্দ্র! অভীষ্টবর্ষী সুন্দর মধুবিশিষ্ট, সুন্দর শরীরযুক্ত, সখিভূত অশ্বদ্বয় তোমাকে যজ্ঞস্থলে আনুক। ভুষ্টষবযুক্ত যজ্ঞসেবাকারী সখা ইন্দ্র স্তোতার বন্দনা শুনুন।"},{"n":5,"d":"कुविन मा गोपां करसे जनस्य कुविद राजानं मघवन्न्र्जीषिन | कुविन म रषिं पपिवांसं सुतस्य कुविन मे वस्वो अम्र्तस्य शिक्षाः ||","b":"কুবিন মা গোপাং করসে জনস্য কুবিদ রাজানং মঘবন্ন্র্জীষিন | কুবিন ম রষিং পপিবাংসং সুতস্য কুবিন মে বস্বো অম্র্তস্য শিক্ষাঃ ||","e":"Wilt thou not make me guardian of the people, make me, impetuous Maghavan, their ruler? Make me a Ṛṣi having drunk of Soma? Wilt thou not give me wealth that lasts for ever?","mb":"হে ইন্দ্র! তোমাকে লোকের রক্ষক কর। হে মঘবা জসোমবান ইন্দ্র। আমাকে সকলের স্বামী কর। ঋষি কর, অভিষূত সোমের পানকর্তাও কর এবং ক্ষয় রহিত ধন প্রদান কর।"},{"n":6,"d":"आ तवा बर्हन्तो हरयो युजाना अर्वागिन्द्र सधमादो वहन्तु | पर ये दविता दिव रञ्जन्त्याताः सुसम्म्र्ष्टासो वर्षभस्य मूराः ||","b":"আ তবা বর্হন্তো হরযো যুজানা অর্বাগিন্দ্র সধমাদো বহন্তু | পর যে দবিতা দিব রঞ্জন্ত্যাতাঃ সুসম্ম্র্ষ্টাসো বর্ষভস্য মূরাঃ ||","e":"Yoked to thy chariot, led thy tall Bays, Indra, companions of thy banquet, bear thee hither, Who from of old press to heaven's farthest limits, the Bull's impetuous and well-groomed Horses.","mb":"হে ইন্দ্র! মহান ও রথে যোজিত অশ্বগণ একযোগে প্রমত্ত হয়ে তোমাকে আমাদের অভিমুখে আনুক। জওরা অভষ্টবর্ষী, ইন্দ্রের শত্রুগণের বিনাশক, ইন্দ্র োদের পৃষ্ঠদেশ সংসৃষ্ট করলে , ওরা নভোদেশ হতে এসে দিক সকলকে দ্বিধা করে গমন করে।"},{"n":7,"d":"इन्द्र पिब वर्षधूतस्य वर्ष्ण आ यं ते शयेन उशते जभार | यस्य मदे चयावयसि पर कर्ष्टीर्यस्य मदे अप गोत्रा ववर्थ ||","b":"ইন্দ্র পিব বর্ষধূতস্য বর্ষ্ণ আ যং তে শযেন উশতে জভার | যস্য মদে চযাবযসি পর কর্ষ্টীর্যস্য মদে অপ গোত্রা ববর্থ ||","e":"Drink of the strong pressed out by strong ones, Indra, that which the Falcon brought thee when thou longedst; In whose wild joy thou stirrest up the people, in whose wild joy thou didst unbar the cow-stalls.","mb":"হে ইন্দ্র! তুমি  সোমাভিলাষী, তুমি প্রস্তরদ্বারা অভিষুত অভিমত ফলসেচক সোম রস পান কর। শোনপক্ষী তোমার জন্য এ আহরণ করেছে (১)। সোমজনিত হর্ষ উৎপন্ন হলে তুমি শত্রুভূত মানুষদের পতিত কর এবং সোমজনিত হর্ষ উৎপন্ন হলে তুমি মেঘ সকল অপাবৃত কর।"},{"n":8,"d":"शुनं हुवेम ... ||","b":"শুনং হুবেম ... ||","e":"Call we on Indra, Makhavan, auspicious, best Hero in the fight where spoil is gathered; The Strong, who listens, who gives aid in battles, who slays the Vṛtras, wins and gathers riches.","mb":"হে ইন্দ্র! তুমি অন্নলাভ কর, যুদ্ধে উৎসাহ দ্বারা প্রবৃদ্ধ, তুমি ধনবান, প্রভূত ঐশ্বর্যসম্পন্ন, নেতৃশ্রেষ্ঠ, স্তুতিশ্রবণকারী, উগ্র, সংগ্রামে শত্রুবিনাশী এবং ধনজেতা। আমরা আশ্রয় লাভের জন্য তোমাকে আহ্বান করছি।"}]},{"n":44,"t":"Indra","v":[{"n":1,"d":"अयं ते अस्तु हर्यतः सोम आ हरिभिः सुतः | जुषाण इन्द्र हरिभिर्न आ गह्या तिष्ठ हरितं रथम ||","b":"অযং তে অস্তু হর্যতঃ সোম আ হরিভিঃ সুতঃ | জুষাণ ইন্দ্র হরিভির্ন আ গহ্যা তিষ্ঠ হরিতং রথম ||","e":"May this delightsome Soma be expressed for thee by tawny stones. Joying thereat, O Indra, with thy Bay Steeds come:. ascend thy golden-coloured car.","mb":"হে ইন্দ্র! প্রস্তর দ্বারা অভিষূত কমনীয়, প্রীতিকর এ সোম তোমার হোক। তুমি অশ্বযুক্ত হরিৎবর্ণ রথে আরোহণ কর, আমাদের অভিমুখে এস।"},{"n":2,"d":"हर्यन्नुषसमर्चयः सूर्यं हर्यन्नरोचयः | विद्वांष्चिकित्वान हर्यश्व वर्धस इन्द्र विश्वा अभि शरियः ||","b":"হর্যন্নুষসমর্চযঃ সূর্যং হর্যন্নরোচযঃ | বিদ্বাংষ্চিকিত্বান হর্যশ্ব বর্ধস ইন্দ্র বিশ্বা অভি শরিযঃ ||","e":"In love thou madest Uṣas glow, in love thou madest Sūrya shine. Thou, Indra, knowing, thinking, Lord of Tawny Steeds, above all glories waxest great.","mb":"হে ইন্দ্র! তুমি সোমাভিলাষে ঊষাকে পূজা করে থাক, তুমি সোমাভিলাষে সূর্যকে প্রদীপ্ত করে থাক। হে হর্যশ্ব! তুমি বিদ্বান ও জ্ঞানবান, তুমি আমাদের সমস্ত সম্পদ বর্ধিত করছ।"},{"n":3,"d":"दयामिन्द्रो हरिधायसं पर्थिवीं हरिवर्पसम | अधारयद धरितोर्भूरि भोजनं ययोरन्तर्हरिश्चरत ||","b":"দযামিন্দ্রো হরিধাযসং পর্থিবীং হরিবর্পসম | অধারযদ ধরিতোর্ভূরি ভোজনং যযোরন্তর্হরিশ্চরত ||","e":"The heaven with streams of golden hue, earth with her tints of green and gold- The golden Pair yield Indra plenteous nourishment: between them moves the golden One.","mb":"ইন্দ্র হরিদ্বর্ণ রশ্মিবিশিষ্ট দ্যুলোককে ধারণ করেছেন, ঔষধিদ্বার, হরিৎবর্ণা পৃথিবীকে ধারণ করেছেন। হরিৎবর্ণা দ্র্যাবাপৃথিবীর মধ্যে ইন্দ্রের অশ্বদ্বয়ের প্রভূত খাদ্য আছে, ইন্দ্র ঐ দ্যাবাপৃথিবীর মধ্যে বিচরণ করেন।"},{"n":4,"d":"जज्ञानो हरितो वर्षा विश्वमा भाति रोचनम | हर्यश्वो हरितं धत्त आयुधमा वज्रं बाह्वोर्हरिम ||","b":"জজ্ঞানো হরিতো বর্ষা বিশ্বমা ভাতি রোচনম | হর্যশ্বো হরিতং ধত্ত আযুধমা বজ্রং বাহ্বোর্হরিম ||","e":"When born to life the golden Bull illumines all the realm of light. He takes his golden weapon, Lord of Tawny Steeds, the golden thunder in his arms.","mb":"অভীষ্টবর্ষী, হরিৎবর্ণোপেত ইন্দ্র জন্মানমাত্রেই সমস্ত দীপ্তিমান লোককে প্রকাশিত করেন। হর্যশ্ব বাহুদ্বয়ে হরিদ্বর্ণোপেত অস্ত্র ধারণ করেন, শত্রুদের প্রাণনাশক  বজ্র ধারণ করেন। । ইন্দ্র কমনীয়, শূভ, শুভ্রক্ষীরাদি দ্বারা ব্যাপ্ত, বেগবান ও প্রস্তরদ্বারা অভিষূত সোম অপাবৃত করেছেন তিনি পণিগণ কর্তৃক অপহৃত গাভী সকল বার করেছেন।"},{"n":5,"d":"इन्द्रो हर्यन्तमर्जुनं वज्रं शुक्रैरभीव्र्तम | अपाव्र्णोद धरिभिरद्रिभिः सुतमुद गा हरिभिराजत ||","b":"ইন্দ্রো হর্যন্তমর্জুনং বজ্রং শুক্রৈরভীব্র্তম | অপাব্র্ণোদ ধরিভিরদ্রিভিঃ সুতমুদ গা হরিভিরাজত ||","e":"The bright, the well-loved thunderbolt, girt with the bright, Indra disclosed, Disclosed the Soma juice pressed out by tawny stones, with tawny steeds drave forth the kine.","mb":"উজ্জ্বল, প্রিয় বজ্র, দীপ্তিতে আবৃত — ইন্দ্র প্রকাশ করলেন, পিঙ্গল প্রস্তরে নিষ্কাশিত সোমরস প্রকাশ করলেন, পিঙ্গল অশ্বে গাভীদের চালিত করলেন।"}]},{"n":45,"t":"Indra","v":[{"n":1,"d":"आ मन्द्रैरिन्द्र हरिभिर्याहि मयूररोमभिः | मा तवा केचिन नि यमन विं न पाशिनो.अति धन्वेव तानिहि ||","b":"আ মন্দ্রৈরিন্দ্র হরিভির্যাহি মযূররোমভিঃ | মা তবা কেচিন নি যমন বিং ন পাশিনো.অতি ধন্বেব তানিহি ||","e":"COME hither, Indra, with Bay Steeds, joyous, with tails like peacocks' plumes. Let no men cheek thy course as fowlers stay the bird: pass o’er them as o’er desert lands.","mb":"হে ইন্দ্র! তুমি মাদক ও ময়ূরের লোমের ন্যায় লোমযুক্ত অশ্বের সাথে এস। ব্যাধ যেরূপ পক্ষীকে বাধা দেয়, সেরূপ তোমাকে যেন কেউ বাধা না দেয়। পথিক যেরূপ মরুদেশ অতিক্রম করে, সেরূপ তুমি শীঘ্র ঐ সকল বাধা অতিক্রম করে এস।"},{"n":2,"d":"वर्त्रखादो वलंरुजः पुरां दर्मो अपामजः | सथाता रथस्य हर्योरभिस्वर इन्द्रो दर्ळ्हा चिदारुजः ||","b":"বর্ত্রখাদো বলংরুজঃ পুরাং দর্মো অপামজঃ | সথাতা রথস্য হর্যোরভিস্বর ইন্দ্রো দর্ল্হা চিদারুজঃ ||","e":"He who slew Vṛtra, burst the cloud, brake the strongholds and drave the floods, Indra who mounts his chariot at his Bay Steeds' cry, shatters e’en things that stand most firm.","mb":"্ইন্দ্র বৃত্রের বিনাশক, তিনি মেঘ বিদীর্ণ করেন ও জল প্রেরণ করেন। তিনি শত্রুপুরী বিদীর্ণ করেন, তিনি অশ্বদ্বয়কে আমাদের অভিমুখে প্রেরণ করবার জন্য রথে আরোহণ করেন। তিনি বলবান শত্রুদেরও ভগ্ন কেরন।"},{"n":3,"d":"गम्भीरानुदधीन्रिव करतुं पुष्यसि गा इव | पर सुगोपायवसं धेनवो यथा हरदं कुल्या इवाशत ||","b":"গম্ভীরানুদধীন্রিব করতুং পুষ্যসি গা ইব | পর সুগোপাযবসং ধেনবো যথা হরদং কুল্যা ইবাশত ||","e":"Like pools of water deep and full, like kine thou cherishest thy might; Like the milch-cows that go well-guarded to the mead, like water-brooks that reach the lake.","mb":"হে ইন্দ্র! সাধু গো পালক যেরূপ গাভী সকলকে পুরিপুষ্ট করে, তুমি যেরূপ সমুদ্রকে নদীদ্বারা পরিপুষ্ট কর, সেরূপ তুমি যজ্ঞকর্তাকে পুষ্ট করে থাক। ধেনুগণ যেরূপ তৃণাদি প্রাপ্ত হয়, সেরূপ তুম  সোমরস প্রাপ্ত হ{েয় থাক, সরিৎ যেরূপ হৃদ প্রাপ্ত হয়, সেরূপ সোমরস তোমাকে ব্যাপ্ত করে;"},{"n":4,"d":"आ नस्तुजं रयिं भरांशं न परतिजानते | वर्क्षं पक्वं फलमङकीव धूनुहीन्द्र सम्पारणं वसु ||","b":"আ নস্তুজং রযিং ভরাংশং ন পরতিজানতে | বর্ক্ষং পক্বং ফলমঙকীব ধূনুহীন্দ্র সম্পারণং বসু ||","e":"Bring thou us wealth with power to strike, our share, 'gainst him who calls it his. Shake, Indra, as with hooks, the tree for ripened fruit, for wealth to satisfy our wish.","mb":"হে ইন্দ্র! পিতা যেরূপ ব্যবহারঞ্জ পুত্রকে ধনের অংশ দান করেন, সেরূপ তুমি আমাদের শত্রুর বাধাকারী ধনরুপ পুত্র দান কর। আকুষী যেরূপ পক্ক ফলের জন্য বৃক্ষকে চালিত করে, সেরূপ তুমি আমাদরে অভিলাষ পুরক ধন চালিত কর।"},{"n":5,"d":"सवयुरिन्द्र सवराळ असि समद्दिष्टिः सवयशस्तरः | स वाव्र्धान ओजसा पुरुष्टुत भवा नः सुश्रवस्तमः ||","b":"সবযুরিন্দ্র সবরাল অসি সমদ্দিষ্টিঃ সবযশস্তরঃ | স বাব্র্ধান ওজসা পুরুষ্টুত ভবা নঃ সুশ্রবস্তমঃ ||","e":"Indra, self-ruling Lord art thou, good Leader, of most glorious fame. So, waxen in thy strength, O thou whom many praise, be thou most swift to hear our call.","mb":"হ ইন্দ্র! তুমি ধনবান, তুমি স্বর্গের রাজা, তোমার বাক্য সাধু, তোমার কীর্তি প্রভূত। হে বহুজনস্তুত ইন্দ্র! তুমি বলদ্বারা বর্ধিত হয়ে আমাদের সর্বোৎকৃষ্ট শোভনীয় অন্নদাতা হও।"}]},{"n":46,"t":"Indra","v":[{"n":1,"d":"युध्मस्य ते वर्षभस्य सवराज उग्रस्य यून सथविरस्य घर्ष्वेः | अजूर्यतो वज्रिणो वीर्याणीन्द्र शरुतस्य महतो महानि ||","b":"যুধ্মস্য তে বর্ষভস্য সবরাজ উগ্রস্য যূন সথবিরস্য ঘর্ষ্বেঃ | অজূর্যতো বজ্রিণো বীর্যাণীন্দ্র শরুতস্য মহতো মহানি ||","e":"OF thee, the Bull, the Warrior, Sovran Ruler, joyous and fierce, ancient and ever youthful, The undecaying One who wields the thunder, renowned and great, great are the exploits, Indra.","mb":"হে ইন্দ্র! তুমি যুদ্ধশীল, অভীষ্টবর্ষী, ধনাধিপতি, উগ্র, নিত্য তরুণ, চিরন্তন, শত্রুধর্ষক, জরারহিত, বজ্রধারী, প্রসিদ্ধ ও মহান। তোমার বর্যি মহৎ।"},{"n":2,"d":"महानसि महिष वर्ष्ण्येभिर्धनस्प्र्दुग्र सहमानो अन्यान | एको विश्वस्य भुवनस्य राजा स योधया च कषयया च जनान ||","b":"মহানসি মহিষ বর্ষ্ণ্যেভির্ধনস্প্র্দুগ্র সহমানো অন্যান | একো বিশ্বস্য ভুবনস্য রাজা স যোধযা চ কষযযা চ জনান ||","e":"Great art thou, Mighty Lord, through manly vigour, O fierce One, gathering spoil, subduing others, Thyself alone the universe's Sovran: so send forth men to combat and to rest them.","mb":"হে পূজনীয় উগ্র ইন্দ্র! তুমি মহান, তুমি ধনকে পারে নিয়ে যাও, তুমি বীর্য দ্বারা শত্রুদের অভিভূত করে থাক। তুমি সমস্ত ভূবনের একমাত্র রাজা, তুমি শত্রুদের প্রহার কর ও সাধুব্যক্তিদের  স্বস্থানে স্থাপিত কর।"},{"n":3,"d":"पर मात्राभी रिरिचे रोचमानः पर देवेभिर्विश्वतो अप्रतीतः | पर मज्मना दिव इन्द्रः पर्थिव्याः परोरोर्महो अन्तरिक्षाद रजीषी ||","b":"পর মাত্রাভী রিরিচে রোচমানঃ পর দেবেভির্বিশ্বতো অপ্রতীতঃ | পর মজ্মনা দিব ইন্দ্রঃ পর্থিব্যাঃ পরোরোর্মহো অন্তরিক্ষাদ রজীষী ||","e":"He hath surpassed all measure in his brightness, yea, and the Gods, for none may be his equal. Impetuous Indra in his might cxccedcth wide vast mid-air and heaven and earth together.","mb":"দ্যুতিমান ও সর্ব প্রকারে অপরিমিত ইন্দ্র সোমপান করে পর্বত হতেও শ্রেষ্ঠ হন, বলে দেবতা গণের অপেক্ষাও শ্রেষ্ঠ হন, দ্যাবাপৃথিবী হতেও শ্রেষ্ঠ হন, বিস্তীর্ণ অন্তরীক্ষ হতেও শ্রেষ্ঠ হন।"},{"n":4,"d":"उरुं गभीरं जनुषाभ्युग्रं विश्वव्यचसमवतं मतीनाम | इन्द्रं सोमासः परदिवि सुतासः समुद्रं न सरवता विशन्ति ||","b":"উরুং গভীরং জনুষাভ্যুগ্রং বিশ্বব্যচসমবতং মতীনাম | ইন্দ্রং সোমাসঃ পরদিবি সুতাসঃ সমুদ্রং ন সরবতা বিশন্তি ||","e":"To Indra, even as rivers to the ocean, flow forth from days of old the Soma juices; To him wide deep and mighty from his birth-time, the well of holy thoughts, aIl-comprehending.","mb":"ইন্দ্র মহান, গম্ভরি স্বভাবত: ইগ্র, বিশ্বব্যাপ্ত ও স্তোতাগণের রক্ষক। নদীগণ যেরূপ সমুদ্রের অভিমুখে যায়, সেরুপ পূর্বকাল হতে অভিষূত সোম ইন্দ্রের অভিমুখে যায়।"},{"n":5,"d":"यं सोममिन्द्र पर्थिवीद्यावा गर्भं न माता बिभ्र्तस्त्वाया | तं ते हिन्वन्ति तमु ते मर्जन्त्यध्वर्यवो वर्षभ पातवा उ ||","b":"যং সোমমিন্দ্র পর্থিবীদ্যাবা গর্ভং ন মাতা বিভ্র্তস্ত্বাযা | তং তে হিন্বন্তি তমু তে মর্জন্ত্যধ্বর্যবো বর্ষভ পাতবা উ ||","e":"The Soma, Indra, which the earth and heaven bear for thee as a mother bears her infant, This they send forth to thee, this, vigorous Hero! Adhvaryus purify for thee to drink of.","mb":"হে ইন্দ্র! মাতা যেরূপ গর্ভ ধারণ করে, সেরূপ দ্যাবাপৃথিবী তোমার জন্য, সোম ধারণ করে। হে অভীষ্টবর্ষী! অধ্বর্যুগণ সে সোমকে তোমার উদ্দেশে প্রেরণ করছে ও তোমার পানের জন্য শোধিত করছে।"}]},{"n":47,"t":"Indra","v":[{"n":1,"d":"मरुत्वानिन्द्र वर्षभो रणाय पिबा सोममनुष्वधं मदाय | आ सिञ्चस्व जठरे मध्व ऊर्मिं तवं राजासि परदिवः सुतानाम ||","b":"মরুত্বানিন্দ্র বর্ষভো রণায পিবা সোমমনুষ্বধং মদায | আ সিঞ্চস্ব জঠরে মধ্ব ঊর্মিং তবং রাজাসি পরদিবঃ সুতানাম ||","e":"DRINK, Indra, Marut-girt, as Bull, the Soma, for joy, for rapture even as thou listest. Pour down the flood of meath within thy belly: thou from of old art King of Soma juices.","mb":"হে ইন্দ্র! তুমি অভীষ্টবর্ষী ও মরুৎগণযুক্ত। তুমি রণে হর্ষের জন্য রীতি অনুসারে সোম পান কর, হর্যকর বহু সোমরস জঠরে বিশেষরূপে সেক কর। যেহেতু তুমি পুরাকাল হতে অভিষুত সোমের রাজা।"},{"n":2,"d":"सजोषा इन्द्र सगणो मरुद्भिः सोमं पिब वर्त्रहा शूर विद्वान | जहि शत्रून्रप मर्धो नुदस्वाथाभयं कर्णुहि विश्वतो नः ||","b":"সজোষা ইন্দ্র সগণো মরুদ্ভিঃ সোমং পিব বর্ত্রহা শূর বিদ্বান | জহি শত্রূন্রপ মর্ধো নুদস্বাথাভযং কর্ণুহি বিশ্বতো নঃ ||","e":"Indra, accordant, with the banded Maruts, drink Soma, Hero, as wise Vṛtra-slayer. Slay thou our foemen, drive away assailants and make us safe on every side from danger.","mb":"হে শুর ইন্দ্র! তুমি দেবগণদ্বরা সঙ্গত, মরুৎগণযেুক্ত, বৃত্রহস্তা ও বিদ্বান। তুমি সোম পান কর, শত্রুগণকে বধ কর, হিংসকদের দূর করে দাও। অনন্তর আমাদের সর্ব প্রকারে অভয় দান কর।"},{"n":3,"d":"उत रतुभिर्र्तुपाः पाहि सोममिन्द्र देवेभिः सखिभिः सुतं नः | यानाभजो मरुतो ये तवान्वहन वर्त्रमदधुस्तुभ्यमोजः ||","b":"উত রতুভির্র্তুপাঃ পাহি সোমমিন্দ্র দেবেভিঃ সখিভিঃ সুতং নঃ | যানাভজো মরুতো যে তবান্বহন বর্ত্রমদধুস্তুভ্যমোজঃ ||","e":"And, drinker at due seasons, drink in season, Indra, with friendly Gods, our pressed-out Soma. The Maruts following, whom thou madest sharers, gave thee the victory, and thou slewest Vṛtra.","mb":"হে ঋতুপা ইন্দ্র! তুমি সখিভূত মরুৎগণের সাথে আমাদের অভিষুত সোম পান কর। তুমি  যাদের যুদ্ধে সাহায্যর্থে গ্রহণ করেছিলে যারা তোমাকে আনুকুল্য করায় তুমি বৃত্তকে বধ করেছিলে, সে মরুৎগণ তোমাকে পরাক্রম প্রদান করেছিলেন।"},{"n":4,"d":"ये तवाहिहत्ये मघवन्नवर्धन ये शाम्बरे हरिवो ये गविष्टौ | ये तवा नूनमनुमदन्ति विप्राः पिबेन्द्र सोमं सगणो मरुद्भिः ||","b":"যে তবাহিহত্যে মঘবন্নবর্ধন যে শাম্বরে হরিবো যে গবিষ্টৌ | যে তবা নূনমনুমদন্তি বিপ্রাঃ পিবেন্দ্র সোমং সগণো মরুদ্ভিঃ ||","e":"Drink Soma, Indra, banded with the Maruts who, Maghavan, strengthened thee at Ahi's slaughter, 'Gainst Śambara, Lord of Bays! in winning cattle, and now rejoice in thee, the holy Singers.","mb":"হে মঘবন ইন্দ্র! যারা বৃত্র বধে তোমাকে প্রোৎসাহিত করেছিলেন, হে অশ্ববান! যারা শম্বর বধে তোমাকে প্রোৎসাহিত করেছিলেন যার ধেনুগণের জন্য যুদ্ধে তোমাকে প্রোৎসাহিত করেছিলেন, যারা অদ্যাপি তোমাকে হৃষ্ট করেন, সে মরুৎগণের সাথে সোম পান কর।"},{"n":5,"d":"मरुत्वन्तं वर्षभं वाव्र्धानमकवारिं दिव्यं शासमिन्द्रम | विश्वासाहमवसे नूतनायोग्रं सहोदामिह तंहुवेम ||","b":"মরুত্বন্তং বর্ষভং বাব্র্ধানমকবারিং দিব্যং শাসমিন্দ্রম | বিশ্বাসাহমবসে নূতনাযোগ্রং সহোদামিহ তংহুবেম ||","e":"The Bull whose strength hath waxed, whom Maruts follow, free-giving Indra, the celestial Ruler, Mighty, all-conquering, the victory-giver, him let us call to grant us new protection.","mb":"আমরা মরুৎগণযুক্ত, জলবর্ষী, প্রোৎসাহক, প্রভূত শত্রুবিশিষ্ট,  দিবা, শাসনকর্তা বিশ্বের অভিভবিতা, উগ্র, বলপ্রদ ইন্দ্রকে নূতন আশ্রয়লাভের জন্য এ যজ্ঞে আহ্বান করছি।"}]},{"n":48,"t":"Indra","v":[{"n":1,"d":"सद्यो ह जातो वर्षभः कनीनः परभर्तुमावदन्धसः सुतस्य | साधोः पिब परतिकामं यथा ते रसाशिरः परथमं सोम्यस्य ||","b":"সদ্যো হ জাতো বর্ষভঃ কনীনঃ পরভর্তুমাবদন্ধসঃ সুতস্য | সাধোঃ পিব পরতিকামং যথা তে রসাশিরঃ পরথমং সোম্যস্য ||","e":"SOON as the young Bull sprang into existence he longed to taste the pressed-out Soma's liquor. Drink thou thy fill, according to thy longing, first, of the goodly mixture blent with Soma.","mb":"জলবর্ষী ও জন্মিবামাত্র কমনীয় ইন্দ্র অভূষূত সোমরুপ অন্নের সংগ্রহীতাকে রক্ষা করুন। হে ইন্দ্র! তুমি ইচ্ছা  হলেই সাধু  গব্যমিশ্রিত সোমরস পান কর।"},{"n":2,"d":"यज्जायथास्तदहरस्य कामे.अंशोः पीयूषमपिबो गिरिष्ठाम तं | ते माता परि योषा जनित्री महः पितुर्दम आसिञ्चदग्रे ||","b":"যজ্জাযথাস্তদহরস্য কামে.অংশোঃ পীযূষমপিবো গিরিষ্ঠাম তং | তে মাতা পরি যোষা জনিত্রী মহঃ পিতুর্দম আসিঞ্চদগ্রে ||","e":"That day when thou wast born thou, fain to taste it, drankest the plant's milk which the mountains nourish. That milk thy Mother first, the Dame who bare thee, poured for thee in thy mighty Father's dwelling.","mb":"যে দিন তুমি জন্মগ্রহণ করেছ, সে দিনেই সোম পানের ইচ্ছা হলে তুমি  পর্বতস্থ সোমলতার রস পান করেছিলে! যেহেতু তোমার মাতা যুবতী অদিতি তোমার প্রসিদ্ধ পিতার গৃহে স্তন্যদানের পূর্বে তোমায় সোম দান করে ছিলেন।"},{"n":3,"d":"उपस्थाय मातरमन्नमैट्ट तिग्ममपश्यदभि सोममूधः | परयावयन्नचरद गर्त्सो अन्यान महानि चक्रे पुरुधप्रतीकः ||","b":"উপস্থায মাতরমন্নমৈট্ট তিগ্মমপশ্যদভি সোমমূধঃ | পরযাবযন্নচরদ গর্ত্সো অন্যান মহানি চক্রে পুরুধপ্রতীকঃ ||","e":"Desiring food he came unto his Mother, and on her breast beheld the pungent Soma. Wise, he moved on, keeping aloof the others, and wrought great exploits in his varied aspects.","mb":"্ইন্দ্র মাতার নিকট এসে অন্ন যাচঞ্চা করেছিলেন, ও তার স্তনে দীপ্ত সোম দর্শন করেছিলেন। তিনি শত্রুদের চালিত করে বিচরণ করেন, তিনি বহুপ্রকারে অঙ্গ বিক্ষেপ করে মহৎ কার্য সকল সম্পাদন করেছেন।"},{"n":4,"d":"उग्रस्तुराषाळ अभिभूत्योजा यथावशं तन्वं चक्र एषः | तवष्टारमिन्द्रो जनुषाभिभूयामुष्या सोममपिबच्चमूषु ||","b":"উগ্রস্তুরাষাল অভিভূত্যোজা যথাবশং তন্বং চক্র এষঃ | তবষ্টারমিন্দ্রো জনুষাভিভূযামুষ্যা সোমমপিবচ্চমূষু ||","e":"Fierce, quickly conquering, of surpassing vigour, he framed his body even as he listed. E’en from his birth-time Indra conquered Tvaṣṭar, bore off the Soma and in beakers drank it.","mb":"তিনি উগ্র, শীঘ্র অভিভবিতা এবং অভিভবকর, পরাক্রমযুক্ত হয়ে শরীরকে নানাবিধ রূপবিশিষ্ট করেছিলেন। ইন্দ্র ত্বষ্টাকে সামর্থ্যদ্বারা পরাভূত করে তার চমসস্থিত  সোম পান করেছিলেন।"},{"n":5,"d":"शुनं हुवेम ... ||","b":"শুনং হুবেম ... ||","e":"Call we on Maghavan, auspicious Indra, best Hero in the fight where spoil is gathered; The Strong, who listens, who gives aid in battles, who slays the Vṛtras, wins and gathers riches.","mb":"হে ইন্দ্র! তুমি অন্নলাভ কর, যুদ্ধে উৎসাহদ্বারা প্রবৃদ্ধ, তুমি  ধনবান, প্রভূত ঐশ্বর্যসম্পন্ন, নেতৃশ্রেষ্ঠ, স্তুতিশ্রবনকারী, উগ্র, সংগ্রামে শত্রুবিনাশী এবং ধনজেতা। আমরা আশ্রয় লাভের জন্য তোমাকে আহ্বান করছি।"}]},{"n":49,"t":"Indra","v":[{"n":1,"d":"शंसा महामिन्द्रं यस्मिन विश्वा आ कर्ष्टयः सोमपाः काममव्यन | यं सुक्रतुं धिषणे विभ्वतष्टं घनं वर्त्राणां जनयन्त देवाः ||","b":"শংসা মহামিন্দ্রং যস্মিন বিশ্বা আ কর্ষ্টযঃ সোমপাঃ কামমব্যন | যং সুক্রতুং ধিষণে বিভ্বতষ্টং ঘনং বর্ত্রাণাং জনযন্ত দেবাঃ ||","e":"GREAT Indra will I laud, in whom all people who drink the Soma have attained their longing; Whom, passing wise, Gods, Heaven and Earth, engendered, formed by a Master's hand, to crush the Vṛtras.","mb":"মহান ইন্দ্রকে স্তব কর, তিনি রক্ষক হলে সমস্ত মনুষ্য সোম পান করে অভীষ্ট লাভ করে। দ্যাবাপৃথিবী ও দেবগণ সে সুক্রতু ইন্দ্রকে শত্রুদের পক্ষে বিভব নির্মিত মুগ্ধররূপে জন্ম দিয়েছেন।"},{"n":2,"d":"यं नु नकिः पर्तनासु सवराजं दविता तरति नर्तमं हरिष्ठाम | इनतमः सत्वभिर्यो ह शूषैः पर्थुज्रया अमिनादायुर्दस्योः ||","b":"যং নু নকিঃ পর্তনাসু সবরাজং দবিতা তরতি নর্তমং হরিষ্ঠাম | ইনতমঃ সত্বভির্যো হ শূষৈঃ পর্থুজ্রযা অমিনাদাযুর্দস্যোঃ ||","e":"Whom, most heroic, borne by Tawny Coursers, verily none subdueth in the battle; Who, reaching far, most vigorous, hath shortened the Dasyu's life with Warriors bold of spirit.","mb":"যে ইন্দ্র সংগ্রামে শোভমান, অশ্বযুক্ত ও নেতৃতম, যিনি সেনাকে দ্বিধা ভেদ করলে কেহ তাকে অতিক্রম করতে পারে না, সে উৎকৃষ্ট সেনাপতি ইন্দ্র মরুৎগণের সাথে গিয়ে বলদ্বারা তীব্রবেগে শত্রুর আয়ু নাশ করেন।"},{"n":3,"d":"सहावा पर्त्सु तरणिर्नार्वा वयानशी रोदसी मेहनावान | भगो न कारे हव्यो मतीनां पितेव चारुः सुहवो वयोधाः ||","b":"সহাবা পর্ত্সু তরণির্নার্বা বযানশী রোদসী মেহনাবান | ভগো ন কারে হব্যো মতীনাং পিতেব চারুঃ সুহবো বযোধাঃ ||","e":"Victor in fight, swift mover like a warhorse, pervading both worlds, rainer down of blessings, To he invoked in war like Bhaga, Father, as ’twere, of hymns, fair, prompt to hear, strength-giver.","mb":"ইন্দ্র বলবান অশ্বের ন্যায় সংগ্রামী  বিজয়ী ও ধনবান, ইন্দ্রকে যজ্ঞে ভাগের ন্যায় হোম করা উচিত। তিনি স্তোতাগণের পিতা স্বরূপ, তিনি কমনীয়, আহরণযুক্ত ও অন্নদাতা।"},{"n":4,"d":"धर्ता दिवो रजसस पर्ष्ट ऊर्ध्वो रथो न वायुर्वसुभिर्नियुत्वान | कषपां वस्ता जनिता सूर्यस्य विभक्ता भागं धिषणेव वाजम ||","b":"ধর্তা দিবো রজসস পর্ষ্ট ঊর্ধ্বো রথো ন বাযুর্বসুভির্নিযুত্বান | কষপাং বস্তা জনিতা সূর্যস্য বিভক্তা ভাগং ধিষণেব বাজম ||","e":"Supporting heaven, the high back of the region, his car is Vāyu with his team of Vasus. Illumining the nights, the Sun's creator, like Dhiṣaṇā he deals forth strength and riches.","mb":"তিনি দ্যুলোক ও অন্তরিক্ষের ধারক, তিনি উর্ধ্বগামী রথের ন্যায় এবং  বসুগণের দ্বারা যুক্ হয়ে নিযুক্ত যুক্ত বায়ুর ন্যায়। তিনি রাত্রির আচ্ছাদক, সুর্যৈর জনয়িতা। ধনীর বাক্য যেমন ধন বিভাগ করে, তিনিও সেরূপ ন্নৈর বিভাগ কর্তা।"},{"n":5,"d":"शुनं हुवेम ... ||","b":"শুনং হুবেম ... ||","e":"Call we on Maghavan, auspicious Indra, best Hero in the fight where spoil is gathered; The Strong, who listens, who gives aid in battles, who slays the Vṛtras, wins and gathers treasure.","mb":"হে ইন্দ্র! তুমি অন্নলাভ কর যুদ্ধে উৎসাহদ্বারা প্রবৃদ্ধ, তুমি ধনবান, প্রভূত ঐশ্বর্যসম্পন্ন, নেতৃশ্রেষ্ঠ স্তুতিশ্রবণ কারী, উগ্র, সংগ্রামে শত্রুবিনাশী এবং ধনজেতা। আমরা আশ্রয় লাভের জন্য তোমাকে আহ্বান করছি।"}]},{"n":50,"t":"Indra","v":[{"n":1,"d":"इन्द्रः सवाहा पिबतु यस्य सोम आगत्या तुम्रो वर्षभो मरुत्वान | ओरुव्यचाः पर्णतामेभिरन्नैरास्य हविस्तन्वःकामं रध्याः ||","b":"ইন্দ্রঃ সবাহা পিবতু যস্য সোম আগত্যা তুম্রো বর্ষভো মরুত্বান | ওরুব্যচাঃ পর্ণতামেভিরন্নৈরাস্য হবিস্তন্বঃকামং রধ্যাঃ ||","e":"LET Indra drink, All-hail! for his is Soma,—the mighty Bull come, girt by Maruts, hither. Far-reaching, let him fill him with these viands, and let our offering sate his body's longing.","mb":"ইন্দ্র স্বাহাকৃত এ সোম পান করুন। এস সোম তারই; তিনি শত্রুহিংসক অভীষ্টবর্ষী ও মরুৎগণ যুক্ত এবং প্রভূত ব্যাপ্তিবিশিষ্ট হয়ে এ অন্ন দ্বারা প্রীত হোন হব্য তার শরীরের অভিলাষ পূর্ণ করুক।"},{"n":2,"d":"आ ते सपर्यू जवसे युनज्मि ययोरनु परदिवः शरुष्टिमावः | इह तवा धेयुर्हरयः सुशिप्र पिबा तवस्य सुषुतस्य चारोः ||","b":"আ তে সপর্যূ জবসে যুনজ্মি যযোরনু পরদিবঃ শরুষ্টিমাবঃ | ইহ তবা ধেযুর্হরযঃ সুশিপ্র পিবা তবস্য সুষুতস্য চারোঃ ||","e":"I yoke thy pair of trusty Steeds for swiftness, whose faithful service from of old thou lovest. Here, fair of cheek! let thy Bay Coursers place thee: drink of this lovely welleffused libation.","mb":"হে ইন্দ্র! তোামর আগমনের জন্য পরিচারক অশ্বদ্বয়কে যোজিত করছি। তুমি পুরাতন, তুমি এদের বেগ অনুগমন করে থাক। হে শোভনহনু! অশ্বগণ তোমাকে এ যজ্ঞে ধারণ করুক, তুমি সুন্দররূপে অভিষুত কমনীয় এ  সোম শীঘ্র পান কর।"},{"n":3,"d":"गोभिर्मिमिक्षुं दधिरे सुपारमिन्द्रं जयैष्ठ्याय धायसे गर्णानाः | मन्दानः सोमं पपिवान रजीषिन समस्मभ्यं पुरुधा गा इषण्य ||","b":"গোভির্মিমিক্ষুং দধিরে সুপারমিন্দ্রং জযৈষ্ঠ্যায ধাযসে গর্ণানাঃ | মন্দানঃ সোমং পপিবান রজীষিন সমস্মভ্যং পুরুধা গা ইষণ্য ||","e":"With milk they made Indra their good Preserver, lauding for help and rule the bounteous rainer. Impetuous God, when thou hast drunk the Soma, enraptured send us cattle in abundance.","mb":"ঋত্বিকগণ ফলদানেচ্ছু ও স্তুতিপ্রি{য় ইন্দ্রকে শ্রেষ্ঠত্ব ও দীর্ঘায়ু লাভের জন্য গোসমূহ দ্বারা ধারণ করেন। হে সোমবান! তুমি সোম পান করে হৃষ্ট হয়ে স্তোতাগণকে বহুবিধ গাভী প্রেরণ কর।"},{"n":4,"d":"इमं कामं ... ||","b":"ইমং কামং ... ||","e":"With kine and horses satisfy this longing with very splendid bounty still extend it. Seeking the light, with hymns to thee, O Indra, the Kuśikas have brought their gift, the singers.","mb":"আমাদের অভিলাষ গো, অশ্ব ও দীপ্তিযুক্ত ধনদ্বারা পূর্ণ কর এবং তা দিয়ে আমাদের বিখ্যাত কর। হে ইন্দ্র! স্বগৃাদি সুখাভিলাষী কর্মকুশল কুশিকনন্দন মন্ত্র দ্বারা তোমার স্তুতি করেছে।"},{"n":5,"d":"शुनं हुवेम ... ||","b":"শুনং হুবেম ... ||","e":"Call we on Maghavan, auspicious Indra, best Hero in the fight where spoil is gathered; The Strong, who listens, who gives aid in battles, who slays the Vṛtras, wins and gathers riches.","mb":"হে ইন্দ্র! তুমি অন্ন লাভ কর, যুদ্ধে উৎসাহ দ্বারা প্রবৃদ্ধ, তুমি ধনবান, প্রভূ ঐশ্বর্য সমস্পন্ন, নেতৃশ্রেষ্ঠ, স্তুতিশ্রবণকারী, উগ্র, সংগ্রামে শত্রুবিনাশী এবং ধনজেতা। আমরা আশ্রয় লাভের জন্য তোমাকে আহ্বান করছি।"}]},{"n":51,"t":"Indra","v":[{"n":1,"d":"चर्षणीध्र्तं मघवानमुक्थ्यमिन्द्रं गिरो बर्हतीरभ्यनूषत | वाव्र्धानं पुरुहूतं सुव्र्क्तिभिरमर्त्यं जरमाणं दिवे-दिवे ||","b":"চর্ষণীধ্র্তং মঘবানমুক্থ্যমিন্দ্রং গিরো বর্হতীরভ্যনূষত | বাব্র্ধানং পুরুহূতং সুব্র্ক্তিভিরমর্ত্যং জরমাণং দিবে-দিবে ||","e":"HIGH hymns have sounded forth the praise of Maghavan, supporter of mankind, of Indra meet for lauds; Him who hath waxen great, invoked with beauteous songs, Immortal One, whose praise each day is sung aloud.","mb":"ইন্দ্র মানুষের পোষক, ধনবান, উকথদ্বারা প্রশংসনীয়, বর্ধমান, বহুবার আহুত, মরণরহিত ও সুন্দর স্তুতিদ্বারা প্রত্যহ স্তুয়মান। ইন্দ্রকে প্রভূত স্তুতিবাক্যে সর্বতোভাবে স্তব করুক।"},{"n":2,"d":"शतक्रतुमर्णवं शाकिनं नरं गिरो म इन्द्रमुप यन्ति विश्वतः | वाजसनिं पूर्भिदं तूर्णिमप्तुरं धामसाचमभिषाचं सवर्विदम ||","b":"শতক্রতুমর্ণবং শাকিনং নরং গিরো ম ইন্দ্রমুপ যন্তি বিশ্বতঃ | বাজসনিং পূর্ভিদং তূর্ণিমপ্তুরং ধামসাচমভিষাচং সবর্বিদম ||","e":"To Indra from all sides go forth my songs of praise, the Lord of Hundred Powers, strong, Hero, like the sea, Swift, winner of the booty, breaker-down of forts, faithful and ever-glorious, finder of the light.","mb":"্ইন্দ্র শত যজ্ঞবিশিষ্ট, জলবান মরুৎগণযুক্ত, নেতা, অন্নদাতা, শত্রুগণের পুরীভেদক, যুদ্ধে শীঘ্রগামী, জলপ্রেরক, ধনদাতা অভিভবিতা ও স্বর্গদাতা; ইন্দ্রের নিকট আমার স্তুতিবাক্য  সর্বতোভাবে গমন করুক।"},{"n":3,"d":"आकरे वसोर्जरिता पनस्यते.अनेहस सतुभ इन्द्रो दुवस्यति | विवस्वतः सदन आ हि पिप्रिये सत्रासाहमभिमातिहनं सतुहि ||","b":"আকরে বসোর্জরিতা পনস্যতে.অনেহস সতুভ ইন্দ্রো দুবস্যতি | বিবস্বতঃ সদন আ হি পিপ্রিযে সত্রাসাহমভিমাতিহনং সতুহি ||","e":"Where battle's spoil is piled the singer winneth praise, for Indra taketh care of matchless worshippers. He in Vivasvān's dwelling findeth his delight: praise thou the ever-conquering slayer of the foe.","mb":"শত্রুগণের বিনাশক ইন্দ্র যুদ্ধে স্তুত হন, তিনি পাপরহিত স্তুতি সকলকে সম্মানিত করেন, তিনি যজমানের গৃহে প্রীত হন। হে বিশ্বামিত্র! মরুৎগণের সাথে অভিভবিতা শত্রুহন্তা ইন্দ্রকে স্তব কর।"},{"n":4,"d":"नर्णामु तवा नर्तमं गीर्भिरुक्थैरभि पर वीरमर्चता सबाधः | सं सहसे पुरुमायो जिहीते नमो अस्य परदिव एक ईशे ||","b":"নর্ণামু তবা নর্তমং গীর্ভিরুক্থৈরভি পর বীরমর্চতা সবাধঃ | সং সহসে পুরুমাযো জিহীতে নমো অস্য পরদিব এক ঈশে ||","e":"Thee, valorous, most heroic of the heroes, shall the priests glorify with songg and praises. Full of all wondrous power he goes to conquest: worship is his, sole Lord from days aforetime.","mb":"হে ইনদ্র! তুমি মনুষ্যগণের নেতা ও বীর, বাধাপ্রাপ্ত ঋত্বিকগণ তোমাকে স্তুতিদ্বারা ও উকথদ্বারা বিশেষরূপে অর্চনা করে। বহু কর্মবিশিষ্ট ইন্দ্র বলের জন্য গমনোদ্যম করেন, পুরাতন এক মাত্র ইন্দ্র এ অন্নের ঈশ্বর, তাকে নমস্কার।"},{"n":5,"d":"पूर्वीरस्य निष्षिधो मर्त्येषु पुरू वसूनि पर्थिवी बिभर्ति | इन्द्राय दयाव ओषधीरुतापो रयिं रक्षन्ति जीरयो वनानि ||","b":"পূর্বীরস্য নিষ্ষিধো মর্ত্যেষু পুরূ বসূনি পর্থিবী বিভর্তি | ইন্দ্রায দযাব ওষধীরুতাপো রযিং রক্ষন্তি জীরযো বনানি ||","e":"Abundant are the gifts he gives to mortals: for him the earth bears a rich store of treasures. The heavens, the growing plants, the living waters, the forest trees preserve their wealth for Indra.","mb":"মানুষগণের মধ্যে ইন্দ্রের অনুশাসন নানা প্রকার। ইন্দ্রের অনুশাসনক্রমে পৃথিবী বহু ধন ধারণ করে, দ্যুলোক, ওষধি, জল, মনুষ্য, বন ও বৃক্ষ ধন রক্ষা করে।"},{"n":6,"d":"तुभ्यं बरह्माणि गिर इन्द्र तुभ्यं सत्रा दधिरे हरिवो जुषस्व | बोध्यापिरवसो नूतनस्य सखे वसो जरित्र्भ्यो वयोधाः ||","b":"তুভ্যং বরহ্মাণি গির ইন্দ্র তুভ্যং সত্রা দধিরে হরিবো জুষস্ব | বোধ্যাপিরবসো নূতনস্য সখে বসো জরিত্র্ভ্যো বযোধাঃ ||","e":"To thee, O Indra, Lord of Bays, for ever are offered prayers and songs: accept them gladly. As Kinsman think thou of some fresh assistance; good Friend, give strength and life to those who praise thee.","mb":"হে অশ্ববান ইন্দ্র! ঋত্বিকগণ তোমার জন্য স্তোত্র, তোমার জন্য  শস্ত্র যথার্থই ধারণ করছেন, তা গ্রহণ কর। হে নিরাসয়িতা সখিভূত ইন্দ্র! তুমি ব্যাপ্ত, তুমি নূতন অন্ন গ্রহণ কর, স্তোতাকে অন্ন দান কর। হে মরুৎগণযুক্ত ইন্দ্র! তুমি যেরূপ শর্যাতির পুত্রের অভিযুত সোম পনা করেছিলেন, সেরূপ এ যজ্ঞে সোম পান কর। হে শুর! তৈয়ার নির্বাধ স্থানে স্থিত সুন্দর যজ্ঞ বিশিষ্ট কবিগণ হব্যদ্বারা পরিচর্যা করে।"},{"n":7,"d":"इन्द्र मरुत्व इह पाहि सोमं यथा शार्याते अपिबः सुतस्य | तव परणीती तव शूर शर्मन्ना विवासन्ति कवयःसुयज्ञाः ||","b":"ইন্দ্র মরুত্ব ইহ পাহি সোমং যথা শার্যাতে অপিবঃ সুতস্য | তব পরণীতী তব শূর শর্মন্না বিবাসন্তি কবযঃসুযজ্ঞাঃ ||","e":"Here, Indra, drink thou Soma with the Maruts, as thou didst drink the juice beside Śāryāta. Under thy guidance, in thy keeping, Hero, the singers serve, skilled in fair sacrifices.","mb":"হে ইন্দ্র, মরুৎদের সাথে এখানে সোমপান করো, যেমন তুমি শার্যাতের পাশে রসপান করেছিলে। তোমার নেতৃত্বে, তোমার রক্ষায়, হে শূর, কবিরা সেবা করেন, সুষ্ঠু যজ্ঞে দক্ষ।"},{"n":8,"d":"स वावशान इह पाहि सोमं मरुद्भिरिन्द्र सखिभिः सुतं नः | जातं यत तवा परि देवा अभूषन महे भराय पुरुहूत विश्वे ||","b":"স বাবশান ইহ পাহি সোমং মরুদ্ভিরিন্দ্র সখিভিঃ সুতং নঃ | জাতং যত তবা পরি দেবা অভূষন মহে ভরায পুরুহূত বিশ্বে ||","e":"So eagerly desirous drink the Soma, our juice, O Indra, with thy friends the Maruts, Since at thy birth all Deities adorned thee for the great fight, O thou invoked of many.","mb":"হে মরুৎগণ! ইনি জল প্রেরণ বিষয়ে তোমাদের সখা। বলদাতা মরুৎগণ ইন্দ্রকে হৃষ্ট করেছিলেন। বৃত্তহন্তা তাদের সাথে  যজমানের গৃহে অভিষুত সোম পান করুন।"},{"n":9,"d":"अप्तूर्ये मरुत आपिरेषो.अमन्दन्निन्द्रमनु दातिवाराः | तेभिः साकं पिबतु वर्त्रखादः सुतं सोमं दाशुषः सवे सधस्थे ||","b":"অপ্তূর্যে মরুত আপিরেষো.অমন্দন্নিন্দ্রমনু দাতিবারাঃ | তেভিঃ সাকং পিবতু বর্ত্রখাদঃ সুতং সোমং দাশুষঃ সবে সধস্থে ||","e":"He was your comrade in your zeal, O Maruts: they, rich in noble gifts, rejoiced in Indra. With them together let the Vṛtra-slayer drink in his home the worshipper's libation.","mb":"তিনি ছিলেন তোমাদের সহচর তোমাদের উৎসাহে, হে মরুৎগণ: তাঁরা মহান দানে সমৃদ্ধ হয়ে ইন্দ্রে আনন্দিত হলেন। তাঁদের সাথে বৃত্রহন্তা নিজ গৃহে উপাসকের সোমাহুতি পান করুন।"},{"n":10,"d":"इदं हयन्वोजसा सुतं राधानां पते | पिबा तवस्य गिर्वणः ||","b":"ইদং হযন্বোজসা সুতং রাধানাং পতে | পিবা তবস্য গির্বণঃ ||","e":"So, Lord of affluent gifts, this juice hath been pressed for thee with strength Drink of it, thou who lovest song.","mb":"হে ধনপতি স্তুতিপ্রিয় ইন্দ্র! তুমি এ উদ্দেশানুক্রমে বল দ্বারা অভিষুত সোম শীঘঞ্র পান কর।"},{"n":11,"d":"यस्ते अनु सवधामसत सुते नि यछ तन्वम | स तवा ममत्तु सोम्यम ||","b":"যস্তে অনু সবধামসত সুতে নি যছ তন্বম | স তবা মমত্তু সোম্যম ||","e":"Incline thy body to this juice which suits thy Godlike nature well: May it cheer thee who lovest it.","mb":"হে ইন্দ্র! তোমার অন্নের জন্য যে সোম অভিষুত হয়েছে, সে অভিষুত সোমে শরীর নিমগ্ন কর। তুমি সোমার্হ, সোম তোমাকে হৃষ্ট করুক।"},{"n":12,"d":"पर ते अश्नोतु कुक्ष्योः परेन्द्र बरह्मणा शिरः | पर बाहू शूर राधसे ||","b":"পর তে অশ্নোতু কুক্ষ্যোঃ পরেন্দ্র বরহ্মণা শিরঃ | পর বাহূ শূর রাধসে ||","e":"Brave Indra, let it work through both thy flanks, and through thy head by prayer, And through thine arms, to prosper us.","mb":"হে ইন্দ্র! এ তোমার কুক্ষিদ্বয়ে ব্যাপ্ত হোক, এ স্তোত্রের সাথে তোমার শরীর ব্যাপ্ত হোক; হে শুর! ধনদানের জন্য এ তোমার বাহুদ্বয়ে ব্যাপ্ত হোক।"}]},{"n":52,"t":"Indra","v":[{"n":1,"d":"धानावन्तं करम्भिणमपूपवन्तमुक्थिनम | इन्द्र परातर्जुषस्व नः ||","b":"ধানাবন্তং করম্ভিণমপূপবন্তমুক্থিনম | ইন্দ্র পরাতর্জুষস্ব নঃ ||","e":"INDRA, accept at break of day our Soma mixt with roasted corn, With groats with cake, with eulogies.","mb":"হে ইন্দ্র! ভুষ্ট যবযুক্ত, সক্তযুক্ত, পিষ্টকযুক্ত ও উকথবিশিষ্ট আমাদের সোম প্রাত:সবনে গ্রহণ কর।"},{"n":2,"d":"पुरोळाशं पचत्यं जुषस्वेन्द्रा गुरस्व च | तुभ्यं हव्यानि सिस्रते ||","b":"পুরোলাশং পচত্যং জুষস্বেন্দ্রা গুরস্ব চ | তুভ্যং হব্যানি সিস্রতে ||","e":"Accept, O Indra, and enjoy the well-dressed sacrificial cake: Oblations are poured forth to thee.","mb":"হে ইন্দ্র! পক পুরোডাশ গ্রহণ কর, ভক্ষণে উদ্যম কর, তোমার উদ্দেশে হব্য সকল যাচ্ছে।"},{"n":3,"d":"पुरोळाशं च नो घसो जोषयासे गिरश्च नः | वधूयुरिव योषणाम ||","b":"পুরোলাশং চ নো ঘসো জোষযাসে গিরশ্চ নঃ | বধূযুরিব যোষণাম ||","e":"Consume our sacrificial cake, accept the songs of praise we sing, As he who woes accepts his bride.","mb":"তুমি আমাদের পুরোডাশ ভক্ষণ কর এবং স্ত্রৈণ ব্যক্তি যেরূপ যুবতীকে সেবা করে, সেরূপ তুমি আমাদের স্তুতি সেবা কর।"},{"n":4,"d":"पुरोळाशं सनश्रुत परातःसावे जुषस्व नः | इन्द्र करतुर्हि ते बर्हन ||","b":"পুরোলাশং সনশ্রুত পরাতঃসাবে জুষস্ব নঃ | ইন্দ্র করতুর্হি তে বর্হন ||","e":"Famed from of old, accept the cake at our libation poured at dawn, Forgreat, O Indra, is thy power.","mb":"হে প্রাচীন কাল হতে প্রসিদ্ধ ইন্দ্র! তুমি প্রাত:সবনে আমাদের পুরোডাশ গ্রহণ কর, কারণ তোমার কর্ম মহৎ।"},{"n":5,"d":"माध्यन्दिनस्य सवनस्य धानाः पुरोळाशमिन्द्र कर्ष्वेहचारुम | पर यत सतोता जरिता तूर्ण्यर्थो वर्षायमाण उप गीर्भिरीट्टे ||","b":"মাধ্যন্দিনস্য সবনস্য ধানাঃ পুরোলাশমিন্দ্র কর্ষ্বেহচারুম | পর যত সতোতা জরিতা তূর্ণ্যর্থো বর্ষাযমাণ উপ গীর্ভিরীট্টে ||","e":"Let roasted corn of our midday libation, and sacrificial cake here please thee, Indra, What time the lauding singer, keen of purpose and eager as a bull, with hymns implores thee.","mb":"হে ইন্দ্র! সে সময়ে পরিচর্যাকারী চঞ্চলগতি, অতএব বৃষের ন্যায় আচরণকারী স্তোতা মন্ত্রদ্বারা তোমাকে প্রকর্যরূপে স্তুতি করে, সে মাধ্যন্দিন সবনের ভূষ্ট যব ও কমনীয় পুরোডাশ এ যজ্ঞে ভক্ষণ দ্বারা সংস্কৃত কর।"},{"n":6,"d":"तर्तीये धानाः सवने पुरुष्टुत पुरोळाशमाहुतं मामहस्व नः | रभुमन्तं वाजवन्तं तवा कवे परयस्वन्त उप शिक्षेम धीतिभिः ||","b":"তর্তীযে ধানাঃ সবনে পুরুষ্টুত পুরোলাশমাহুতং মামহস্ব নঃ | রভুমন্তং বাজবন্তং তবা কবে পরযস্বন্ত উপ শিক্ষেম ধীতিভিঃ ||","e":"At the third sacrifice, O thou whom many praise, give glory to the roasted corn and holy cake. With offered viands and with songs may we assist thee, Sage, whom Vāja and the Ṛbhus wait upon.","mb":"হে বহুস্তোতৃগণস্তুত ইন্দ্র! তৃতীয় সবনে আমাদের হূত ভুষ্টযব ও পুরোডাশ ভক্ষণদ্বারা সম্মানিত কর। আমরা হব্য বিশিষ্ট হয়ে ঋভুযুক্ত ও বাজযুক্ত হয়ে কবি ইন্দ্রকে স্তুতিদ্বারা পরিচর্যা করব।"},{"n":7,"d":"पूषण्वते ते चक्र्मा करम्भं हरिवते हर्यश्वाय धानाः | अपूपमद्धि सगणो मरुद्भिः सोमं पिब वर्त्रहा शूर विद्वान ||","b":"পূষণ্বতে তে চক্র্মা করম্ভং হরিবতে হর্যশ্বায ধানাঃ | অপূপমদ্ধি সগণো মরুদ্ভিঃ সোমং পিব বর্ত্রহা শূর বিদ্বান ||","e":"The groats have we prepared for thee with Pūṣan, corn for thee, Lord of Bay Steeds, with thy horses. Eat thou the meal-cake, banded with the Maruts, wise Hero, Vṛtra-slayer, drink the Soma.","mb":"আমরা পুষার সাথে যুক্ত হয়ে ইন্দ্র রজন্য দীধমিশ্রিত সক্তু প্রস্তুত করেছি। আমরা অশ্বযুক্ত ইন্দ্রের জন্য ভুষ্ট যব প্রস্তুত করেছি। হে ইন্দ্র! মরুৎ গণের সঙ্গে যুক্ত হয়ে পিষ্টক ভক্ষণ কর। হে শুর বৃত্রহন্তা বিদ্বান ইন্দ্র! তুমি সোম পান কর।"},{"n":8,"d":"परति धाना भरत तूयमस्मै पुरोळाशं वीरतमाय नर्णाम | दिवे-दिवे सद्र्शीरिन्द्र तुभ्यं वर्धन्तु तवा सोमपेयाय धर्ष्णो ||","b":"পরতি ধানা ভরত তূযমস্মৈ পুরোলাশং বীরতমায নর্ণাম | দিবে-দিবে সদ্র্শীরিন্দ্র তুভ্যং বর্ধন্তু তবা সোমপেযায ধর্ষ্ণো ||","e":"Bring forth the roasted corn to meet him quickly, cake for the bravest Hero mid the heroes. Indra, may hymns accordant with thee daily strengthen thee, Bold One, for the draught of Soma.","mb":"একে শীঘ্র ভুষ্ট যব প্রদান কর। ইনি নেতাগণের মধ্যে শ্রেষ্ঠবীর, একে পুরোডাশ প্রদান কর। হে অভিভবিতা ইন্দ্র! তোমার উদ্দেশে প্রত্যহ একবিধ স্তুতি করা হয়ে থাকে, এ সোম পানের জন্য তোমাকে প্রোৎসাহিত করুক।"}]},{"n":53,"t":"Indra, Parvata, Others","v":[{"n":1,"d":"इन्द्रापर्वता बर्हता रथेन वामीरिष आ वहतं सुवीराः | वीतं हव्यान्यध्वरेषु देवा वर्धेथां गीर्भीरिळया मदन्ता ||","b":"ইন্দ্রাপর্বতা বর্হতা রথেন বামীরিষ আ বহতং সুবীরাঃ | বীতং হব্যান্যধ্বরেষু দেবা বর্ধেথাং গীর্ভীরিলযা মদন্তা ||","e":"ON a high car, O Parvata and Indra, bring pleasant viands, with brave heroes, hither. Enjoy the gifts, Gods, at our sacrifices wax strong by hymns, rejoice in our oblation.","mb":"হে ইন্দ্র ও পর্জন্য! তোমরা বৃহৎ রথে মনোহর সুন্দর পুত্রবিশিষ্ট অন্ন আনয়ন কর। হে দ্যোতমান! তোমরা যজ্ঞে হব্য ভক্ষণ কর, হব্যদ্বারা হৃষ্ট স্তুতি দ্বারা বর্ধিত হও।"},{"n":2,"d":"तिष्ठा सु कं मघवन मा परा गाः सोमस्य नु तवा सुषुतस्य यक्षि | पितुर्न पुत्रः सिचमा रभे त इन्द्र सवादिष्ठया गिरा शचीवः ||","b":"তিষ্ঠা সু কং মঘবন মা পরা গাঃ সোমস্য নু তবা সুষুতস্য যক্ষি | পিতুর্ন পুত্রঃ সিচমা রভে ত ইন্দ্র সবাদিষ্ঠযা গিরা শচীবঃ ||","e":"Stay still, O Maghavan, advance no farther. a draught of well-pressed Soma will I give thee. With sweetest song I grasp, O Mighty Indra, thy garment's hem as a child grasps his father's.","mb":"হে মঘবন! এ যজ্ঞে কিছু কাল সুখে অবস্থান কর, চলে  যেও না। যেহেতু সুন্দররূপে অভিষুত সোম দ্বারা আমি তোমার  যাগ করছি। হে শক্তিমান! পুত্র যেরূপ বাক্যে পিতার বস্ত্রপ্রান্ত গ্রহণ করে, আমি সেরূপ সুমধুর স্তুতিদ্বারা তোমার বস্ত্রপ্রান্ত গ্রহণ করছি।"},{"n":3,"d":"शंसावाध्वर्यो परति मे गर्णीहीन्द्राय वाहः कर्णवाव जुष्टम | एदं बर्हिर्यजमानस्य सीदाथा च भूदुक्थमिन्द्राय शस्तम ||","b":"শংসাবাধ্বর্যো পরতি মে গর্ণীহীন্দ্রায বাহঃ কর্ণবাব জুষ্টম | এদং বর্হির্যজমানস্য সীদাথা চ ভূদুক্থমিন্দ্রায শস্তম ||","e":"Adhvaryu, sing we both; sing thou in answer: make we a laud acceptable to Indra. Upon this sacrificer's grass he seated: to Indra shall our eulogy be uttered.","mb":"হে অধুর্যু আমরা দুজনে স্তুতি করব, তুমি আমাকে উত্তর দান কর। আমসরা দুজনে ইন্দ্রের উদ্দেশে প্রীতিযুক্ত স্তোত্র করব। তুমি যজমানের কুশোপরি উপবেশন কর। ইন্দ্রের উদ্দেশে উকথ প্রশস্ত হোক।"},{"n":4,"d":"जायेदस्तं मघवन सेदु योनिस्तदित तवा युक्ता हरयो वहन्तु | यदा कदा च सुनवाम सोममग्निष टवा दूतो धन्वात्यछ ||","b":"জাযেদস্তং মঘবন সেদু যোনিস্তদিত তবা যুক্তা হরযো বহন্তু | যদা কদা চ সুনবাম সোমমগ্নিষ টবা দূতো ধন্বাত্যছ ||","e":"A wife, O Maghavan is home and dwelling: so let thy Bay Steeds yoked convey thee hither. Whenever we press out for thee the Soma, let Agni as our Herald speed to call thee.","mb":"হে মঘবন! জায়াই গৃহ, জায়াই সন্তানোৎপাদয়িত্রী। যোজিত অশ্বিদ্বয় তোমাকে সেখানে নিয়ে যাক। আমরা যে কোন সময়ে সোম অভিষুত করব, সে সময়েই যেন দূত অগ্নি তোমার নিকট যায়।"},{"n":5,"d":"परा याहि मघवन्ना च याहीन्द्र भरातरुभयत्रा ते अर्थम | यत्रा रथस्य बर्हतो निधानं विमोचनं वाजिनो रासभस्य ||","b":"পরা যাহি মঘবন্না চ যাহীন্দ্র ভরাতরুভযত্রা তে অর্থম | যত্রা রথস্য বর্হতো নিধানং বিমোচনং বাজিনো রাসভস্য ||","e":"Depart, O Maghavan;again come hither: both there and here thy goat is Indra, Brother, Where thy tall chariot hath a place to rest in, and where thqu loosest thy loud-neighing Courser.","mb":"হে মঘবন! স্বগৃহে চলে যাও অথবা এই যজ্ঞে এস। হে ভ্রাতা! উভয় স্থলেই তোমার প্রয়োজন আছে (১)। গৃহে গমনের জন্য মহৎ রথোপরি অবস্থান কর অথবা হ্রেষারবকারী অশ্বকে বিমুক্ত করে এ যজ্ঞে অবস্থান কর।"},{"n":6,"d":"अपाः सोममस्तमिन्द्र पर याहि कल्याणीर्जया सुरणंग्र्हे ते | यत्रा रथस्य बर्हतो निधानं विमोचनं वाजिनोदक्षिणावत ||","b":"অপাঃ সোমমস্তমিন্দ্র পর যাহি কল্যাণীর্জযা সুরণংগ্র্হে তে | যত্রা রথস্য বর্হতো নিধানং বিমোচনং বাজিনোদক্ষিণাবত ||","e":"Thou hast drunk Soma, Indra, turn thee homeward; thy joy is in thy home, thy racious Consort; Where thy tall chariot hath a place to rest in, and thy strong Courser is set free with guerdon.","mb":"হে ইন্দ্র! সোম পান কর, তারপরে গৃহে যাও, তোমার গৃহে কল্যাণকারিণী জায়া ও সুন্দর ধ্বনি আছে, গৃহ গমনের জন্য মহৎ রথোপরি অবস্থান কর, অথবা অশ্বকে বিমুক্ত করে এ যজ্ঞে অবস্থান কর।"},{"n":7,"d":"इमे भोजा अङगिरसो विरूपा दिवस पुत्रासो असुरस्य वीराः | विश्वामित्राय ददतो मघानि सहस्रसावे पर तिरन्त आयुः ||","b":"ইমে ভোজা অঙগিরসো বিরূপা দিবস পুত্রাসো অসুরস্য বীরাঃ | বিশ্বামিত্রায দদতো মঘানি সহস্রসাবে পর তিরন্ত আযুঃ ||","e":"Bounteous are these, Aṅgirases, Virupas: the Asura's Heroes and the Sons of Heaven. They, giving store of wealth to Viśvāmitra, prolong his life through countless Soma-pressings.","mb":"এ ভোজগণ, বিরূপ অঙ্গিরাগণ অপেক্ষা অসুর আকাশের বীর পুত্রগণ বিশ্বামিত্রকে সহস্রসুষজ্ঞে ধনদান করে তার জীবন বর্ধিত করুন।"},{"n":8,"d":"रूपं-रूपं मघवा बोभवीति मायाः कर्ण्वानस्तन्वं परि सवाम | तरिर्यद दिवः परि मुहूर्तमागात सवैर्मन्त्रैरन्र्तुपा रतावा ||","b":"রূপং-রূপং মঘবা বোভবীতি মাযাঃ কর্ণ্বানস্তন্বং পরি সবাম | তরির্যদ দিবঃ পরি মুহূর্তমাগাত সবৈর্মন্ত্রৈরন্র্তুপা রতাবা ||","e":"Maghavan weareth every shape at pleasure, effecting magic changes in his body, Holy One, drinker out of season, coming thrice, in a moment, through fit prayers, from heaven.","mb":"মঘবা স্বকীয় শরীর হতে মায়া করে ভিন্ন ভিন্ন রূপ ধারণ করেন।  তিনি  ঋতবান হলেও অঋতুতে সোম পান করেন। তিনি স্বকীয় স্তুতি দ্বারা আহূত হয়ে স্বর্গলোক হতে মুহুর্তমধ্যে সবনত্রয়ে যান।"},{"n":9,"d":"महान रषिर्देवजा देवजूतो.अस्तभ्नात सिन्धुमर्णवं नर्चक्षाः | विश्वामित्रो यदवहत सुदासमप्रियायत कुशिकेभिरिन्द्रः ||","b":"মহান রষির্দেবজা দেবজূতো.অস্তভ্নাত সিন্ধুমর্ণবং নর্চক্ষাঃ | বিশ্বামিত্রো যদবহত সুদাসমপ্রিযাযত কুশিকেভিরিন্দ্রঃ ||","e":"The mighty sage, God-born and God-incited, who looks on men, restrained the billowy river. When Viśvāmitra was Sudās's escort, then Indra through the Kuśikas grew friendly.","mb":"বিশ্বামিত্র মহজান ও ঋষি, তিনি দেবের জনয়িতা ও দেবকর্তৃক আকৃষ্ট এবং নেতৃগণের উপদেশক; তিনি জলবিশিষ্ট সিন্ধুর  বেগ নিরুদ্ধ করেছিলেন। তিনি সুদাস রাজাকে তাড়না করেছিলেন, (২) এবং ইন্দ্রকে কুশিকবংশীয়দের প্রিয় করেছিলেন।"},{"n":10,"d":"हंसा इव कर्णुथ शलोकमद्रिभिर्मदन्तो गीर्भिरध्वरे सुते सचा | देवेभिर्विप्रा रषयो नर्चक्षसो वि पिबध्वं कुशिकाः सोम्यं मधु ||","b":"হংসা ইব কর্ণুথ শলোকমদ্রিভির্মদন্তো গীর্ভিরধ্বরে সুতে সচা | দেবেভির্বিপ্রা রষযো নর্চক্ষসো বি পিবধ্বং কুশিকাঃ সোম্যং মধু ||","e":"Like swans, prepare a song of praise with pressing-stones, glad in your hymns with juice poured forth in sacrifice. Ye singers, with the Gods, sages who look on men, ye Kutikas drink up the Soma's savoury meath.","mb":"হে মেধাবী, নেতৃগণের উপদেশক কুশিকগণ! প্রস্তর দ্বারা সোম অভিষুত হলে পরে তোমরা স্তুতিদ্বারা দেবগণকে হৃষ্ট করে শব্দায়মান হংসের ন্যায় মন্ত্র উচ্চারণ কর, দেবগণের সাথে মধুর"},{"n":11,"d":"उप परेत कुशिकाश्चेतयध्वमश्वं राये पर मुञ्चता सुदासः | राजा वर्त्रं जङघनत परागपागुदगथा यजाते वर आ पर्थिव्याः ||","b":"উপ পরেত কুশিকাশ্চেতযধ্বমশ্বং রাযে পর মুঞ্চতা সুদাসঃ | রাজা বর্ত্রং জঙঘনত পরাগপাগুদগথা যজাতে বর আ পর্থিব্যাঃ ||","e":"Come forward, Kuśikas, and be attentive; let loose Sudās's horse to win him riches. East, west, and north, let the King slay the foeman, then at earth's choicest place perform his worship.","mb":"হে কুশিকগণ! তোমরা অশ্বের সমীপে যাও, অশ্বকে উত্তেজিত কর, ধনের জন্য সুদাসের অশ্বকে ছেড়ে  দাও। রাজা ইন্দ্র বৃত্তকে পূর্ব পশ্চিম ও উত্তর দেশে বধ করেছেন, অতএব সুদাস রাজা পৃথিবীর উত্তম স্থানে যজ্ঞ করুন।"},{"n":12,"d":"य इमे रोदसी उभे अहमिन्द्रमतुष्टवम | विश्वामित्रस्यरक्षति बरह्मेदं भारतं जनम ||","b":"য ইমে রোদসী উভে অহমিন্দ্রমতুষ্টবম | বিশ্বামিত্রস্যরক্ষতি বরহ্মেদং ভারতং জনম ||","e":"Praises to Indra have I sung, sustainer of this earth and heaven. This prayer of Viśvāmitra keeps secure the race of Bharatas.","mb":"আমি দ্যাবাপৃথিবীদ্বারা ইন্দ্রকে জস্তব করিয়েছি, বিশ্বামিত্রের এ স্তোত্র ভারতলোকদের রক্ষা করুক। (৩)"},{"n":13,"d":"विश्वामित्रा अरासत बरह्मेन्द्राय वज्रिणे | करदिन नः सुराधसः ||","b":"বিশ্বামিত্রা অরাসত বরহ্মেন্দ্রায বজ্রিণে | করদিন নঃ সুরাধসঃ ||","e":"The Viśvāmitras have sung forth this prayer to Indra Thunder-aimed: So let him make us prosperous.","mb":"বিশ্বামিত্র বংশীয়েরা বজ্রহস্ত ইন্দ্রকে স্তুতি করেছে, তিনি আমাদের ধনাঢ্য করুন।"},{"n":14,"d":"किं ते कर्ण्वन्ति कीकटेषु गावो नाशिरं दुह्रे न तपन्तिघर्मम | आ नो भर परमगन्दस्य वेदो नैचाशाखं मघवन्रन्धया नः ||","b":"কিং তে কর্ণ্বন্তি কীকটেষু গাবো নাশিরং দুহ্রে ন তপন্তিঘর্মম | আ নো ভর পরমগন্দস্য বেদো নৈচাশাখং মঘবন্রন্ধযা নঃ ||","e":"Among the Kikatas what do thy cattle? They pour no milky draught, they heat no caldron. Bring thou to us the wealth of Pramaganda;give up to us, O Maghavan, the low-born.","mb":"কীকট সমূহের মধ্যে গাভী সকল তোমার কি করবে? ওরা সোমের সাথে মিশ্রিত হবার যোগ্য দুগ্ধ দান করে না, দুগ্ধ প্রদান দ্বারা পাত্রকেও দীপ্ত করে না। ওদের আমাদরে নিকট  আন, প্রমগন্দের ধন আন (৪)। হে মঘবন! নীচবংশীয়দের ধন আমাদের প্রদান কর।"},{"n":15,"d":"ससर्परीरमतिं बाधमाना बर्हन मिमाय जमदग्निदत्ता | आ सूर्यस्य दुहिता ततान शरवो देवेष्वम्र्तमजुर्यम ||","b":"সসর্পরীরমতিং বাধমানা বর্হন মিমায জমদগ্নিদত্তা | আ সূর্যস্য দুহিতা ততান শরবো দেবেষ্বম্র্তমজুর্যম ||","e":"Sasarpari, the gift of Jamadagnis, hath lowed with mighty voice dispelling famine. The Daughter of the Sun hath spread our glory among the Gods, imperishable, deathless.","mb":"জমদগ্নি দত্তা সসর্পরী (৫) অজ্ঞানকে বাধাদান করে আকাশে প্রভূত শব্দ করছেন। সূর্যের দুহিতা দেবগণের নিকট ক্ষয়রহিত অমৃতরূপ অন্ন বিস্তার করেছেন।"},{"n":16,"d":"ससर्परीरभरत तूयमेभ्यो.अधि शरवः पाञ्चजन्यासु कर्ष्टिषु | सा पक्ष्या नव्यमायुर्दधाना यां मे पलस्तिजमदग्नयो ददुः ||","b":"সসর্পরীরভরত তূযমেভ্যো.অধি শরবঃ পাঞ্চজন্যাসু কর্ষ্টিষু | সা পক্ষ্যা নব্যমাযুর্দধানা যাং মে পলস্তিজমদগ্নযো দদুঃ ||","e":"Sasarpari brought glory speedily to these, over the generations of the Fivefold Race; Daughter of Paksa, she bestows new vital power, she whom the ancient Jamadagnis gave to me.","mb":"পঞ্চশ্রেণী লোকের মধ্যে যে অন্ন  আছে, সসর্পরী শীঘ্র তা আমাদের অধিক পমিাণে দান করুন। বুদ্ধ জমদগ্নিগণ আমাদের যে পক্ষ্যা দান করেছেন, সে সূর্য দুহিতা নুতন অন্ন দান করুন।"},{"n":17,"d":"सथिरौ गावौ भवतां वीळुरक्षो मेषा वि वर्हि मा युगं वि शारि | इन्द्रः पातल्ये ददतां शरीतोररिष्टनेमे अभि नः सचस्व ||","b":"সথিরৌ গাবৌ ভবতাং বীলুরক্ষো মেষা বি বর্হি মা যুগং বি শারি | ইন্দ্রঃ পাতল্যে দদতাং শরীতোররিষ্টনেমে অভি নঃ সচস্ব ||","e":"Strong be the pair of oxen, firm the axles, let not the pole slip nor the yoke be broken. May Indra, keep the yoke-pins from decaying: attend us, thou whose fellies are uninjured.","mb":"গোদ্বয় স্থির হোক, দন্ড যেন বিনষ্ট না হয়, যুগ যেন বিশীর্ণ না হয়। ইন্দ্র কীলদ্বয়কে বিশীর্ণ হবার পূর্বে ধারণ করুন, হে অহিংসিত নেমিবিশিষ্ট রথ! তুমি আমাদের অভিমুখে এস (৬)।"},{"n":18,"d":"बलं धेहि तनूषु नो बलमिन्द्रानळुत्सु नः | बलं तोकाय तनयाय जीवसे तवं हि बलदा असि ||","b":"বলং ধেহি তনূষু নো বলমিন্দ্রানলুত্সু নঃ | বলং তোকায তনযায জীবসে তবং হি বলদা অসি ||","e":"O Indra, give our bodies strength, strength to the bulls who draw the wains, Strength to our seed and progeny that they may live, for thou art he who giveth strength.","mb":"হে ইন্দ্র! আমাদের শরীরে বল দান কর, আমাদের আমাদের বলীবর্দ দানকে বল দান কর। আমাদের পুত্রপৌত্রগণকে চিরজীবী হবা রজন্য বল দান কর। কারণ তুমি বলপ্রদ।"},{"n":19,"d":"अभि वययस्व खदिरस्य सारमोजो धेहि सपन्दने शिंशपायाम | अक्ष वीळो वीळित वीळयस्व मा यामादस्मादव जीहिपो नः ||","b":"অভি বযযস্ব খদিরস্য সারমোজো ধেহি সপন্দনে শিংশপাযাম | অক্ষ বীলো বীলিত বীলযস্ব মা যামাদস্মাদব জীহিপো নঃ ||","e":"Enclose thee in the heart of Khayar timber, in the car wrought of Sinsapa put firmness. Show thyself strong, O Axle, fixed and strengthened: throw us not from the car whereon we travel.","mb":"রথের খদির কাষ্ঠের সারকে দৃঢ় কর রথের শিশস্পা কাষ্ঠকে দৃঢ় কর (৭)। হে দৃঢ় ও আমাদের কর্তৃক দৃঢ়কৃত অক্ষ! দৃঢ় হও, এ রথ হতে আমসাদের ফেলে দিও না। ২০। বনস্পতি এ রথ আমাদের যেন ফেলে না দেয়, যেন আঘাত না করে। আমাদের গৃহগমন পর্যন্ত মঙ্গল হোক। রথের বেগের অবসান পর্যন্ত মঙ্গল হোক, অশ্বগণের বিমোচন পর্যন্ত মঙ্গল হোক"},{"n":20,"d":"अयमस्मान वनस्पतिर्मा च हा मा च रीरिषत | सवस्त्याग्र्हेभ्य आवसा आ विमोचनात ||","b":"অযমস্মান বনস্পতির্মা চ হা মা চ রীরিষত | সবস্ত্যাগ্র্হেভ্য আবসা আ বিমোচনাত ||","e":"Let not this sovran of the wood leave us forlorn or injure us. Safe may we be until we reach our homes and rest us and unyoke.","mb":"এই বনস্পতি আমাদের পরিত্যক্ত বা আহত করবেন না। আমরা গৃহে ফিরে বিশ্রাম নিয়ে রথ খুলে না নেওয়া পর্যন্ত নিরাপদ থাকি।"},{"n":21,"d":"इन्द्रोतिभिर्बहुलाभिर्नो अद्य याच्छ्रेष्ठाभिर्मघवञ्छूर जिन्व | यो नो दवेष्ट्यधरः सस पदीष्ट यमु दविष्मस्तमु पराणो जहातु ||","b":"ইন্দ্রোতিভির্বহুলাভির্নো অদ্য যাচ্ছ্রেষ্ঠাভির্মঘবঞ্ছূর জিন্ব | যো নো দবেষ্ট্যধরঃ সস পদীষ্ট যমু দবিষ্মস্তমু পরাণো জহাতু ||","e":"With various aids this day come to us, Indra, with best aids speed us, Maghavan, thou Hero. Let him who hatcth us fall headlong downward: him whom we hate let vital breath abandon.","mb":"হে শুর ধনবান! আমরা শত্রুহিংসক। আমাদের প্রভূত ও শ্রেষ্ঠ আশ্রয়দান দ্বারা প্রীত কর। যে আমাদের দ্বেষ করে, সে নিকৃষ্ট হয়ে পতিত হোক, আমার যাকে  দ্বেষ করি, প্রাণবায়ু তাকে পরিত্যাগ করুক।"},{"n":22,"d":"परशुं चिद वि तपति शिम्बलं चिद वि वर्श्चति | उखा चिदिन्द्र येषन्ती परयस्ता फेनमस्यति ||","b":"পরশুং চিদ বি তপতি শিম্বলং চিদ বি বর্শ্চতি | উখা চিদিন্দ্র যেষন্তী পরযস্তা ফেনমস্যতি ||","e":"He heats his very axe, and then cuts a mere Semal blossom off. O Indra, like a caldron cracked and seething, so he pours out foam.","mb":"পরশুদ্বারা বৃক্ষ যেরূপ তাপ প্রাপ্ত হয়, সেরূপ শত্রু তাপ প্রাপ্ত হোক, শিমুল ফুল যেরূপ অনায়াসে বিচ্ছিন্ন হয়, সেরূপ শত্রু বিচ্ছিন্ন শরীর হোক, প্রহত, জলস্রাবী পাকস্থলী যেরূপ ফেন উদগীরণ করে, সেরূপ শত্রু মুখ হতে ফেন উদ্গীরণ করুক।"},{"n":23,"d":"न सायकस्य चिकिते जनासो लोधं नयन्ति पशु मन्यमानाः | नावाजिनं वाजिना हासयन्ति न गर्दभं पुरो अश्वान नयन्ति ||","b":"ন সাযকস্য চিকিতে জনাসো লোধং নযন্তি পশু মন্যমানাঃ | নাবাজিনং বাজিনা হাসযন্তি ন গর্দভং পুরো অশ্বান নযন্তি ||","e":"Men notice not the arrow, O ye people; they bring the red beast deeming it a bullock. A sluggish steed men run not with the courser, nor ever lead an ass before a charger.","mb":"হে জনগণ! তোমরা অবসানকারী বিশ্বামিত্রকে জান না, তপ:ফল লুদ্ধকে পশুবৎ মনে করে নিয়ে যাচ্ছে। প্রাজ্ঞ ব্যক্তি মুর্খব্যক্তিকে হজাস্যাস্পদ করে না (৮) অশ্বের সম্মুখে গর্দ ভকে নিয়ে যায় না।"},{"n":24,"d":"इम इन्द्र भरतस्य पुत्रा अपपित्वं चिकितुर्न परपित्वम | हिन्वन्त्यश्वमरणं न नित्यं जयावाजं परि णयन्त्याजौ ||","b":"ইম ইন্দ্র ভরতস্য পুত্রা অপপিত্বং চিকিতুর্ন পরপিত্বম | হিন্বন্ত্যশ্বমরণং ন নিত্যং জযাবাজং পরি ণযন্ত্যাজৌ ||","e":"These men, the sons of Bhārata, O Indra, regard not severance or close connexion. They urge their own steed as it were another's, and take him, swift as the bow's string, to battle.","mb":"হে ইন্দ্র! ভারতগণ বশিষ্ঠগণের সাথে পার্থক্যই জানে, একতা জানে না। সংগ্রামে তাদরে প্রতি সহজ শত্রুর ন্যায় অশ্ব প্রেরণ করে ধনুক ধারণ করে (৯)।"}]},{"n":54,"t":"Viśvedevas","v":[{"n":1,"d":"इमं महे विदथ्याय शूषं शश्वत कर्त्व ईड्यय पर जभ्रुः | शर्णोतु नो दम्येभिरनीकैः शर्णोत्वग्निर्दिव्यैरजस्रः ||","b":"ইমং মহে বিদথ্যায শূষং শশ্বত কর্ত্ব ঈড্যয পর জভ্রুঃ | শর্ণোতু নো দম্যেভিরনীকৈঃ শর্ণোত্বগ্নির্দিব্যৈরজস্রঃ ||","e":"To him adorable, mighty, meet for synods, this strengthening hymn, unceasing, have they offered. May Agni hear us with his homely splendours, hear us, Eternal One, with heavenly lustre.","mb":"মহান, যজ্ঞে নিষ্পাদ্যমান ও স্তুতিযোগ্য অগ্নির উদ্দেশে সুখকর এ স্তোম বার বার উচ্চারণ করছে। অগ্নি দমনকুশল তেজযুক্ত হয়ে আমাদের স্তুতি শুনুন, নিরন্তর দিব্য তেজযুক্ত হয়ে আমাদরে স্তুতি শুনুন।"},{"n":2,"d":"महि महे दिवे अर्चा पर्थिव्यै कामो म इछञ्चरति परजानन | ययोर्ह सतोमे विदथेषु देवाः सपर्यवो मादयन्ते सचायोः ||","b":"মহি মহে দিবে অর্চা পর্থিব্যৈ কামো ম ইছঞ্চরতি পরজানন | যযোর্হ সতোমে বিদথেষু দেবাঃ সপর্যবো মাদযন্তে সচাযোঃ ||","e":"To mighty Heaven and Earth I sing forth loudly: my wish goes out desirous and well knowing Both, at whose laud in synods, showing favour, the Gods rejoice them with the living mortal.","mb":"মহতী দ্যাবাপৃথিবীর মাহাত্মা জেনে তাদরে অর্চনা কর। আমার মনোরথ তাদের অভিলাষে বিচরণ করছে। পুজাভিলাষী দেবগণ সকল মানুষের যজ্ঞে দ্যাবাপৃথিবীর স্তোত্রে মত্ত হন।"},{"n":3,"d":"युवोर्र्तं रोदसी सत्यमस्तु महे षु णः सुविताय पर भूतम | इदं दिवे नमो अग्ने पर्थिव्यै सपर्यामि परयसा यामि रत्नम ||","b":"যুবোর্র্তং রোদসী সত্যমস্তু মহে ষু ণঃ সুবিতায পর ভূতম | ইদং দিবে নমো অগ্নে পর্থিব্যৈ সপর্যামি পরযসা যামি রত্নম ||","e":"O Heaven and Earth, may your great law he faithful: he ye our leaders for our high advantage. To Heaven and Earth I offer this my homage, with food, O Agni, as I pray for riches.","mb":"হে দ্যাবাপৃথিবী! তোমাদের ঋত যথার্থ হোক। তোমরা আমাদের মহৎ যজ্ঞসমাপ্তি কার্যে সমর্থ হও। হে অগ্নি! দ্যুলোক ও পৃথিবীকে নমস্কার। আমি হব্যদ্বারা পরিচর্যা করছি, আমি উত্তম ধন প্রার্থনা করছি।"},{"n":4,"d":"उतो हि वां पूर्व्या आविविद्र रतावरी रोदसी सत्यवाचः | नरश्चिद वां समिथे शूरसातौ ववन्दिरे पर्थिवि वेविदानाः ||","b":"উতো হি বাং পূর্ব্যা আবিবিদ্র রতাবরী রোদসী সত্যবাচঃ | নরশ্চিদ বাং সমিথে শূরসাতৌ ববন্দিরে পর্থিবি বেবিদানাঃ ||","e":"Yea, holy Heaven and Earth, the ancient sages whose word was ever true had power to find you; And brave men in the fightwhere heroes conquer, O Earth, have known you well and paid you honour.","mb":"হে সত্যযুক্ত দ্যাবাপৃথিবী! পুরাতন সত্যবাদী মহর্ষিগণ তোমাদের নিকট হতে অভিলষিত লাভ করেছিল। হে পৃথিবী! মনুষ্যগণ শুরপরিভবকর যুদ্ধে তোমাদের মাহাত্ম্য জেনে তোমাদের স্তব করে।"},{"n":5,"d":"को अद्धा वेद क इह पर वोचद देवानछा पथ्या का समेति | दद्र्श्र एषामवमा सदांसि परेषु या गुह्येषु वरतेषु ||","b":"কো অদ্ধা বেদ ক ইহ পর বোচদ দেবানছা পথ্যা কা সমেতি | দদ্র্শ্র এষামবমা সদাংসি পরেষু যা গুহ্যেষু বরতেষু ||","e":"What pathway leadeth to the Gods? Who knoweth this of a truth, and who will now declare it? Seen are their lowest dwelling-places only, but they are in remote and secret regions.","mb":"কে সত্যকে জানে? কে তা বলে? কোন পথ দেবতাদরে নিকট নিয়ে যায়? দেবগণের অধ:স্থান অর্থাৎ দ্যুলোক  স্থিত নক্ষত্রাদি দেখা যায়, তা উৎকৃষ্ঠ দুর্জ্ঞেয় ব্রতে অবস্থিতি করে।"},{"n":6,"d":"कविर्न्र्चक्षा अभि षीमचष्ट रतस्य योना विघ्र्ते मदन्ती | नाना चक्राते सदनं यथा वः समानेन करतुना संविदाने ||","b":"কবির্ন্র্চক্ষা অভি ষীমচষ্ট রতস্য যোনা বিঘ্র্তে মদন্তী | নানা চক্রাতে সদনং যথা বঃ সমানেন করতুনা সংবিদানে ||","e":"The Sage who looketh on mankind hath viewed them bedewed, rejoicing in the seat of Order. They make a home as for a bird, though parted, with one same will finding themselves together.","mb":"কবি, মনুষ্যগণের  দ্রষ্টা, সুর্য, এ দ্যাবাপৃথিবীকে সর্বতোভাবে দর্শন করেন। জলের উৎপত্তি স্থান অন্তরীক্ষে হর্ষকারিণী, রসবতী ও সমান কর্ম দ্বারা ঐক্য ভাবাপন্না দ্যাবাপৃথিবী পক্ষীর কুলায়ের ন্যায় নানা স্থান অধিকার করেছেন।"},{"n":7,"d":"समान्या वियुते दूरेन्ते धरुवे पदे तस्थतुर्जागरूके | उत सवसारा युवती भवन्ती आदु बरुवाते मिथुनानि नाम ||","b":"সমান্যা বিযুতে দূরেন্তে ধরুবে পদে তস্থতুর্জাগরূকে | উত সবসারা যুবতী ভবন্তী আদু বরুবাতে মিথুনানি নাম ||","e":"Partners though parted, with far-distant limits, on one firm place both stand for ever watchful, And, being young for evermore, as sisters, speak to each other names that are united.","mb":"সমান কর্ম বিশিষ্টা, বিযুক্তা দূর সীমাযুস্তা ও বিনাশরহিত দ্যাবাপৃথিবী জাগরণশী{ল হয়ে অবিনাশী পদে অন্তরীক্ষে নিত্যতরুণী ভগিনীদ্বয়ের ন্যায় আছেন। তারা দুজনে পরস্পরকে মিথুন নামে ডেকে থাকেন।"},{"n":8,"d":"विश्वेदेते जनिमा सं विविक्तो महो देवान बिभ्रती न वयथेते | एजद धरुवं पत्यते विश्वमेकं चरत पतत्रि विषुणं वि जातम ||","b":"বিশ্বেদেতে জনিমা সং বিবিক্তো মহো দেবান বিভ্রতী ন বযথেতে | এজদ ধরুবং পত্যতে বিশ্বমেকং চরত পতত্রি বিষুণং বি জাতম ||","e":"All living things they part and keep asunder; though bearing up the mighty Gods they reel not. One All is Lord of what is fixed and moving, that walks, that flies, this multiform creation.","mb":"তারা সমস্ত ভূতজাতকে বিভক্ত রে রাখেন এবং মহৎ দেবগণকে ধারণ করেও ব্যাখ্যা পান না। স্থাবরজঙ্গমাত্মক সকলেই এক আধারে অবস্থিতি করে সনস্ত পশুপক্ষী সেখানে আছে।"},{"n":9,"d":"सना पुराणमध्येम्यारान महः पितुर्जनितुर्जामि तन नः | देवासो यत्र पनितार एवैरुरौ पथि वयुते तस्थुरन्तः ||","b":"সনা পুরাণমধ্যেম্যারান মহঃ পিতুর্জনিতুর্জামি তন নঃ | দেবাসো যত্র পনিতার এবৈরুরৌ পথি বযুতে তস্থুরন্তঃ ||","e":"Afar the Ancient from of old I ponder, our kinship with our mighty Sire and Father,— Singing the praise whereof the Gods by custom stand on the spacious far-extended pathway.","mb":"আমি এক্ষণে মহৎ পিতার সে সনাতন পুরাতন জ্ঞতিত্ব চিনতা করি। তার বিস্তীর্ণ নির্জন পথে স্তুতিকারী দেবগণ স্বীয় সবীয় বাহনের সাথে অবস্থান করেন।"},{"n":10,"d":"इमं सतोमं रोदसी पर बरवीम्य रदूदराः शर्णवन्नग्निजिह्वाः | मित्रः सम्राजो वरुणो युवान आदित्यासः कवयः पप्रथानाः ||","b":"ইমং সতোমং রোদসী পর বরবীম্য রদূদরাঃ শর্ণবন্নগ্নিজিহ্বাঃ | মিত্রঃ সম্রাজো বরুণো যুবান আদিত্যাসঃ কবযঃ পপ্রথানাঃ ||","e":"This laud, O Heaven and Earth, to you I utter: let the kind-hearted hear, whose tongue is Agni, Young, Sovran Rulers, Varuṇa and Mitra, the wise and very glorious Ādityas.","mb":"হে দ্যাবাপৃথিবী! আমি এ স্তাম উচ্চারণ করছি। কোমলোদর, অগ্নি জিহ্বাবিশিষ্ট, দীপ্তিমান, নিত্যতরুণ, কবি ও স্বকর্মকীর্তনকারী মিত্র, বরুণ প্রভূতি অদিতি পুত্রগণ শুনুন।"},{"n":11,"d":"हिरण्यपाणिः सविता सुजिह्वस्त्रिरा दिवो विदथे पत्यमानः | देवेषु च सवितः शलोकमश्रेरादस्मभ्यमा सुवसर्वतातिम ||","b":"হিরণ্যপাণিঃ সবিতা সুজিহ্বস্ত্রিরা দিবো বিদথে পত্যমানঃ | দেবেষু চ সবিতঃ শলোকমশ্রেরাদস্মভ্যমা সুবসর্বতাতিম ||","e":"The fair-tongued Savitar, the golden-handed, comes thrice from heaven as Lord in our assembly. Bear to the Gods this song of praise, and send us, then, Savitar, complete and perfect safety.","mb":"সুবর্ণ পাণি, সুবাক সবিতা আকাশ হতে যজ্ঞে সবনত্ত{েয় আসেন। সে সবিতা! তুমি স্তোতাগণের স্তোত্র গ্রহণ কর, তারপরে আমাদের সমস্ত অভিলষিত দান কর।"},{"n":12,"d":"सुक्र्त सुपाणिः सववान रतावा देवस्त्वष्टावसे तानि नोधात | पूषण्वन्त रभवो मादयध्वमूर्ध्वग्रावाणो अध्वरमतष्ट ||","b":"সুক্র্ত সুপাণিঃ সববান রতাবা দেবস্ত্বষ্টাবসে তানি নোধাত | পূষণ্বন্ত রভবো মাদযধ্বমূর্ধ্বগ্রাবাণো অধ্বরমতষ্ট ||","e":"Deft worker, skiful-handed, helpful, holy, may Tvaṣṭar, God, give us these things to aid us, Take your delight, Ye Ṛbhus joined with Pūṣan: ye have prepared the rite with stones adjusted.","mb":"সুকুৎ, সুপাণি, ধনবান, সত্যসংকল্প ত্বষ্টাদের আশ্রয় দানের জন্য আমাদরে সে সকল অভিলষিত দান করুন। হে ঋভুগণ! তোমরা পুষার সাথে যুক্ত হয়ে আমাদরে হৃষ্ট কর, যেহেতু ঋত্বিকগণ প্রস্তর উত্তোলন করে যজ্ঞ করছেন।"},{"n":13,"d":"विद्युद्रथा मरुत रष्टिमन्तो दिवो मर्या रतजाता अयासः | सरस्वती शर्णवन यज्ञियासो धाता रयिं सहवीरं तुरासः ||","b":"বিদ্যুদ্রথা মরুত রষ্টিমন্তো দিবো মর্যা রতজাতা অযাসঃ | সরস্বতী শর্ণবন যজ্ঞিযাসো ধাতা রযিং সহবীরং তুরাসঃ ||","e":"Borne on their flashing car, the spear-armed Maruts, the nimble Youths of Heaven, the Sons of Order, The Holy, and Sarasvatī, shall hear us: ye Mighty, give us wealth with noble offspring.","mb":"বিদ্যুৎ রথযুক্ত, আয়ুধবান, দীপ্তিমান, বিনাশক, যজ্ঞোৎপন্ন, সতত গমনশীল ও যজ্ঞঝার্হ মরুৎগণ ও সরস্বতী আমাদের স্তোত্র শুনুন। হে ত্বরান্বিত মরুৎগণ! তোমরা পুত্রবিশিষ্ট ধন দান কর।"},{"n":14,"d":"विष्णुं सतोमासः पुरुदस्ममर्का भगस्येव कारिणो यामनि गमन | उरुक्रमः ककुहो यस्य पूर्विर्न मर्धन्ति युवतयोजनित्रीः ||","b":"বিষ্ণুং সতোমাসঃ পুরুদস্মমর্কা ভগস্যেব কারিণো যামনি গমন | উরুক্রমঃ ককুহো যস্য পূর্বির্ন মর্ধন্তি যুবতযোজনিত্রীঃ ||","e":"To Viṣṇu rich in marvels, songs And praises shall go as singers on the road of Bhaga,— The Chieftain of the Mighty Stride, whose Mothers, the many young Dames, never disregard him.","mb":"দনের হেতুভূত এ স্তোত্র এবং শস্ত্র সকল এ যজ্ঞেঝর বহুকর্মা বিষ্ণুর নিকট যাক। তিনি উরু বিক্রমী। পূর্বকারীনা, যুবতী মাতাস্বরূপ দিকসকল তাকে লঙ্ঘন করেনা।"},{"n":15,"d":"इन्द्रो विश्वैर्वीर्यैः पत्यमान उभे आ पप्रौ रोदसी महित्वा | पुरन्दरो वर्त्रहा धर्ष्णुषेणः संग्र्भ्या न आ भरा भूरि पश्वः ||","b":"ইন্দ্রো বিশ্বৈর্বীর্যৈঃ পত্যমান উভে আ পপ্রৌ রোদসী মহিত্বা | পুরন্দরো বর্ত্রহা ধর্ষ্ণুষেণঃ সংগ্র্ভ্যা ন আ ভরা ভূরি পশ্বঃ ||","e":"Indra, who rules through all his powers heroic, hath with his majesty filled earth and heaven. Lord of brave hosts, Fort-crusher, Vṛtra-slayer, gather thou up and bring us store of cattle.","mb":"সর্বসামর্থ্যসম্পন্ন ইন্দ্র দ্যাবাপৃথিবী, উভয়কেই, মহিমা দ্বারা পূর্ণ করেছেন। হে ্নদ্রি! তুমি পুরভেদী, বৃত্রহন্তা ও শত্রুজয়শীল সেনাযুক্ত; তুমি পশু সংগ্রহ করে আমাদরে প্রচুর পরিমাণে দান কর।"},{"n":16,"d":"नासत्या मे पितरा बन्धुप्र्छा सजात्यमश्विनोश्चारु नाम | युवं हि सथो रयिदौ नो रयीणां दात्रं रक्षेथे अकवैरदब्धा ||","b":"নাসত্যা মে পিতরা বন্ধুপ্র্ছা সজাত্যমশ্বিনোশ্চারু নাম | যুবং হি সথো রযিদৌ নো রযীণাং দাত্রং রক্ষেথে অকবৈরদব্ধা ||","e":"My Sires are the Nāsatyas, kind tokinsmen: the Aśvins' kinship is a glorious title. For ye are they who give us store of riches: ye guard your gift uncheated by the bounteous.","mb":"হে নাসত্যদ্বয়। তোমরা বন্ধুদের অভিলষিত জিজ্ঞাসা করে থাক, তোমরা আমার পালক হও। অশ্বিদ্বয়ের মিলন কমনীয়।  তোমরা আমাদের উত্তম ধন দান কর। তোমরা অতিরস্কৃত, তোমরা হব্যদাতাকে অনিন্দ্যনীয় কর্ম দ্বারা রক্ষা কর।"},{"n":17,"d":"महत तद वः कवयश्चारु नाम यद ध देव भवथ विश्व इन्द्रे | सख रभुभिः पुरुहूत परियेभिरिमां धियं सातये तक्षता नः ||","b":"মহত তদ বঃ কবযশ্চারু নাম যদ ধ দেব ভবথ বিশ্ব ইন্দ্রে | সখ রভুভিঃ পুরুহূত পরিযেভিরিমাং ধিযং সাতযে তক্ষতা নঃ ||","e":"This is, ye Wise, your great and glorious title, that all ye Deities abide in Indra. Friend, Much-invoked! art thou with thy dear Ṛbhus: fashion ye this our hymn for our advantage.","mb":"হে কবি দেবগণ! তোমাদরে জসে মহৎ কর্ম মনোহজর, যে কর্ম দ্বারা তোমরা সকলে ইন্দ্রলোকে দেবত্ব প্রাপ্ত হয়েছ। হে পুরুহুত ইনদ্র! তুমি ঋভুগণের সাথে সখ্য ভাবাপন্ন। তোমরা এ স্তুতি আমাদের ধন লাভের জন্য স্বীকার কর।"},{"n":18,"d":"अर्यमा णो अदितिर्यज्ञियासो.अदब्धानि वरुणस्य वरतानि | युयोत नो अनपत्यानि गन्तोः परजावान नः पशुमानस्तु गातुः ||","b":"অর্যমা ণো অদিতির্যজ্ঞিযাসো.অদব্ধানি বরুণস্য বরতানি | যুযোত নো অনপত্যানি গন্তোঃ পরজাবান নঃ পশুমানস্তু গাতুঃ ||","e":"Aryaman, Aditi deserve our worship: the laws of Varuṇa remain unbroken. The lot of childlessness remove ye from us, and let our course be rich in kine and offspring.","mb":"অর্যমা, অদিতি, যজ্ঞঝার্হ দেবগণ এবং অহিংসিতকর্মা বরু, আমাদরে রক্ষা করুন, আমাদের মার্গ হতে পুত্রগণের অকল্যাণ দূর করুন। আমাদের গৃহ পশুুক্ত ও অপত্যবিশিষ্ট হোক।"},{"n":19,"d":"देवानां दूतः पुरुध परसूतो.अनागान नो वोचतु सर्वताता | शर्णोतु नः पर्थिवी दयौरुतापः सूर्यो नक्षत्रैरुर्वन्तरिक्षम ||","b":"দেবানাং দূতঃ পুরুধ পরসূতো.অনাগান নো বোচতু সর্বতাতা | শর্ণোতু নঃ পর্থিবী দযৌরুতাপঃ সূর্যো নক্ষত্রৈরুর্বন্তরিক্ষম ||","e":"May the Gods’ envoy, sent to many a quarter, proclaim us sinless for our perfect safety. May Earth and Heaven, the Sun, the waters, hear us, and the wide firmament and constellations.","mb":"বহুস্থানে বিহিত ও দেবগণের দ্রুত অগ্নি আমাদরে সর্বত্র নিরপরাধী  বলুন। পৃথিবী, দ্যুলোক, জল সমূহ সূর্য ও নক্ষত্রপূর্ণ বিশাল অন্তরীক্ষ আমাদের স্তুতি শুনুন। ২০। অভীষ্টবর্ষী মরুৎগণ এবং নিশ্চল পর্বতগণ হব্যদ্বারা হৃষ্ট হয়ে আমাদের স্তুতি শুনুন। আদিত্যগণের সাথে অদিতি আমাদের স্তুতি শুনুন। আমাদরে কল্রণকর সুখ দান করুন।"},{"n":20,"d":"शर्ण्वन्तु नो वर्षणः पर्वतासो धरुवक्षेमास इळया मदन्तः | आदित्यैर्नो अदितिः शर्णोतु यछन्तु नो मरुतः शर्मभद्रम ||","b":"শর্ণ্বন্তু নো বর্ষণঃ পর্বতাসো ধরুবক্ষেমাস ইলযা মদন্তঃ | আদিত্যৈর্নো অদিতিঃ শর্ণোতু যছন্তু নো মরুতঃ শর্মভদ্রম ||","e":"Hear us the mouatains which distil the rain-drops, and, resting firm, rejoice in freshening moisture. May Aditi with the Ādityas hear us, and Maruts grant us their auspicious shelter.","mb":"বৃষ্টিধারা বর্ষণকারী পর্বতরা আমাদের শুনুন, স্থিরভাবে দাঁড়িয়ে তাজা আর্দ্রতায় আনন্দ করুন। আদিত্যদের সাথে অদিতি আমাদের শুনুন, এবং মরুৎগণ আমাদের মঙ্গলময় আশ্রয় দান করুন।"},{"n":21,"d":"सदा सुगः पितुमानस्तु पन्था मध्व देवा ओषधीः सम्पिप्र्क्त | भगो मे अग्ने सख्ये न मर्ध्या उद रायो अश्यां सदनं पुरुक्षोः ||","b":"সদা সুগঃ পিতুমানস্তু পন্থা মধ্ব দেবা ওষধীঃ সম্পিপ্র্ক্ত | ভগো মে অগ্নে সখ্যে ন মর্ধ্যা উদ রাযো অশ্যাং সদনং পুরুক্ষোঃ ||","e":"Soft be our path for ever, well-provisioned: with pleasant meath, O Gods, the herbs besprinkle. Safe be my bliss, O Agni, in thy friendship: may I attain the seat of foodful. riches,","mb":"আমাদরে পথ সর্বদা সুগম ও অন্নযুক্ত হোক। হে দেবগণ? তোমরা জলদ্বারা ওষধিগণকে সংসিক্ত কর। হে অগ্নি! তুমি সখা হলে আমাদের ধন যেন বিনষ্ট না হয়, আমি যেন ধন ও বহুল অন্নযুক্ত স্থান প্রাপত্ হই।"},{"n":22,"d":"सवदस्व हव्या समिषो दिदीह्यस्मद्र्यक सं मिमीहि शरवांसि | विश्वानग्ने पर्त्सु तञ जेषि शत्रूनहा विश्वा सुमना दीदिही नः ||","b":"সবদস্ব হব্যা সমিষো দিদীহ্যস্মদ্র্যক সং মিমীহি শরবাংসি | বিশ্বানগ্নে পর্ত্সু তঞ জেষি শত্রূনহা বিশ্বা সুমনা দীদিহী নঃ ||","e":"Enjoy the offering: beam thou strength upon us; combine thou for our good all kinds of glory. Conquer in battle, Agni, all those foemen, and light us every day with loving kindness.","mb":"হে অগ্নি! হব্য আস্বাদন কর, অন্ন সম্যকরূপে প্রকাশ কর, অন্ন আমাদরে অভিমুখীন কর, সংগ্রামে সে সমস্ত শত্রুগণকে জয় কর, প্রফুল্ল মনে আমাদরে দিন সকল প্রকাশ কর।"}]},{"n":55,"t":"Viśvedevas","v":[{"n":1,"d":"उषसः पूर्वा अध यद वयूषुर्महद वि जज्ञे अक्षरं पदे गोः | वरता देवानामुप नु परभूषन महद देवानामसुरत्वमेकम ||","b":"উষসঃ পূর্বা অধ যদ বযূষুর্মহদ বি জজ্ঞে অক্ষরং পদে গোঃ | বরতা দেবানামুপ নু পরভূষন মহদ দেবানামসুরত্বমেকম ||","e":"AT the first shining of the earliest Mornings, in the Cow's home was born the Great Eternal. Now shall the statutes of the Gods be valid. Great is the Gods’ supreme and sole dominion -","mb":"ঊষা যখন পূর্বেই প্রকাশিত হন, তখন অবিনাশী, মহজান সূর্য জলের স্থান উৎপন্ন হন, যজমান দেবগণের সমীপে শীঘ্র  ব্রত সকল উপস্থিত করেন। দেবগণের মহৎ বল একই (১)।"},{"n":2,"d":"मो षू णो अत्र जुहुरन्त देवा मा पूर्वे अग्ने पितरः पदज्ञाः | पुराण्योः सद्मनोः केतुरन्तर्म... ||","b":"মো ষূ ণো অত্র জুহুরন্ত দেবা মা পূর্বে অগ্নে পিতরঃ পদজ্ঞাঃ | পুরাণ্যোঃ সদ্মনোঃ কেতুরন্তর্ম... ||","e":"Let not the Gods here injure us, O Agni, nor Fathers of old time who know the region, Nor the sign set between two ancient dwellings. Great is the Gods’ supreme and sole dominion.","mb":"হে অগ্নি! এক্ষণে দেবগণ যেন আমাদরে হিংসা না করে, দেবপদভাক পূর্ব পুরুষগণ যেন আমাদরে হিংসা না করে, কেতু সূর্য পুরাতন দ্যাবাপৃথিবীর মধ্যে উদিত হচ্ছেন। দেবগগণের মহৎ বল একই।"},{"n":3,"d":"वि मे पुरुत्रा पतयन्ति कामाः शम्यछा दीद्ये पूर्व्याणि | समिद्धे अग्नाव रतमिद वदेम म... ||","b":"বি মে পুরুত্রা পতযন্তি কামাঃ শম্যছা দীদ্যে পূর্ব্যাণি | সমিদ্ধে অগ্নাব রতমিদ বদেম ম... ||","e":"My wishes fly abroad to many places: I glance back to the ancient sacrifices. Let us declare the truth when fire is kindled. Great is the Gods’ supreme and sole dominion.","mb":"আমার বিবিধ অভিলাষ বিবিধ দিকে যাচ্ছে, আমি যজ্ঞের উদ্দেশে পুরাতন স্তোত্র সকল প্রদীপ্ত করছি, অগ্নি সমিদ্ধ হওয়ার পর, আমরা কেবল সত্যই বলব। দেবগণের মহৎ বল একই।"},{"n":4,"d":"समानो राजा विभ्र्तः पुरुत्रा शये शयासु परयुतो वनानु | अन्या वत्सं भरति कषेति माता म... ||","b":"সমানো রাজা বিভ্র্তঃ পুরুত্রা শযে শযাসু পরযুতো বনানু | অন্যা বত্সং ভরতি কষেতি মাতা ম... ||","e":"King Universal, born to sundry quarters, extended through the wood be lies on couches. One Mother rests: another feeds the Infant. Great is the Gods’ supreme and sole dominion.","mb":"সর্বসাধারণের রাজা বহুপ্রদেশে স্থাপিত হন, তিনি বেদিতে শয়ন করেন, বনমধ্যে (২) বিভক্ত হন। অন্য দ্যুলোক বৎসভূত সোম বা অগ্নিকে বৃষ্টিদ্বারা পোষণ করেন, মাতা পৃথিবী ধারণ করেন। দেবগণের মহৎ বল একই।"},{"n":5,"d":"आक्षित पूर्वास्वपरा अनूरुत सद्यो जातासु तरुणीष्वन्तः | अन्तर्वतीः सुवते अप्रवीता म... ||","b":"আক্ষিত পূর্বাস্বপরা অনূরুত সদ্যো জাতাসু তরুণীষ্বন্তঃ | অন্তর্বতীঃ সুবতে অপ্রবীতা ম... ||","e":"Lodged in old plants, he grows again in younger, swiftly within the newly-born and tender. Though they are unimpregned, he makes them fruitful. Great is the Gods’ supreme and sole dominion.","mb":"অগ্নি অথবা সূর্য জীর্ণ ওষধি সকলের মধ্যে বাস করেন। অজাতগর্ভা ওষধিগণ গর্ভবতী হয়ে ফল প্রসব করে। দেব গণের মহৎ বল একই।"},{"n":6,"d":"शयुः परस्तादध नु दविमाताबन्धनश्चरति वत्स एकः | मित्रस्य ता वरुणस्य वरतानि म... ||","b":"শযুঃ পরস্তাদধ নু দবিমাতাবন্ধনশ্চরতি বত্স একঃ | মিত্রস্য তা বরুণস্য বরতানি ম... ||","e":"Now lying far away, Child of two Mothers, he wanders unrestrained, the single youngling. These are the laws of Varuṇa and Mitra. Great is the Gods’ supreme and sole dominion.","mb":"দ্বিমাতা (৩) সূর্য পশ্চিমদিকে শয়ন করেন, কিন্তু উদয় কালে সে বৎস সূর্য অপ্রতিবন্ধ গতিতে বিচরণ করেন। এ সকল মিত্র ও বরুণের কর্ম। দেবগণের মহৎ বল একই।"},{"n":7,"d":"दविमाता होता विदथेषु सम्राळ अन्वग्रं चरति कषेति बुध्नः | पर रण्यानि रण्यवाचो भरन्ते म... ||","b":"দবিমাতা হোতা বিদথেষু সম্রাল অন্বগ্রং চরতি কষেতি বুধ্নঃ | পর রণ্যানি রণ্যবাচো ভরন্তে ম... ||","e":"Child of two Mothers, Priest, sole Lord in synods, he still precedes while resting as foundation. They who speak sweetly bring him sweet addresses. Great is the Gods’ supreme and sole dominion.","mb":"দি্বিমাতা যজ্ঞের হোতা ও সম্রাট অগ্নি অগ্রে আকাশে সূর্যরূপে বিচরণ করেন। তিনি সকলের মুলভূত হয়ে ভূমিতে বাস করেন। রমণীয় বাকযুক্ত স্তোতাগণ রমণীয় স্তোত্র করছেন। দেব গণের মহৎ বল একই।"},{"n":8,"d":"शूरस्येव युध्यतो अन्तमस्य परतीचीनं दद्र्शे विश्वमायत | अन्तर्मतिश्चरति निष्षिधं गोर्म... ||","b":"শূরস্যেব যুধ্যতো অন্তমস্য পরতীচীনং দদ্র্শে বিশ্বমাযত | অন্তর্মতিশ্চরতি নিষ্ষিধং গোর্ম... ||","e":"As to a friendly warrior when he battles, each thing that comes anear is seen to meet him. The hymn commingles with the cow's oblation. Great is the Gods’ supreme and sole dominion.","mb":"যুদ্ধকারী শুরব্যক্তির অভিমুখে আগমনকারী শত্রুসৈন্যকে যেরূপ পরাম্মুখ হতে দেখা যায়, সেরূপ সমীপবর্তী অগ্নির অভিমুখে আগমনকারী ভূতজাতকে পররাম্মুখ হতে দেখা যায়। অগ্নির মধ্যে জলের বিনাশক দীপ্তি আছে। দেবগণের মহৎ বল একই।"},{"n":9,"d":"नि वेवेति पलितो दूत आस्वन्तर्महांश्चरति रोचनेन | वपूंषि बिभ्रदभि नो वि चष्टे म... ||","b":"নি বেবেতি পলিতো দূত আস্বন্তর্মহাংশ্চরতি রোচনেন | বপূংষি বিভ্রদভি নো বি চষ্টে ম... ||","e":"Deep within these the hoary envoy pierceth; mighty, he goeth to the realm of splendour, And looketh on us, clad in wondrous beauty. Great is the Gods’ supreme and sole dominion.","mb":"পালয়িতা দূত অগ্নি ঐ সকল ওষধি মধ্যে ব্যাপ্ত আছেন। তিনি মহজান, তিনি সূর্যের সাথে দ্যাবাপৃথিবীর মধ্যে বিচরণ করেন। তিনি নানাবিধ রূপ ধারণ করে আমাদের দর্শন করেন। দেবগণের মহৎ বল একই।"},{"n":10,"d":"विष्णुर्गोपाः परमं पाति पाथः परिया धामान्यम्र्तादधानः | अग्निष टा विश्वा भुवनानि वेद म... ||","b":"বিষ্ণুর্গোপাঃ পরমং পাতি পাথঃ পরিযা ধামান্যম্র্তাদধানঃ | অগ্নিষ টা বিশ্বা ভুবনানি বেদ ম... ||","e":"Viṣṇu, the guardian, keeps the loftiest station, upholding dear, immortal dwelling-places. Agni knows well all these created beings. Great is the Gods’ supreme and sole dominion.","mb":"রক্ষক বিষ্ণু (৪) প্রিয়তম অক্ষয় তেজ ধারণ করে পরম স্থান রক্ষা করেন। অগ্নি সমস্ত ভূতজাতকে জানেন। দেবগণের মহৎ বল একই। জ"},{"n":11,"d":"नाना चक्राते यम्या वपूंषि तयोरन्यद रोचते कर्ष्णमन्यत | शयावी च यदरुषी च सवसारौ म... ||","b":"নানা চক্রাতে যম্যা বপূংষি তযোরন্যদ রোচতে কর্ষ্ণমন্যত | শযাবী চ যদরুষী চ সবসারৌ ম... ||","e":"Ye, variant Pair, have made yourselves twin beauties: one of the Twain is dark, bright shines the other; And yet these two, the dark, the red, are Sisters. Great is the Gods’ supreme and sole dominion.","mb":"মিথুনভূত অহ: ও রাত্রি নানাবিধরূপ ধারণ করেন। কৃষ্ণবর্ণা ও শুক্রবর্ণা যে ভগিনীদ্বয়, তাদরে একজন দীপ্তিশাল ও অন্য জন কৃষ্ণবর্ণ। দেবগণের মহৎ বল একই।"},{"n":12,"d":"माता च यत्र दुहिता च धेनू सबर्दुघे धापयेते समीची | रतस्य ते सदसीळे अन्तर्म... ||","b":"মাতা চ যত্র দুহিতা চ ধেনূ সবর্দুঘে ধাপযেতে সমীচী | রতস্য তে সদসীলে অন্তর্ম... ||","e":"Where the two Cows, the Mother and the Daughter, meet and give suck yielding their lordly nectar, I praise them at the seat of law eternal. Great is the Gods’ supreme and sole dominion.","mb":"মাতা পৃথিবী ও দুহিতা দ্যুলোক স্বরূপ ক্ষীরদায়িনী ধেনুদ্বয়, যে অন্তরীক্ষে পরস্পর সঙ্গত হয়ে পরস্পরকে রস পান করাচ্ছেন, জলের স্থানভূত সে অন্তরীক্ষের মধ্যস্থিত দ্যাব্যাপৃথিবী আমি স্তব করছি। দেবগণের  মহৎ বল একই।"},{"n":13,"d":"अन्यस्या वत्सं रिहती मिमाय कया भुवा नि दधे धेनुरूधः | रतस्य सा पयसापिन्वतेळा म... ||","b":"অন্যস্যা বত্সং রিহতী মিমায কযা ভুবা নি দধে ধেনুরূধঃ | রতস্য সা পযসাপিন্বতেলা ম... ||","e":"Loud hath she lowed, licking the other's youngling. On what world hath the Milch-cow laid her udder? This Iḷā streameth with the milk of Order. Great is the Gods’ supreme and sole dominion.","mb":"দ্যুলোক পৃথিবীর বৎস অগ্নিকে লেহন করে ধ্বনি করে। দ্যুরূপা ধেনু পৃথিবীকে জলশূন্য করে স্বীয় উধ:প্রদেশ পূর্ণ করে, সে পৃথিবী আদিত্যের জল দ্বারা সিক্ত হয়। দেবগণের মহৎ বল একই।"},{"n":14,"d":"पद्या वस्ते पुरुरूपा वपूंष्यूर्ध्वा तस्थौ तर्यविं रेरिहाणा | रतस्य सद्म वि चरामि विद्वान म... ||","b":"পদ্যা বস্তে পুরুরূপা বপূংষ্যূর্ধ্বা তস্থৌ তর্যবিং রেরিহাণা | রতস্য সদ্ম বি চরামি বিদ্বান ম... ||","e":"Earth weareth beauties manifold: uplifted, licking her Calf of eighteen months, she standeth. Well-skilled I seek the seat of law eternal. Great is the Gods’ supreme and sole dominion.","mb":"পৃথিবী নানবিধ শরীর পরিধান করেন, তিনি উন্নত হয়ে সার্ধ সম্ববৎসর বয়সের বৎসকে (৩) লেহন করে অবস্থান করেন। আমি সূর্যের স্থান জেনে পরিচর্যা করছি। দেবগণের মহৎ বল একই।"},{"n":15,"d":"पदे इव निहिते दस्मे अन्तस्तयोरन्यद गुह्यमाविरन्यत | सध्रीचीना पथ्या सा विषूची म... ||","b":"পদে ইব নিহিতে দস্মে অন্তস্তযোরন্যদ গুহ্যমাবিরন্যত | সধ্রীচীনা পথ্যা সা বিষূচী ম... ||","e":"Within a wondrous place the Twain are treasured: the one is manifest, the other hidden. One common pathway leads in two directions. Great is the Gods’ supreme and sole dominion.","mb":"পদদ্বয়ের ন্যায় দর্শনীয় অহোরাত্রি দ্যাবাপৃথিবীর মধ্যে স্থাপিত আছে। তাদের মধ্যে একজন গৃঢ় আয় একজন আবির্ভূত। এদের পরস্পর মিলন পথ কা{ল পুন্যকারী ও অপুরণ্যকারী উভয়কেই প্রাপ্ত হয়। দেবগণের মহৎ বল একই।"},{"n":16,"d":"आ धेनवो धुनयन्तामशिश्वीः सबर्दुघाः शशया अप्रदुग्धाः | नव्या-नव्या युवतयो भवन्तीर्म... ||","b":"আ ধেনবো ধুনযন্তামশিশ্বীঃ সবর্দুঘাঃ শশযা অপ্রদুগ্ধাঃ | নব্যা-নব্যা যুবতযো ভবন্তীর্ম... ||","e":"Let the milch-kine that have no calves storm downward, yielding rich nectar, streaming, unexhausted, These who are ever new and fresh and youthful. Great is the Gods’ supreme and sole dominion.","mb":"শিশুরহিতা নভ:প্রদেশে শয়ানা, অক্ষীণরসা, কষীরপ্রসবিনী যুবতী ও সর্বদা নুতনা মেঘসকল কম্পিত হোক। দেবগণের মহৎ বল একই।"},{"n":17,"d":"यदन्यासु वर्षभो रोरवीति सो अन्यस्मिन यूथे नि दधातिरेतः | स हि कषपावान स भगः स राजा म... ||","b":"যদন্যাসু বর্ষভো রোরবীতি সো অন্যস্মিন যূথে নি দধাতিরেতঃ | স হি কষপাবান স ভগঃ স রাজা ম... ||","e":"What time the Bull bellows in other regions, another herd receives the genial moisture; For he is Bhaga, King, the earth's Protector. Great is the Gods’ supreme and sole dominion.","mb":"অভীষ্টবর্ষী ইন্দ্র, কোন কোন দিকে অত্যন্ত মেঘের শব্দ করেন, অন্যান্য দিক সমূহে জল বর্ষণ করেন। তিনি জল ক্ষেপণবান, তিনি সকলের ভজনীয়, তিনি রাজা। দেবগণের মহজৎ ফল একই।"},{"n":18,"d":"वीरस्य नु सवश्व्यं जनासः पर नु वोचाम विदुरस्य देवाः | षोळ्हा युक्ताः पञ्च-पञ्चा वहन्ति म... ||","b":"বীরস্য নু সবশ্ব্যং জনাসঃ পর নু বোচাম বিদুরস্য দেবাঃ | ষোল্হা যুক্তাঃ পঞ্চ-পঞ্চা বহন্তি ম... ||","e":"Let us declare the Hero's wealth in horses, O all ye folk: of this the Gods have knowledge. Sixfold they bear him, or by fives are harnessed. Great is the Gods’ supreme and sole dominion.","mb":"হে জন সকল! আমরা শুর ইন্দ্রের সুন্দর অশ্বসমূহের কথা বলছি। দেবগণল তা জানেন। তারা ছটি অথবা পাচটি করে যোজিত হয়ে তাকে বহন করে। (৬) দেবগণের মহৎ বল একই।"},{"n":19,"d":"देवस्त्वष्टा सविता विश्वरूपः पुपोष परजाः पुरुधाजजान | इमा च विश्वा भुवनान्यस्य म... ||","b":"দেবস্ত্বষ্টা সবিতা বিশ্বরূপঃ পুপোষ পরজাঃ পুরুধাজজান | ইমা চ বিশ্বা ভুবনান্যস্য ম... ||","e":"Tvaṣṭar the God, the omniform. Creator, begets and feeds mankind in various manner. His, verily, arc all these living creatures. Great is the Gods’ supreme dominion.","mb":"সকলের প্রেরক, নানাবিধ  রূপবিশিষ্ট ত্বষ্টদেব বহু প্রকারে পুত্র উৎপাদন করেন ও পালন করেন। এ সমস্ত ভুবন তার। দেবগণের মহৎ বল একই। ২০। তিনি মহতী পরস্পর সঙ্গত দ্যাবাপৃথিবীকে পশুপক্ষী যুক্ত করেছেন। তারা উভয়ে ইন্দ্রের তেজ: দ্বারা ব্যাপ্ত। তিনি বীর তিনি শত্রুর ধন গ্রহণে বিখ্যাত, দেবগণের মহৎ বল একই।"},{"n":20,"d":"मही समैरच्चम्वा समीची उभे ते अस्य वसुना नय्र्ष्टे | शर्ण्वे वीरो विन्दमानो वसूनि म... ||","b":"মহী সমৈরচ্চম্বা সমীচী উভে তে অস্য বসুনা নয্র্ষ্টে | শর্ণ্বে বীরো বিন্দমানো বসূনি ম... ||","e":"The two great meeting Bowls hath he united: each of the Pair is laden with histreasure. The Hero is renowned for gathering riches. Great is the Gods’ supreme and sole dominion.","mb":"দুই মহান মিলনরত পাত্র তিনি একত্র করেছেন: প্রতিটি তাঁর ধনে পূর্ণ। বীর ধনসংগ্রহে প্রসিদ্ধ। দেবতাদের পরম ও একমাত্র আধিপত্য মহান।"},{"n":21,"d":"इमां च नः पर्थिवीं विश्वधाया उप कषेति हितमित्रो नराजा | पुरःसदः शर्मसदो न वीरा म... ||","b":"ইমাং চ নঃ পর্থিবীং বিশ্বধাযা উপ কষেতি হিতমিত্রো নরাজা | পুরঃসদঃ শর্মসদো ন বীরা ম... ||","e":"Yea, and on this our earth the All-Sustainer dwells like a King with noble friends about him. In his protection heroes rest in safety. Great is the Cods' supreme and sole dominion.","mb":"বিশ্বধাতা আমাদের রাজা ইন্দ্র এ পৃথিবী ও অন্তরীক্ষের সমীপে হিতকারী মিত্রের ন্যায় বাস করেন। বীর মরুৎগণ কইন্দ্রের অগ্রে অগ্রে যুদ্ধে গমন করেন এবং তার গৃহে বাস ককরেন। দেবগণের মহৎ বল একই।"},{"n":22,"d":"निष्षिध्वरीस्त ओषधीरुतापो रयिं त इन्द्र पर्थिवी बिभर्ति | सखायस्ते वामभाजः सयाम म... ||","b":"নিষ্ষিধ্বরীস্ত ওষধীরুতাপো রযিং ত ইন্দ্র পর্থিবী বিভর্তি | সখাযস্তে বামভাজঃ সযাম ম... ||","e":"Rich in their gifts for thee are herbs and waters, and earth brings all her wealth for thee, O Indra. May we as friends of thine share goodly treasures. Great is the Gods’ supreme and sole dominion.","mb":"হে ইন্দ্র! ওষধি সকল তোমা কর্তৃক সিদ্ধি প্রাপত্ হয়, জল তোমা হতে নির্গত হয়। পৃথিবী তোমার জন্য ধন ধারণ করেন। আমরা তোমার সখা। আমরা যেন তোমার ধনের ভাগী হতে পারি। দেবগণের মহৎ বল একই (৭)।"}]},{"n":56,"t":"Viśvedevas","v":[{"n":1,"d":"न ता मिनन्ति मायिनो न धीरा वरता देवानां परथमा धरुवाणि | न रोदसी अद्रुहा वेद्याभिर्न पर्वता निनमे तस्थिवांसः ||","b":"ন তা মিনন্তি মাযিনো ন ধীরা বরতা দেবানাং পরথমা ধরুবাণি | ন রোদসী অদ্রুহা বেদ্যাভির্ন পর্বতা নিনমে তস্থিবাংসঃ ||","e":"NOT men of magic skill, not men of wisdom impair the Gods’ first steadfast ordinances. Ne’er may the earth and heaven which know not malice, nor the fixed hills, be bowed by sage devices.","mb":"মায়াবী বা জ্ঞানীরা দেবতাদের প্রথম স্থির বিধানগুলি খর্ব করতে পারে না। কখনো নিষ্কলুষ পৃথিবী ও স্বর্গ, কিংবা স্থির পর্বতরাশি, প্রজ্ঞার কৌশলে নত হবে না।"},{"n":2,"d":"षड भारानेको अचरन बिभर्त्य रतं वर्षिष्ठमुप गाव आगुः तिस्रो महीरुपरास्तस्थुरत्या गुहा दवे निहितेदर्श्येका ||","b":"ষড ভারানেকো অচরন বিভর্ত্য রতং বর্ষিষ্ঠমুপ গাব আগুঃ তিস্রো মহীরুপরাস্তস্থুরত্যা গুহা দবে নিহিতেদর্শ্যেকা ||","e":"One, moving not away, supports six burthens: the Cows proceed to him the true, the Highest. Near stand three Mighty Ones who travel swiftly: two are concealed from sight, one is apparent.","mb":"্একটি স্থায়ী বৎসর ছয়টি ভার ঋতু ধারণ করে। গাভী সকল রশ্মি সকল সত্য ও প্রবৃদ্ধ আদিত্য{াত্মক সশ্বৎসরে মিলিত হয়। চঞ্চল লোকত্রয় উপরি উপরি বর্তমান রয়েছে, দুটি স্বর্গ ও অন্তরীক্ষ গুহায় নিহিত, একটি পৃথিবী দেখতে পারা যায়।"},{"n":3,"d":"तरिपाजस्यो वर्षभो विश्वरूप उत तर्युधा पुरुध परजावान | तर्यनीकः पत्यते माहिनावान स रेतोधा वर्षभः शश्वतीनाम ||","b":"তরিপাজস্যো বর্ষভো বিশ্বরূপ উত তর্যুধা পুরুধ পরজাবান | তর্যনীকঃ পত্যতে মাহিনাবান স রেতোধা বর্ষভঃ শশ্বতীনাম ||","e":"The Bull who wears all shapes, the triple-breasted, three-uddered, with a brood in many places, Ruleth majestic with his triple aspect, the Bull, the Everlasting Ones' impregner.","mb":"তিন বক্ষবিশিষ্ট, তিন উধ:বিশিষ্ট বিশ্বরূপ, বহু প্রকার ও প্রজাবান এবং ত্রিগুণযুক্ত মহিমাবান বৃষভ আসছে। সে বৃষভ সকলের জন্য রস ধারণ করে (১)।"},{"n":4,"d":"अभीक आसां पदवीरबोध्यादित्यानामह्वे चारु नाम | आपश्चिदस्मा अरमन्त देवीः पर्थग वरजन्तीः परि षीमव्र्ञ्जन ||","b":"অভীক আসাং পদবীরবোধ্যাদিত্যানামহ্বে চারু নাম | আপশ্চিদস্মা অরমন্ত দেবীঃ পর্থগ বরজন্তীঃ পরি ষীমব্র্ঞ্জন ||","e":"When nigh them, as their tracer he observed them: he called aloud the dear name of Ādityas. The Goddesses, the Waters, stayed to meet him: they who were wandering separate enclosed him.","mb":"সশ্বৎসর এ সকল ঔষধির সমীপে এদের পদবীস্বরূপ জাগরিত হয়েছে। আমি আদিত্যগণের মনোহর নাম উচ্চারণ করছি। স্বতন্ত্র স্বতন্ত্র পথে চলিত, দ্যুতিমান জলসমূহ ওকে প্রীত করে, আবার পরিত্যাগ করে (২)।"},{"n":5,"d":"तरी षधस्था सिन्धवस्त्रिः कवीनामुत तरिमाता विदथेषु सम्राट | रतावरीर्योषणास्तिस्रो अप्यास्त्रिरा दिवो विदथे पत्यमानाः ||","b":"তরী ষধস্থা সিন্ধবস্ত্রিঃ কবীনামুত তরিমাতা বিদথেষু সম্রাট | রতাবরীর্যোষণাস্তিস্রো অপ্যাস্ত্রিরা দিবো বিদথে পত্যমানাঃ ||","e":"Streams! the wise Gods have thrice three habitations. Child of three Mothers, he is Lord in synods. Three are the holy Ladies of the Waters, thrice here from heaven supreme in our assembly.","mb":"হে নদীগণ! কবিগণের অর্থাৎ দেবগণের ত্রিগুণিত ত্রিসংখ্যক স্থান আছে। তত্রিমাতা (৩) সশ্বৎসর যজ্ঞের সম্রাট। জরবত{ী অন্তরীক্ষচারিণী তিন যোষিত (৪) যজ্ঞে দিবসে তিন বার অর্থাৎ তিন সবনে আসেন।"},{"n":6,"d":"तरिरा दिवः सवितर्वार्याणि दिवे-दिव आ सुव तरिर्नो अह्नः | तरिधातु राय आ सुवा वसूनि भग तरातर्धिषणे सातये धाः ||","b":"তরিরা দিবঃ সবিতর্বার্যাণি দিবে-দিব আ সুব তরির্নো অহ্নঃ | তরিধাতু রায আ সুবা বসূনি ভগ তরাতর্ধিষণে সাতযে ধাঃ ||","e":"Do thou, O Savitar, from heaven thrice hither, three times a day, send down thy blessings daily. Send us, O Bhaga, triple wealth and treasure; cause the two worlds to prosper us, Preserver!","mb":"হে সরিতা দ্যুলোক হতে আগমন করে প্রত্যহ তিনবার করে আমাদরে বরণী{য় ধন প্রদান কর। হে ত্রাতা ভগ! আমাদরে দিবসের মধ্যে তিনবার তিন ধাতুর (৫) ধন ও গোধন প্রদান কর। হেজ ধিষনা! আমাদরে যাতে ধন রাভ হয তা কর। জ"},{"n":7,"d":"तरिरा दिवः सविता सोषवीति राजाना मित्रावरुणा सुपाणी | आपश्चिदस्य रोदसी चिदुर्वी रत्नं भिक्षन्त सवितुः सवाय ||","b":"তরিরা দিবঃ সবিতা সোষবীতি রাজানা মিত্রাবরুণা সুপাণী | আপশ্চিদস্য রোদসী চিদুর্বী রত্নং ভিক্ষন্ত সবিতুঃ সবায ||","e":"Savitar thrice from heaven pours down abundance, and the fair-handed Kings Varuṇa, Mitra; And spacious Heaven and Earth, yea, and the Waters, solicit wealth that Savitar may send us.","mb":"সবিতা যে দিনে তিনবার ধন প্রদান করেন।  কল্যাণপাণি রাজা মিত্রাবরুণ, দ্যাবাপৃথিবী ও অন্তীক্ষ এরা সকলে সবিতার বদান্যতা হতেই  রত্নলাভের আশা করেন।"},{"n":8,"d":"तरिरुत्तमा दूणशा रोचनानि तरयो राजन्त्यसुरस्य वीराः | रतावान इषिरा दूळभासस्त्रिरा दिवो विदथे सन्तु देवाः ||","b":"তরিরুত্তমা দূণশা রোচনানি তরযো রাজন্ত্যসুরস্য বীরাঃ | রতাবান ইষিরা দূলভাসস্ত্রিরা দিবো বিদথে সন্তু দেবাঃ ||","e":"Three are the bright realms, best, beyond attainment, and three, the Asura's Heroes, rule as Sovrans, Holy and vigorous, never to be injured. Thrice may the Gods from heaven attend our synod.","mb":"উত্তম, বিনাশরহিত ও দীপ্তিমান স্থানের সংখ্যা তিন। অসুরের তিন পুত্র (৬) শোভা পাচ্ছেন। যজ্ঞবান, শীঘ্রগামী, অহিংসনীয় দেবগণ দিনে তিনবার যজ্ঞে আসেন।"}]},{"n":57,"t":"Viśvedevas","v":[{"n":1,"d":"पर मे विविक्वानविदन मनीषां धेनुं चरन्तीं परयुतामगोपाम | सद्यश्चिद या दुदुहे भूरि धासेरिन्द्रस्तदग्निः पनितारो अस्याः ||","b":"পর মে বিবিক্বানবিদন মনীষাং ধেনুং চরন্তীং পরযুতামগোপাম | সদ্যশ্চিদ যা দুদুহে ভূরি ধাসেরিন্দ্রস্তদগ্নিঃ পনিতারো অস্যাঃ ||","e":"MY thought with fine discernment hath discovered the Cow who wanders free without a herdsman, Her who hath straightway poured me food in plenty: Indra and Agni therefore are her praisers.","mb":"বিবেকশাল (ইন্দ্র) গোপহীনা, একাকিনী, (গোষ্ঠে) বিহারিণী ধেনুর ন্যায় আমার এ স্তুতি অবগত হোন। ওকে (ইচ্ছা করলে) তৎক্ষনাৎ প্রভূত অন্ন দোহন করা যায়া। অতএব ইনদ্র ও অগ্নি ওর প্রশংসা করুন।"},{"n":2,"d":"इन्द्रः सु पूषा वर्षणा सुहस्ता दिवो न परीताः शशयं दुदुह्रे | विश्वे यदस्यां रणयन्त देवाः पर वो.अत्र वसवः सुम्नमश्याम ||","b":"ইন্দ্রঃ সু পূষা বর্ষণা সুহস্তা দিবো ন পরীতাঃ শশযং দুদুহ্রে | বিশ্বে যদস্যাং রণযন্ত দেবাঃ পর বো.অত্র বসবঃ সুম্নমশ্যাম ||","e":"Indra and Pūṣan, deft of hand and mighty, well-pleased have drained the heaven's exhaustless udder. As in this praise the Gods have all delighted, may I win blessing here from you, O Vasus.","mb":"ইন্দ্র পূষা এবং অভীষ্টবর্ষী কল্যাণপাণি মিত্রাবরুণ প্রীত হয়ে সম্প্রতি অন্তরীক্ষশায়ী মেঘকে অন্তরীক্ষ হতেই দোহন করছেন। হে নিবাসপ্রদ বিশ্বদেবগণ! তোমরা এ বেদিতে বিহার কর, আমরা যেন তোমাদের প্রদত্ত সুখ প্রাপ্ত হতে পারি।"},{"n":3,"d":"या जामयो वर्ष्ण इछन्ति शक्तिं नमस्यन्तीर्जानते गर्भमस्मिन | अछा पुत्रं धेनवो वावशाना महश्चरन्ति बिभ्रतं वपूंषि ||","b":"যা জামযো বর্ষ্ণ ইছন্তি শক্তিং নমস্যন্তীর্জানতে গর্ভমস্মিন | অছা পুত্রং ধেনবো বাবশানা মহশ্চরন্তি বিভ্রতং বপূংষি ||","e":"Fain to lend vigour to the Bull, the siste.. with reverence recognize the germ within him. The Cows come lowing hither to the Youngling, to him endued with great and wondrous beauties.","mb":"যে জামিগণ (১) জলবর্ষী ইন্দ্রের শক্তি বাঞ্চা করে, তারা নম্র হয়ে ইন্দ্রের গর্ভাধান শক্তি অবগত হয়। ফলাভিলাষী ধেনুগণ অর্থাৎ ওষধি সকল, নানারূপধারী পুত্রের অর্থাৎ গবাদি শসের অভিমুখে বিচরণ করে।"},{"n":4,"d":"अछा विवक्मि रोदसी सुमेके गराव्णो युजानो अध्वरे मनीषा | इमा उ ते मनवे भूरिवारा ऊर्ध्वा भवन्ति दर्शता यजत्राः ||","b":"অছা বিবক্মি রোদসী সুমেকে গরাব্ণো যুজানো অধ্বরে মনীষা | ইমা উ তে মনবে ভূরিবারা ঊর্ধ্বা ভবন্তি দর্শতা যজত্রাঃ ||","e":"Fixing with thought, at sacrifice, the press-stones, I bid the well-formed Heaven and Earth come hither; For these thy flames, which give men boons in plenty, rise up on high, the beautiful, the holy.","mb":"যজ্ঞে প্রস্তর ধারণ করে আমি সুন্দর জরূপবিশিষ্ট দ্যাবাপৃথিবীকে স্তুতি দ্বারা প্রীত করছি। হে অগ্নি! তোমার অতিশয় কমনীয়, বরণীয় দীক্তি সকল মনুষ্যদের জন্য ঊর্ধ্বমুখ হচ্ছে।"},{"n":5,"d":"या ते जिह्वा मधुमती सुमेधा अग्ने देवेषूच्यत उरूची | तयेह विश्वानवसे यजत्राना सादय पायया चा मधूनि ||","b":"যা তে জিহ্বা মধুমতী সুমেধা অগ্নে দেবেষূচ্যত উরূচী | তযেহ বিশ্বানবসে যজত্রানা সাদয পাযযা চা মধূনি ||","e":"Agni, thy meath-sweet tongue that tastes fair viands, which among Gods is called the far-extended,— Therewith make all the Holy Odes be seated here for our help, and feed them with sweet juices.","mb":"হে অগ্নি! তোমার যে মধুমতী প্রজ্ঞাশালিনী জিহ্বা অত্যন্ত ব্যাপ্তবিশিষ্ট হয়ে দেবগণের প্রতি প্রেরিত হয়, তা দ্বারা তুমি সমস্ত যজনীয় দেবগণকে আমাদরে রক্ষার জন্য এখানে উপবেশন করাও এবং তাদরে হর্ষকর সোম পান করাও।"},{"n":6,"d":"या ते अग्ने पर्वतस्येव धारासश्चन्ती पीपयद देव चित्रा | तामस्मभ्यं परमतिं जातवेदो वसो रास्व सुमतिं विश्वजन्याम ||","b":"যা তে অগ্নে পর্বতস্যেব ধারাসশ্চন্তী পীপযদ দেব চিত্রা | তামস্মভ্যং পরমতিং জাতবেদো বসো রাস্ব সুমতিং বিশ্বজন্যাম ||","e":"Let thy stream give us drink, O God, O Agni, wonderful and exhaustless like the rain-clouds. Thus care for us, O Vasu Jātavedas, show us thy loving-kindness, reaching all men.","mb":"হে দ্যুতিমান অগ্নি! তোমার যে অনুগ্রহ বুদ্ধি আমাদরে ছেড়ে অন্যত্র যায় না সেই অনুগ্রহ বুদ্ধি মেঘের ধারার ন্যায় আমাদরে আপ্যায়িত করুক। হে নিবাসপ্রদ জাতবেদা। আমাদের সে অনুগ্রহ বুদ্ধি প্রদান কর, বিশ্বজনের হিতকর অনুগ্রহ বুদ্ধি আমাদের প্রদান কর।"}]},{"n":58,"t":"Aśvins","v":[{"n":1,"d":"धेनुः परत्नस्य काम्यं दुहानान्तः पुत्रश्चरति दक्षिणायाः | आ दयोतनिं वहति शुभ्रयामोषस सतोमो अश्विनावजीगः ||","b":"ধেনুঃ পরত্নস্য কাম্যং দুহানান্তঃ পুত্রশ্চরতি দক্ষিণাযাঃ | আ দযোতনিং বহতি শুভ্রযামোষস সতোমো অশ্বিনাবজীগঃ ||","e":"THE Ancient's Milch-cow yields the things we long for: the Son of Dakṣiṇā travels between them. She with the splendid chariot brings refulgence. The praise of Uṣas hath awoke the Aśvins.","mb":"ধেনু ঊষা পুরাতন অগ্নির জন্য কমনীয় দুগ্ধ দোহন করছেন। দক্ষিনার পুত্র সূর্য মধ্যে প্রবেশ করছেন, পরে শুভ্রদীপ্তি দিবস দ্যোতমান সূর্যকে বহন করে আনছে। অশ্বিদ্বয়ের স্তোতা উষার পূর্বে জাগরিত হচ্ছে।"},{"n":2,"d":"सुयुग वहन्ति परति वां रतेनोर्ध्वा भवन्ति पितरेव मेधाः | जरेथामस्मद वि पणेर्महीषां युवोरवश्चक्र्मा यातमर्वाक ||","b":"সুযুগ বহন্তি পরতি বাং রতেনোর্ধ্বা ভবন্তি পিতরেব মেধাঃ | জরেথামস্মদ বি পণের্মহীষাং যুবোরবশ্চক্র্মা যাতমর্বাক ||","e":"They bear you hither by well-orderd statute: our sacred offerings rise as if to parents. Destroy in us the counsel of the niggard come hitherward, for we have shown you favour.","mb":"হে অশ্বিদ্বয়! উত্তমরূপে যোজিত অশ্বদ্বয় সত্যরূপ রথে তোমাদের বহন করছে। পুত্র পিতার জন্য যেরূপ উন্মুখ হয়, যজ্ঞগণ সেরূপ তোমাদের জন্য উন্মুখ হয়ে আছে। আমাদরে নিকট হতে পণির বৃদ্ধি বিশেষরূপে নাশ কর। আমরা তোমাদের জন্য হবি প্রস্তুত করছি, তোমরা এস।"},{"n":3,"d":"सुयुग्भिरश्वैः सुव्र्ता रथेन दस्राविमं शर्णुतं शलोकमद्रेः | किमङग वां परत्यवर्तिं गमिष्ठाहुर्विप्रासो अश्विना पुराजाः ||","b":"সুযুগ্ভিরশ্বৈঃ সুব্র্তা রথেন দস্রাবিমং শর্ণুতং শলোকমদ্রেঃ | কিমঙগ বাং পরত্যবর্তিং গমিষ্ঠাহুর্বিপ্রাসো অশ্বিনা পুরাজাঃ ||","e":"With lightly-rolling car and well-yoked horses hear this, the press-stone's song, ye Wonder-Workers. Have not the sages of old time, ye Aśvins, called you most prompt to come and stay misfortune?","mb":"হে অশ্বিদ্বয়! সুন্দর চক্রবিশিষ্ট রথে আরোহণ করে উত্তমরূপে যোজিত অশ্বদ্বরা বাহিত হয়ে তোমরা, স্তুতিকারীর এ শ্লোক  শ্রবণ কর। হে অশ্বিদ্বয়! পুরাতন মেধাবীগণ কি বলেন নি, যে তোমরা বৃত্তিহানির বিরুদ্ধে যাও।"},{"n":4,"d":"आ मन्येथामा गतं कच्चिदेवैर्विश्वे जनासो अश्विना हवन्ते | इमा हि वां गोर्जीका मधूनि पर मित्रासो न ददुरुस्रो अग्रे ||","b":"আ মন্যেথামা গতং কচ্চিদেবৈর্বিশ্বে জনাসো অশ্বিনা হবন্তে | ইমা হি বাং গোর্জীকা মধূনি পর মিত্রাসো ন দদুরুস্রো অগ্রে ||","e":"Remember us, and come to us, for ever men, as their wont is, invocate the Aśvins. Friends as it were have offered you these juices, sweet, blent with milk at the first break of morning.","mb":"হে অশ্বিদ্বয়! তোমরা আমার স্তুতি অবগত হও এবং অশ্বগণের সাথে এস। সমস্ত লোক তোমাদের আহ্বান করছে, তারা বন্ধুর ন্যায় তোমাদের দুগ্ধমিশ্রিত হর্ষকর সোম প্রদান করছে। সূর্য অগ্রে উদয় হচ্ছেন।"},{"n":5,"d":"तिरः पुरू चिदश्विना रजांस्याङगूषो वां मघवाना जनेषु | एह यातं पथिभिर्देवयानैर्दस्राविमे वां निधयो मधूनाम ||","b":"তিরঃ পুরূ চিদশ্বিনা রজাংস্যাঙগূষো বাং মঘবানা জনেষু | এহ যাতং পথিভির্দেবযানৈর্দস্রাবিমে বাং নিধযো মধূনাম ||","e":"Even through many regions, O ye Aśvins high praise is yours among mankind, ye Mighty- Come, helpers, on the paths which Gods have travelled: here your libations of sweet meath are ready.","mb":"হে অশ্বিদ্বয়! নানা দেশকে তিরস্কৃত করে দেবযান পথে এ স্থলে আগমন কর। তোমরা  ধনবান, তোমাদের স্তোত্র উদ্ঘোষিত হচ্ছে, তোমাদের জন্য মধুর আধার সকল সজ্জিত হয়েছে।"},{"n":6,"d":"पुराणमोकः सख्यं शिवं वां युवोर्नरा दरविणं जह्नाव्याम | पुनः कर्ण्वानाः सख्या शिवानि मध्वा मदेमसह नू समानाः ||","b":"পুরাণমোকঃ সখ্যং শিবং বাং যুবোর্নরা দরবিণং জহ্নাব্যাম | পুনঃ কর্ণ্বানাঃ সখ্যা শিবানি মধ্বা মদেমসহ নূ সমানাঃ ||","e":"Ancient your home, auspicious is your friendship: Heroes, your wealth is with the house of Jahnu. Forming again with you auspicious friendship, let us rejoice with draughts of meath together.","mb":"হে অশ্বিদ্বয়! তোমাদের পুরাতন সখ্য বাঞ্চনীয় ও মসঙ্গলকর। হেজ নেতৃদ্বয়। জাহুবীতে (১) তোমাদের ধন আছে। তোমাদের সুখকর সখ্য বার বার প্রাপ্ত হয়ে আমরা তোমাদের সমান হয়েছি। আমরা হর্ষকর সোমদ্বারা তোমাদের শীঘ্র ও যুগপৎ হৃষ্ট করব।"},{"n":7,"d":"अश्विना वायुना युवं सुदक्षा नियुद्भिष च सजोषसा युवाना | नासत्या तिरोह्न्यं जुषाणा सोमं पिबतमस्रिधा सुदानू ||","b":"অশ্বিনা বাযুনা যুবং সুদক্ষা নিযুদ্ভিষ চ সজোষসা যুবানা | নাসত্যা তিরোহ্ন্যং জুষাণা সোমং পিবতমস্রিধা সুদানূ ||","e":"O Aśvins, Very Mighty ones, with Vāyu and with his steeds, one-minded, ever-youthful, Nāsatyas, joying in the third day's Soma, drink it, not hostile, Very Bounteous Givers.","mb":"অক্ষীণ, সোমপায়ী, সুদক্ষ, নিত্যতরুণ অসত্যরহিত এবং সুদানশীল অশ্বিদ্বয় বায়ু ও নিষুতগণের সাথে মিলিত হয়ে দিবসের শেষে সোম পান করুন।"},{"n":8,"d":"अश्विना परि वामिषः पुरूचीरीयुर्गीर्भिर्यतमाना अम्र्ध्राः | रथो ह वां रतजा अद्रिजूतः परि दयावाप्र्थिवी याति सद्यः ||","b":"অশ্বিনা পরি বামিষঃ পুরূচীরীযুর্গীর্ভির্যতমানা অম্র্ধ্রাঃ | রথো হ বাং রতজা অদ্রিজূতঃ পরি দযাবাপ্র্থিবী যাতি সদ্যঃ ||","e":"Aśvins, to you are brought abundant viands in rivalry with sacred songs, unceasing. Sprung from high Law your car, urged on by press-stones, goes round the earth and heaven in one brief moment.","mb":"হে অশ্বিদ্বয়! প্রচুর হবি তোমাদের নিকট গমন করছে, দোষশূন্য কর্মকুশল  স্তোতুগণ স্তুতিদ্বারা তোমাদের পরিচর্যা করছে। স্তোতৃগণ কর্তৃক আকৃষ্ট, জলপ্রদ রথ সদা  দ্যাবাপৃথিবীর অভিমুখে যাচ্ছে।"},{"n":9,"d":"अश्विना मधुषुत्तमो युवाकुः सोमस्तं पातमा गतं दुरोणे | रथो ह वां भूरि वर्पः करिक्रत सुतावतो निष्क्र्तमागमिष्ठः ||","b":"অশ্বিনা মধুষুত্তমো যুবাকুঃ সোমস্তং পাতমা গতং দুরোণে | রথো হ বাং ভূরি বর্পঃ করিক্রত সুতাবতো নিষ্ক্র্তমাগমিষ্ঠঃ ||","e":"Aśvins, your Soma sheds delicious sweetness: drink ye thereof and come unto our dwelling. Your car, assuming many a shape, most often goes to the Soma-presser's place of meeting.","mb":"হে অশ্বিদ্বয়! অত্য্নত মধুর রস বিশিষ্ট সোম মিশ্রিত হয়েছে, পান কর, ও যজ্ঞঝশালায় প্রবেশ কর। তোমাদের বারবার ধনদানকারী রথ সোমাভিষবকারীর সংস্কৃত  গহৃহে আসছে।"}]},{"n":59,"t":"Mitra","v":[{"n":1,"d":"मित्रो जनान यातयति बरुवाणो मित्रो दाधार पर्थिवीमुत दयाम | मित्रः कर्ष्टीरनिमिषाभि चष्टे मित्राय हव्यंघ्र्तवज्जुहोत ||","b":"মিত্রো জনান যাতযতি বরুবাণো মিত্রো দাধার পর্থিবীমুত দযাম | মিত্রঃ কর্ষ্টীরনিমিষাভি চষ্টে মিত্রায হব্যংঘ্র্তবজ্জুহোত ||","e":"MITRA, when speaking, stirreth men to labour: Mitra sustaineth both the earth and heaven. Mitra beholdeth men with eyes that close not. To Mitra bring, with holy oil, oblation.","mb":"মিত্র স্তুত হয়ে লোক সকলকে কার্যে প্রবর্তিত করছেন। মিত্র পৃথিবী এবং দ্যুলোক ধারণ করে আছেন, মিত্র অনিমেষনেত্রে লোক সকলের দিকে চেয়ে আছেন। মিত্রের উদ্দশে ঘৃতবিশিষ্ট হব্য প্রদান কর।"},{"n":2,"d":"पर स मित्र मर्तो अस्तु परयस्वान यस्त आदित्य शिक्षति वरतेन | न हन्यते न जीयते तवोतो नैनमंहो अश्नोत्यन्तितो न दूरात ||","b":"পর স মিত্র মর্তো অস্তু পরযস্বান যস্ত আদিত্য শিক্ষতি বরতেন | ন হন্যতে ন জীযতে তবোতো নৈনমংহো অশ্নোত্যন্তিতো ন দূরাত ||","e":"Foremost be he who brings thee food, O Mitra, who strives to keep thy sacred Law, Āditya. He whom thou helpest ne’er is slain or conquered, on him, from near or far, falls no affliction.","mb":"হে আদিত্য মিত্র। যে মনুষ্য ব্রতানুসারে তোমাকে হব্য প্রদান করে, সে অন্নবান হোক। তুমি যাকে রক্ষা কর, তাকে কেউ বিনাশ করতে বা অভিভব করতে পারে না। পাপ দূর হতে অথবা নিকট হতে সে ব্যক্তিকে স্পর্শ করতে পারে না।"},{"n":3,"d":"अनमीवास इळया मदन्तो मितज्ञवो वरिमन्ना पर्थिव्याः | आदित्यस्य वरतमुपक्षियन्तो वयं मित्रस्य सुमतौ सयाम ||","b":"অনমীবাস ইলযা মদন্তো মিতজ্ঞবো বরিমন্না পর্থিব্যাঃ | আদিত্যস্য বরতমুপক্ষিযন্তো বযং মিত্রস্য সুমতৌ সযাম ||","e":"joying in sacred food and free from sickness, with knees bent lowly on the earth's broad surface, Following closely the Āditya's statute, may we remain in Mitra's gracious favour.","mb":"আমরা রোগবর্জিত ও অন্নলাভে হৃষ্ট হয়ে পৃথিবীর বিস্তীর্ণ প্রদেশে জানুপেতে সর্বত্রগামী আদিত্যের ব্রতেকর নিকট অবস্থিতি করছি। মিত্র যেন আমাদরে প্রতি অনুগ্রহ করেন।"},{"n":4,"d":"अयं मित्रो नमस्यः सुशेवो राजा सुक्षत्रो अजनिष्ट वेधाः | तस्य वयं ... ||","b":"অযং মিত্রো নমস্যঃ সুশেবো রাজা সুক্ষত্রো অজনিষ্ট বেধাঃ | তস্য বযং ... ||","e":"Auspicious and adorable, this Mitra was born with fair dominion, King, Disposer. May we enjoy the grace of him the Holy, yea, rest in his propitious loving-kindness.","mb":"্এ মিত্র প্রাদুর্ভূত হয়েছেন, ইনি নমস্কারযোগ্য সুন্দর মুখ বিশিষ্ট রাজা ও অত্যন্ত বলবিশিষ্ট এবং সকলের বিধাতা। ইনি যজ্ঞাহ আমরা যেন এর অনুগ্রহ ও কল্যাণকর বাৎসল্য লাভ করতে পারি।"},{"n":5,"d":"महानादित्यो नमसोपसद्यो यातयज्जनो गर्णते सुशेवः | तस्मा एतत पन्यतमाय जुष्टमग्नौ मित्राय हविरा जुहोत ||","b":"মহানাদিত্যো নমসোপসদ্যো যাতযজ্জনো গর্ণতে সুশেবঃ | তস্মা এতত পন্যতমায জুষ্টমগ্নৌ মিত্রায হবিরা জুহোত ||","e":"The great Āditya, to be served with wor. ship, who stirreth men, is gracious to the singer. To Mitra, him most highly to be lauded, offer in fire oblation that he loveth.","mb":"্আদিত্য মহজানু তিনি সকল লোকের প্রবর্তক, নমস্কার দ্বারা তার উপাসনা করা উচিত। তিনি স্তুতিকারীর প্রতি প্রসন্নমুখ। স্তুতিযোগ্য মিত্রের প্রীতিকর এ হব্য অগ্নিতে অর্পণ  কর।"},{"n":6,"d":"मित्रस्य चर्षणीध्र्तो.अवो देवस्य सानसि | दयुम्नं चित्रश्रवस्तमम ||","b":"মিত্রস্য চর্ষণীধ্র্তো.অবো দেবস্য সানসি | দযুম্নং চিত্রশ্রবস্তমম ||","e":"The gainful grace of Mitra,. God, supporter of the race of man, Gives splendour of most.glorious fame.","mb":"মনুষ্যগণের পালক মিত্রদেবের অন্ন ও ভজনীয় ধন অত্যন্ত কীর্তিযুক্ত।"},{"n":7,"d":"अभि यो महिना दिवं मित्रो बभूव सप्रथाः | अभि शरवोभिः पर्थिवीम ||","b":"অভি যো মহিনা দিবং মিত্রো বভূব সপ্রথাঃ | অভি শরবোভিঃ পর্থিবীম ||","e":"Mitra whose glory spreads afar, he who in might surpasses heaven, Surpasses earth in his renown.","mb":"যে মিত্র নিজ মহিজমায় দ্যুলোক অভিভূত করছেন, তিনি কীর্তিযুক্ত হয়ে পৃথিবীকে প্রচুর অন্নবিশিষ্টা করেছেন।"},{"n":8,"d":"मित्राय पञ्च येमिरे जना अभिष्टिशवसे | स देवान विश्वान बिभर्ति ||","b":"মিত্রায পঞ্চ যেমিরে জনা অভিষ্টিশবসে | স দেবান বিশ্বান বিভর্তি ||","e":"All the Five Races have repaired to Mitra, ever strong to aid, For he sustaineth all the Gods.","mb":"পঞ্চজন, শত্রুজয়ক্ষম বলবিশিষ্ট মিত্রের উদ্দেশে হব্য প্রদান করেছেন, তিনি সমস্ত দেবগণকে ধারণ করছেন।"},{"n":9,"d":"मित्रो देवेष्वायुषु जनाय वर्क्तबर्हिषे | इष इष्टव्रताकः ||","b":"মিত্রো দেবেষ্বাযুষু জনায বর্ক্তবর্হিষে | ইষ ইষ্টব্রতাকঃ ||","e":"Mitra to Gods, to living men, to him who strews the holy grass, Gives food fulfilling sacred Law.","mb":"মিত্র, দেব ও নুষ্যদিগের মধ্যে যে ব্যক্তি কৃশচ্ছেদ করেছে, তাকে কল্যাণকর অন্ন প্রদান করেন।"}]},{"n":60,"t":"Ṛbhus","v":[{"n":1,"d":"इहेह वो मनसा बन्धुता नर उशिजो जग्मुरभि तानि वेदसा | याभिर्मायाभिः परतिजूतिवर्पसः सौधन्वना यज्ञियं भागमानश ||","b":"ইহেহ বো মনসা বন্ধুতা নর উশিজো জগ্মুরভি তানি বেদসা | যাভির্মাযাভিঃ পরতিজূতিবর্পসঃ সৌধন্বনা যজ্ঞিযং ভাগমানশ ||","e":"HERE is your ghostly kinship, here, O Men: they came desirous to these holy rites with store of wealth, With wondrous arts, whereby, with schemes to meet each need, Ye gained, Sudhanvan's Sons! your share in sacrifice.","mb":"হে ঋভুগণ! তোমাদের কমৃ সকলেই জানে, হে মনুষ্যগণ? তোমরা সুধম্বার পুত্র, তোমরা যে সকল কর্মদ্বারা শত্রুপরাভবোপযুক্ত তেজবিশিষ্ট হয়ে যজ্ঞীয় ভাগ প্রাপ্ত হয়েছে, যজ্ঞভাগ কামনা কালে তোমরা সে সকল কর্মজানতে পেরেছিলে।"},{"n":2,"d":"याभिः शचीभिश्चमसानपिंशत यया धिया गामरिणीत चर्मणः | येन हरी मनसा निरतक्षत तेन देवत्वं रभवः समानश ||","b":"যাভিঃ শচীভিশ্চমসানপিংশত যযা ধিযা গামরিণীত চর্মণঃ | যেন হরী মনসা নিরতক্ষত তেন দেবত্বং রভবঃ সমানশ ||","e":"The mighty powers wherewith. ye formed the chalices, the thought by which ye drew the cow from out the hide, The intellect wherewith ye wrought the two Bay Steeds,—through these, O Ṛbhus, ye attained divinity.","mb":"হে ঋভুগণ! তোমরা যে শক্তি দ্বারা চমসকে বিভক্ত করেছিলে, যে প্রজ্ঞাবলে গোশরীরে চর্ম যোজনা করেছিলে, যে মনীষাদ্বারা ইন্দ্রের অশ্বদ্বয়কে নিমৃাণ করেছিলে সে সকলের দ্বারা দেবত্ব প্রাপ্ত হয়েছে।"},{"n":3,"d":"इन्द्रस्य सख्यं रभवः समानशुर्मनोर्नपातो अपसो दधन्विरे | सौधन्वनासो अम्र्तत्वमेरिरे विष्ट्वी शमीभिः सुक्र्तः सुक्र्त्यया ||","b":"ইন্দ্রস্য সখ্যং রভবঃ সমানশুর্মনোর্নপাতো অপসো দধন্বিরে | সৌধন্বনাসো অম্র্তত্বমেরিরে বিষ্ট্বী শমীভিঃ সুক্র্তঃ সুক্র্ত্যযা ||","e":"Friendship with Indra have the Ṛbhus, fully gained: grandsons of Manu, they skilfully urged the work. Sudhanvan's Children won them everlasting life, serving with holy rites, pious with noble acts. 4:In company with Indra come ye to the juice, then gloriously shall your wishes be fulfilled. Not to be paragoned, ye Priests, are your good deeds, nor your heroic acts, Ṛbhus, Sudhanvan's Sons.","mb":"মনুষ্যের নপ্তা ঋভুগণ বাগাদিকর্ম করে ইন্দ্রের সখিত্ব প্রাপ্ত হয়েছিলেন এবং প্রাণ ধারণ করেছিলেন। সুধম্বার পুণ্যকার্যকারী পুত্রগণ কর্মবলে ও যজ্ঞাদি বলে  ব্যাপ্ত হ{েয় অমৃতত্ব প্রাপ্ত হয়েছেন।"},{"n":4,"d":"इन्द्रेण याथ सरथं सुते सचानथो वशानां भवथासह शरिया | न वः परतिमै सुक्र्तानि वाघतः सौधन्वना रभवो वीर्याणि च ||","b":"ইন্দ্রেণ যাথ সরথং সুতে সচানথো বশানাং ভবথাসহ শরিযা | ন বঃ পরতিমৈ সুক্র্তানি বাঘতঃ সৌধন্বনা রভবো বীর্যাণি চ ||","e":"O Indra, with the Ṛbhus, Mighty Ones, pour down the Soma juice effused, well-blent, from both thy hands. Maghalan, urged by song, in the drink-offerer's house rejoice thee with the Heroes, with Sudhanvan's Sons.","mb":"হে ঋভুগণ! তোমরা ইন্দ্রের সাথে একরথে সোমাভিষব স্থানে যাও। পরে মনুষ্যগণের স্তুতি গ্রহণ  কর। হে ফলবাহক সুধম্বার পুত্রগণ! তোমাদের সুকৃত কেহ ইয়ত্তা করতে পা রনা। হে ঋভুগণ! তোমাদের বীর্যও কেউ ইয়ত্তা করতে পারে না।"},{"n":5,"d":"इन्द्र रभुभिर्वाजवद्भिः समुक्षितं सुतं सोममा वर्षस्वा गभस्त्योः | धियेषितो मघवन दाशुषो गर्हे सौधन्वनेभिः सह मत्स्वा नर्भिः ||","b":"ইন্দ্র রভুভির্বাজবদ্ভিঃ সমুক্ষিতং সুতং সোমমা বর্ষস্বা গভস্ত্যোঃ | ধিযেষিতো মঘবন দাশুষো গর্হে সৌধন্বনেভিঃ সহ মত্স্বা নর্ভিঃ ||","e":"With Ṛbhu near, and Vāja, Indra, here exult, with Saci, praised of many, in the juice we pour. These homes wherein we dwell have turned themselves to thee, -devotions to the Gods, as laws of men ordain.","mb":"হে ইন্দ্র! তুমি বাজবিশিষ্ট ঋভুগণের সাথে সম্যকরূপে জলদ্বারা সিক্ত অভিষুত সোম দু হাতে গ্রহণ করে পান কর। হেজ মঘবন! তুমি স্তুতিদ্বারা প্রেরিত হয়ে যজমানের গৃহে সুধম্বার পুত্রগণের সঙ্গে উল্লসিত হও।"},{"n":6,"d":"इन्द्र रभुमान वाजवान मत्स्वेह नो.अस्मिन सवने शच्या पुरुष्टुत | इमानि तुभ्यं सवसराणि येमिरे वरता देवानां मनुषश्च धर्मभिः ||","b":"ইন্দ্র রভুমান বাজবান মত্স্বেহ নো.অস্মিন সবনে শচ্যা পুরুষ্টুত | ইমানি তুভ্যং সবসরাণি যেমিরে বরতা দেবানাং মনুষশ্চ ধর্মভিঃ ||","e":"Come with the mighty Ṛbhus, Indra, come to us, strengthening with thy help the singer's holy praise; At hundred eager calls come to the living man, with thousand arts attend the act of sacrifice.","mb":"হে বহুলোক স্তুত ইন্দ্র! তুমি ঋভু ও বাজের সমভিব্যাহারে আমাদরে এ যজ্ঞে (১) আনন্দিত হও। হে ইন্দ্র! দিন সকল তোমার জন্য নিয়ত হয়েছে। দেবগণের ব্রত মনুষ্যগণের কর্মের সাথে দিন সকল তোমাদের জন্য নিয়ত হয়েছে।"},{"n":7,"d":"इन्द्र रभुभिर्वाजिभिर्वाजयन्निह सतोमं जरितुरुप याहि यज्ञियम | शतं केतेभिरिषिरेभिरायवे सहस्रणीथोध्वरस्य होमनि ||","b":"ইন্দ্র রভুভির্বাজিভির্বাজযন্নিহ সতোমং জরিতুরুপ যাহি যজ্ঞিযম | শতং কেতেভিরিষিরেভিরাযবে সহস্রণীথোধ্বরস্য হোমনি ||","e":"Missing line from Griffith.","mb":"হে ইন্দ্র! তুমি স্তোতার অন্ন সম্পাদন করে বাজযুক্ত ঋতুগণের সাথে এ যজ্ঞে স্তোতার স্তোত্র অভিমুখে এস। মরুৎগণও শতসংখ্যক গমনকুশল অশ্বের সাথে যজমানরে সহস্র প্রকারে প্রনীত অধ্বরের এস।"}]},{"n":61,"t":"Uṣas","v":[{"n":1,"d":"उषो वाजेन वाजिनि परचेता सतोमं जुषस्व गर्णतो मघोनि | पुराणी देवि युवतिः पुरन्धिरनु वरतं चरसि विश्ववारे ||","b":"উষো বাজেন বাজিনি পরচেতা সতোমং জুষস্ব গর্ণতো মঘোনি | পুরাণী দেবি যুবতিঃ পুরন্ধিরনু বরতং চরসি বিশ্ববারে ||","e":"O Uṣas, strong with strength, endowed witli knowledge, accept the singer's praise, O wealthy Lady. Thou, Goddess, ancient, young, and full of wisdom, movest, all-bounteous! as the Law ordaineth.","mb":"হে অন্নবতী ধনবতী উষা! আমি স্তব করছি, তুমি প্রকৃষ্ট জ্ঞানবতী হয়ে আমা রস্তোত্র গ্রহণ কর। হে সকলের বরণীয়া পুরাতনী যুবতীর ন্যায় শোভমানা ও বহস্তোত্রবতী উষা! তুমি যজ্ঞকর্মাভিমুখে এস।"},{"n":2,"d":"उषो देव्यमर्त्या वि भाहि चन्द्ररथा सून्र्ता ईरयन्ती | आ तवा वहन्तु सुयमासो अश्वा हिरण्यवर्णां पर्थुपाजसो ये ||","b":"উষো দেব্যমর্ত্যা বি ভাহি চন্দ্ররথা সূন্র্তা ঈরযন্তী | আ তবা বহন্তু সুযমাসো অশ্বা হিরণ্যবর্ণাং পর্থুপাজসো যে ||","e":"Shine forth, O Morning, thou auspicious Goddess, on thy bright car awaking pleasant voices. Let docile horses of far-reaching splendour convey thee hitherward, the goldencoloured.","mb":"হে মরণরহিতা চন্দ্ররথা (১) সুনুতবাক্যোচ্চারণশীলা ঊষা! তুমি শোভমানা হও। যে সকল প্রভূত বলযুক্ত হিরণ্যবর্ণ অশ্ব আছে, তাদের মুখে রথে যোজিত করতে পারা যায়। তারা তোমাকে আহ্বান করুক।"},{"n":3,"d":"उषः परतीची भुवनानि विश्वोर्ध्वा तिष्ठस्यम्र्तस्य केतुः | समानमर्थं चरणीयमाना चक्रमिव नव्यस्या वव्र्त्स्व ||","b":"উষঃ পরতীচী ভুবনানি বিশ্বোর্ধ্বা তিষ্ঠস্যম্র্তস্য কেতুঃ | সমানমর্থং চরণীযমানা চক্রমিব নব্যস্যা বব্র্ত্স্ব ||","e":"Thou, Morning, turning thee to every creature, standest on high as ensign of the Immortal, To one same goal ever and ever wending now, like a wheel, O newly-born, roll hi ther.","mb":"হে ঊষা! তুমি মরণধর্শ রহিত সূর্যের কেতুস্বরূপ। তুমি ত্রিভূবনাভিমুখে গমনশীলা। তুমি আকাশে উন্নতা হ{েয় আছ। হে নবতররা ঊষা! তুমি একপথে বিচরণ করতে ইচ্ছা করে চক্রের ন্যায় পুনরাবৃত্ত হও।"},{"n":4,"d":"अव सयूमेव चिन्वती मघोन्युषा याति सवसरस्य पत्नी | सवर्जनन्ती सुभगा सुदंसा आन्ताद दिवः पप्रथ आ पर्थिव्याः ||","b":"অব সযূমেব চিন্বতী মঘোন্যুষা যাতি সবসরস্য পত্নী | সবর্জনন্তী সুভগা সুদংসা আন্তাদ দিবঃ পপ্রথ আ পর্থিব্যাঃ ||","e":"Letting her reins drop downward, Morning cometh, the wealthy Dame, the Lady of the dwelling; Bringing forth light, the Wonderful, the Blessed hath spread her from the bounds of earth and heaven.","mb":"যে ঊষা  বস্ত্রের ন্যায় বিস্তীর্ণ অন্ধকার ক্ষয়িত করে সূর্যের পত্নী হয়ে যান, সে সৌভাগ্যবতী সৎকার্যশালিনী উষা দ্যুলোক ও পৃথিবীর অন্ত হতে প্রকাশিত হচ্ছেন।"},{"n":5,"d":"अछा वो देवीमुषसं विभातीं पर वो भरध्वं नमसा सुव्र्क्तिम | ऊर्ध्वं मधुधा दिवि पाजो अश्रेत पर रोचना रुरुचे रण्वसन्द्र्क ||","b":"অছা বো দেবীমুষসং বিভাতীং পর বো ভরধ্বং নমসা সুব্র্ক্তিম | ঊর্ধ্বং মধুধা দিবি পাজো অশ্রেত পর রোচনা রুরুচে রণ্বসন্দ্র্ক ||","e":"Hither invoke the radiant Goddess Morning, and bring with reverence your hymn to praise her. She, dropping sweets, hath set in heaven her brightness, and, fair to look on, hath beamed forth her splendour.","mb":"হে স্তোতৃগণ! উষাদেবী তোমাদের অভিমুখে শোভা পাচ্ছেন। তোমরা  নমস্কার করে উত্তমরূপে তার স্তুতি কর। মধুধা উষা আকাশে উর্ধ্বাভিমুখে তেজের আশ্রয় করছেন। দীপ্তিমতী রমণীয় দর্শনা উষা অতিশয় দীপ্তি পাচ্ছেন।"},{"n":6,"d":"रतावरी दिवो अर्कैरबोध्या रेवती रोदसी चित्रमस्थात | आयतीमग्न उषसं विभातीं वाममेषि दरविणं भिक्षमाणः ||","b":"রতাবরী দিবো অর্কৈরবোধ্যা রেবতী রোদসী চিত্রমস্থাত | আযতীমগ্ন উষসং বিভাতীং বামমেষি দরবিণং ভিক্ষমাণঃ ||","e":"From heaven, with hymns, the Holy One was wakened: brightly to both worlds came the wealthy Lady. To Morning, Agni, when she comes refulgent, thou goest forth soliciting fair riches.","mb":"সত্যবতী যে উষার তেজপ্রভাবে সকলে তাকে জানতে পারে, ধনবতী যে উষা বিচিত্রভাবে দ্যাবাপৃথিবী ব্যাপ্ত করে আছেন, হে অগ্নি! যখন সে শোভমানা উষা তোমার অভিমুখে আসেন তখন প্রার্থনা করলে তুমি মনোহর ধন প্রাপ্ত হও।"},{"n":7,"d":"रतस्य बुध्न उषसामिषण्यन वर्षा मही रोदसी आ विवेश | मही मित्रस्य वरुणस्य माया चन्द्रेव भानुं वि दधे पुरुत्रा ||","b":"রতস্য বুধ্ন উষসামিষণ্যন বর্ষা মহী রোদসী আ বিবেশ | মহী মিত্রস্য বরুণস্য মাযা চন্দ্রেব ভানুং বি দধে পুরুত্রা ||","e":"On Law's firm base the speeder of the Mornings, the Bull, hath entered mighty earth and heaven. Great is the power of Varuṇa and Mitra, which, bright, hath spread in every place its splendour.","mb":"অভীষ্টবর্ষী আদিত্য সত্যভূত  দিবসের  মুলে উষাকে প্রেরণ করে বিস্তীর্ণ দ্যাবাপৃথিবীর মধ্যে প্রবেশ করলেন। পরে বিস্তীর্ণা উষা মিত্র ও বরুণের প্রভাস্বরূপ হয়ে নানাস্থানে আপনার শোভা বিকীর্ণ করলেন।"}]},{"n":62,"t":"Indra And Others","v":[{"n":1,"d":"इमा उ वां भर्मयो मन्यमाना युवावते न तुज्या अभूवन | कव तयदिन्द्रावरुणा यशो वां येन समा सिनं भरथः सखिभ्यः ||","b":"ইমা উ বাং ভর্মযো মন্যমানা যুবাবতে ন তুজ্যা অভূবন | কব তযদিন্দ্রাবরুণা যশো বাং যেন সমা সিনং ভরথঃ সখিভ্যঃ ||","e":"YOUR well-known prompt activities aforetime needed no impulse from your faithful servant. Where, Indra-Varuṇa, is now that glory wherewith ye brought support to those who loved you?","mb":"হে ইন্দ্রাবরুণ! অভিমন্যমান ও ভ্রমণশীল তোমাদের এ প্রজাগণ যেন তরুণবয়স্ক শত্রুকর্তৃক হিংসিত না হয়। তোমার যে যশোদ্বারা বন্ধুবর্গ আমাদের জন্য অন্ন সম্পাদন করেছে, তোমাদের জন্য অন্ন সম্পাদন করেছ, তোমাদরে সেরূপ যশ কোথায় আছে?"},{"n":2,"d":"अयमु वां पुरुतमो रयीयञ्छश्वत्तममवसे जोहवीति | सजोषाविन्द्रावरुणा मरुद्भिर्दिवा पर्थिव्या शर्णुतं हवम्मे ||","b":"অযমু বাং পুরুতমো রযীযঞ্ছশ্বত্তমমবসে জোহবীতি | সজোষাবিন্দ্রাবরুণা মরুদ্ভির্দিবা পর্থিব্যা শর্ণুতং হবম্মে ||","e":"This man, most diligent, seeking after riches, incessantly invokes you for your favour. Accordant, Indra-Varuṇa, with Maruts, with Heaven and Earth, hear ye mine invocation.","mb":"হে ইন্দ্রবরণ! ধনলাভের অভিলাষে এ মহান যজমান আশ্রয় লাভের জন্য তোমাদরে আহ্বান করছে। তোমরা দ্যুলোক পৃথিবী এবং মরুৎগণের সাথে মিলিত হয়ে আমাদরে আহ্বান শোন।"},{"n":3,"d":"अस्मे तदिन्द्रावरुणा वसु षयादस्मे रयिर्मरुतः सर्ववीरः | अस्मान वरूत्रीः शरणैरवन्त्वस्मान होत्रा भारती दक्षिणाभिः ||","b":"অস্মে তদিন্দ্রাবরুণা বসু ষযাদস্মে রযির্মরুতঃ সর্ববীরঃ | অস্মান বরূত্রীঃ শরণৈরবন্ত্বস্মান হোত্রা ভারতী দক্ষিণাভিঃ ||","e":"O Indra-Varuṇa, ours be this treasure ours be wealth, Maruts, with full store of heroes. May the Varūtrīs with their shelter aid us, and Bhāratī and Hotrā with the Mornings.","mb":"হে ইন্দ্রাবরুণ! সে ধন আমাদ রহোক, হে মরুৎগণ! সর্বকর্ম সমর্থ ধন আমাদের হোক। সকলের ভজনীয়া দেবপত্নীগণ শরণ দ্বারা আমাদরে পালন করুন। হোত্রাভারতী দক্ষিণা দ্বারা আমাদরে পালন করুন।"},{"n":4,"d":"बर्हस्पते जुषस्व नो हव्यानि विश्वदेव्य | रास्व रत्नानि दाशुषे ||","b":"বর্হস্পতে জুষস্ব নো হব্যানি বিশ্বদেব্য | রাস্ব রত্নানি দাশুষে ||","e":"Be pleased! with our oblations, thou loved of all Gods, Bṛhaspati: Give wealth to him who brings thee gifts.","mb":"হে সকল দেবগণের তহতকর বৃহস্পতি! আমাদরে হব্য গ্রহণ করি। হব্য প্রদায়ীকে উত্তম ধন প্রদান কর।"},{"n":5,"d":"शुचिमर्कैर्ब्र्हस्पतिमध्वरेषु नमस्यत | अनाम्योज आचके ||","b":"শুচিমর্কৈর্ব্র্হস্পতিমধ্বরেষু নমস্যত | অনাম্যোজ আচকে ||","e":"At sacrifices, with your hymns worship the pure Bṛhaspati— I pray for power which none may bend—","mb":"হে ঋত্বিকগণ! তোমরা যজ্ঞ সমূহে স্তোত্রদ্বারা বিশুদ্ধ বৃহস্পতির পরিচর্যা কর। আমি তার অনভিভবনীয় বল প্রার্থনা করি।"},{"n":6,"d":"वर्षभं चर्षणीनां विश्वरूपमदाभ्यम | बर्हस्पतिंवरेण्यम ||","b":"বর্ষভং চর্ষণীনাং বিশ্বরূপমদাভ্যম | বর্হস্পতিংবরেণ্যম ||","e":"The Bull of men, whom none deceive, the wearer of each shape at will, Bṛhaspati Most Excellent.","mb":"মানুষগণের অভীষ্টবর্ষী বিশ্বরূপ বরণীয় বৃহস্পতির নিকট অভিমত ফ{ল কামনা করি।"},{"n":7,"d":"इयं ते पूषन्नाघ्र्णे सुष्टुतिर्देव नव्यसी | अस्माभिस्तुभ्यं शस्यते ||","b":"ইযং তে পূষন্নাঘ্র্ণে সুষ্টুতির্দেব নব্যসী | অস্মাভিস্তুভ্যং শস্যতে ||","e":"Divine, resplendent Pūṣan, this our newest hymn of eulogy, By us is chanted forth to thee.","mb":"হে দীপ্তিমান পূর্ষা! এ নূতন স্তুতি তোমারই জন্য। এ স্তুতি আমরা তোমার জন্য উচ্চারণ করছি।"},{"n":8,"d":"तां जुषस्व गिरं मम वाजयन्तीमवा धियम | वधूयुरिव योषणाम ||","b":"তাং জুষস্ব গিরং মম বাজযন্তীমবা ধিযম | বধূযুরিব যোষণাম ||","e":"Accept with favour this my song, be gracious to the earnest thought, Even as a bridegroom to his bride.","mb":"হে পুষা! আামর সে স্তুতি গ্রহণ কর! স্প্রীপ্রিয় ব্যক্তি যেরূপ স্ত্রীর অভিমুখে আসে সেরুপ তুমি হর্ষকারিণী এ স্তুতির অভিমুখে এস।"},{"n":9,"d":"यो विश्वाभि विपश्यति भुवना सं च पश्यति | स नः पूषाविता भुवत ||","b":"যো বিশ্বাভি বিপশ্যতি ভুবনা সং চ পশ্যতি | স নঃ পূষাবিতা ভুবত ||","e":"May he who sees all living things, see, them together at a glance,— May he, may Pūṣan be our help.","mb":"যে পুষা বিশ্ব জগৎ বিশেষরূপে দর্শন করেন, সে পূষা আমাদরে রক্ষক হোন।"},{"n":10,"d":"तत सवितुर्वरेण्यं भर्गो देवस्य धीमहि | धियो यो नः परचोदयात ||","b":"তত সবিতুর্বরেণ্যং ভর্গো দেবস্য ধীমহি | ধিযো যো নঃ পরচোদযাত ||","e":"May we attain that excellent glory of Savitar the God: So May he stimulate our prayers.","mb":"আমরা সেই সবিতৃদেবের উৎকৃষ্ট তেজ ধ্যান করি, যিনি আমাদের বুদ্ধি ও ধীশক্তিকে প্রেরণা দান করেন।"},{"n":11,"d":"देवस्य सवितुर्वयं वाजयन्तः पुरन्ध्या | भगस्य रातिमीमहे ||","b":"দেবস্য সবিতুর্বযং বাজযন্তঃ পুরন্ধ্যা | ভগস্য রাতিমীমহে ||","e":"With understanding, earnestly, of Savitar the God we crave Our portion of prosperity.","mb":"আমরা সবিতৃদেবের শক্তি প্রার্থনা করি, পুষ্টি ও প্রজ্ঞা সহকারে, ঘৃতাক্ত (সমৃদ্ধ) ধীশক্তি সাধন করতে।"},{"n":12,"d":"देवं नरः सवितारं विप्रा यज्ञैः सुव्र्क्तिभिः | नमस्यन्ति धियेषिताः ||","b":"দেবং নরঃ সবিতারং বিপ্রা যজ্ঞৈঃ সুব্র্ক্তিভিঃ | নমস্যন্তি ধিযেষিতাঃ ||","e":"Men, singers worship Savitar the God with hymn and holy rites, Urged by the impulse of their thoughts.","mb":"কর্মরতা মেধাবী অদ্বর্যগুণ বুদ্ধিদ্বারা প্রেরিত হয়ে যজ্ঞ ও সুন্দর স্তোত্রদ্বারা সবিতা দেবতাকে পূজা করেন।"},{"n":13,"d":"सोमो जिगाति गातुविद देवानामेति निष्क्र्तम | रतस्य योनिमासदम ||","b":"সোমো জিগাতি গাতুবিদ দেবানামেতি নিষ্ক্র্তম | রতস্য যোনিমাসদম ||","e":"Soma who gives success goes forth, goes to the gathering place of Gods, To seat him at the seat of Law.","mb":"পথজ্ঞ সোম গমন করছেন। উপবেশনকারী দেবগণের জন্য সংস্কৃত যজ্ঞস্থানে গমন করছেন।"},{"n":14,"d":"सोमो अस्मभ्यं दविपदे चतुष्पदे च पशवे | अनमीवा इषस करत ||","b":"সোমো অস্মভ্যং দবিপদে চতুষ্পদে চ পশবে | অনমীবা ইষস করত ||","e":"To us and to our cattle may Soma give salutary food, To biped and to quadruped.","mb":"সোম আমাদরে জন্য এবং দ্বিপদ ও চতুস্পদ পশুদের জন্য রোগশুন্য অন্ন প্রদান করুন।"},{"n":15,"d":"अस्माकमायुर्वर्धयन्नभिमातीः सहमानः | सोमः सधस्थमासदत ||","b":"অস্মাকমাযুর্বর্ধযন্নভিমাতীঃ সহমানঃ | সোমঃ সধস্থমাসদত ||","e":"May Soma, strengthening our power of life, and conquering our foes, In our assembly take his seat.","mb":"সোম আমাদরে আয়ু বর্ধিত করে এবং শত্রুগণকে অভিভূত করে যজ্ঞস্থান্উপবেশন করুন।"},{"n":16,"d":"आ नो मित्रावरुणा घर्तैर्गव्यूतिमुक्षतम | मध्वा रजांसि सुक्रतू ||","b":"আ নো মিত্রাবরুণা ঘর্তৈর্গব্যূতিমুক্ষতম | মধ্বা রজাংসি সুক্রতূ ||","e":"May Mitra-Varuṇa, sapient Pair, bedew our pasturage with oil, With meatb the regions of the air.","mb":"হে শোভনকর্মকারী মিত্রাবরুণ! আমাদের গোষ্ঠ দুগ্ধপূর্ণ কর; আমাদরে আবাসস্থান মধুর রসপূর্ণ কর।"},{"n":17,"d":"उरुशंसा नमोव्र्धा मह्ना दक्षस्य राजथः | दराघिष्ठाभिः शुचिव्रता ||","b":"উরুশংসা নমোব্র্ধা মহ্না দক্ষস্য রাজথঃ | দরাঘিষ্ঠাভিঃ শুচিব্রতা ||","e":"Far-ruling, joyful when adored, ye reign through majesty of might, With pure laws everlastingly.","mb":"হে শুচিব্রত! তোমরা অনেকের স্তুতিভাজন এবং উপসনাদ্বারা বর্ধমান। তোমরা দীর্ঘ স্তুতিযুক্ত হয়ে বলমাহাত্ম্যে বিরাজ কর।"},{"n":18,"d":"गर्णाना जमदग्निना योनाव रतस्य सीदतम | पातं सोमं रताव्र्धा ||","b":"গর্ণানা জমদগ্নিনা যোনাব রতস্য সীদতম | পাতং সোমং রতাব্র্ধা ||","e":"Lauded by Jamadagni's song, sit in the place of holy Law:","mb":"হে দেব সবিতৃ, সমস্ত পাপ ও দুরিত দূর করো। যা কল্যাণকর তা আমাদের দান করো।"}]}]});